-- Poems batch 468
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-28','送惠補闕','林寬','唐','御定全唐诗','yuding','','[]','詔下搜岩野，高人入竹林。長因抗疏日，便作去官心。',48,'御定全唐詩/json/606.json','["詔下搜岩野，高人入竹林。長因抗疏日，便作去官心。", "清俸供僧盡，滄洲寄跡深。東門有歸路，徒自棄華簪。"]'),
('yuding-29','和友人賊後','林寬','唐','御定全唐诗','yuding','','[]','帶號乞兵急，英雄陷賊圍。江山猶未靜，魚鳥欲何歸。',48,'御定全唐詩/json/606.json','["帶號乞兵急，英雄陷賊圍。江山猶未靜，魚鳥欲何歸。", "城露桑榆盡，時平老幼稀。書從戰後得，讀徹血盈衣。"]'),
('yuding-30','長安即事','林寬','唐','御定全唐诗','yuding','','[]','暝鼓才終複曉雞，九門何計出沉迷，樵童亂打金吾鼓，',40,'御定全唐詩/json/606.json','["暝鼓才終複曉雞，九門何計出沉迷，樵童亂打金吾鼓，", "須知不是詩人事，空憶泉聲菊畔畦。"]'),
('yuding-31','和周繇校書先輩省中寓直','林寬','唐','御定全唐诗','yuding','','[]','古木重門掩，幽深只欠溪。此中真吏隱，何必更岩棲。',120,'御定全唐詩/json/606.json','["古木重門掩，幽深只欠溪。此中真吏隱，何必更岩棲。", "名姓鐫幢記，經書逐庫題。字隨飛蠹缺，階與落星齊。", "伴直僧談靜，侵霜蛩韻低。粘塵賀草沒，剝粉薛禽迷。", "衰蘚牆千堵，微陽菊半畦。鼓殘鴉去北，漏在月沉西。", "每憶終南雪，幾登雲閣梯。時因搜句次，那惜一招攜。"]'),
('yuding-32','苦雨','林寬','唐','御定全唐诗','yuding','','[]','霪霖翳日月，窮巷變溝坑。驟灑纖枝折，奔傾壞堵平。',120,'御定全唐詩/json/606.json','["霪霖翳日月，窮巷變溝坑。驟灑纖枝折，奔傾壞堵平。", "蒙簦來客絕，躍甃噪蛙獰。敗屐陰苔積，摧簷濕菌生。", "斜飛穿裂瓦，迸落打空鐺。葉底遲歸蝶，林中滯出鶯。", "潤侵書縫黑，冷浸鬢絲明。牖暗參差影，階寒斷續聲。", "尺薪功比桂，寸粒價高瓊。遙想管弦裏，無因識此情。"]'),
('yuding-0','翰林作','劉鄴','唐','御定全唐诗','yuding','','[]','曾是江波垂釣人，自憐深厭九衢塵。浮生漸老年隨水，',40,'御定全唐詩/json/607.json','["曾是江波垂釣人，自憐深厭九衢塵。浮生漸老年隨水，", "多慚不是相如筆，虛直金鑾接侍臣。"]'),
('yuding-1','待漏院吟','劉鄴','唐','御定全唐诗','yuding','','[]','玉堂簾外獨遲遲，明月初沉勘契時。',32,'御定全唐詩/json/607.json','["玉堂簾外獨遲遲，明月初沉勘契時。", "閑聽景陽鐘盡後，兩鶯飛上萬年枝。"]'),
('yuding-2','慧山寺肄業送懷坦上人','李騭','唐','御定全唐诗','yuding','','[]','流水何山分，浮雲空中遇。我生無根株，聚散亦難固。',132,'御定全唐詩/json/607.json','["流水何山分，浮雲空中遇。我生無根株，聚散亦難固。", "憶昨鬥龍春，岩棲侶高步。清懷去羈束，幽境無滓汙。", "日落九峰明，煙生萬華暮。茲歡未雲隔，前笑倏已故。", "四時難信留，百草換霜露。離襟一成解，悵抱將何諭。", "驚泉有餘哀，永日誰與度。緬思孤帆影，再往重江路。", "去去忽淒悲，因風暫回顧。"]'),
('yuding-3','讀惠山若冰師集因題故院三首','李騭','唐','御定全唐诗','yuding','','[]','五天何處望，心念起皆知。化塔留今日，泉鳴自昔時。',144,'御定全唐詩/json/607.json','["五天何處望，心念起皆知。化塔留今日，泉鳴自昔時。", "古苔生石靜，秋草滿山悲。莫道聲容遠，長歌白雪詞。", "高懷逢異境，佳句想吟頻。月冷松溪夜，煙濃草寺春。", "浮雲將世遠，清聽與名新。不見開岩日，空為拜影人。", "景物搜求歇，山雲放縱飛。樹寒煙鶴去，池靜水龍歸。", "暗榻塵飄滿，陰簷月到稀。何年燈焰盡，風動影堂扉。"]'),
('yuding-4','自惠山至吳下寄酬南徐從事','李騭','唐','御定全唐诗','yuding','','[]','不接芳晨遊，獨此長洲苑。風顏一成阻，翰墨勞空返。',72,'御定全唐詩/json/607.json','["不接芳晨遊，獨此長洲苑。風顏一成阻，翰墨勞空返。", "悠悠汀渚長，杳杳蘋花晚。如何西府歡，尚念東吳遠。", "瑤音動清韻，蘭思芬盈畹。猶及九峰春，歸吟白雲巘。"]'),
('yuding-5','中秋夜戲酬顧道流','孫蜀','唐','御定全唐诗','yuding','','[]','不那此身偏愛月，等閒看月即更深。',32,'御定全唐詩/json/607.json','["不那此身偏愛月，等閒看月即更深。", "仙翁每被嫦娥使，一度逢圓一度吟。"]'),
('yuding-6','詠燕上主司鄭愚','歐陽澥','唐','御定全唐诗','yuding','','[]','翩翩雙燕畫堂開，送古迎今幾萬回。',32,'御定全唐詩/json/607.json','["翩翩雙燕畫堂開，送古迎今幾萬回。", "長向春秋社前後，為誰歸去為誰來。"]'),
('yuding-7','句','歐陽澥','唐','御定全唐诗','yuding','','[]','黃菊離家十四年。',28,'御定全唐詩/json/607.json','["黃菊離家十四年。", "離家已是夢松年。", "落日望鄉處，何人知客情？"]'),
('yuding-8','自詠豆花','陳黯','唐','御定全唐诗','yuding','','[]','玳瑁應難比，斑犀定不加。天嫌未端正，滿面與妝花。',24,'御定全唐詩/json/607.json','["玳瑁應難比，斑犀定不加。天嫌未端正，滿面與妝花。"]'),
('yuding-9','雪詩','張孜','唐','御定全唐诗','yuding','','[]','長安大雪天，鳥雀難相覓。其中豪貴家，搗椒泥四壁。',72,'御定全唐詩/json/607.json','["長安大雪天，鳥雀難相覓。其中豪貴家，搗椒泥四壁。", "到處爇紅爐，周回下羅冪。暖手調金絲，蘸甲斟瓊液。", "醉唱玉塵飛，困融香汗滴。豈知饑寒人，手腳生皴劈。"]'),
('yuding-10','句','張孜','唐','御定全唐诗','yuding','','[]','著牙賣朱紫，斷錢賒舉選。',48,'御定全唐詩/json/607.json','["著牙賣朱紫，斷錢賒舉選。", "華山秀作英雄骨，黃河瀉出縱橫才。", "夢破青霄春，煙霞無去塵。若誇郭璞五色筆，"]'),
('yuding-11','贈妓仙哥','鄭仁表','唐','御定全唐诗','yuding','','[]','嚴吹如何下太清，玉肌無疹六銖輕。',32,'御定全唐詩/json/607.json','["嚴吹如何下太清，玉肌無疹六銖輕。", "自知不是流霞酌，願聽雲和瑟一聲。"]'),
('yuding-12','贈妓命洛真','鄭仁表','唐','御定全唐诗','yuding','','[]','巧制新章拍拍新，金罍巡舉助精神。',32,'御定全唐詩/json/607.json','["巧制新章拍拍新，金罍巡舉助精神。", "時時欲得橫波眄，又怕回籌錯指人。"]'),
('yuding-13','句','鄭仁表','唐','御定全唐诗','yuding','','[]','文章世上爭開路，閥閱山東拄破天。',16,'御定全唐詩/json/607.json','["文章世上爭開路，閥閱山東拄破天。"]'),
('yuding-14','杜甫同谷茅茨','趙鴻','唐','御定全唐诗','yuding','','[]','工部棲遲後，鄰家大半無。青羌迷道路，白社寄杯盂。',48,'御定全唐詩/json/607.json','["工部棲遲後，鄰家大半無。青羌迷道路，白社寄杯盂。", "大雅何人繼，全生此地孤。孤雲飛鳥什，空勒舊山隅。"]'),
('yuding-15','栗亭','趙鴻','唐','御定全唐诗','yuding','','[]','杜甫栗亭詩，詩人多在口。悠悠二甲子，題紀今何有。',24,'御定全唐詩/json/607.json','["杜甫栗亭詩，詩人多在口。悠悠二甲子，題紀今何有。"]'),
('yuding-16','泥功山','趙鴻','唐','御定全唐诗','yuding','','[]','立石泥功狀，天然詭怪形。未嘗私禍福，終不費丹青。',24,'御定全唐詩/json/607.json','["立石泥功狀，天然詭怪形。未嘗私禍福，終不費丹青。"]'),
('yuding-17','昆明池織女石','童翰卿','唐','御定全唐诗','yuding','','[]','一片昆明石，千秋織女名。見人虛脈脈，臨水更盈盈。',72,'御定全唐詩/json/607.json','["一片昆明石，千秋織女名。見人虛脈脈，臨水更盈盈。", "苔作輕衣色，波為促杼聲。岸雲連鬢濕，沙月對眉生。", "有臉蓮同笑，無心鳥不驚。還如朝鏡裏，形影兩分明。"]'),
('yuding-18','絕句','童翰卿','唐','御定全唐诗','yuding','','[]','大樸逐物盡，哀我天地功。爭得榮辱心，灑然歸西風。',24,'御定全唐詩/json/607.json','["大樸逐物盡，哀我天地功。爭得榮辱心，灑然歸西風。"]'),
('yuding-0','補周禮九夏系文：九夏歌九篇','皮日休','唐','御定全唐诗','yuding','','[]','爣爣皎日，欻麗於天。厥明禦舒，如王出焉。',465,'御定全唐詩/json/608.json','["爣爣皎日，欻麗於天。厥明禦舒，如王出焉。", "爣爣皎日，欻入於地。厥晦厥貞，如王入焉。", "出有龍旗，入有珩佩。勿驅勿馳，惟慎惟戒。", "出有嘉謀，入有內則。繄彼臣庶，欽王之式。", "愔愔清廟，儀儀象服。我屍出矣，迎神之穀。", "杳杳陰竹，坎坎路鼓。我屍入矣，得神之祜。", "有鬱其鬯，有儼其彝。九變未作，全乘來之。", "既醑既酢，爰朄爰舞。象物既降，全乘之去。", "麟之儀儀，不縶不維。樂德而至，如賓之嬉。", "鳳之愉愉，不篝不笯。樂德而至，如賓之娛。", "自筐及筥，我有牢醑。自筐及篚，我有貨幣。", "我牢不愆，我貨不匱。碩碩其才，有樂而止。", "王有虎臣，錫之鈇鉞。征彼不憓，一撲而滅。", "王有虎臣，錫之圭瓚。征彼不享，一烘而泮。", "王有掌訝，偵爾疆理。王有掌客，饋爾饔餼。", "何以樂之，金石九奏。何以錫之，龍旗九旒。", "玲玲衡笄，翬衣榆翟。自內而祭，為君之則。", "洪源誰孕，疏為江河。大塊孰埏，播為山阿。", "厥流浩漾，厥勢嵯峨。今君之酌，慰我實多。", "禮酒既酌，嘉賓既厚，牘為之奏。", "禮酒既竭，嘉賓既悅，應為之節。", "禮酒既罄，嘉賓既醒，雅為之行。", "桓桓其珪，袞袞其衣。出作二伯，天子是毗。", "桓桓其珪，袞袞其服。入作三孤，國人是福。"]'),
('yuding-1','三羞詩三首','皮日休','唐','御定全唐诗','yuding','','[]','吾聞古君子，介介勵其節。入門疑儲宮，撫己思鈇鉞。',564,'御定全唐詩/json/608.json','["吾聞古君子，介介勵其節。入門疑儲宮，撫己思鈇鉞。", "志者若不退，佞者何由達。君臣一殽膳，家國共殘殺。", "此道見於今，永思心若裂。王臣方謇謇，佐我無玷缺。", "如何以謀計，中道生芽蘖。憲司遵故典，分道播南越。", "蒼惶出班行，家室不容別。玄鬢行為霜，清淚立成血。", "乘遽劇飛鳥，就傳過風發。嗟吾何為者，叨在造士列。", "獻文不上第，歸於淮之汭。蹇蹄可再奔，退羽可後歇。", "利則侶軒裳，塞則友松月。而於方寸內，未有是愁結。", "未為祿食仕，俯不愧梁糲。未為冠冕人，死不慚忠烈。", "如何有是心，不能叩丹闕。赫赫負君歸，南山采芝蕨。", "南荒不擇吏，致我交址覆。綿聯三四年，流為中夏辱。", "懦者鬥即退，武者兵則黷。軍庸滿天下，戰將多金玉。", "刮則齊民癰，分為猛士祿。雄健許昌師，忠武冠其族。", "去為萬騎風，住作一川肉。昨朝殘卒回，千門萬戶哭。", "哀聲動閭裏，怨氣成山谷。誰能聽晝鼙，不忍看金鏃。", "吾有制勝術，不奈賤碌碌。貯之胸臆間，慚見許師屬。", "自嗟胡為者，得躡前修躅。家不出軍租，身不識部曲。", "亦衣許師衣，亦食許師粟。方知古人道，蔭我已為足。", "念此向誰羞，悠悠潁川綠。", "天子丙戌年，淮右民多饑。就中潁之汭，轉徙何累累。", "夫婦相顧亡，棄卻抱中兒。兄弟各自散，出門如大癡。", "一金易蘆蔔，一縑換鳧茈。荒村墓鳥樹，空屋野花籬。", "兒童齧草根，倚桑空羸羸。斑白死路傍，枕土皆離離。", "方知聖人教，于民良在斯。厲能去人愛，荒能奪人慈。"]'),
('yuding-2','七愛詩：房杜二相國','皮日休','唐','御定全唐诗','yuding','','[]','吾愛房與杜，貧賤共聯步。脫身拋亂世，策杖歸真主。',120,'御定全唐詩/json/608.json','["吾愛房與杜，貧賤共聯步。脫身拋亂世，策杖歸真主。", "縱橫握中算，左右天下務。骯髒無敵才，磊落不世遇。", "美矣名公卿，魁然真宰輔。黃閣三十年，清風一萬古。", "巨業照國史，大勳鎮王府。遂使後世民，至今受陶鑄。", "粵吾少有志，敢躡前賢路。苟得同其時，願為執鞭豎。"]'),
('yuding-3','七愛詩：李太尉','皮日休','唐','御定全唐诗','yuding','','[]','吾愛李太尉，崛起定中原。驍雄十萬兵，四面圍國門。',156,'御定全唐詩/json/608.json','["吾愛李太尉，崛起定中原。驍雄十萬兵，四面圍國門。", "一戰取王畿，一叱散妖氛。乘輿既反正，凶豎爭亡魂。", "巍巍柱天功，蕩蕩蓋世勳。仁于曹孟德，勇過霍將軍。", "丹券入帑藏，青史傳子孫。所謂大丈夫，動合驚乾坤。", "所謂聖天子，難得忠貞臣。下以契魚水，上以合風雲。", "百世必一亂，千年方一人。吾雖翰墨子，氣概敢不群。", "願以太平頌，題向甘泉春。"]'),
('yuding-4','七愛詩：盧征君','皮日休','唐','御定全唐诗','yuding','','[]','吾愛盧征君，高臥嵩山裏。百辟未一顧，三征方暫起。',216,'御定全唐詩/json/608.json','["吾愛盧征君，高臥嵩山裏。百辟未一顧，三征方暫起。", "坦腹對宰相，岸幘揖天子。建禮門前吟，金鑾殿裏醉。", "天下皆餔糟，征君獨潔己。天下皆樂聞，征君獨洗耳。", "天下皆懷羞，征君獨多恥。銀黃不妨懸，赤紱不妨被。", "而於心抱中，獨作羲皇地。籃輿一雲返，泥詔褒不已。", "再看緱山雲，重酌嵩陽水。放曠書裏終，逍遙醉中死。", "吾謂伊與周，不若征君貴。吾謂巢與許，不若征君義。", "高名無階級，逸跡絕涯涘。萬世唐書中，逸名不可比。", "粵吾慕真隱，強以骨肉累。如教不為名，敢有征君志。"]'),
('yuding-5','七愛詩：元魯山','皮日休','唐','御定全唐诗','yuding','','[]','吾愛元紫芝，清介如伯夷。輦母遠之官，宰邑無玷疵。',168,'御定全唐詩/json/608.json','["吾愛元紫芝，清介如伯夷。輦母遠之官，宰邑無玷疵。", "三年魯山民，豐稔不暫饑。三年魯山吏，清慎各自持。", "只飲魯山泉，只采魯山薇。一室冰檗苦，四遠聲光飛。", "退歸舊隱來，鬥酒入茅茨。雞黍匪家畜，琴尊常自怡。", "盡日一菜食，窮年一布衣。清似匣中鏡，直如琴上絲。", "世無用賢人，青山生白髭。既臥黔婁衾，空立陳寔碑。", "吾無魯山道，空有魯山辭。所恨不相識，援毫空涕垂。"]'),
('yuding-6','七愛詩：李翰林','皮日休','唐','御定全唐诗','yuding','','[]','吾愛李太白，身是酒星魄。口吐天上文，跡作人間客。',181,'御定全唐詩/json/608.json','["吾愛李太白，身是酒星魄。口吐天上文，跡作人間客。", "磥砢千丈林，澄澈萬尋碧。醉中草樂府，十幅筆一息。", "召見承明廬，天子親賜食。醉曾吐禦床，傲幾觸天澤。", "權臣妒逸才，心如鬥筲窄。失恩出內署，海岳甘自適。", "刺謁戴接z5，赴宴著縠屐。諸侯百步迎，明君九天憶。", "竟遭腐脅疾，醉魄歸八極。大鵬不可籠，大椿不可植。", "蓬壺不可見，姑射不可識。五嶽為辭鋒，四溟作胸臆。", "惜哉千萬年，此俊不可得。"]'),
('yuding-7','七愛詩：白太傅','皮日休','唐','御定全唐诗','yuding','','[]','吾愛白樂天，逸才生自然。誰謂辭翰器，乃是經綸賢。',168,'御定全唐詩/json/608.json','["吾愛白樂天，逸才生自然。誰謂辭翰器，乃是經綸賢。", "欻從浮豔詩，作得典誥篇。立身百行足，為文六藝全。", "清望逸內署，直聲驚諫垣。所刺必有思，所臨必可傳。", "忘形任詩酒，寄傲遍林泉。所望標文柄，所希持化權。", "何期遇訾毀，中道多左遷。天下皆汲汲，樂天獨怡然。", "天下皆悶悶，樂天獨舍旃。高吟辭兩掖，清嘯罷三川。", "處世似孤鶴，遺榮同脫蟬。仕若不得志，可為龜鏡焉。"]'),
('yuding-8','正樂府十篇：卒妻怨','皮日休','唐','御定全唐诗','yuding','','[]','河湟戍卒去，一半多不回。家有半菽食，身為一囊灰。',132,'御定全唐詩/json/608.json','["河湟戍卒去，一半多不回。家有半菽食，身為一囊灰。", "官吏按其籍，伍中斥其妻。處處魯人髽，家家杞婦哀。", "少者任所歸，老者無所攜。況當劄瘥年，米粒如瓊瑰。", "累累作餓殍，見之心若摧。其夫死鋒刃，其室委塵埃。", "其命即用矣，其賞安在哉。豈無黔敖恩，救此窮餓骸。", "誰知白屋士，念此翻欸欸。"]'),
('yuding-9','正樂府十篇：橡媼歎','皮日休','唐','御定全唐诗','yuding','','[]','秋深橡子熟，散落榛蕪岡。傴傴黃發媼，拾之踐晨霜。',156,'御定全唐詩/json/608.json','["秋深橡子熟，散落榛蕪岡。傴傴黃發媼，拾之踐晨霜。", "移時始盈掬，盡日方滿筐。幾嚗複幾蒸，用作三冬糧。", "山前有熟稻，紫穗襲人香。細獲又精舂，粒粒如玉璫。", "持之納於官，私室無倉箱。如何一石餘，只作五鬥量。", "狡吏不畏刑，貪官不避贓。農時作私債，農畢歸官倉。", "自冬及於春，橡實誑饑腸。吾聞田成子，詐仁猶自王。", "籲嗟逢橡媼，不覺淚沾裳。"]'),
('yuding-10','正樂府十篇：貪官怨','皮日休','唐','御定全唐诗','yuding','','[]','國家省闥吏，賞之皆與位。素來不知書，豈能精吏理。',156,'御定全唐詩/json/608.json','["國家省闥吏，賞之皆與位。素來不知書，豈能精吏理。", "大者或宰邑，小者皆尉史。愚者若混沌，毒者如雄虺。", "傷哉堯舜民，肉袒受鞭棰。吾聞古聖王，天下無遺士。", "朝廷及下邑，治者皆仁義。國家選賢良，定制兼拘忌。", "所以用此徒，令之充祿仕。何不廣取人，何不廣曆試。", "下位既賢哉，上位何如矣。胥徒賞以財，俊造悉為吏。", "天下若不平，吾當甘棄市。"]'),
('yuding-11','正樂府十篇：農父謠','皮日休','唐','御定全唐诗','yuding','','[]','農父冤辛苦，向我述其情。難將一人農，可備十人征。',96,'御定全唐詩/json/608.json','["農父冤辛苦，向我述其情。難將一人農，可備十人征。", "如何江淮粟，挽漕輸咸京。黃河水如電，一半沈與傾。", "均輸利其事，職司安敢評。三川豈不農，三輔豈不耕。", "奚不車其粟，用以供天兵。美哉農父言，何計達王程。"]'),
('yuding-12','正樂府十篇：路臣恨','皮日休','唐','御定全唐诗','yuding','','[]','路臣何方來，去馬真如龍。行驕不動塵，滿轡金瓏璁。',120,'御定全唐詩/json/608.json','["路臣何方來，去馬真如龍。行驕不動塵，滿轡金瓏璁。", "有人自天來，將避荊棘叢。獰呼不覺止，推下蒼黃中。", "十夫掣鞭策，禦之如驚鴻。日行六七郵，瞥若鷹無蹤。", "路臣慎勿愬，愬則刑爾躬。軍期方似雨，天命正如風。", "七雄戰爭時，賓旅猶自通。如何太平世，動步卻途窮。"]'),
('yuding-13','正樂府十篇：賤貢士','皮日休','唐','御定全唐诗','yuding','','[]','南越貢珠璣，西蜀進羅綺。到京未晨旦，一一見天子。',96,'御定全唐詩/json/608.json','["南越貢珠璣，西蜀進羅綺。到京未晨旦，一一見天子。", "如何賢與俊，為貢賤如此。所知不可求，敢望前席事。", "吾聞古聖人，射宮親選士。不肖盡屏跡，賢能皆得位。", "所以謂得人，所以稱多士。歎息幾編書，時哉又何異。"]'),
('yuding-14','正樂府十篇：頌夷臣','皮日休','唐','御定全唐诗','yuding','','[]','夷師本學外，仍善唐文字。吾人本尚舍，何況夷臣事。',60,'御定全唐詩/json/608.json','["夷師本學外，仍善唐文字。吾人本尚舍，何況夷臣事。", "所以不學者，反為夷臣戲。所以屍祿人，反為夷臣忌。", "籲嗟華風衰，何嘗不由是。"]'),
('yuding-15','正樂府十篇：惜義鳥','皮日休','唐','御定全唐诗','yuding','','[]','商顏多義鳥，義鳥實可嗟。危巢末累累，隱在栲木花。',108,'御定全唐詩/json/608.json','["商顏多義鳥，義鳥實可嗟。危巢末累累，隱在栲木花。", "他巢若有雛，乳之如一家。他巢若遭捕，投之同一羅。", "商人每秋貢，所貴複如何。飽以稻粱滋，飾以組繡華。", "惜哉仁義禽，委戲于宮娥。吾聞鳳之貴，仁義亦足誇。", "所以不遭捕，蓋緣生不多。"]'),
('yuding-16','正樂府十篇：誚虛器','皮日休','唐','御定全唐诗','yuding','','[]','襄陽作髹器，中有庫露真。持以遺北虜，紿雲生有神。',84,'御定全唐詩/json/608.json','["襄陽作髹器，中有庫露真。持以遺北虜，紿雲生有神。", "每歲走其使，所費如雲屯。吾聞古聖王，修德來遠人。", "未聞作巧詐，用欺禽獸君。吾道尚如此，戎心安足雲。", "如何漢宣帝，卻得呼韓臣。"]'),
('yuding-17','正樂府十篇：哀隴民','皮日休','唐','御定全唐诗','yuding','','[]','隴山千萬仞，鸚鵡巢其巔。窮危又極嶮，其山猶不全。',132,'御定全唐詩/json/608.json','["隴山千萬仞，鸚鵡巢其巔。窮危又極嶮，其山猶不全。", "蚩蚩隴之民，懸度如登天。空中覘其巢，墮者爭紛然。", "百禽不得一，十人九死焉。隴川有戍卒，戍卒亦不閑。", "將命提雕籠，直到金台前。彼毛不自珍，彼舌不自言。", "胡為輕人命，奉此玩好端。吾聞古聖王，珍禽皆舍旃。", "今此隴民屬，每歲啼漣漣。"]'),
('yuding-18','奉獻致政裴秘監','皮日休','唐','御定全唐诗','yuding','','[]','何胤本征士，高情動天地。既無閥閱門，常嫌冠冕累。',216,'御定全唐詩/json/608.json','["何胤本征士，高情動天地。既無閥閱門，常嫌冠冕累。", "宰邑著嘉政，為郡留高致。移官在書府，方樂鴛池貴。", "玉季牧江西，泣之不忍離。舍杖隨之去，天下欽高義。", "烏帽白絺裘，籃輿竹如意。黃菊陶潛酒，青山謝公妓。", "月檻詠詩情，花溪釣魚戲。鐘陵既方舟，魏闕將結駟。", "甘求白首閑，不為蒼生起。優詔加大監，所以符公議。", "既為逍遙公，又作鴟夷子。安車懸不出，駟馬閑無事。", "微雨漢陂舟，殘日終南騎。富貴盡淩雲，何人能至此。", "猜禍皆及身，何複至如是。賢哉此丈夫，百世一人矣。"]'),
('yuding-19','秋夜有懷','皮日休','唐','御定全唐诗','yuding','','[]','夢裏憂身泣，覺來衣尚濕。骨肉煎我心，不是謀生急。',72,'御定全唐詩/json/608.json','["夢裏憂身泣，覺來衣尚濕。骨肉煎我心，不是謀生急。", "如何欲佐主，功名未成立。處世既孤特，傳家無承襲。", "明朝走梁楚，步步出門澀。如何一寸心，千愁萬愁入。"]'),
('yuding-20','喜鵲','皮日休','唐','御定全唐诗','yuding','','[]','棄膻在庭際，雙鵲來搖尾。欲啄怕人驚，喜語晴光裏。',36,'御定全唐詩/json/608.json','["棄膻在庭際，雙鵲來搖尾。欲啄怕人驚，喜語晴光裏。", "何況佞幸人，微禽解如此。"]'),
('yuding-21','蚊子','皮日休','唐','御定全唐诗','yuding','','[]','隱隱聚若雷，噆膚不知足。皇天若不平，微物教食肉。',48,'御定全唐詩/json/608.json','["隱隱聚若雷，噆膚不知足。皇天若不平，微物教食肉。", "貧士無絳紗，忍苦臥茅屋。何事覓膏腴，腹無太倉粟。"]'),
('yuding-22','鹿門夏日','皮日休','唐','御定全唐诗','yuding','','[]','滿院松桂陰，日午卻不知。山人睡一覺，庭鵲立未移。',73,'御定全唐詩/json/608.json','["滿院松桂陰，日午卻不知。山人睡一覺，庭鵲立未移。", "出簷趁雲去，忘戴白接z5。書眼若薄霧，酒腸如漏卮。", "身外所勞者，飲食須自持。何如便絕粒，直使身無為。"]'),
('yuding-23','偶書','皮日休','唐','御定全唐诗','yuding','','[]','女媧掉繩索，縆泥成下人。至今頑愚者，生如土偶身。',48,'御定全唐詩/json/608.json','["女媧掉繩索，縆泥成下人。至今頑愚者，生如土偶身。", "雲物養吾道，天爵高我貧。大笑猗氏輩，為富皆不仁。"]'),
('yuding-24','讀書','皮日休','唐','御定全唐诗','yuding','','[]','家資是何物，積帙列梁梠。高齋曉開卷，獨共聖人語。',48,'御定全唐詩/json/608.json','["家資是何物，積帙列梁梠。高齋曉開卷，獨共聖人語。", "英賢雖異世，自古心相許。案頭見蠹魚，猶勝凡儔侶。"]'),
('yuding-25','貧居秋日','皮日休','唐','御定全唐诗','yuding','','[]','亭午頭未冠，端坐獨愁予。貧家煙爨稀，灶底陰蟲語。',48,'御定全唐詩/json/608.json','["亭午頭未冠，端坐獨愁予。貧家煙爨稀，灶底陰蟲語。", "門小愧車馬，廩空慚雀鼠。盡室未寒衣，機聲羨鄰女。"]'),
('yuding-0','魯望讀《襄陽耆舊傳》，見贈五百言，過褒庸材，靡有稱是。然襄陽曩事歷歷在目，夫《耆舊傳》所未載者，漢陽王則宗社元勛，孟浩然則文章大匠，予次而贊之，因而寄答，亦詩人無言不酬之義也，次韻','皮日休','唐','御定全唐诗','yuding','','[]','漢水碧于天，南荊廓然秀。廬羅遵古俗，鄢郢迷昔囿。',576,'御定全唐詩/json/609.json','["漢水碧于天，南荊廓然秀。廬羅遵古俗，鄢郢迷昔囿。", "幽奇無得狀，巉絕不能究。興替忽矣新，山川悄然舊。", "斑斑生造士，一一應玄宿。巴庸乃嶮岨，屈景實豪右。", "是非既自分，涇渭不相就。粵自靈均來，清才若天漱。", "偉哉泂上隱，卓爾隆中耨。始將麋鹿狎，遂與麒麟鬥。", "萬乘不可謁，千鐘固非茂。爰從景升死，境上多兵候。", "檀溪試戈船，峴嶺屯貝胄。寂寞數百年，質唯包礫琇。", "上玄賞唐德，生賢命之授。是為漢陽王，帝曰俞爾奏。", "巨德聳神鬼，宏才轢前後。勢端唯金莖，質古乃玉豆。", "行葉蔭大椿，詞源吐洪溜。六成清廟音，一柱明堂構。", "在昔房陵遷，圓穹正中漏。繄王揭然出，上下拓宇宙。", "俯視三事者，騃騃若童幼。低摧護中興，若鳳視其鷇。", "遇險必伸足，逢誅將引脰。既正北極尊，遂治眾星謬。", "重聞章陵幸，再見岐陽狩。日似新刮膜，天如重熨縐。", "易政疾似欬，求賢甚於購。化之未期年，民安而國富。", "翼衛兩舜趨，鉤陳十堯驟。忽然遺相印，如羿卸其彀。", "奸幸卻乘釁，播遷遂終壽。遺廟屹峰崿，功名紛組繡。", "開元文物盛，孟子生荊岫。斯文縱奇巧，秦璽新雕鏤。", "甘窮臥牛衣，受辱對狗竇。思變如易爻，才通似玄首。", "秘于龍宮室，怪於天篆籀。知者競欲戴，嫉者或將詬。", "任達且百觚，遂為當時陋。既作才鬼終，恐為仙籍售。", "予生二賢末，得作升木狖。兼濟與獨善，俱敢懷其臭。", "江漢稱炳靈，克明嗣清晝。繼彼欲為三，如醨如醇酎。", "既見陸夫子，駑心卻伏廄。結彼世外交，遇之於邂逅。"]'),
('yuding-1','魯望昨以五百言見貽，過有褒美，內揣庸陋，彌增愧悚，因成一千言上述吾唐文物之盛，次敘相得之歡，亦迭和之微旨也','皮日休','唐','御定全唐诗','yuding','','[]','三辰至精氣，生自蒼頡前。粵從有文字，精氣銖於綿。',578,'御定全唐詩/json/609.json','["三辰至精氣，生自蒼頡前。粵從有文字，精氣銖於綿。", "所以楊墨後，文詞縱橫顛。元狩富材術，建安儼英賢。", "厥祀四百餘，作者如排穿。五馬渡江日，群魚食蒲年。", "大風蕩天地，萬陣黃須膻。縱有命世才，不如一空弮。", "後至陳隋世，得之拘且緛。太浮如瀲灩，太細如蚳蝝。", "太亂如靡靡，太輕如芊芊。流之為䣱醟，變之為遊畋。", "百足雖雲眾，不救殺馬蚿。君臣作降虜，北走如㺦猭。", "所以文字妖，致其國朝遷。吾唐革其弊，取士將科縣。", "文星下為人，洪秀密於緶。大開紫宸扉，來者皆詳延。", "日晏朝不罷，龍姿歡䡒䡒。于焉周道反，由是秦法悛。", "射洪陳子昂，其聲亦喧闐。惜哉不得時，將奮猶拘攣。", "玉壘李太白，銅堤孟浩然。李寬包堪輿，孟澹擬漪漣。", "埋骨採石壙，留神鹿門埏。俾其羈旅死，實覺天地孱。", "猗與子美思，不盡如轉輇。縱為三十車，一字不可捐。", "既作風雅主，遂司歌詠權。誰知耒陽土，埋卻真神仙。", "當于李杜際，名輩或溯沿。良禦非異馬，由弓非他弦。", "其物無同異，其人有媸妍。自開元至今，宗社紛如煙。", "爽若沆瀣英，高如昆侖巔。百家囂浮說，諸子率寓篇。", "築之為京觀，解之為牲牷。各持天地維，率意東西牽。", "競抵元化首，爭扼真宰咽。或作制誥藪，或為宮體淵。", "或堪被金石，或可投花鈿。或為輿隸唱，或被兒童憐。", "烏壘虜亦寫，雞林夷爭傳。披揭覆載樞，捭闔神異鍵。", "力掀尾閭立，思軋大塊旋。降氣或若虹，耀影或如wH。", "萬象瘡複痏，百靈瘠且q3。謂乎數十公，筆若明堂椽。"]'),
('yuding-2','吳中苦雨因書一百韻寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','全吳臨巨溟，百里到滬瀆。海物競駢羅，水怪爭滲漉。',577,'御定全唐詩/json/609.json','["全吳臨巨溟，百里到滬瀆。海物競駢羅，水怪爭滲漉。", "狂蜃吐其氣，千尋勃然蹙。一刷半天墨，架為欹危屋。", "怒鯨瞪相向，吹浪山轂轂。倏忽腥杳冥，須臾坼崖谷。", "帝命有嚴程，慈物敢潛伏。噓之為玄雲，彌亙千萬幅。", "直拔倚天劍，又建橫海纛。化之為暴雨，潈潈射平陸。", "如將月窟寫，似把天河撲。著樹勝戟支，中人過箭鏃。", "龍光倏閃照，虯角搊琤觸。此時一千里，平下天臺瀑。", "雷公恣其志，䃸磹裂電目。蹋破霹靂車，折卻三四輻。", "雨工避罪者，必在蚊睫宿。狂發鏗訇音，不得懈怠僇。", "頃刻勢稍止，尚自傾蔌蔌。不敢履洿處，恐蹋爛地軸。", "自爾凡十日，茫然晦林麓。只是遇滂沱，少曾逢霢霂。", "伊餘之廨宇，古制拙蔔築。頹簷倒菌黃，破砌頑莎綠。", "只有方丈居，其中蹐且局。朽處或似醉，漏時又如沃。", "階前平氾濫，牆下起趢趚。唯堪著笞笠，複可乘艒宿。", "雞犬並淋漓，兒童但咿噢。勃勃生濕氣，人人牢於鋦。", "鬚眉漬將斷，肝膈蒸欲熟。當庭死蘭芷，四垣盛薋菉。", "解帙展斷書，拂床安壞櫝。跳樑老蛙黽，直向床前浴。", "蹲前但相聒，似把白丁辱。空廚方欲炊，漬米未離bL。", "薪蒸濕不著，白晝須然燭。汙萊既已濘，買魚不獲鮛。", "竟未成麥饘，安能得粱肉。更有陸先生，荒林抱窮蹙。", "壞宅四五舍，病筱三兩束。蓋簷低礙首，蘚地滑澾足。", "注欲透承塵，濕難庇廚簏。低摧在圭竇，索漠拋偏裻。", "手指既已胼，肌膚亦將瘯。一苞勢欲陊，將撐乏寸木。", "盡日欠束薪，經時無寸粟。䗂蝓將入甑，蟚蜞已臨鍑。"]'),
('yuding-3','初夏即事寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','夏景恬且曠，遠人疾初平。黃鳥語方熟，紫桐陰正清。',276,'御定全唐詩/json/609.json','["夏景恬且曠，遠人疾初平。黃鳥語方熟，紫桐陰正清。", "廨宇有幽處，私游無定程。歸來閉雙關，亦忘枯與榮。", "土室作深谷，蘚垣為幹城。俯杉突杝架，迸筍支簷楹。", "片石共坐穩，病鶴同喜晴。癭木四五器，筇杖一兩莖。", "泉為葛天味，松作羲皇聲。或看名畫徹，或吟閑詩成。", "忽枕素琴睡，時把仙書行。自然寡儔侶，莫說更紛爭。", "具區包地髓，震澤含天英。粵從三讓來，俊造紛然生。", "顧予客茲地，薄我皆為傖。唯有陸夫子，盡力提客卿。", "各負出俗才，俱懷超世情。駐我一棧車，啜君數藜羹。", "敲門若我訪，倒屣欣逢迎。胡餅蒸甚熟，貊盤舉尤輕。", "茗脆不禁炙，酒肥或難傾。掃除就藤下，移榻尋虛明。", "唯共陸夫子，醉與天壤並。"]'),
('yuding-4','二遊詩：徐詩','皮日休','唐','御定全唐诗','yuding','','[]','東莞為著姓，奕代皆雋哲。強學取科第，名聲盡孤揭。',447,'御定全唐詩/json/609.json','["東莞為著姓，奕代皆雋哲。強學取科第，名聲盡孤揭。", "自為方州來，清操稱凜冽。唯寫墳籍多，必雲清俸絕。", "宣毫利若風，剡紙光與月。劄吏指欲胼，萬通排未闋。", "樓船若夏屋，欲載如垤eJ。轉徙入吳都，縱橫礙門闑。", "縹囊輕似霧，緗帙殷於血。以此為基構，將斯用貽厥。", "重于通侯印，貴卻全師節。我愛參卿道，承家能介潔。", "潮田五萬步，草屋十餘楶。微宦不能去，歸來坐如刖。", "保茲萬卷書，守慎如羈絏。念我曾苦心，相逢無間別。", "引之看秘寶，任得窮披閱。軸閑翠鈿剝，簽古紅牙折。", "帙解帶芸香，卷開和桂屑。枕兼石鋒刃，榻共松瘡癤。", "一臥寂無喧，數編看盡徹。或攜歸廨宇，或把穿林樾。", "挈過太湖風，抱宿支硎雪。如斯未星紀，悉得分毫末。", "翦除幽僻藪，滌蕩玄微窟。學海正狂波，予頭向中bK。", "聖人患不學，垂誡尤為切。苟昧古與今，何殊喑共fw。", "昔之慕經史，有以傭筆劄。何況遇斯文，借之不曾輟。", "吾衣任縠纑，吾食某糠核。其道苟可光，斯文那自伐。", "何竹青堪殺，何蒲重好截。如能盈兼兩，便足酬饑渴。", "有此競苟榮，聞之兼可噦。東皋耨煙雨，南嶺提薇蕨。", "何以謝徐君，公車不聞設。"]'),
('yuding-5','二遊詩：任詩','皮日休','唐','御定全唐诗','yuding','','[]','任君恣高放，斯道能寡合。一宅閑林泉，終身遠囂雜。',350,'御定全唐詩/json/609.json','["任君恣高放，斯道能寡合。一宅閑林泉，終身遠囂雜。", "嘗聞佐浩穰，散性多儑bY。欻爾解其綬，遺之如棄靸。", "歸來鄉黨內，卻與親朋洽。開溪未讓丁，列第方稱甲。", "入門約百步，古木聲霎霎。廣檻小山欹，斜廊怪石夾。", "白蓮倚闌楯，翠鳥緣簾押。地勢似五瀉，岩形若三峽。", "猿眠但膃肭，鳧食時啑唼。撥荇下文竿，結藤縈桂楫。", "門留醫樹客，壁倚栽花鍤。度歲止褐衣，經旬唯白vS。", "多君方閉戶，顧我能倒屟。請題在茅棟，留坐于石榻。", "魂從清景遛，衣任煙霞裛。階墀龜任上，枕席鷗方狎。", "沼似頗黎鏡，當中見魚眨。杯杓悉杉瘤，盤筵盡荷葉。", "閑斟不置罰，閑弈無爭劫。閑日不整冠，閑風無用箑。", "以斯為思慮，吾道寧疲苶。袞衣競璀璨，鼓吹爭鞺鞳。", "欲者解擠排，詬者能詀讘。權豪暫翻覆，刑禍相填壓。", "此時一圭竇，不肯饒閶闔。有第可棲息，有書可漁獵。", "吾欲與任君，終身以斯愜。"]'),
('yuding-6','追和虎丘寺清遠道士詩','皮日休','唐','御定全唐诗','yuding','','[]','成道自衰周，避世窮炎漢。荊杞雖雲梗，煙霞尚容竄。',144,'御定全唐詩/json/609.json','["成道自衰周，避世窮炎漢。荊杞雖雲梗，煙霞尚容竄。", "茲岑信靈異，吾懷愜流玩。石澀古鐵鉎，嵐重輕埃漫。", "松膏膩幽徑，蘋沫著孤岸。諸蘿幄幕暗，眾鳥陶匏亂。", "岩罅地中心，海光天一半。玄猿行列歸，白雲次第散。", "蟾蜍生夕景，沆瀣餘清旦。風日采幽什，墨客學靈翰。", "嗟予慕斯文，一詠複三歎。顯晦雖不同，茲吟粗堪贊。"]'),
('yuding-7','追和幽獨君詩次韻','皮日休','唐','御定全唐诗','yuding','','[]','念爾風雅魄，幽咽猶能文。空令傷魂鳥，啼破山邊墳。',96,'御定全唐詩/json/609.json','["念爾風雅魄，幽咽猶能文。空令傷魂鳥，啼破山邊墳。", "恨劇但埋土，聲幽難放哀。墳古春自晚，愁緒空崔嵬。", "白楊老無花，枯根侵夜台。天高有時裂，川去何時回。", "雙睫不能濡，六藏無可摧。不聞搴蓬事，何必深悲哉。"]'),
('yuding-8','奉和魯望讀陰符經見寄','皮日休','唐','御定全唐诗','yuding','','[]','三百八十言，出自伊祁氏。上以生神仙，次雲立仁義。',372,'御定全唐詩/json/609.json','["三百八十言，出自伊祁氏。上以生神仙，次雲立仁義。", "玄機一以發，五賊紛然起。結為日月精，融作天地髓。", "不測似陰陽，難名若神鬼。得之升高天，失之沈厚地。", "具茨雲木老，大塊煙霞委。自顓頊以降，賊為聖人軌。", "堯乃一庶人，得之賊帝摯。摯見其德尊，脫身授其位。", "舜唯一鰥民，冗冗作什器。得之賊帝堯，白丁作天子。", "禹本刑人後，以功繼其嗣。得之賊帝舜，用以平洚水。", "自禹及文武，天機嗒然弛。姬公樹其綱，賊之為聖智。", "聲詩川競大，禮樂山爭峙。爰從幽厲餘，宸極若孩稚。", "九伯真犬彘，諸侯實虎兕。五星合其耀，白日下闕裏。", "由是聖人生，于焉當亂紀。黃帝之五賊，拾之若青紫。", "高揮春秋筆，不可刊一字。賊子虐甚斨，奸臣痛于棰。", "至今千餘年，蚩蚩受其賜。時代更複改，刑政崩且陊。", "予將賊其道，所動多訾毀。叔孫與臧倉，賢聖多如此。", "如何黃帝機，吾得多坎躓。縱失生前祿，亦多身後利。", "我欲賊其名，垂之千萬祀。"]'),
('yuding-9','初夏遊楞伽精舍','皮日休','唐','御定全唐诗','yuding','','[]','越舼輕似萍，漾漾出煙郭。人聲漸疏曠，天氣忽寥廓。',446,'御定全唐詩/json/609.json','["越舼輕似萍，漾漾出煙郭。人聲漸疏曠，天氣忽寥廓。", "伊予愜斯志，有似劀q3瘼。遇勝即夷猶，逢幽且淹泊。", "俄然棹深處，虛無倚岩崿。霜毫一道人，引我登龍閣。", "當中見壽象，欲禮光紛箔。珠幡時相鏗，恐是諸天樂。", "樹杪見觚棱，林端逢赭堊。千尋井猶在，萬祀靈不涸。", "下通蛟人道，水色黮而惡。欲照六藏驚，將窺百骸愕。", "朅去山南嶺，其險如邛笮。悠然放吾興，欲把青天摸。", "紫藤垂罽珥，紅荔懸纓絡。蘚厚滑似漦，峰尖利如鍔。", "斯須到絕頂，似愈漸離z8。一片太湖光，只驚天漢落。", "梅風脫綸帽，乳水透芒屩。嵐姿與波彩，不動渾相著。", "既不暇供應，將何以酬酢。卻來穿竹徑，似入青油幕。", "穴恐水君開，龕如鬼工鑿。窮幽入茲院，前楯臨巨壑。", "遺畫龍奴獰，殘香蟲篆薄。褫魂窺玉鏡，澄慮聞金鐸。", "雲態共縈留，鳥言相許諾。古木勢如虺，近之恐相蠚。", "怒泉聲似激，聞之意爭博。時禽倏已嘿，眾籟蕭然作。", "遂令不羈性，戀此如纏縛。念彼上人者，將生付寂寞。", "曾無膚撓事，肯把心源度。胡為儒家流，沒齒勤且恪。", "沐猴本不冠，未是謀生錯。言行既異調，棲遲亦同托。", "願力儻不遺，請作華林鶴。"]'),
('yuding-10','公齋四詠：小松','皮日休','唐','御定全唐诗','yuding','','[]','婆娑只三尺，移來白雲徑。亭亭向空意，已解淩遼夐。',108,'御定全唐詩/json/609.json','["婆娑只三尺，移來白雲徑。亭亭向空意，已解淩遼夐。", "葉健似虯須，枝脆如鶴脛。清音猶未成，紺彩空不定。", "陰圓小芝蓋，鱗澀修荷柄。先愁被鷃搶，預恐遭蝸病。", "結根幸得地，且免離離映。磥砢不難遇，在保晚成性。", "一日造明堂，為君當畢命。"]'),
('yuding-11','公齋四詠：小桂','皮日休','唐','御定全唐诗','yuding','','[]','一子落天上，生此青璧枝。欻從山之幽，劚斷雲根移。',96,'御定全唐詩/json/609.json','["一子落天上，生此青璧枝。欻從山之幽，劚斷雲根移。", "勁挺隱珪質，盤珊緹油姿。葉彩碧髓融，花狀白毫蕤。", "棱層立翠節，偃蹇樛青螭。影淡雪霽後，香泛風和時。", "吾祖在月竁，孤貞能見怡。願老君子地，不敢辭喧卑。"]'),
('yuding-12','公齋四詠：新竹','皮日休','唐','御定全唐诗','yuding','','[]','笠澤多異竹，移之植後楹。一架三百本，綠沈森冥冥。',109,'御定全唐詩/json/609.json','["笠澤多異竹，移之植後楹。一架三百本，綠沈森冥冥。", "圓緊珊瑚節，釤利翡翠翎。儼若青帝仗，矗如紫姑屏。", "槭槭微風度，漠漠輕靄生。如神語鈞天，似樂奏洞庭。", "一玩九藏冷，再聞百骸醒。有根可以執，有pF可以馨。", "願稟君子操，不敢先凋零。"]'),
('yuding-13','公齋四詠：鶴屏','皮日休','唐','御定全唐诗','yuding','','[]','三幅吹空縠，孰寫仙禽狀。bo耳側以聽，赤精曠如望。',97,'御定全唐詩/json/609.json','["三幅吹空縠，孰寫仙禽狀。bo耳側以聽，赤精曠如望。", "引吭看雲勢，翹足臨池樣。頗似近蓐席，還如入方丈。", "盡日空不鳴，窮年但相向。未許子晉乘，難教道林放。", "貌既合羽儀，骨亦符法相。願升君子堂，不必思昆閬。"]'),
('yuding-14','奉酬崔璐進士見寄次韻','皮日休','唐','御定全唐诗','yuding','','[]','伊餘幼且賤，所稟自以殊。弱歲謬知道，有心匡皇符。',132,'御定全唐詩/json/609.json','["伊餘幼且賤，所稟自以殊。弱歲謬知道，有心匡皇符。", "意超海上鷹，運局轅下駒。縱性作古文，所為皆自如。", "但恐才格劣，敢誇詞彩敷。句句考事實，篇篇窮玄虛。", "誰能變羊質，競不獲驪珠。粵有造化手，曾開天地爐。", "文章鄴下秀，氣貌淹中儒。展我此志業，期君持中樞。", "蒼生眼穿望，勿作磻溪謨。"]'),
('yuding-0','太湖詩：初入太湖','皮日休','唐','御定全唐诗','yuding','','[]','聞有太湖名，十年未曾識。今朝得遊泛，大笑稱平昔。',219,'御定全唐詩/json/610.json','["聞有太湖名，十年未曾識。今朝得遊泛，大笑稱平昔。", "一舍行胥塘，盡日到震澤。三萬六千頃，千頃頗黎色。", "連空淡無纇，照野平絕隙。好放青翰舟，堪弄白玉笛。", "疏岑七十二，eH々露矛戟。悠然嘯傲去，天上搖畫艗。", "西風乍獵獵，驚波罨涵碧。倏忽雷陣吼，須臾玉崖坼。", "樹動為蜃尾，山浮似鼇脊。落照射鴻溶，清輝蕩拋cQ。", "雲輕似可染，霞爛如堪摘。漸暝無處泊，挽帆從所適。", "枕下聞澎湃，肌上生瘮t7。討異足邅回，尋幽多阻隔。", "願風與良便，吹入神仙宅。甘將一蘊書，永事嵩山伯。"]'),
('yuding-1','太湖詩：曉次神景宮','皮日休','唐','御定全唐诗','yuding','','[]','夜半幽夢中，扁舟似鳧躍。曉來到何許，俄倚包山腳。',348,'御定全唐詩/json/610.json','["夜半幽夢中，扁舟似鳧躍。曉來到何許，俄倚包山腳。", "三百六十丈，攢空利如削。遐瞻但徙倚，欲上先矍鑠。", "濃露濕莎裳，淺泉漸草屩。行行未一裏，節境轉寂寞。", "靜徑侵泬寥，仙扉傍岩崿。松聲正凊絕，海日方照灼。", "欻臨幽虛天，萬想皆擺落。壇靈有芝菌，殿聖無鳥雀。", "瓊幃自迴旋，錦旌空粲錯。鼎氣為龍虎，香煙混丹雘。", "凝看出次雲，默聽語時鶴。綠書不可注，雲笈應無鑰。", "晴來鳥思喜，崦裏花光弱。天籟如擊琴，泉聲似摐鐸。", "清齋洞前院，敢負玄科約。空中悉羽章，地上皆靈藥。", "金醴可酣暢，玉豉堪咀嚼。存心服燕胎，叩齒讀龍蹻。", "福地七十二，茲焉永堪托。在獸乏虎貙，於蟲不毒蠚。", "嘗聞擇骨錄，仙志非可作。綠腸既朱髓，青肝複紫絡。", "伊餘乏此相，天與形貌惡。每嗟原憲瘇，常苦齊侯瘧。", "終然合委頓，剛亦慕寥廓。三茅亦常住，竟與珪組薄。", "欲問包山神，來賒少岩壑。"]'),
('yuding-2','太湖詩：入林屋洞','皮日休','唐','御定全唐诗','yuding','','[]','齋心已三日，筋骨如煙輕。腰下佩金獸，手中持火鈴。',434,'御定全唐詩/json/610.json','["齋心已三日，筋骨如煙輕。腰下佩金獸，手中持火鈴。", "幽塘四百里，中有日月精。連亙三十六，各各為玉京。", "自非心至誠，必被神物烹。顧余慕大道，不能惜微生。", "遂招放曠侶，同作幽憂行。其門才函丈，初若盤薄硎。", "洞氣黑昳ft，苔發紅鬇鬡。試足值坎窞，低頭避崢嶸。", "攀緣不知倦，怪異焉敢驚。匍匐一百步，稍稍策可橫。", "忽然白蝙蝠，來撲松炬明。人語散澒洞，石響高玲玎。", "腳底龍蛇氣，頭上波濤聲。有時若服匿，偪仄如見繃。", "俄爾造平淡，豁然逢光晶。金堂似鐫出，玉座如琢成。", "前有方丈沼，凝碧融人睛。雲漿湛不動，璚露涵而馨。", "漱之恐減算，酌之必延齡。愁為三官責，不敢攜一bl。", "昔雲夏后氏，于此藏真經。刻之以紫琳，秘之以丹瓊。", "期之以萬祀，守之以百靈。焉得彼丈人，竊之不加刑。", "石匱一以出，左神俄不扃。禹書既雲得，吳國由是傾。", "蘚縫才半尺，中有怪物腥。欲去既嚄唶，將回又伶俜。", "卻遵舊時道，半日出杳冥。屨泥惹石髓，衣濕沾雲英。", "玄籙乏仙骨，青文無絳名。雖然入陰宮，不得朝上清。", "對彼神仙窟，自厭濁俗形。卻憎造物者，遣我騎文星。"]'),
('yuding-3','太湖詩：雨中游包山精舍','皮日休','唐','御定全唐诗','yuding','','[]','松門亙五裏，彩碧高下絢。幽人共躋攀，勝事頗清便。',204,'御定全唐詩/json/610.json','["松門亙五裏，彩碧高下絢。幽人共躋攀，勝事頗清便。", "翣翣林上雨，隱隱湖中電。薜帶輕束腰，荷笠低遮面。", "濕屨黏煙霧，穿衣落霜霰。笑次度岩壑，困中遇台殿。", "老僧三四人，梵字十數卷。施稀無夏屋，境僻乏朝膳。", "散發抵泉流，支頤數雲片。坐石忽忘起，捫蘿不知倦。", "異蝶時似錦，幽禽或如鈿。篥簩還戛刃，栟櫚自搖扇。", "俗態既鬥藪，野情空眷戀。道人摘芝菌，為予備午饌。", "渴興石榴羹，饑愜胡麻飯。如何事于役，茲遊急於傳。", "卻將塵土衣，一任瀑絲濺。"]'),
('yuding-4','太湖詩：游毛公壇','皮日休','唐','御定全唐诗','yuding','','[]','卻上南山路，松行儼如廡。松根礙幽徑，孱顏不能斧。',312,'御定全唐詩/json/610.json','["卻上南山路，松行儼如廡。松根礙幽徑，孱顏不能斧。", "擺履跨亂雲，側巾蹲怪樹。三休且半日，始到毛公塢。", "兩水合一澗，潈崖卻為浦。相敵百千戟，共攂十萬鼓。", "噴散日月精，射破神仙府。唯愁絕地脈，又恐折天柱。", "一窺耳目眩，再聽雲發豎。次到煉丹井，井幹翳宿莽。", "下有蕊剛丹，勺之百疾愈。凝于白獺髓，湛似桐馬乳。", "黃露醒齒牙，碧黏甘肺腑。檜異松複怪，枯疏互撐拄。", "幹蛟一百丈，髐然半天舞。下有毛公壇，壇方不盈畝。", "當時雲龍篆，一片苔蘚古。時時仙禽來，忽忽祥煙聚。", "我愛周息元，忽起應明主。三諫卻歸來，回頭唾圭組。", "伊余何不幸，斯人不復睹。如何大開口，與世爭枯腐。", "將山待誇娥，以肉投猰貐。欻坐侵桂陰，不知巳與午。", "茲地足靈境，他年終結宇。敢道萬石君，輕於一絲縷。"]'),
('yuding-5','太湖詩：三宿神景宮','皮日休','唐','御定全唐诗','yuding','','[]','古觀岑且寂，幽人情自怡。一來包山下，三宿湖之湄。',192,'御定全唐詩/json/610.json','["古觀岑且寂，幽人情自怡。一來包山下，三宿湖之湄。", "況此深夏夕，不逢清月姿。玉泉浣衣後，金殿添香時。", "客省高且敞，客床蟠複奇。石枕冷入腦，筍席寒侵肌。", "氣清寐不著，起坐臨階墀。松陰忽微照，獨見螢火芝。", "素鶴警微露，白蓮明暗池。窗櫺帶乳蘚，壁縫含雲蕤。", "聞磬走魍魎，見燭奔羈雌。沆瀣欲滴瀝，芭蕉未離披。", "五更山蟬響，醒發如吹篪。杉風忽然起，飄破步虛詞。", "道客巾屨樣，上清朝禮儀。明發作此事，豈複甘趨馳。"]'),
('yuding-6','太湖詩：以毛公泉一瓶獻上諫議因寄','皮日休','唐','御定全唐诗','yuding','','[]','劉根昔成道，茲塢四百年。毿毿被其體，號為綠毛仙。',240,'御定全唐詩/json/610.json','["劉根昔成道，茲塢四百年。毿毿被其體，號為綠毛仙。", "因思清泠汲，鑿彼岝峉巔。五色既煉矣，一勺方鏗然。", "既用文武火，俄窮雌雄篇。赤鹽撲紅霧，白華飛素煙。", "服之生羽翼，倏爾沖玄天。真隱尚有跡，厥祀將近千。", "我來討靈勝，到此期終焉。滴苦破竇淨，蘚深餘甃圓。", "澄如玉髓潔，泛若金精鮮。顏色半帶乳，氣味全和鉛。", "飲之融痞蹇，濯之伸拘攣。有時玩者觸，倏忽風雷顛。", "素綆絲不短，越罌腹甚便。汲時月液動，擔處玉漿旋。", "敢獻大司諫，置之鈴閣前。清如介潔性，滌比掃蕩權。", "炙背野人興，亦思侯伯憐。也知飲冰苦，願受一瓶泉。"]'),
('yuding-7','太湖詩：縹緲峰','皮日休','唐','御定全唐诗','yuding','','[]','頭戴華陽帽，手拄大夏筇。清晨陪道侶，來上縹緲峰。',293,'御定全唐詩/json/610.json','["頭戴華陽帽，手拄大夏筇。清晨陪道侶，來上縹緲峰。", "帶露嗅藥蔓，和雲尋鹿蹤。時驚q0p0鼠，飛上千丈松。", "翠壁內有室，叩之虛eGcP。古穴下徹海，視之寒鴻蒙。", "遇歇有佳思，緣危無倦容。須臾到絕頂，似鳥穿樊籠。", "恐足蹈海日，疑身淩天風。眾岫點巨浸，四方接圓穹。", "似將青螺髻，撒在明月中。片白作越分，孤嵐為吳宮。", "一陣靉靆氣，隱隱生湖東。激雷與波起，狂電將日紅。", "礊礊雨點大，金髇轟下空。暴光隔雲閃，仿佛亙天龍。", "連拳百丈尾，下拔湖之洪。捽為一雪山，欲與昭回通。", "移時卻cs下，細碎衡與嵩。神物諒不測，絕景尤難窮。", "杖策下返照，漸聞仙觀鐘。煙波濆肌骨，雲壑闐心胸。", "竟死愛未足，當生且歡逢。不然把天爵，自拜太湖公。"]'),
('yuding-8','太湖詩：桃花塢','皮日休','唐','御定全唐诗','yuding','','[]','夤緣度南嶺，盡日穿林樾。窮深到茲塢，逸興轉超忽。',144,'御定全唐詩/json/610.json','["夤緣度南嶺，盡日穿林樾。窮深到茲塢，逸興轉超忽。", "塢名雖然在，不見桃花發。恐是武陵溪，自閉仙日月。", "倚峰小精舍，當嶺殘耕垡。將洞任回環，把雲恣披拂。", "閑禽啼叫窕，險狖眠硉矹。微風吹重嵐，碧埃輕勃勃。", "清陰減鶴睡，秀色治人渴。敲竹鬥錚摐，弄泉爭咽嗢。", "空齋蒸柏葉，野飯調石發。空羨塢中人，終身無履襪。"]'),
('yuding-9','太湖詩：明月灣','皮日休','唐','御定全唐诗','yuding','','[]','曉景澹無際，孤舟恣回環。試問最幽處，號為明月灣。',156,'御定全唐詩/json/610.json','["曉景澹無際，孤舟恣回環。試問最幽處，號為明月灣。", "半岩翡翠巢，望見不可攀。柳弱下絲網，藤深垂花鬘。", "松癭忽似狖，石文或如虥。釣壇兩三處，苔老腥斒斑。", "沙雨幾處霽，水禽相向閑。野人波濤上，白屋幽深間。", "曉培橘栽去，暮作魚梁還。清泉出石砌，好樹臨柴關。", "對此老且死，不知憂與患。好境無處住，好處無境刪。", "赧然不自適，脈脈當湖山。"]'),
('yuding-10','太湖詩：練瀆','皮日休','唐','御定全唐诗','yuding','','[]','吳王厭得國，所玩終不足。一上姑蘇台，猶自嫌局促。',204,'御定全唐詩/json/610.json','["吳王厭得國，所玩終不足。一上姑蘇台，猶自嫌局促。", "艅艎六宮鬧，艨沖後軍肅。一陣水麝風，空中蕩平淥。", "鳥困避錦帆，龍跧防鐵軸。流蘇惹煙浪，羽葆飄岩穀。", "靈境太蹂踐，因茲塞林屋。空闊嫌太湖，崎嶇開練瀆。", "三尋齾石齒，數裏穿山腹。底靜似金膏，礫碎如丹粟。", "波殿鄭妲醉，蟾閣西施宿。幾轉含煙舟，一唱來雲曲。", "不知闌楯上，夜有越人鏃。君王掩面死，嬪禦不敢哭。", "豔魄逐波濤，荒宮養麋鹿。國破溝亦淺，代變草空綠。", "白鳥都不知，朝眠還暮浴。"]'),
('yuding-11','太湖詩：投龍潭','皮日休','唐','御定全唐诗','yuding','','[]','龜山下最深，惡氣何洋溢。涎水瀑龍巢，腥風卷蛟室。',156,'御定全唐詩/json/610.json','["龜山下最深，惡氣何洋溢。涎水瀑龍巢，腥風卷蛟室。", "曉來林岑靜，獰色如怒日。氣湧撲炱煤，波澄掃純漆。", "下有水君府，貝闕光比櫛。左右列介臣，縱橫守鱗卒。", "月中珠母見，煙際楓人出。生犀不敢燒，水怪恐摧捽。", "時有慕道者，作彼投龍術。端嚴持碧簡，齋戒揮紫筆。", "兼以金蜿蜒，投之光焌律。琴高坐赤鯉，何許縱仙逸。", "我願與之遊，茲焉托靈質。"]'),
('yuding-12','太湖詩：孤園寺','皮日休','唐','御定全唐诗','yuding','','[]','艇子小且兀，緣湖蕩白芷。縈紆泊一碕，宛到孤園寺。',218,'御定全唐詩/json/610.json','["艇子小且兀，緣湖蕩白芷。縈紆泊一碕，宛到孤園寺。", "蘿島凝清陰，松門湛虛翠。寒泉飛碧螭，古木鬥蒼兕。", "鐘梵在水魄，樓臺入雲肆。岩邊足鳴wJ，樹杪多飛鸓。", "香莎滿院落，風泛金靃靡。靜鶴啄柏蠹，閑猱弄榅eb。", "小殿熏陸香，古經貝多紙。老僧方瞑坐，見客還強起。", "指茲正險絕，何以來到此。先言洞壑數，次話真如理。", "磬韻醒閒心，茶香凝皓齒。巾之劫貝布，饌以栴檀餌。", "數刻得清淨，終身欲依止。可憐陶侍讀，身列丹台位。", "雅號曰勝力，亦聞師佛氏。今日到孤園，何妨稱弟子。"]'),
('yuding-13','太湖詩：上真觀','皮日休','唐','御定全唐诗','yuding','','[]','徑盤在山肋，繚繞窮雲端。摘菌杖頭紫，緣崖屐齒刓。',324,'御定全唐詩/json/610.json','["徑盤在山肋，繚繞窮雲端。摘菌杖頭紫，緣崖屐齒刓。", "半日到上真，洞宮知造難。雙戶啟真景，齋心方可觀。", "天鈞鳴響亮，天祿行蹣跚。琪樹夾一徑，萬條青琅玕。", "兩松峙庭際，怪狀籲可歎。大螾騰共結，修蛇飛相盤。", "皮膚坼甲胄，枝節擒貙犴。罅處似天裂，朽中如井眢。", "褵褷風聲癬，跁跒地方痑。根上露鉗釱，空中狂波瀾。", "合時若莽蒼，辟處如轘轅。儼對無霸陣，靜問嚴陵灘。", "靈飛一以護，山都焉敢幹。兩廊潔寂曆，中殿高巑岏。", "靜架九色節，閑懸十絕幡。微風時一吹，百寶清闌珊。", "昔有葉道士，位當升靈官。欲箋紫微志，唯食虹影丹。", "既逐隱龍去，道風由此殘。猶聞絳目草，往往生空壇。", "羽客兩三人，石上譚泥丸。謂我或龍胄，粲然與之歡。", "衣巾紫華冷，食次白芝寒。自覺有真氣，恐隨風力摶。", "明朝若更住，必擬隳儒冠。"]'),
('yuding-14','太湖詩：銷夏灣','皮日休','唐','御定全唐诗','yuding','','[]','太湖有曲處，其門為兩崖。當中數十頃，別如一天池。',181,'御定全唐詩/json/610.json','["太湖有曲處，其門為兩崖。當中數十頃，別如一天池。", "號為銷夏灣，此名無所私。赤日莫斜照，清風多遙吹。", "沙嶼掃粉墨，松竹調塤篪。山果紅靺鞨，水苔青wK髵。", "木陰厚若瓦，岩磴滑如飴。我來此游息，夏景方赫曦。", "一坐磐石上，肅肅寒生肌。小艖或可泛，短策或可支。", "行驚翠羽起，坐見白蓮披。斂袖弄輕浪，解巾敵涼颸。", "但有水雲見，更餘沙禽知。京洛往來客，暍死緣賓士。", "此中便可老，焉用名利為。"]'),
('yuding-15','太湖詩：包山祠','皮日休','唐','御定全唐诗','yuding','','[]','白雲最深處，像設盈岩堂。村祭足茗粣，水奠多桃漿。',170,'御定全唐詩/json/610.json','["白雲最深處，像設盈岩堂。村祭足茗粣，水奠多桃漿。", "箘uM突古砌，薜荔繃頹牆。爐灰寂不然，風送杉桂香。", "積雨晦州裏，流波漂稻粱。恭惟大司諫，憫此如發狂。", "命予傳明禱，祗事實不遑。一奠若肸蚃，再祝如激揚。", "出廟未半日，隔雲逢澹光。gf々雨點少，漸收羽林槍。", "忽然山家犬，起吠白日傍。公心與神志，相向如玄黃。", "我願作一疏，奏之於穹蒼。留神千萬祀，永福吳封疆。"]'),
('yuding-16','太湖詩：聖姑廟','皮日休','唐','御定全唐诗','yuding','','[]','洛神有靈逸，古廟臨空渚。暴雨駁丹青，荒蘿繞梁梠。',120,'御定全唐詩/json/610.json','["洛神有靈逸，古廟臨空渚。暴雨駁丹青，荒蘿繞梁梠。", "野風旋芝蓋，饑烏銜椒糈。寂寂落楓花，時時鬥鼯鼠。", "常雲三五夕，盡會妍神侶。月下留紫姑，霜中召青女。", "俄然響環佩，倏爾鳴機杼。樂至有聞時，香來無定處。", "目瞪如有待，魂斷空無語。雲雨竟不生，留情在何處。"]'),
('yuding-17','太湖詩：太湖石','皮日休','唐','御定全唐诗','yuding','','[]','茲山有石岸，抵浪如受屠。雪陣千萬戰，蘚岩高下刳。',204,'御定全唐詩/json/610.json','["茲山有石岸，抵浪如受屠。雪陣千萬戰，蘚岩高下刳。", "乃是天詭怪，信非人功夫。白丁一雲取，難甚網珊瑚。", "厥狀複若何，鬼工不可圖。或拳若虺蜴，或蹲如虎貙。", "連絡若鉤鎖，重疊如萼跗。或若巨人骼，或如太帝符。", "胮肛筼簹筍，格磔琅玕株。斷處露海眼，移來和沙須。", "求之煩耄倪，載之勞舳艫。通侯一以眄，貴卻驪龍珠。", "厚賜以賝贐，遠去窮京都。五侯土山下，要爾添岩齬。", "賞玩若稱意，爵祿行斯須。苟有王佐士，崛起於太湖。", "試問欲西笑，得如茲石無。"]'),
('yuding-18','太湖詩：崦裏','皮日休','唐','御定全唐诗','yuding','','[]','崦裏何幽奇，膏腴二十頃。風吹稻花香，直過龜山頂。',120,'御定全唐詩/json/610.json','["崦裏何幽奇，膏腴二十頃。風吹稻花香，直過龜山頂。", "青苗細膩臥，白羽悠溶靜。塍畔起鸊鵜，田中通舴艋。", "幾家傍潭洞，孤戍當林嶺。罷釣時煮菱，停繰或焙茗。", "峭然八十翁，生計於此永。苦力供征賦，怡顏過朝暝。", "洞庭取異事，包山極幽景。念爾飽得知，亦是遺民幸。"]'),
('yuding-19','太湖詩：石板','皮日休','唐','御定全唐诗','yuding','','[]','翠石數百步，如板漂不流。空疑水妃意，浮出青玉洲。',132,'御定全唐詩/json/610.json','["翠石數百步，如板漂不流。空疑水妃意，浮出青玉洲。", "中若瑩龍劍，外唯疊蛇矛。狂波忽然死，浩氣清且浮。", "似將翠黛色，抹破太湖秋。安得三五夕，攜酒棹扁舟。", "召取月夫人，嘯歌於上頭。又恐霄景闊，虛皇拜仙侯。", "欲建九錫碑，當立十二樓。瓊文忽然下，石板誰能留。", "此事少知者，唯應波上鷗。"]'),
('yuding-0','奉和魯望漁具十五詠：網','皮日休','唐','御定全唐诗','yuding','','[]','晚掛溪上網，映空如霧縠。閑來發其機，旋旋沈平綠。',48,'御定全唐詩/json/611.json','["晚掛溪上網，映空如霧縠。閑來發其機，旋旋沈平綠。", "下處若煙雨，牽時似崖谷。必若遇鯤鮞，從教通一目。"]'),
('yuding-1','奉和魯望漁具十五詠：罩','皮日休','唐','御定全唐诗','yuding','','[]','芒鞋下葑中，步步沈輕罩。既為菱浪颭，亦為蓮泥膠。',48,'御定全唐詩/json/611.json','["芒鞋下葑中，步步沈輕罩。既為菱浪颭，亦為蓮泥膠。", "人立獨無聲，魚煩似相抄。滿手搦霜鱗，思歸舉輕棹。"]'),
('yuding-2','奉和魯望漁具十五詠：罱','皮日休','唐','御定全唐诗','yuding','','[]','煙雨晚來好，東塘下罱去。網小正星bI，舟輕欲騰翥。',49,'御定全唐詩/json/611.json','["煙雨晚來好，東塘下罱去。網小正星bI，舟輕欲騰翥。", "誰知荇深後，恰值魚多處。浦口更有人，停橈一延佇。"]'),
('yuding-3','奉和魯望漁具十五詠：釣筒','皮日休','唐','御定全唐诗','yuding','','[]','籠籦截數尺，標置能幽絕。從浮笠澤煙，任臥桐江月。',48,'御定全唐詩/json/611.json','["籠籦截數尺，標置能幽絕。從浮笠澤煙，任臥桐江月。", "絲隨碧波漫，餌逐清灘發。好是趁筒時，秋聲正清越。"]'),
('yuding-4','奉和魯望漁具十五詠：釣車','皮日休','唐','御定全唐诗','yuding','','[]','得樂湖海志，不厭華輈小。月中拋一聲，驚起灘上鳥。',48,'御定全唐詩/json/611.json','["得樂湖海志，不厭華輈小。月中拋一聲，驚起灘上鳥。", "心將潭底測，手把波文嫋。何處覓奔車，平波今渺渺。"]'),
('yuding-5','奉和魯望漁具十五詠：漁梁','皮日休','唐','御定全唐诗','yuding','','[]','波際插翠筠，離離似清籞。遊鱗到溪口，入此無逃所。',48,'御定全唐詩/json/611.json','["波際插翠筠，離離似清籞。遊鱗到溪口，入此無逃所。", "斜臨楊柳津，靜下鸕鷀侶。編此欲何之，終焉富春渚。"]'),
('yuding-6','奉和魯望漁具十五詠：叉魚','皮日休','唐','御定全唐诗','yuding','','[]','列炬春溪口，平潭如不流。照見游泳魚，一一如清晝。',48,'御定全唐詩/json/611.json','["列炬春溪口，平潭如不流。照見游泳魚，一一如清晝。", "中目碎瓊碧，毀鱗殷組繡。樂此何太荒，居然愧川後。"]'),
('yuding-7','奉和魯望漁具十五詠：射魚','皮日休','唐','御定全唐诗','yuding','','[]','注矢寂不動，澄潭晴轉烘。下窺見魚樂，怳若翔在空。',48,'御定全唐詩/json/611.json','["注矢寂不動，澄潭晴轉烘。下窺見魚樂，怳若翔在空。", "驚羽決凝碧，傷鱗浮殷紅。堪將指杯術，授與太湖公。"]'),
('yuding-8','奉和魯望漁具十五詠：鳴桹','皮日休','唐','御定全唐诗','yuding','','[]','盡日平湖上，鳴桹仍動槳。丁丁入波心，澄澈和清響。',48,'御定全唐詩/json/611.json','["盡日平湖上，鳴桹仍動槳。丁丁入波心，澄澈和清響。", "鷺聽獨寂寞，魚驚昧來往。盡水無所逃，川中有鉤黨。"]'),
('yuding-9','奉和魯望漁具十五詠：滬','皮日休','唐','御定全唐诗','yuding','','[]','波中植甚固，磔磔如蝦須。濤頭倏爾過，數頃跳鯆cr。',49,'御定全唐詩/json/611.json','["波中植甚固，磔磔如蝦須。濤頭倏爾過，數頃跳鯆cr。", "不是細羅密，自為朝夕驅。空憐指魚命，遣出海邊租。"]'),
('yuding-10','奉和魯望漁具十五詠：qF','皮日休','唐','御定全唐诗','yuding','','[]','伐彼槎蘖枝，放於冰雪浦。遊魚趁暖處，忽爾來相聚。',48,'御定全唐詩/json/611.json','["伐彼槎蘖枝，放於冰雪浦。遊魚趁暖處，忽爾來相聚。", "徒為棲托心，不問庇庥主。一旦懸鼎鑊，禍機真自取。"]'),
('yuding-11','奉和魯望漁具十五詠：種魚','皮日休','唐','御定全唐诗','yuding','','[]','移土湖岸邊，一半和魚子。池中得春雨，點點活如蟻。',48,'御定全唐詩/json/611.json','["移土湖岸邊，一半和魚子。池中得春雨，點點活如蟻。", "一月便翠鱗，終年必赬尾。借問兩綬人，誰知種魚利。"]'),
('yuding-12','奉和魯望漁具十五詠：藥魚','皮日休','唐','御定全唐诗','yuding','','[]','吾無竭澤心，何用藥魚藥。見說放溪上，點點波光惡。',48,'御定全唐詩/json/611.json','["吾無竭澤心，何用藥魚藥。見說放溪上，點點波光惡。", "食時競夷猶，死者爭紛泊。何必重傷魚，毒涇猶可作。"]'),
('yuding-13','奉和魯望漁具十五詠：舴艋','皮日休','唐','御定全唐诗','yuding','','[]','闊處只三尺，翛然足吾事。低篷掛釣車，枯蚌盛魚餌。',48,'御定全唐詩/json/611.json','["闊處只三尺，翛然足吾事。低篷掛釣車，枯蚌盛魚餌。", "只好攜橈坐，唯堪蓋蓑睡。若遣遂平生，艅艎不如是。"]'),
('yuding-14','奉和魯望漁具十五詠：笭箵','皮日休','唐','御定全唐诗','yuding','','[]','朝空笭箵去，暮實笭箵歸。歸來倒卻魚，掛在幽窗扉。',48,'御定全唐詩/json/611.json','["朝空笭箵去，暮實笭箵歸。歸來倒卻魚，掛在幽窗扉。", "但聞蝦蜆氣，欲生蘋藻衣。十年佩此處，煙雨苦霏霏。"]'),
('yuding-15','添魚具詩：魚庵','皮日休','唐','御定全唐诗','yuding','','[]','庵中只方丈，恰稱幽人住。枕上悉漁經，門前空釣具。',48,'御定全唐詩/json/611.json','["庵中只方丈，恰稱幽人住。枕上悉漁經，門前空釣具。", "束竿時倚壁，曬網還侵戶。上泂有楊顒，須留往來路。"]'),
('yuding-16','添魚具詩：釣磯','皮日休','唐','御定全唐诗','yuding','','[]','盤灘一片石，置我山居足。窪處著筣笓，竅中維艒fR。',49,'御定全唐詩/json/611.json','["盤灘一片石，置我山居足。窪處著筣笓，竅中維艒fR。", "多逢沙鳥汙，愛彼潭雲觸。狂奴臥此多，所以蹋帝腹。"]'),
('yuding-17','添魚具詩：蓑衣','皮日休','唐','御定全唐诗','yuding','','[]','一領蓑正新，著來沙塢中。隔溪遙望見，疑是綠毛翁。',49,'御定全唐詩/json/611.json','["一領蓑正新，著來沙塢中。隔溪遙望見，疑是綠毛翁。", "襟色裛xU靄，袖香褵褷風。前頭不施袞，何以為三公。"]'),
('yuding-18','添魚具詩：箬笠','皮日休','唐','御定全唐诗','yuding','','[]','圓似寫月魂，輕如織煙翠。涔涔向上雨，不亂窺魚思。',48,'御定全唐詩/json/611.json','["圓似寫月魂，輕如織煙翠。涔涔向上雨，不亂窺魚思。", "攜來沙日微，掛處江風起。縱帶二梁冠，終身不忘爾。"]'),
('yuding-19','添魚具詩：背篷','皮日休','唐','御定全唐诗','yuding','','[]','儂家背篷樣，似個大龜甲。雨中局蹐時，一向聽霎霎。',49,'御定全唐詩/json/611.json','["儂家背篷樣，似個大龜甲。雨中局蹐時，一向聽霎霎。", "甘從魚不見，亦任鷗相狎。深擁竟無言，空成睡齁qf。"]'),
('yuding-20','奉和魯望樵人十詠：樵溪','皮日休','唐','御定全唐诗','yuding','','[]','何時有此溪，應便生幽木。橡實養山禽，藤花蒙澗鹿。',48,'御定全唐詩/json/611.json','["何時有此溪，應便生幽木。橡實養山禽，藤花蒙澗鹿。", "不止產蒸薪，願當歌棫樸。君知天意無，以此安吾族。"]'),
('yuding-21','奉和魯望樵人十詠：樵家','皮日休','唐','御定全唐诗','yuding','','[]','空山最深處，太古兩三家。雲蘿共夙世，猿鳥同生涯。',48,'御定全唐詩/json/611.json','["空山最深處，太古兩三家。雲蘿共夙世，猿鳥同生涯。", "衣服濯春泉，盤餐烹野花。居茲老複老，不解歎年華。"]'),
('yuding-22','奉和魯望樵人十詠：樵叟','皮日休','唐','御定全唐诗','yuding','','[]','不曾照青鏡，豈解傷華髮。至老未息肩，至今無病骨。',48,'御定全唐詩/json/611.json','["不曾照青鏡，豈解傷華髮。至老未息肩，至今無病骨。", "家風是林嶺，世祿為薇蕨。所以兩大夫，天年自為伐。"]'),
('yuding-23','奉和魯望樵人十詠：樵子','皮日休','唐','御定全唐诗','yuding','','[]','相約晚樵去，跳踉上山路。將花餌鹿麛，以果投猿父。',48,'御定全唐詩/json/611.json','["相約晚樵去，跳踉上山路。將花餌鹿麛，以果投猿父。", "束薪白雲濕，負擔春日暮。何不壽童烏，果為玄所誤。"]'),
('yuding-24','奉和魯望樵人十詠：樵徑','皮日休','唐','御定全唐诗','yuding','','[]','蒙蘢中一徑，繞在千峰裏。歇處遇松根，危中值石齒。',48,'御定全唐詩/json/611.json','["蒙蘢中一徑，繞在千峰裏。歇處遇松根，危中值石齒。", "花穿枲衣落，雲拂芒鞋起。自古行此途，不聞顛與墜。"]'),
('yuding-25','奉和魯望樵人十詠：樵斧','皮日休','唐','御定全唐诗','yuding','','[]','腰間插大柯，直入深溪裏。空林伐一聲，幽鳥相呼起。',48,'御定全唐詩/json/611.json','["腰間插大柯，直入深溪裏。空林伐一聲，幽鳥相呼起。", "倒樹去李父，傾巢啼木魅。不知仗鉞者，除害誰如此。"]'),
('yuding-26','奉和魯望樵人十詠：樵擔','皮日休','唐','御定全唐诗','yuding','','[]','不敢量樵重，唯知益薪束。軋軋下山時，彎彎向身曲。',48,'御定全唐詩/json/611.json','["不敢量樵重，唯知益薪束。軋軋下山時，彎彎向身曲。", "清泉洗得潔，翠靄侵來綠。看取荷戈人，誰能似吾屬。"]'),
('yuding-27','奉和魯望樵人十詠：樵風','皮日休','唐','御定全唐诗','yuding','','[]','野船渡樵客，來往平波中。縱橫清飆吹，旦暮歸期同。',48,'御定全唐詩/json/611.json','["野船渡樵客，來往平波中。縱橫清飆吹，旦暮歸期同。", "蘋光惹衣白，蓮影涵薪紅。吾當請封爾，直作鏡湖公。"]'),
('yuding-28','奉和魯望樵人十詠：樵火','皮日休','唐','御定全唐诗','yuding','','[]','山客地爐裏，然薪如陽輝。松膏作滫瀡，杉子為珠璣。',48,'御定全唐詩/json/611.json','["山客地爐裏，然薪如陽輝。松膏作滫瀡，杉子為珠璣。", "響誤擊刺鬧，焰疑彗孛飛。傍邊暖白酒，不覺瀑冰垂。"]'),
('yuding-29','奉和魯望樵人十詠：樵歌','皮日休','唐','御定全唐诗','yuding','','[]','此曲太古音，由來無管奏。多雲采樵樂，或說林泉候。',48,'御定全唐詩/json/611.json','["此曲太古音，由來無管奏。多雲采樵樂，或說林泉候。", "一唱凝閑雲，再謠悲顧獸。若遇采詩人，無辭收鄙陋。"]'),
('yuding-30','酒中十詠：酒星','皮日休','唐','御定全唐诗','yuding','','[]','誰遣酒旗耀，天文列其位。彩微嘗似酣，芒弱偏如醉。',48,'御定全唐詩/json/611.json','["誰遣酒旗耀，天文列其位。彩微嘗似酣，芒弱偏如醉。", "唯憂犯帝座，只恐騎天駟。若遇捲舌星，讒君應墮地。"]'),
('yuding-31','酒中十詠：酒泉','皮日休','唐','御定全唐诗','yuding','','[]','羲皇有玄酒，滋味何太薄。玉液是澆漓，金沙乃糟粕。',48,'御定全唐詩/json/611.json','["羲皇有玄酒，滋味何太薄。玉液是澆漓，金沙乃糟粕。", "春從野鳥沽，晝仍閑猿酌。我願葬茲泉，醉魂似鳧躍。"]'),
('yuding-32','酒中十詠：酒篘','皮日休','唐','御定全唐诗','yuding','','[]','翠篾初織來，或如古魚器。新從山下買，靜向甔中試。',48,'御定全唐詩/json/611.json','["翠篾初織來，或如古魚器。新從山下買，靜向甔中試。", "輕可網金醅，疏能容玉蟻。自此好成功，無貽我罍恥。"]'),
('yuding-33','酒中十詠：酒床','皮日休','唐','御定全唐诗','yuding','','[]','糟床帶松節，酒膩肥如羜。滴滴連有聲，空疑杜康語。',48,'御定全唐詩/json/611.json','["糟床帶松節，酒膩肥如羜。滴滴連有聲，空疑杜康語。", "開眉既壓後，染指偷嘗處。自此得公田，不過渾種黍。"]'),
('yuding-34','酒中十詠：酒壚','皮日休','唐','御定全唐诗','yuding','','[]','紅壚高幾尺，頗稱幽人意。火作縹醪香，灰為冬醷氣。',48,'御定全唐詩/json/611.json','["紅壚高幾尺，頗稱幽人意。火作縹醪香，灰為冬醷氣。", "有槍盡龍頭，有主皆犢鼻。倘得作杜根，傭保何足愧。"]'),
('yuding-35','酒中十詠：酒樓','皮日休','唐','御定全唐诗','yuding','','[]','鉤楯跨通衢，喧鬧當九市。金罍瀲灩後，玉斝紛綸起。',48,'御定全唐詩/json/611.json','["鉤楯跨通衢，喧鬧當九市。金罍瀲灩後，玉斝紛綸起。", "舞蝶傍應酣，啼鶯聞亦醉。野客莫登臨，相讎多失意。"]'),
('yuding-36','酒中十詠：酒旗','皮日休','唐','御定全唐诗','yuding','','[]','青幟闊數尺，懸於往來道。多為風所颺，時見酒名號。',48,'御定全唐詩/json/611.json','["青幟闊數尺，懸於往來道。多為風所颺，時見酒名號。", "拂拂野橋幽，翻翻江市好。雙眸複何事，終竟望君老。"]'),
('yuding-37','酒中十詠：酒樽','皮日休','唐','御定全唐诗','yuding','','[]','犧樽一何古，我抱期幽客。少恐消醍醐，滿擬烘琥珀。',48,'御定全唐詩/json/611.json','["犧樽一何古，我抱期幽客。少恐消醍醐，滿擬烘琥珀。", "猿窺曾撲瀉，鳥蹋經欹仄。度度醒來看，皆如死生隔。"]'),
('yuding-38','酒中十詠：酒城','皮日休','唐','御定全唐诗','yuding','','[]','萬仞峻為城，沈酣浸其俗。香侵井幹過，味染濠波淥。',48,'御定全唐詩/json/611.json','["萬仞峻為城，沈酣浸其俗。香侵井幹過，味染濠波淥。", "朝傾逾百榼，暮壓幾千斛。吾將隸此中，但為閽者足。"]'),
('yuding-39','酒中十詠：酒鄉','皮日休','唐','御定全唐诗','yuding','','[]','何人置此鄉，杳在天皇外。有事忘哀樂，有時忘顯晦。',48,'御定全唐詩/json/611.json','["何人置此鄉，杳在天皇外。有事忘哀樂，有時忘顯晦。", "如尋罔象歸，似與希夷會。從此共君遊，無煩用冠帶。"]'),
('yuding-40','奉和添酒中六詠：酒池','皮日休','唐','御定全唐诗','yuding','','[]','八齊競奔注，不知深幾丈。竹葉島紆徐，鳧花波蕩漾。',48,'御定全唐詩/json/611.json','["八齊競奔注，不知深幾丈。竹葉島紆徐，鳧花波蕩漾。", "醺應爛地軸，浸可柔天壤。以此獻吾君，願銘於几杖。"]'),
('yuding-41','奉和添酒中六詠：酒龍','皮日休','唐','御定全唐诗','yuding','','[]','銅為蚴蟉鱗，鑄作鱙qT角。吐處百里雷，瀉時千丈壑。',49,'御定全唐詩/json/611.json','["銅為蚴蟉鱗，鑄作鱙qT角。吐處百里雷，瀉時千丈壑。", "初疑潛苑囿，忽似拏寥廓。遂使銅雀台，香消野花落。"]'),
('yuding-42','奉和添酒中六詠：酒甕','皮日休','唐','御定全唐诗','yuding','','[]','堅淨不苦窳，陶于醉封疆。臨溪刷舊痕，隔屋聞新香。',48,'御定全唐詩/json/611.json','["堅淨不苦窳，陶于醉封疆。臨溪刷舊痕，隔屋聞新香。", "移來近麹室，倒處臨糟床。所嗟無比鄰，餘亦能偷嘗。"]'),
('yuding-43','奉和添酒中六詠：酒船','皮日休','唐','御定全唐诗','yuding','','[]','剡桂複刳蘭，陶陶任行樂。但知涵泳好，不計風濤惡。',48,'御定全唐詩/json/611.json','["剡桂複刳蘭，陶陶任行樂。但知涵泳好，不計風濤惡。", "嘗行麹封內，稍系糟丘泊。東海如可傾，乘之就斟酌。"]'),
('yuding-44','奉和添酒中六詠：酒槍','皮日休','唐','御定全唐诗','yuding','','[]','象鼎格仍高，其中不烹飪。唯將煮濁醪，用以資酣飲。',48,'御定全唐詩/json/611.json','["象鼎格仍高，其中不烹飪。唯將煮濁醪，用以資酣飲。", "偏宜旋樵火，稍近餘酲枕。若得伴琴書，吾將著閑品。"]'),
('yuding-45','奉和添酒中六詠：酒杯','皮日休','唐','御定全唐诗','yuding','','[]','昔有嵇氏子，龍章而鳳姿。手揮五弦罷，聊複一樽持。',48,'御定全唐詩/json/611.json','["昔有嵇氏子，龍章而鳳姿。手揮五弦罷，聊複一樽持。", "但取性淡泊，不知味醇醨。茲器不復見，家家唯玉卮。"]'),
('yuding-46','茶中雜詠：茶塢','皮日休','唐','御定全唐诗','yuding','','[]','閑尋堯氏山，遂入深深塢。種荈已成園，栽葭寧記畝。',48,'御定全唐詩/json/611.json','["閑尋堯氏山，遂入深深塢。種荈已成園，栽葭寧記畝。", "石窪泉似掬，岩罅雲如縷。好是夏初時，白花滿煙雨。"]'),
('yuding-47','茶中雜詠：茶人','皮日休','唐','御定全唐诗','yuding','','[]','生於顧渚山，老在漫石塢。語氣為茶荈，衣香是煙霧。',49,'御定全唐詩/json/611.json','["生於顧渚山，老在漫石塢。語氣為茶荈，衣香是煙霧。", "庭從dx子遮，果任獳師虜。日晚相笑歸，腰間佩輕簍。"]'),
('yuding-48','茶中雜詠：茶筍','皮日休','唐','御定全唐诗','yuding','','[]','褎然三五寸，生必依岩洞。寒恐結紅鉛，暖疑銷紫汞。',48,'御定全唐詩/json/611.json','["褎然三五寸，生必依岩洞。寒恐結紅鉛，暖疑銷紫汞。", "圓如玉軸光，脆似瓊英凍。每為遇之疏，南山掛幽夢。"]'),
('yuding-49','茶中雜詠：茶籝','皮日休','唐','御定全唐诗','yuding','','[]','筤篣曉攜去，驀個山桑塢。開時送紫茗，負處沾清露。',48,'御定全唐詩/json/611.json','["筤篣曉攜去，驀個山桑塢。開時送紫茗，負處沾清露。", "歇把傍雲泉，歸將掛煙樹。滿此是生涯，黃金何足數。"]'),
('yuding-50','茶中雜詠：茶舍','皮日休','唐','御定全唐诗','yuding','','[]','陽崖枕白屋，幾口嬉嬉活。棚上汲紅泉，焙前蒸紫蕨。',48,'御定全唐詩/json/611.json','["陽崖枕白屋，幾口嬉嬉活。棚上汲紅泉，焙前蒸紫蕨。", "乃翁研茗後，中婦拍茶歇。相向掩柴扉，清香滿山月。"]'),
('yuding-51','茶中雜詠：茶灶','皮日休','唐','御定全唐诗','yuding','','[]','南山茶事動，灶起岩根傍。水煮石發氣，薪然杉脂香。',48,'御定全唐詩/json/611.json','["南山茶事動，灶起岩根傍。水煮石發氣，薪然杉脂香。", "青瓊蒸後凝，綠髓炊來光。如何重辛苦，一一輸膏粱。"]'),
('yuding-52','茶中雜詠：茶焙','皮日休','唐','御定全唐诗','yuding','','[]','鑿彼碧岩下，恰應深二尺。泥易帶雲根，燒難礙石脈。',48,'御定全唐詩/json/611.json','["鑿彼碧岩下，恰應深二尺。泥易帶雲根，燒難礙石脈。", "初能燥金餅，漸見幹瓊液。九裏共杉林，相望在山側。"]'),
('yuding-53','茶中雜詠：茶鼎','皮日休','唐','御定全唐诗','yuding','','[]','龍舒有良匠，鑄此佳樣成。立作菌蠢勢，煎為潺湲聲。',48,'御定全唐詩/json/611.json','["龍舒有良匠，鑄此佳樣成。立作菌蠢勢，煎為潺湲聲。", "草堂暮雲陰，松窗殘雪明。此時勺複茗，野語知逾清。"]'),
('yuding-54','茶中雜詠：茶甌','皮日休','唐','御定全唐诗','yuding','','[]','邢客與越人，皆能造茲器。圓似月魂墮，輕如雲魄起。',48,'御定全唐詩/json/611.json','["邢客與越人，皆能造茲器。圓似月魂墮，輕如雲魄起。", "棗花勢旋眼，蘋沫香沾齒。松下時一看，支公亦如此。"]'),
('yuding-55','茶中雜詠：煮茶','皮日休','唐','御定全唐诗','yuding','','[]','香泉一合乳，煎作連珠沸。時看蟹目濺，乍見魚鱗起。',48,'御定全唐詩/json/611.json','["香泉一合乳，煎作連珠沸。時看蟹目濺，乍見魚鱗起。", "聲疑松帶雨，餑恐生煙翠。尚把瀝中山，必無千日醉。"]'),
('yuding-56','石榴歌','皮日休','唐','御定全唐诗','yuding','','[]','蟬噪秋枝槐葉黃，石榴香老愁寒霜。流霞包染紫鸚粟，',40,'御定全唐詩/json/611.json','["蟬噪秋枝槐葉黃，石榴香老愁寒霜。流霞包染紫鸚粟，", "蕭娘初嫁嗜甘酸，嚼破水精千萬粒。"]'),
('yuding-0','奉和魯望四明山九題：石窗','皮日休','唐','御定全唐诗','yuding','','[]','窗開自真宰，四達見蒼涯。苔染渾成綺，雲漫便當紗。',48,'御定全唐詩/json/612.json','["窗開自真宰，四達見蒼涯。苔染渾成綺，雲漫便當紗。", "欞中空吐月，扉際不扃霞。未會通何處，應憐玉女家。"]'),
('yuding-1','奉和魯望四明山九題：過雲','皮日休','唐','御定全唐诗','yuding','','[]','粉洞二十裏，當中幽客行。片時迷鹿跡，寸步隔人聲。',48,'御定全唐詩/json/612.json','["粉洞二十裏，當中幽客行。片時迷鹿跡，寸步隔人聲。", "以杖探虛翠，將襟惹薄明。經時未過得，恐是入層城。"]'),
('yuding-2','奉和魯望四明山九題：雲南','皮日休','唐','御定全唐诗','yuding','','[]','雲南背一川，無雁到峰前。墟裏生紅藥，人家發白泉。',48,'御定全唐詩/json/612.json','["雲南背一川，無雁到峰前。墟裏生紅藥，人家發白泉。", "兒童皆似古，婚嫁盡如仙。共作真官戶，無由稅石田。"]'),
('yuding-3','奉和魯望四明山九題：雲北','皮日休','唐','御定全唐诗','yuding','','[]','雲北晝冥冥，空疑背壽星。犬能諳藥氣，人解寫芝形。',48,'御定全唐詩/json/612.json','["雲北晝冥冥，空疑背壽星。犬能諳藥氣，人解寫芝形。", "野歇遇松蓋，醉書逢石屏。焚香住此地，應得入金庭。"]'),
('yuding-4','奉和魯望四明山九題：鹿亭','皮日休','唐','御定全唐诗','yuding','','[]','鹿群多此住，因構白雲楣。待侶傍花久，引麛穿竹遲。',48,'御定全唐詩/json/612.json','["鹿群多此住，因構白雲楣。待侶傍花久，引麛穿竹遲。", "經時掊玉澗，盡日嗅金芝。為在石窗下，成仙自不知。"]'),
('yuding-5','奉和魯望四明山九題：樊榭','皮日休','唐','御定全唐诗','yuding','','[]','主人成列仙，故榭獨依然。石洞哄人笑，松聲驚鹿眠。',48,'御定全唐詩/json/612.json','["主人成列仙，故榭獨依然。石洞哄人笑，松聲驚鹿眠。", "井香為大藥，鶴語是靈篇。欲買重棲隱，雲峰不售錢。"]'),
('yuding-6','奉和魯望四明山九題：潺湲洞','皮日休','唐','御定全唐诗','yuding','','[]','陰宮何處淵，到此洞潺湲。敲碎一輪月，熔銷半段天。',48,'御定全唐詩/json/612.json','["陰宮何處淵，到此洞潺湲。敲碎一輪月，熔銷半段天。", "響高吹穀動，勢急噴雲旋。料得深秋夜，臨流盡古仙。"]'),
('yuding-7','奉和魯望四明山九題：青欞子','皮日休','唐','御定全唐诗','yuding','','[]','山風熟異果，應是供真仙。味似雲腴美，形如玉腦圓。',48,'御定全唐詩/json/612.json','["山風熟異果，應是供真仙。味似雲腴美，形如玉腦圓。", "銜來多野鶴，落處半靈泉。必共玄都奈，花開不記年。"]'),
('yuding-8','奉和魯望四明山九題：鞠侯','皮日休','唐','御定全唐诗','yuding','','[]','堪羨鞠侯國，碧岩千萬重。煙蘿為印綬，雲壑是堤封。',49,'御定全唐詩/json/612.json','["堪羨鞠侯國，碧岩千萬重。煙蘿為印綬，雲壑是堤封。", "泉遣狙公護，果教ce子供。爾徒如不死，應得躡玄蹤。"]'),
('yuding-9','五貺詩：五瀉舟','皮日休','唐','御定全唐诗','yuding','','[]','何事有青錢，因人買釣船。闊容兼餌坐，深許共蓑眠。',48,'御定全唐詩/json/612.json','["何事有青錢，因人買釣船。闊容兼餌坐，深許共蓑眠。", "短好隨朱鷺，輕堪倚白蓮。自知無用處，卻寄五湖仙。"]'),
('yuding-10','五貺詩：華頂杖','皮日休','唐','御定全唐诗','yuding','','[]','金庭仙樹枝，道客自攜持。探洞求丹粟，挑雲覓白芝。',48,'御定全唐詩/json/612.json','["金庭仙樹枝，道客自攜持。探洞求丹粟，挑雲覓白芝。", "量泉將濯足，闌鶴把支頤。以此將為贈，惟君盡得知。"]'),
('yuding-11','五貺詩：太湖硯','皮日休','唐','御定全唐诗','yuding','','[]','求于花石間，怪狀乃天然。中瑩五寸劍，外差千疊蓮。',48,'御定全唐詩/json/612.json','["求于花石間，怪狀乃天然。中瑩五寸劍，外差千疊蓮。", "月融還似洗，雲濕便堪研。寄與先生後，應添內外篇。"]'),
('yuding-12','五貺詩：烏龍養和','皮日休','唐','御定全唐诗','yuding','','[]','壽木拳數尺，天生形狀幽。把疑傷虺節，用恐破蛇瘤。',48,'御定全唐詩/json/612.json','["壽木拳數尺，天生形狀幽。把疑傷虺節，用恐破蛇瘤。", "置合月觀內，買須雲肆頭。料君攜去處，煙雨太湖舟。"]'),
('yuding-13','五貺詩：訶陵樽','皮日休','唐','御定全唐诗','yuding','','[]','一片鱟魚殼，其中生翠波。買須能紫貝，用合對紅螺。',48,'御定全唐詩/json/612.json','["一片鱟魚殼，其中生翠波。買須能紫貝，用合對紅螺。", "盡瀉判狂藥，禁敲任浩歌。明朝與君後，爭那玉山何。"]'),
('yuding-14','早春病中書事寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','眼暈見雲母，耳虛聞海濤。惜春狂似蝶，養病躁於猱。',48,'御定全唐詩/json/612.json','["眼暈見雲母，耳虛聞海濤。惜春狂似蝶，養病躁於猱。", "案靜方書古，堂空藥氣高。可憐真宰意，偏解困吾曹。"]'),
('yuding-15','又寄次前韻','皮日休','唐','御定全唐诗','yuding','','[]','病根冬養得，春到一時生。眼暗憐晨慘，心寒怯夜清。',48,'御定全唐詩/json/612.json','["病根冬養得，春到一時生。眼暗憐晨慘，心寒怯夜清。", "妻仍嫌酒癖，醫只禁詩情。應被高人笑，憂身不似名。"]'),
('yuding-16','秋晚留題魯望郊居二首','皮日休','唐','御定全唐诗','yuding','','[]','竹樹冷濩落，入門神已清。寒蛩傍枕響，秋菜上牆生。',96,'御定全唐詩/json/612.json','["竹樹冷濩落，入門神已清。寒蛩傍枕響，秋菜上牆生。", "黃犬病仍吠，白驢饑不鳴。唯將一杯酒，盡日慰劉楨。", "冷臥空齋內，餘酲夕未消。秋花如有恨，寒蝶似無憀。", "簷上落鬥雀，籬根生晚潮。若輪羈旅事，猶自勝皋橋。"]'),
('yuding-17','初冬章上人院','皮日休','唐','御定全唐诗','yuding','','[]','寒到無妨睡，僧吟不廢禪。尚關經病鶴，猶濾欲枯泉。',48,'御定全唐詩/json/612.json','["寒到無妨睡，僧吟不廢禪。尚關經病鶴，猶濾欲枯泉。", "靜案貝多紙，閑爐波律煙。清譚兩三句，相向自翛然。"]'),
('yuding-18','臨頓為吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欸然惜去因成五言十首奉題屋壁','皮日休','唐','御定全唐诗','yuding','','[]','一方蕭灑地，之子獨深居。繞屋親栽竹，堆床手寫書。',480,'御定全唐詩/json/612.json','["一方蕭灑地，之子獨深居。繞屋親栽竹，堆床手寫書。", "高風翔砌鳥，暴雨失池魚。暗識歸山計，村邊買鹿車。", "籬疏從綠槿，簷亂任黃茅。壓酒移溪石，煎茶拾野巢。", "靜窗懸雨笠，閑壁掛煙匏。支遁今無骨，誰為世外交。", "繭稀初上簇，醅盡未幹床。盡日留蠶母，移時祭麹王。", "趁泉澆竹急，候雨種蓮忙。更葺園中景，應為顧辟疆。", "靜僻無人到，幽深每自知。鶴來添口數，琴到益家資。", "壞塹生魚沫，頹簷落燕兒。空將綠蕉葉，來往寄閑詩。", "夏過無擔石，日高開板扉。僧雖與筒簟，人不典蕉衣。", "鶴靜共眠覺，鷺馴同釣歸。生公石上月，何夕約譚微。", "經歲岸烏紗，讀書三十車。水痕侵病竹，蛛網上衰花。", "詩任傳漁客，衣從遞酒家。知君秋晚事，白幘刈胡麻。", "寂曆秋懷動，蕭條夏思殘。久貧空酒庫，多病束魚竿。", "玄想凝鶴扇，清齋拂鹿冠。夢魂無俗事，夜夜到金壇。", "閉門無一事，安穩臥涼天。砌下翹饑鶴，庭陰落病蟬。", "倚杉閑把易，燒朮靜論玄。賴有包山客，時時寄紫泉。", "病起扶靈壽，翛然強到門。與杉除敗葉，為石整危根。", "薜蔓任遮壁，蓮莖臥枕盆。明朝有忙事，召客斫桐孫。", "緩頰稱無利，低眉號不能。世情都太薄，俗意就中憎。", "雲態不知驟，鶴情非會征。畫臣誰奉詔，來此寫薑肱。"]'),
('yuding-19','遊棲霞寺','皮日休','唐','御定全唐诗','yuding','','[]','不見明居士，空山但寂寥。白蓮吟次缺，青靄坐來銷。',48,'御定全唐詩/json/612.json','["不見明居士，空山但寂寥。白蓮吟次缺，青靄坐來銷。", "泉冷無三伏，松枯有六朝。何時石上月，相對論逍遙。"]'),
('yuding-20','旅舍除夜','皮日休','唐','御定全唐诗','yuding','','[]','永夜誰能守，羈心不放眠。挑燈猶故歲，聽角已新年。',48,'御定全唐詩/json/612.json','["永夜誰能守，羈心不放眠。挑燈猶故歲，聽角已新年。", "出穀空嗟晚，銜杯尚愧先。晚來辭逆旅，雪涕野槐天。"]'),
('yuding-21','魯望示廣文先生吳門二章，情格高散，可醒俗態，因追想山中風度，次韻屬和，存於詩編，魯望之命也','皮日休','唐','御定全唐诗','yuding','','[]','我見先生道，休思鄭廣文。鶴翻希作伴，鷗卻覓為群。',96,'御定全唐詩/json/612.json','["我見先生道，休思鄭廣文。鶴翻希作伴，鷗卻覓為群。", "逸好冠清月，高宜著白雲。朝廷未無事，爭任醉醺醺。", "能諳肉芝樣，解講隱書文。終古神仙窟，窮年麋鹿群。", "行廚煮白石，臥具拂青雲。應在雷平上，支頤複半醺。"]'),
('yuding-22','虎丘寺殿前有古杉一本，形狀醜怪，圖之不盡，況百卉競媚，若妒若媢，唯此杉死抱奇節，髐然闖然，不知雨露之可生也，風霜之可瘁也，乃造化者方外之材乎？遂賦三百言以見志','皮日休','唐','御定全唐诗','yuding','','[]','種日應逢晉，枯來必自隋。鱷狂將立處，螭鬥未開時。',363,'御定全唐詩/json/612.json','["種日應逢晉，枯來必自隋。鱷狂將立處，螭鬥未開時。", "卓犖擲槍幹，叉牙束戟枝。初驚蟉篆活，複訝獝狂癡。", "勁質如堯瘦，貞容學舜黴。勢能擒土伯，醜可駭山祇。", "虎爪拏岩穩，虯身脫浪欹。槎頭禿似刷，枿觜利於錐。", "突兀方相脛，鱗皴夏氏胝。根應藏鬼血，柯欲漏龍漦。", "拗似神荼怒，呀如猰貐饑。朽癰難可吮，枯瘇不堪治。", "一炷玄雲拔，三尋黑槊奇。狼頭gR窣豎，蠆尾掘攣垂。", "目燥那逢爟，心開豈中鈹。任苔為疥癬，從蠹作瘡痍。", "品格齊遼鶴，年齡等寶龜。將懷宿地力，欲負拔山姿。", "未倒防風骨，初僵負貳屍。漆書明古本，鐵室抗全師。", "碨礧還無極，伶俜又莫持。堅應敵駿骨，文定寫bm皮。", "蟠屈愁淩刹，騰驤恐攫池。搶煙寒嶱gi，披蔦靜褵褷。", "威仰誠難識，句芒恐不知。好燒胡律看，堪共達多期。", "寡色諸芳笑，無聲眾籟疑。終添八柱位，未要一繩維。", "盡日來唯我，當春玩更誰。他年如入用，直構太平基。"]'),
('yuding-23','新秋言懷寄魯望三十韻','皮日休','唐','御定全唐诗','yuding','','[]','新秋入破宅，疏淡若平郊。戶牖深如窟，詩書亂似巢。',361,'御定全唐詩/json/612.json','["新秋入破宅，疏淡若平郊。戶牖深如窟，詩書亂似巢。", "移床驚蟋蟀，拂匣動蠨蛸。靜把泉華掬，閑拈乳管敲。", "檜身渾個矮，石面得能bn。小桂如拳葉，新松似手梢。", "鶴鳴轉清角，鶻下撲金髇。合藥還慵服，為文亦懶抄。", "煩心入夜醒，疾首帶涼抓。杉葉尖如鏃，藤絲韌似鞘。", "僨田含紫芋，低蔓隱青匏。老柏渾如疥，陰苔忽似膠。", "王餘落敗塹，胡孟入空庖。度日忘冠帶，經時憶酒肴。", "有心同木偶，無舌並金鐃。興欲添玄測，狂將換易爻。", "達人唯落落，俗士自譊譊。底力將排難，何顏用解嘲。", "欲銷毀後骨，空轉坐來胞。猶豫應難抱，狐疑不易包。", "等閒逢毒蠚，容易遇咆哮。時事方千蠍，公途正二崤。", "名微甘世棄，性拙任時拋。白日須投分，青雲合定交。", "仕應同五柳，歸莫舍三茅。澗鹿從來去，煙蘿任溷殽。", "狙公鬧後戲，雲母病來摷。從此居方丈，終非競鬥筲。", "道窮應鬼遣，性拙必天教。無限疏慵事，憑君解一瓟。"]'),
('yuding-24','奉和魯望秋日遣懷次韻','皮日休','唐','御定全唐诗','yuding','','[]','高蹈為時背，幽懷是事兼。神仙君可致，江海我能淹。',192,'御定全唐詩/json/612.json','["高蹈為時背，幽懷是事兼。神仙君可致，江海我能淹。", "共守庚申夜，同看乙巳占。藥囊除紫蠹，丹灶拂紅鹽。", "與物深無競，於生亦太廉。鴻災因足警，魚禍為稀潛。", "筆硯秋光洗，衣巾夏蘚沾。酒甔香竹院，魚籠掛茅簷。", "琴忘因拋譜，詩存為致簽。茶旗經雨展，石筍帶雲尖。", "鶴共心情慢，烏同面色黔。向陽裁白帢，終歲憶貂襜。", "取嶺為山障，將泉作水簾。溪晴多晚鷺，池廢足秋蟾。", "破衲雖雲補，閑齋未辦苫。共君還有役，竟夕得厭厭。"]'),
('yuding-25','江南書情二十韻寄秘閣韋校書貽之商洛宋先輩垂文二同年','皮日休','唐','御定全唐诗','yuding','','[]','四載加前字，今來未改銜。君批鳳尾詔，我住虎頭岩。',240,'御定全唐詩/json/612.json','["四載加前字，今來未改銜。君批鳳尾詔，我住虎頭岩。", "季氏唯謀逐，臧倉只擬讒。時訛輕五羖，俗淺重三緘。", "瘦去形如鶴，憂來態似獑。才非師趙壹，直欲效陳咸。", "孤竹寧收笛，黃琮未作瑊。作羊寧免狠，為兔即須毚。", "枕戶槐從亞，侵階草懶芟。壅泉教咽咽，壘石放巉巉。", "掣釣隨心動，抽書任意杴。茶教弩父摘，酒遣僰童監。", "默坐看山困，清齋飲水嚴。蘚生天竺屐，煙外洞庭帆。", "病久新烏帽，閑多著白衫。藥苞陳雨匼，詩草蠹雲函。", "遣客呼林狖，辭人寄海螊。室唯搜古器，錢只買秋杉。", "寡合無深契，相期有至諴。他年如訪問，煙蔦暗髟髟。"]'),
('yuding-26','憶洞庭觀步十韻','皮日休','唐','御定全唐诗','yuding','','[]','前時登觀步，暑雨正錚摐。上戍看綿蕝，登村度石矼。',122,'御定全唐詩/json/612.json','["前時登觀步，暑雨正錚摐。上戍看綿蕝，登村度石矼。", "崦花時有蔟，溪鳥不成雙。遠樹點黑槊，遙峰露碧幢。", "岩根瘦似殼，杉破腹如腔。dpdP漁人服，筕篖野店窗。", "多攜白木鍤，愛買紫泉缸。仙犬聲音古，遺民意緒厖。", "何文堪緯地，底策可經邦。自此將妻子，歸山不姓龐。"]'),
('yuding-27','諫議以罷郡將歸以六韻賜示，因佇酬獻','皮日休','唐','御定全唐诗','yuding','','[]','欲下持衡詔，先容解印歸。露濃春後澤，霜薄霽來威。',72,'御定全唐詩/json/612.json','["欲下持衡詔，先容解印歸。露濃春後澤，霜薄霽來威。", "舊化堪治疾，餘恩可療饑。隔花攀去棹，穿柳挽行衣。", "佐理能無取，酬知力甚微。空將千感淚，異日拜黃扉。"]'),
('yuding-0','過雲居院玄福上人舊居','皮日休','唐','御定全唐诗','yuding','','[]','重到雲居獨悄然，隔窗窺影尚疑禪。不逢野老來聽法，',40,'御定全唐詩/json/613.json','["重到雲居獨悄然，隔窗窺影尚疑禪。不逢野老來聽法，", "南宗弟子時時到，泣把山花奠幾筵。"]'),
('yuding-1','陪江西裴公遊襄州延慶寺','皮日休','唐','御定全唐诗','yuding','','[]','丹霄路上歇征輪，勝地偷閒一日身。不署前驅驚野鳥，',40,'御定全唐詩/json/613.json','["丹霄路上歇征輪，勝地偷閒一日身。不署前驅驚野鳥，", "更向碧山深處問，不妨猶有草茅臣。"]'),
('yuding-2','西塞山泊漁家','皮日休','唐','御定全唐诗','yuding','','[]','白綸巾下發如絲，靜倚楓根坐釣磯。中婦桑村挑葉去，',40,'御定全唐詩/json/613.json','["白綸巾下發如絲，靜倚楓根坐釣磯。中婦桑村挑葉去，", "西塞山前終日客，隔波相羨盡依依。"]'),
('yuding-3','襄州春遊','皮日休','唐','御定全唐诗','yuding','','[]','信馬騰騰觸處行，春風相引與詩情。等閒遇事成歌詠，',40,'御定全唐詩/json/613.json','["信馬騰騰觸處行，春風相引與詩情。等閒遇事成歌詠，", "岑牟單絞何曾著，莫道倡狂似禰衡。"]'),
('yuding-4','送從弟皮崇歸複州','皮日休','唐','御定全唐诗','yuding','','[]','羨爾優遊正少年，竟陵煙月似吳天。車螯近岸無妨取，',40,'御定全唐詩/json/613.json','["羨爾優遊正少年，竟陵煙月似吳天。車螯近岸無妨取，", "殷勤莫笑襄陽住，為愛南溪縮項鯿。"]'),
('yuding-5','題潼關蘭若','皮日休','唐','御定全唐诗','yuding','','[]','潼津罷警有招提，近百年無戰馬嘶。壯士不言三尺劍，',40,'御定全唐詩/json/613.json','["潼津罷警有招提，近百年無戰馬嘶。壯士不言三尺劍，", "關吏不勞重借問，棄繻生擬入耶溪。"]'),
('yuding-6','襄陽閒居與友生夜會','皮日休','唐','御定全唐诗','yuding','','[]','習隱悠悠世不知，林園幽事遞相期。舊絲再上琴調晚，',40,'御定全唐詩/json/613.json','["習隱悠悠世不知，林園幽事遞相期。舊絲再上琴調晚，", "草玄寂淡無人愛，不遇劉歆更語誰。"]'),
('yuding-7','習池晨起','皮日休','唐','御定全唐诗','yuding','','[]','清曙蕭森載酒來，涼風相引繞亭台。數聲翡翠背人去，',40,'御定全唐詩/json/613.json','["清曙蕭森載酒來，涼風相引繞亭台。數聲翡翠背人去，", "竹屏風下登山屐，十宿高陽忘卻回。"]'),
('yuding-8','秋晚自洞庭湖別業寄穆秀才','皮日休','唐','御定全唐诗','yuding','','[]','破村寥落過重陽，獨自攖寧葺草房。風撦紅蕉仍換葉，',40,'御定全唐詩/json/613.json','["破村寥落過重陽，獨自攖寧葺草房。風撦紅蕉仍換葉，", "他日若修耆舊傳，為予添取此書堂。"]'),
('yuding-9','華山李煉師所居','皮日休','唐','御定全唐诗','yuding','','[]','麻姑古貌上仙才，謫向蓮峰管玉台。瑞氣染衣金液啟，',40,'御定全唐詩/json/613.json','["麻姑古貌上仙才，謫向蓮峰管玉台。瑞氣染衣金液啟，", "深夜寂寥存想歇，月天時下草堂來。"]'),
('yuding-10','宏詞下第感恩獻兵部侍郎','皮日休','唐','御定全唐诗','yuding','','[]','分明仙籍列清虛，自是還丹九轉疏。畫虎已成翻類狗，',40,'御定全唐詩/json/613.json','["分明仙籍列清虛，自是還丹九轉疏。畫虎已成翻類狗，", "猶有報恩方寸在，不知通塞竟何如。"]'),
('yuding-11','襄州漢陽王故宅','皮日休','唐','御定全唐诗','yuding','','[]','碑字依稀廟已荒，猶聞耆舊憶賢王。園林一半為他主，',40,'御定全唐詩/json/613.json','["碑字依稀廟已荒，猶聞耆舊憶賢王。園林一半為他主，", "柱天功業緣何事，不得終身似霍光。"]'),
('yuding-12','《傷盧獻秀才','皮日休','唐','御定全唐诗','yuding','','[]','湣征新價欲淩空，一首堪欺左太沖。只為白衣聲過重，',40,'御定全唐詩/json/613.json','["湣征新價欲淩空，一首堪欺左太沖。只為白衣聲過重，", "手弄桂枝嫌不折，直教身歿負春風。"]'),
('yuding-13','南陽','皮日休','唐','御定全唐诗','yuding','','[]','昆陽王氣已蕭疏，依舊山河捧帝居。廢路塌平殘瓦礫，',40,'御定全唐詩/json/613.json','["昆陽王氣已蕭疏，依舊山河捧帝居。廢路塌平殘瓦礫，", "二百年來霸王業，可知今日是丘墟。"]'),
('yuding-14','秋晚訪李處士所居','皮日休','唐','御定全唐诗','yuding','','[]','門前襄水碧潺潺，靜釣歸來不掩關。書閣鼠穿廚簏破，',40,'御定全唐詩/json/613.json','["門前襄水碧潺潺，靜釣歸來不掩關。書閣鼠穿廚簏破，", "莫為愛詩偏念我，訪君多得醉中還。"]'),
('yuding-15','李處士郊居','皮日休','唐','御定全唐诗','yuding','','[]','石衣如發小溪清，溪上柴門架樹成。園裏水流澆竹響，',40,'御定全唐詩/json/613.json','["石衣如發小溪清，溪上柴門架樹成。園裏水流澆竹響，", "滿引紅螺詩一首，劉楨失卻病心情。"]'),
('yuding-16','送令狐補闕歸朝','皮日休','唐','御定全唐诗','yuding','','[]','文如日月氣如虹，舉國重生正始風。且願仲山居左掖，',40,'御定全唐詩/json/613.json','["文如日月氣如虹，舉國重生正始風。且願仲山居左掖，", "為說明年今日事，晉廷新拜黑頭公。"]'),
('yuding-17','洛中寒食二首','皮日休','唐','御定全唐诗','yuding','','[]','千門萬戶掩斜暉，繡幰金銜晚未歸。擊鞠王孫如錦地，',80,'御定全唐詩/json/613.json','["千門萬戶掩斜暉，繡幰金銜晚未歸。擊鞠王孫如錦地，", "唯有路傍無意者，獻書未納問淮肥。", "遠近垂楊映鈿車，天津橋影壓神霞。弄春公子正回首，", "欲知豪貴堪愁處，請看邙山晚照斜。"]'),
('yuding-18','登第後寒食杏園有宴，因寄錄事宋垂文同年','皮日休','唐','御定全唐诗','yuding','','[]','雨洗清明萬象鮮，滿城車馬簇紅筵。恩榮雖得陪高會，',40,'御定全唐詩/json/613.json','["雨洗清明萬象鮮，滿城車馬簇紅筵。恩榮雖得陪高會，", "縱來恐被青娥笑，未納春風一宴錢。"]'),
('yuding-19','陳先輩故居','皮日休','唐','御定全唐诗','yuding','','[]','杉桂交陰一裏餘，逢人渾似洞天居。千株橘樹唯沽酒，',40,'御定全唐詩/json/613.json','["杉桂交陰一裏餘，逢人渾似洞天居。千株橘樹唯沽酒，", "襄陽無限煙霞地，難覓幽奇似此殊。"]'),
('yuding-20','奉和魯望寒夜訪寂上人次韻','皮日休','唐','御定全唐诗','yuding','','[]','院寒青靄正沉沉，霜棧幹鳴入古林。數葉貝書松火暗，',40,'御定全唐詩/json/613.json','["院寒青靄正沉沉，霜棧幹鳴入古林。數葉貝書松火暗，", "何事欲攀塵外契，除君皆有利名心。"]'),
('yuding-21','江南道中懷茅山廣文南陽博士三首','皮日休','唐','御定全唐诗','yuding','','[]','寒嵐依約認華陽，遙想高人臥草堂。半日始齋青z3飯，',121,'御定全唐詩/json/613.json','["寒嵐依約認華陽，遙想高人臥草堂。半日始齋青z3飯，", "誰道夫君無伴侶，不離窗下見羲皇。", "住在華陽第八天，望君唯欲結良緣。堂扃洞裏千秋燕，", "不知何事迎新歲，烏納裘中一覺眠。", "五色香煙惹內文，石飴初熟酒初醺。將開丹灶那防鶴，", "如何世外無交者，一臥金壇只有君。"]'),
('yuding-22','奉和魯望早春雪中作吳體見寄','皮日休','唐','御定全唐诗','yuding','','[]','威仰噤死不敢語，瓊花雲魄清珊珊。溪光冷射觸鸀鳿，',40,'御定全唐詩/json/613.json','["威仰噤死不敢語，瓊花雲魄清珊珊。溪光冷射觸鸀鳿，", "全吳縹瓦十萬戶，惟君與我如袁安。"]'),
('yuding-23','吳中言情寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','古來傖父愛吳鄉，一上胥台不可忘。愛酒有情如手足，',40,'御定全唐詩/json/613.json','["古來傖父愛吳鄉，一上胥台不可忘。愛酒有情如手足，", "為說松江堪老處，滿船煙月濕莎裳。"]'),
('yuding-24','行次野梅','皮日休','唐','御定全唐诗','yuding','','[]','蔦拂蘿捎一樹梅，玉妃無侶獨裴回。好臨王母瑤池發，',40,'御定全唐詩/json/613.json','["蔦拂蘿捎一樹梅，玉妃無侶獨裴回。好臨王母瑤池發，", "不堪便向多情道，萬片霜華雨損來。"]'),
('yuding-25','揚州看辛夷花','皮日休','唐','御定全唐诗','yuding','','[]','臘前千朵亞芳叢，細膩偏勝素柰功。螓首不言披曉雪，',40,'御定全唐詩/json/613.json','["臘前千朵亞芳叢，細膩偏勝素柰功。螓首不言披曉雪，", "應為當時天女服，至今猶未放全紅。"]'),
('yuding-26','暇日獨處寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','幽慵不覺耗年光，犀柄金徽亂一床。野客共為賒酒計，',40,'御定全唐詩/json/613.json','["幽慵不覺耗年光，犀柄金徽亂一床。野客共為賒酒計，", "無限高情好風月，不妨猶得事吾王。"]'),
('yuding-27','屣步訪魯望不遇','皮日休','唐','御定全唐诗','yuding','','[]','雪晴墟裏竹欹斜，蠟屐徐吟到陸家。荒徑掃稀堆柏子，',40,'御定全唐詩/json/613.json','["雪晴墟裏竹欹斜，蠟屐徐吟到陸家。荒徑掃稀堆柏子，", "擬受太玄今不遇，可憐遺恨似侯芭。"]'),
('yuding-28','開元寺客省早景即事','皮日休','唐','御定全唐诗','yuding','','[]','客省蕭條柿葉紅，樓臺如畫倚霜空。銅池數滴桂上雨，',40,'御定全唐詩/json/613.json','["客省蕭條柿葉紅，樓臺如畫倚霜空。銅池數滴桂上雨，", "如何塵外虛為契，不得支公此會同。"]'),
('yuding-29','奉和魯望獨夜有懷吳體見寄','皮日休','唐','御定全唐诗','yuding','','[]','病鶴帶霧傍獨屋，破巢含雪傾孤梧。濯足將加漢光腹，',40,'御定全唐詩/json/613.json','["病鶴帶霧傍獨屋，破巢含雪傾孤梧。濯足將加漢光腹，", "此時枉欠高散物，楠瘤作樽石作壚。"]'),
('yuding-30','病中有人惠海蟹轉寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','紺甲青筐染菭衣，島夷初寄北人時。離居定有石帆覺，',40,'御定全唐詩/json/613.json','["紺甲青筐染菭衣，島夷初寄北人時。離居定有石帆覺，", "病中無用霜螯處，寄與夫君左手持。"]'),
('yuding-31','病中美景頗阻追游因寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','癭床閑臥晝迢迢，唯把真如慰寂寥。南國不須收薏苡，',40,'御定全唐詩/json/613.json','["癭床閑臥晝迢迢，唯把真如慰寂寥。南國不須收薏苡，", "看取病來多少日，早梅零落玉華焦。"]'),
('yuding-32','魯望以花翁之什見招因次韻酬之','皮日休','唐','御定全唐诗','yuding','','[]','九十攜鋤傴僂翁，小園幽事盡能通。劚煙栽藥為身計，',40,'御定全唐詩/json/613.json','["九十攜鋤傴僂翁，小園幽事盡能通。劚煙栽藥為身計，", "不知家道能多少，只在句芒一夜風。"]'),
('yuding-33','病中庭際海石榴花盛發，感而有寄','皮日休','唐','御定全唐诗','yuding','','[]','一夜春光綻絳囊，碧油枝上晝煌煌。風勻只似調紅露，',40,'御定全唐詩/json/613.json','["一夜春光綻絳囊，碧油枝上晝煌煌。風勻只似調紅露，", "不知桂樹知情否，無限同游阻陸郎。"]'),
('yuding-34','早春以橘子寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','個個和枝葉捧鮮，彩凝猶帶洞庭煙。不為韓嫣金丸重，',40,'御定全唐詩/json/613.json','["個個和枝葉捧鮮，彩凝猶帶洞庭煙。不為韓嫣金丸重，", "知君多病仍中聖，盡送寒苞向枕邊。"]'),
('yuding-35','病中書情寄上崔諫議','皮日休','唐','御定全唐诗','yuding','','[]','十日來來曠奉公，閉門無事忌春風。蟲絲度日縈琴薦，',40,'御定全唐詩/json/613.json','["十日來來曠奉公，閉門無事忌春風。蟲絲度日縈琴薦，", "殷勤莫怪求醫切，只為山櫻欲放紅。"]'),
('yuding-36','病孔雀','皮日休','唐','御定全唐诗','yuding','','[]','煙花雖媚思沈冥，猶自抬頭護翠翎。強聽紫簫如欲舞，',40,'御定全唐詩/json/613.json','["煙花雖媚思沈冥，猶自抬頭護翠翎。強聽紫簫如欲舞，", "盡日春風吹不起，鈿毫金縷一星星。"]'),
('yuding-37','奉和魯望上元日道室焚修','皮日休','唐','御定全唐诗','yuding','','[]','明真臺上下仙官，玄藻初吟萬籟寒。飆禦有聲時杳杳，',40,'御定全唐詩/json/613.json','["明真臺上下仙官，玄藻初吟萬籟寒。飆禦有聲時杳杳，", "端簡不知清景暮，靈蕪香燼落金壇。"]'),
('yuding-38','奉酬魯望惜春見寄','皮日休','唐','御定全唐诗','yuding','','[]','十五日中春日好，可憐沉痼冷如灰。以前雖被愁將去，',40,'御定全唐詩/json/613.json','["十五日中春日好，可憐沉痼冷如灰。以前雖被愁將去，", "病中無限花番次，為約東風且住開。"]'),
('yuding-39','聞魯望游顏家林園病中有寄','皮日休','唐','御定全唐诗','yuding','','[]','一夜韶姿著水光，謝家春草滿池塘。細挑泉眼尋新脈，',40,'御定全唐詩/json/613.json','["一夜韶姿著水光，謝家春草滿池塘。細挑泉眼尋新脈，", "分明不得同君賞，盡日傾心羨索郎。"]'),
('yuding-40','奉和魯望春雨即事次韻','皮日休','唐','御定全唐诗','yuding','','[]','織恨凝愁映鳥飛，半旬飄灑掩韶暉。山容洗得如煙瘦，',40,'御定全唐詩/json/613.json','["織恨凝愁映鳥飛，半旬飄灑掩韶暉。山容洗得如煙瘦，", "何年細濕華陽道，兩乘巾車相並歸。"]'),
('yuding-41','魯望春日多尋野景日休抱疾杜門因有是寄','皮日休','唐','御定全唐诗','yuding','','[]','野侶相逢不待期，半緣幽事半緣詩。烏紗任岸穿筋竹，',40,'御定全唐詩/json/613.json','["野侶相逢不待期，半緣幽事半緣詩。烏紗任岸穿筋竹，", "病中不用君相憶，折取山櫻寄一枝。"]'),
('yuding-42','魯望以躬掇野蔬兼示雅什，用以酬謝','皮日休','唐','御定全唐诗','yuding','','[]','杖擿春煙暖向陽，煩君為我致盈筐。深挑乍見牛唇液，',41,'御定全唐詩/json/613.json','["杖擿春煙暖向陽，煩君為我致盈筐。深挑乍見牛唇液，", "雕胡飯熟bu餬軟，不是高人不合嘗。"]'),
('yuding-43','臥病感春寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','烏皮幾上困騰騰，玉柄清羸愧不能。昨夜眠時稀似鶴，',40,'御定全唐詩/json/613.json','["烏皮幾上困騰騰，玉柄清羸愧不能。昨夜眠時稀似鶴，", "任是雨多遊未得，也須收在探花朋。"]'),
('yuding-44','奉和魯望徐方平後聞赦次韻','皮日休','唐','御定全唐诗','yuding','','[]','金雞煙外上臨軒，紫誥新垂作解恩。涿鹿未銷初敗血，',40,'御定全唐詩/json/613.json','["金雞煙外上臨軒，紫誥新垂作解恩。涿鹿未銷初敗血，", "未遣蒲車問幽隱，共君應老抱桐孫。"]'),
('yuding-45','奉酬魯望見答魚箋之什','皮日休','唐','御定全唐诗','yuding','','[]','輕如隱起膩如飴，除卻鮫工解制稀。欲寫恐成河伯詔，',40,'御定全唐詩/json/613.json','["輕如隱起膩如飴，除卻鮫工解制稀。欲寫恐成河伯詔，", "若用莫將閑處去，好題春思贈江妃。"]'),
('yuding-46','病後春思','皮日休','唐','御定全唐诗','yuding','','[]','連錢錦暗麝氛氳，荊思多才詠鄂君。孔雀鈿寒窺沼見，',40,'御定全唐詩/json/613.json','["連錢錦暗麝氛氳，荊思多才詠鄂君。孔雀鈿寒窺沼見，", "應笑病來慚滿願，花箋好作斷腸文。"]'),
('yuding-47','偶成小酌招魯望不至，以詩為解，因次韻酬之','皮日休','唐','御定全唐诗','yuding','','[]','醉侶相邀愛早陽，小筵催辦不勝忙。沖深柳駐吳娃幰，',40,'御定全唐詩/json/613.json','["醉侶相邀愛早陽，小筵催辦不勝忙。沖深柳駐吳娃幰，", "如何共是忘形者，不見漁陽摻一場。"]'),
('yuding-48','以紗巾寄魯望因而有作','皮日休','唐','御定全唐诗','yuding','','[]','周家新樣替三梁。裹發偏宜白麵郎。掩斂乍疑裁黑霧，',40,'御定全唐詩/json/613.json','["周家新樣替三梁。裹發偏宜白麵郎。掩斂乍疑裁黑霧，", "更有一般君未識，虎文巾在絳霄房。"]'),
('yuding-49','臨頓宅將有歸於之日魯望以詩見貺，因抒懷酬之','皮日休','唐','御定全唐诗','yuding','','[]','共老林泉忍暫分，此生應不識回文。幾枚竹笥送德曜，',40,'御定全唐詩/json/613.json','["共老林泉忍暫分，此生應不識回文。幾枚竹笥送德曜，", "居然自是幽人事，輒莫教他孫壽聞。"]'),
('yuding-50','奉和魯望謝惠巨魚之半','皮日休','唐','御定全唐诗','yuding','','[]','釣公來信自松江，三尺春魚撥剌霜。腹內舊鉤苔染澀，',40,'御定全唐詩/json/613.json','["釣公來信自松江，三尺春魚撥剌霜。腹內舊鉤苔染澀，", "何事貺君偏得所，只緣同是越航郎。"]'),
('yuding-51','館娃宮懷古','皮日休','唐','御定全唐诗','yuding','','[]','豔骨已成蘭麝土，宮牆依舊壓層崖。弩台雨壞逢金鏃，',40,'御定全唐詩/json/613.json','["豔骨已成蘭麝土，宮牆依舊壓層崖。弩台雨壞逢金鏃，", "姑蘇麋鹿真閒事，須為當時一愴懷。"]'),
('yuding-52','以紫石硯寄魯望兼酬見贈','皮日休','唐','御定全唐诗','yuding','','[]','樣如金蹙小能輕，微潤將融紫玉英。石墨一研為鳳尾，',40,'御定全唐詩/json/613.json','["樣如金蹙小能輕，微潤將融紫玉英。石墨一研為鳳尾，", "兩地有期皆好用，不須空把洗溪聲。"]'),
('yuding-53','奉和魯望同遊北禪院','皮日休','唐','御定全唐诗','yuding','','[]','戚曆杉陰入草堂，老僧相見似相忘。吟多幾轉蓮花漏，',40,'御定全唐詩/json/613.json','["戚曆杉陰入草堂，老僧相見似相忘。吟多幾轉蓮花漏，", "雲林滿眼空羈滯，欲對彌天卻自傷。"]'),
('yuding-54','孫發百篇將遊天臺請詩贈行，因以送之','皮日休','唐','御定全唐诗','yuding','','[]','孫子荊家思有餘，元戎曾薦入公車。百篇宮體喧金屋，',41,'御定全唐詩/json/613.json','["孫子荊家思有餘，元戎曾薦入公車。百篇宮體喧金屋，", "因逢二老如相問，正滯江南為eE魚。"]'),
('yuding-55','奉和魯望薔薇次韻','皮日休','唐','御定全唐诗','yuding','','[]','誰繡連延滿戶陳，暫應遮得陸郎貧。紅芳掩斂將迷蝶，',40,'御定全唐詩/json/613.json','["誰繡連延滿戶陳，暫應遮得陸郎貧。紅芳掩斂將迷蝶，", "只應是董雙成戲，剪得神霞寸寸新。"]'),
('yuding-56','聞開元寺開筍園寄章上人','皮日休','唐','御定全唐诗','yuding','','[]','園鎖開聲駭鹿群，滿林鮮籜水犀文。森森競泫林梢雨，',40,'御定全唐詩/json/613.json','["園鎖開聲駭鹿群，滿林鮮籜水犀文。森森競泫林梢雨，", "折煙束露如相遺，何胤明朝不茹葷。"]'),
('yuding-57','開元寺佛缽詩','皮日休','唐','御定全唐诗','yuding','','[]','帝青石作綠冰姿，曾得金人手自持。拘律樹邊齋散後，',40,'御定全唐詩/json/613.json','["帝青石作綠冰姿，曾得金人手自持。拘律樹邊齋散後，", "從此共君新頂戴，斜風應不等閒吹。"]'),
('yuding-58','夏首病癒因招魯望','皮日休','唐','御定全唐诗','yuding','','[]','曉入清和尚袷衣，夏陰初合掩雙扉。一聲撥谷桑柘晚，',40,'御定全唐詩/json/613.json','["曉入清和尚袷衣，夏陰初合掩雙扉。一聲撥谷桑柘晚，", "明朝早起非無事，買得蓴絲待陸機。"]'),
('yuding-59','奉和魯望新夏東郊閑泛','皮日休','唐','御定全唐诗','yuding','','[]','水物輕明淡似秋，多情才子倚蘭舟。碧莎裳下攜詩草，',40,'御定全唐詩/json/613.json','["水物輕明淡似秋，多情才子倚蘭舟。碧莎裳下攜詩草，", "共君莫問當時事，一點沙禽勝五侯。"]'),
('yuding-60','奉和魯望四月十五日道室書事','皮日休','唐','御定全唐诗','yuding','','[]','望朝齋戒是尋常，靜啟金根第幾章。竹葉飲為甘露色，',40,'御定全唐詩/json/613.json','["望朝齋戒是尋常，靜啟金根第幾章。竹葉飲為甘露色，", "剩欲與君終此志，頑仙唯恐鬢成霜。"]'),
('yuding-61','奉和魯望看壓新醅','皮日休','唐','御定全唐诗','yuding','','[]','一簀松花細有聲，旋將渠碗撇寒清。秦吳只恐篘來近，',40,'御定全唐詩/json/613.json','["一簀松花細有聲，旋將渠碗撇寒清。秦吳只恐篘來近，", "五湖煙水郎山月，合向樽前問底名。"]'),
('yuding-62','登初陽樓寄懷北平郎中','皮日休','唐','御定全唐诗','yuding','','[]','危樓新制號初陽，白粉青葌射沼光。避酒幾浮輕舴艋，',40,'御定全唐詩/json/613.json','["危樓新制號初陽，白粉青葌射沼光。避酒幾浮輕舴艋，", "莫怪重登頻有恨，二年曾侍舊吳王。"]'),
('yuding-63','夏初訪魯望偶題小齋','皮日休','唐','御定全唐诗','yuding','','[]','半裏芳陰到陸家，藜床相勸飯胡麻。林間度宿拋棋局，',40,'御定全唐詩/json/613.json','["半裏芳陰到陸家，藜床相勸飯胡麻。林間度宿拋棋局，", "踟躕未放閒人去，半岸紗帩待月華。"]'),
('yuding-64','所居首夏，水木尤清，適然有作','皮日休','唐','御定全唐诗','yuding','','[]','病來無事草堂空，晝水休聞十二筒。桂靜似逢青眼客，',40,'御定全唐詩/json/613.json','["病來無事草堂空，晝水休聞十二筒。桂靜似逢青眼客，", "盡日枕書慵起得，被君猶自笑從公。"]'),
('yuding-65','重玄寺元達年逾八十，好種名藥，凡所植者多至自天台四明包山句曲，叢翠紛糅，各可指名，余奇而訪之，因題二章','皮日休','唐','御定全唐诗','yuding','','[]','雨滌煙鋤傴僂齎，紺牙紅甲兩三畦。藥名卻笑桐君少，',80,'御定全唐詩/json/613.json','["雨滌煙鋤傴僂齎，紺牙紅甲兩三畦。藥名卻笑桐君少，", "怪來昨日休持缽，一尺雕胡似掌齊。", "香蔓蒙蘢覆昔邪，桂煙杉露濕袈裟。石盆換水撈松葉，", "支公謾道憐神駿，不及今朝種一麻。"]'),
('yuding-0','懷華陽潤卿博士三首','皮日休','唐','御定全唐诗','yuding','','[]','先生一向事虛皇，天市壇西與世忘。環堵養龜看氣訣，',120,'御定全唐詩/json/614.json','["先生一向事虛皇，天市壇西與世忘。環堵養龜看氣訣，", "聞道征賢須有詔，不知何日到良常。", "冥心唯事白英君，不問人間爵與勳。林下醉眠仙鹿見，", "料得虛皇新詔樣，青瓊板上綠為文。", "鳳骨輕來稱瘦容，華陽館主未成翁。數行玉劄存心久，", "他年欲事先生去，十賚須加陸逸沖。"]'),
('yuding-1','魯望以竹夾膝見寄，因次韻酬謝','皮日休','唐','御定全唐诗','yuding','','[]','圓於玉柱滑于龍，來自衡陽彩翠中。拂潤恐飛清夏雨，',40,'御定全唐詩/json/614.json','["圓於玉柱滑于龍，來自衡陽彩翠中。拂潤恐飛清夏雨，", "從此角巾因爾戴，俗人相訪若為通。"]'),
('yuding-2','夏景無事因懷章來二上人二首','皮日休','唐','御定全唐诗','yuding','','[]','澹景微陰正送梅，幽人逃暑癭楠杯。水花移得和魚子，',80,'御定全唐詩/json/614.json','["澹景微陰正送梅，幽人逃暑癭楠杯。水花移得和魚子，", "更無一事唯留客，卻被高僧怕不來。", "佳樹盤珊枕草堂，此中隨分亦閑忙。平鋪風簟尋琴譜，", "從今有計消閒日，更為支公置一床。"]'),
('yuding-3','寄瓊州楊舍人','皮日休','唐','御定全唐诗','yuding','','[]','德星芒彩瘴天涯，酒樹堪消謫宦嗟。行遇竹王因設奠，',40,'御定全唐詩/json/614.json','["德星芒彩瘴天涯，酒樹堪消謫宦嗟。行遇竹王因設奠，", "清切會須歸有日，莫貪句漏足丹砂。"]'),
('yuding-4','魯望以輪鉤相示，緬懷高致，因作三篇','皮日休','唐','御定全唐诗','yuding','','[]','角柄孤輪細膩輕，翠篷十載伴君行。撚時解轉蟾蜍魄，',121,'御定全唐詩/json/614.json','["角柄孤輪細膩輕，翠篷十載伴君行。撚時解轉蟾蜍魄，", "牛衣鮒足和蓑睡，誰信人間有利名。", "一線飄然下碧塘，溪翁無語遠相望。蓑衣舊去煙披重，", "明朝有物充君信，dX酒三瓶寄夜航。", "盡日悠然舴艋輕，小輪聲細雨溟溟。三尋絲帶桐江爛，", "孤篷半夜無餘事，應被嚴灘聒酒醒。"]'),
('yuding-5','吳中書事寄漢南裴尚書','皮日休','唐','御定全唐诗','yuding','','[]','萬家無事鎖蘭橈，鄉味腥多厭紫虈。水似棋文交度郭，',40,'御定全唐詩/json/614.json','["萬家無事鎖蘭橈，鄉味腥多厭紫虈。水似棋文交度郭，", "唯望舊知憐此意，得為傖鬼也逍遙。"]'),
('yuding-6','夏景沖澹偶然作二首','皮日休','唐','御定全唐诗','yuding','','[]','祗隈蒲褥岸烏紗，味道澄懷景便斜。紅印寄泉慚郡守，',80,'御定全唐詩/json/614.json','["祗隈蒲褥岸烏紗，味道澄懷景便斜。紅印寄泉慚郡守，", "園吏暫棲君莫笑，不妨猶更著南華。", "一室無喧事事幽，還如貞白在高樓。天臺畫得千回看，", "他年謁帝言何事，請贈劉伶作醉侯。"]'),
('yuding-7','送李明府之任海南','皮日休','唐','御定全唐诗','yuding','','[]','五羊城在蜃樓邊，墨綬垂腰正少年。山靜不應聞屈鳥，',40,'御定全唐詩/json/614.json','["五羊城在蜃樓邊，墨綬垂腰正少年。山靜不應聞屈鳥，", "一事與君消遠宦，乳蕉花發訟庭前。"]'),
('yuding-8','寄題羅浮軒轅先生所居','皮日休','唐','御定全唐诗','yuding','','[]','亂峰四百三十二，欲問征君何處尋。紅翠數聲瑤室響，',40,'御定全唐詩/json/614.json','["亂峰四百三十二，欲問征君何處尋。紅翠數聲瑤室響，", "從此謁師知不遠，求官先有葛洪心。"]'),
('yuding-9','宿報恩寺水閣','皮日休','唐','御定全唐诗','yuding','','[]','寺鎖雙峰寂不開，幽人中夜獨裴回。池文帶月鋪金簟，',40,'御定全唐詩/json/614.json','["寺鎖雙峰寂不開，幽人中夜獨裴回。池文帶月鋪金簟，", "可憐此際誰曾見，唯有支公盡看來。"]'),
('yuding-10','醉中偶作呈魯望','皮日休','唐','御定全唐诗','yuding','','[]','溪雲澗鳥本吾儕，剛為浮名事事乖。十裏尋山為思役，',40,'御定全唐詩/json/614.json','["溪雲澗鳥本吾儕，剛為浮名事事乖。十裏尋山為思役，", "爭得草堂歸臥去，共君同作太常齋。"]'),
('yuding-11','寄滑州李副使員外','皮日休','唐','御定全唐诗','yuding','','[]','兵繞臨淮數十重，鐵衣才子正從公。軍前草奏旄頭下，',40,'御定全唐詩/json/614.json','["兵繞臨淮數十重，鐵衣才子正從公。軍前草奏旄頭下，", "故人勳重金章貴，猶在江湖積劍功。"]'),
('yuding-12','傷史拱山人','皮日休','唐','御定全唐诗','yuding','','[]','一緘幽信自襄陽，上報先生去歲亡。山客為醫翻貰藥，',40,'御定全唐詩/json/614.json','["一緘幽信自襄陽，上報先生去歲亡。山客為醫翻貰藥，", "宗炳死來君又去，終身不復到柴桑。"]'),
('yuding-13','吳中言懷寄南海二同年','皮日休','唐','御定全唐诗','yuding','','[]','曲水分飛歲已賒，東南為客各天涯。退公只傍蘇勞竹，',40,'御定全唐詩/json/614.json','["曲水分飛歲已賒，東南為客各天涯。退公只傍蘇勞竹，", "三年謾被鱸魚累，不得橫經侍絳紗。"]'),
('yuding-14','奉和魯望白鷗詩','皮日休','唐','御定全唐诗','yuding','','[]','雪羽褵褷半惹泥，海雲深處舊巢迷。池無飛浪爭教舞，',40,'御定全唐詩/json/614.json','["雪羽褵褷半惹泥，海雲深處舊巢迷。池無飛浪爭教舞，", "主人恩重真難遇，莫為心孤憶舊溪。"]'),
('yuding-15','奉和魯望懷楊台文楊鼎文二秀才','皮日休','唐','御定全唐诗','yuding','','[]','羊曇留我昔經春，各以篇章鬥五雲。賓草每容閑處見，',40,'御定全唐詩/json/614.json','["羊曇留我昔經春，各以篇章鬥五雲。賓草每容閑處見，", "為說風標曾入夢，上仙初著翠霞裙。"]'),
('yuding-16','友人以人參見惠因以詩謝之','皮日休','唐','御定全唐诗','yuding','','[]','神草延年出道家，是誰披露記三椏。開時的定涵雲液，',40,'御定全唐詩/json/614.json','["神草延年出道家，是誰披露記三椏。開時的定涵雲液，", "從今湯劑如相續，不用金山焙上茶。"]'),
('yuding-17','傷進士嚴子重詩','皮日休','唐','御定全唐诗','yuding','','[]','十哭都門榜上塵，蓋棺終是五湖人。生前有敵唯丹桂，',40,'御定全唐詩/json/614.json','["十哭都門榜上塵，蓋棺終是五湖人。生前有敵唯丹桂，", "知君精爽應無盡，必在酆都頌帝晨。"]'),
('yuding-18','奉和魯望早秋吳體次韻','皮日休','唐','御定全唐诗','yuding','','[]','書淫傳癖窮欲死，譊譊何必頻相仍。日幹陰蘚厚堪剝，',40,'御定全唐詩/json/614.json','["書淫傳癖窮欲死，譊譊何必頻相仍。日幹陰蘚厚堪剝，", "安得瑤池飲殘酒，半醉騎下垂天鵬。"]'),
('yuding-19','奉和魯望秋賦有期次韻','皮日休','唐','御定全唐诗','yuding','','[]','十載江湖儘是閑，客兒詩句滿人間。郡侯聞譽親邀得，',40,'御定全唐詩/json/614.json','["十載江湖儘是閑，客兒詩句滿人間。郡侯聞譽親邀得，", "太微宮裏環岡樹，無限瑤枝待爾攀。"]'),
('yuding-20','奉和魯望病中秋懷次韻','皮日休','唐','御定全唐诗','yuding','','[]','貧病於君亦太兼，才高應亦被天嫌。因分鶴料家資減，',40,'御定全唐詩/json/614.json','["貧病於君亦太兼，才高應亦被天嫌。因分鶴料家資減，", "清詞一一侵真宰，甘取窮愁不用占。"]'),
('yuding-21','新秋即事三首','皮日休','唐','御定全唐诗','yuding','','[]','癡號多於顧愷之，更無餘事可從知。酒坊吏到常先見，',120,'御定全唐詩/json/614.json','["癡號多於顧愷之，更無餘事可從知。酒坊吏到常先見，", "共君無事堪相賀，又到金齏玉鱠時。", "堪笑高陽病酒徒，幅巾瀟灑在東吳。秋期淨掃雲根瘦，", "乞求待得西風起，盡挽煙帆入太湖。", "露槿風杉滿曲除，高秋無事似雲廬。醉多已任家人厭，", "君卿唇舌非吾事，且向江南問鰒魚。"]'),
('yuding-22','南陽潤卿將歸雷平因而有贈','皮日休','唐','御定全唐诗','yuding','','[]','借問山中許道士，此回歸去複何如。竹屏風扇抄遺事，',40,'御定全唐詩/json/614.json','["借問山中許道士，此回歸去複何如。竹屏風扇抄遺事，", "東卿旄節看看至，靜啟茅齋慎掃除。"]'),
('yuding-23','訪寂上人不遇','皮日休','唐','御定全唐诗','yuding','','[]','何處尋雲暫廢禪，客來還寄草堂眠。桂寒自落翻經案，',40,'御定全唐詩/json/614.json','["何處尋雲暫廢禪，客來還寄草堂眠。桂寒自落翻經案，", "須將二百簽回去，得得支公恐來年。"]'),
('yuding-24','顧道士亡弟子以束帛乞銘于余魯望因賦戲贈日休奉和','皮日休','唐','御定全唐诗','yuding','','[]','師去東華卻煉形，門人求我志金庭。大椿枯後新為記，',40,'御定全唐詩/json/614.json','["師去東華卻煉形，門人求我志金庭。大椿枯後新為記，", "君才莫歎無茲分，合注神玄劍解經。"]'),
('yuding-25','秋夕文宴得遙字','皮日休','唐','御定全唐诗','yuding','','[]','啼螿衰葉共蕭蕭，文宴無喧夜轉遙。高韻最宜題雪贊，',40,'御定全唐詩/json/614.json','["啼螿衰葉共蕭蕭，文宴無喧夜轉遙。高韻最宜題雪贊，", "無限玄言一杯酒，可能容得蓋寬饒。"]'),
('yuding-26','南陽廣文欲于荊襄卜居因而有贈','皮日休','唐','御定全唐诗','yuding','','[]','地脈從來是福鄉，廣文高致更無雙。青精飯熟雲侵灶，',40,'御定全唐詩/json/614.json','["地脈從來是福鄉，廣文高致更無雙。青精飯熟雲侵灶，", "鱸魚自是君家味，莫背松江憶漢江。"]'),
('yuding-27','寄毗陵魏處士朴','皮日休','唐','御定全唐诗','yuding','','[]','文籍先生不肯官，絮巾沖雪把魚竿。一堆方冊為侯印，',40,'御定全唐詩/json/614.json','["文籍先生不肯官，絮巾沖雪把魚竿。一堆方冊為侯印，", "兔皮衾暖篷舟穩，欲共誰遊七裏灘。"]'),
('yuding-28','初冬偶作寄南陽潤卿','皮日休','唐','御定全唐诗','yuding','','[]','寓居無事入清冬，雖設樽罍酒半空。白菊為霜翻帶紫，',40,'御定全唐詩/json/614.json','["寓居無事入清冬，雖設樽罍酒半空。白菊為霜翻帶紫，", "唯待支硎最寒夜，共君披氅訪林公。"]'),
('yuding-29','冬曉章上人院','皮日休','唐','御定全唐诗','yuding','','[]','山堂冬曉寂無聞，一句清言憶領軍。琥珀珠黏行處雪，',40,'御定全唐詩/json/614.json','["山堂冬曉寂無聞，一句清言憶領軍。琥珀珠黏行處雪，", "不是戀師終去晚，陸機茸內足毛群。"]'),
('yuding-30','寄題鏡岩周尊師所居','皮日休','唐','御定全唐诗','yuding','','[]','八十餘年住鏡岩，鹿皮巾下雪髟髟。床寒不奈雲縈枕，',40,'御定全唐詩/json/614.json','["八十餘年住鏡岩，鹿皮巾下雪髟髟。床寒不奈雲縈枕，", "如何計吏窮於鳥，欲望仙都舉一帆。"]'),
('yuding-31','寒夜文宴得泉字','皮日休','唐','御定全唐诗','yuding','','[]','分明競襞七香箋，王朗風姿盡列仙。盈篋共開華頂藥，',40,'御定全唐詩/json/614.json','["分明競襞七香箋，王朗風姿盡列仙。盈篋共開華頂藥，", "吟罷不知詩首數，隔林明月過中天。"]'),
('yuding-32','庚寅歲十一月新羅弘惠上人與本國同書請日休為靈鷲山周禪師碑將還以詩送之','皮日休','唐','御定全唐诗','yuding','','[]','三十麻衣弄渚禽，豈知名字徹雞林。勒銘雖即多遺草，',24,'御定全唐詩/json/614.json','["三十麻衣弄渚禽，豈知名字徹雞林。勒銘雖即多遺草，"]'),
('yuding-33','送潤卿博士還華陽','皮日休','唐','御定全唐诗','yuding','','[]','雪打篷舟離酒旗，華陽居士半酣歸。逍遙只恐逢雪將，',40,'御定全唐詩/json/614.json','["雪打篷舟離酒旗，華陽居士半酣歸。逍遙只恐逢雪將，", "公車草合蒲輪壞，爭不教他白日飛。"]'),
('yuding-34','寒日書齋即事三首','皮日休','唐','御定全唐诗','yuding','','[]','參佐三間似草堂，恬然無事可成忙。移時寂曆燒松子，',120,'御定全唐詩/json/614.json','["參佐三間似草堂，恬然無事可成忙。移時寂曆燒松子，", "空庭好待中宵月，獨禮星辰學步罡。", "不知何事有生涯，皮褐親裁學道家。深夜數甌唯柏葉，", "江漢欲歸應未得，夜來頻夢赤城霞。", "方朔家貧未有車，肯從榮利舍樵漁。從公未怪多侵酒，", "如鉤得貴非吾事，合向煙波為五魚。"]'),
('yuding-35','臘後送內大德從勖游天臺','皮日休','唐','御定全唐诗','yuding','','[]','講散重雲下九天，大君恩賜許隨緣。霜中一缽無辭乞，',40,'御定全唐詩/json/614.json','["講散重雲下九天，大君恩賜許隨緣。霜中一缽無辭乞，", "他時瓜鏡知何用，吳越風光滿禦筵。"]'),
('yuding-36','寄題玉霄峰葉涵象尊師所居','皮日休','唐','御定全唐诗','yuding','','[]','青冥向上玉霄峰，元始先生戴紫蓉。曉案瓊文光洞壑，',40,'御定全唐詩/json/614.json','["青冥向上玉霄峰，元始先生戴紫蓉。曉案瓊文光洞壑，", "子細捫心無偃骨，欲隨師去肯相容。"]'),
('yuding-37','奉和魯望寄南陽廣文次韻','皮日休','唐','御定全唐诗','yuding','','[]','春彩融融釋凍塘，日精閑咽坐岩房。瓊函靜啟從猿覷，',40,'御定全唐詩/json/614.json','["春彩融融釋凍塘，日精閑咽坐岩房。瓊函靜啟從猿覷，", "不知夢到為何處，紅藥滿山煙月香。"]'),
('yuding-38','題支山南峰僧','皮日休','唐','御定全唐诗','yuding','','[]','雲侵壞衲重隈肩，不下南峰不記年。池裏群魚曾受戒，',40,'御定全唐詩/json/614.json','["雲侵壞衲重隈肩，不下南峰不記年。池裏群魚曾受戒，", "無限吳都堪賞事，何如來此看師眠。"]'),
('yuding-39','送董少卿游茅山','皮日休','唐','御定全唐诗','yuding','','[]','名卿風度足杓斜，一舸閑尋二許家。天影曉通金井水，',40,'御定全唐詩/json/614.json','["名卿風度足杓斜，一舸閑尋二許家。天影曉通金井水，", "盡待於公作廷尉，不須從此便餐霞。"]'),
('yuding-40','酬魯望見迎綠罽次韻','皮日休','唐','御定全唐诗','yuding','','[]','輕裁鴨綠任金刀，不怕西風斷野蒿。酬贈既無青玉案，',40,'御定全唐詩/json/614.json','["輕裁鴨綠任金刀，不怕西風斷野蒿。酬贈既無青玉案，", "成後料君無別事，只應酣飲詠離騷。"]'),
('yuding-41','寄懷南陽潤卿','皮日休','唐','御定全唐诗','yuding','','[]','鹿門山下捕魚郎，今向江南作渴羌。無事只陪看藕樣，',40,'御定全唐詩/json/614.json','["鹿門山下捕魚郎，今向江南作渴羌。無事只陪看藕樣，", "何事對君猶有愧，一篷沖雪返華陽。"]'),
('yuding-42','魯望憫承吉之孤為詩序，邀予屬和，欲用予道振其孤而利之，噫！承吉之困身後乎？魯望視予困與承吉生前孰若哉！未有已困而能振人者，抑為之辭，用塞良友','皮日休','唐','御定全唐诗','yuding','','[]','先生清骨葬煙霞，業破孤存孰為嗟。幾篋詩編分貴位，',40,'御定全唐詩/json/614.json','["先生清骨葬煙霞，業破孤存孰為嗟。幾篋詩編分貴位，", "唯我共君堪便戒，莫將文譽作生涯。"]'),
('yuding-43','寄潤卿博士','皮日休','唐','御定全唐诗','yuding','','[]','高眠可為要玄纁，鵲尾金爐一世焚。塵外鄉人為許掾，',40,'御定全唐詩/json/614.json','["高眠可為要玄纁，鵲尾金爐一世焚。塵外鄉人為許掾，", "若使華陽終臥去，漢家封禪用誰文。"]'),
('yuding-44','奉和魯望白菊','皮日休','唐','御定全唐诗','yuding','','[]','已過重陽半月天，琅華千點照寒煙。蕊香亦似浮金靨，',40,'御定全唐詩/json/614.json','["已過重陽半月天，琅華千點照寒煙。蕊香亦似浮金靨，", "無由擿向牙箱裏，飛上方諸贈列仙。"]'),
('yuding-45','華亭鶴聞之舊矣，及來吳中以錢半千得一隻養之，殆經歲不幸為飲啄所誤，經夕而卒，悼之不已，遂繼以詩。南陽潤卿博士、浙東德師侍御、毘陵魏不琢處士、東吳陸魯望秀才及厚於予者悉寄之，請垂見和','皮日休','唐','御定全唐诗','yuding','','[]','池上低摧病不行，誰教仙魄反層城。陰苔尚有前朝跡，',40,'御定全唐詩/json/614.json','["池上低摧病不行，誰教仙魄反層城。陰苔尚有前朝跡，", "不知此恨何時盡，遇著雲泉即愴情。"]'),
('yuding-46','傷開元觀顧道士','皮日休','唐','御定全唐诗','yuding','','[]','協晨宮上啟金扉，詔使先生坐蛻歸。鶴有一聲應是哭，',40,'御定全唐詩/json/614.json','["協晨宮上啟金扉，詔使先生坐蛻歸。鶴有一聲應是哭，", "腸斷雷平舊遊處，五芝無影草微微。"]'),
('yuding-47','醉中即席贈潤卿博士','皮日休','唐','御定全唐诗','yuding','','[]','適越游吳一散仙，銀瓶玉柄兩翛然。茅山頂上攜書簏，',40,'御定全唐詩/json/614.json','["適越游吳一散仙，銀瓶玉柄兩翛然。茅山頂上攜書簏，", "謝安四十餘方起，猶自高閑得數年。"]'),
('yuding-48','偶留羊振文先輩及一二文友小飲日休以眼病初平不敢飲酒遣侍密歡因成四韻','皮日休','唐','御定全唐诗','yuding','','[]','謝莊初起恰花晴，強侍紅筵不避觥。久斷杯盂華蓋喜，',40,'御定全唐詩/json/614.json','["謝莊初起恰花晴，強侍紅筵不避觥。久斷杯盂華蓋喜，", "猶有僧虔多蜜炬，不辭相伴到天明。"]'),
('yuding-49','奉送浙東德師侍禦罷府西歸','皮日休','唐','御定全唐诗','yuding','','[]','建安才子太微仙，暫上金台許二年。形影欲歸溫室樹，',40,'御定全唐詩/json/614.json','["建安才子太微仙，暫上金台許二年。形影欲歸溫室樹，", "從此受恩知有處，免為傖鬼恨吳天。"]'),
('yuding-50','送羊振文先輩往桂陽歸覲','皮日休','唐','御定全唐诗','yuding','','[]','桂陽新命下彤墀，彩服行當欲雪時。登第已聞傳禰賦，',40,'御定全唐詩/json/614.json','["桂陽新命下彤墀，彩服行當欲雪時。登第已聞傳禰賦，", "無限湘中悼騷恨，憑君此去謝江蘺。"]'),
('yuding-51','褚家林亭','皮日休','唐','御定全唐诗','yuding','','[]','廣亭遙對舊娃宮，竹島蘿溪委曲通。茂苑樓臺低檻外，',40,'御定全唐詩/json/614.json','["廣亭遙對舊娃宮，竹島蘿溪委曲通。茂苑樓臺低檻外，", "爭得共君來此住，便披鶴氅對清風。"]'),
('yuding-52','送圓載上人歸日本國','皮日休','唐','御定全唐诗','yuding','','[]','講殿談餘著賜衣，椰帆卻返舊禪扉。貝多紙上經文動，',40,'御定全唐詩/json/614.json','["講殿談餘著賜衣，椰帆卻返舊禪扉。貝多紙上經文動，", "家山到日將何入，白象新秋十二圍。"]'),
('yuding-53','重送','皮日休','唐','御定全唐诗','yuding','','[]','雲濤萬里最東頭，射馬台深玉署秋。無限屬城為裸國，',40,'御定全唐詩/json/614.json','["雲濤萬里最東頭，射馬台深玉署秋。無限屬城為裸國，", "不奈此時貧且病，乘桴直欲伴師遊。"]'),
('yuding-54','潤卿遺青z3飯兼之一絕，聊用答謝','皮日休','唐','御定全唐诗','yuding','','[]','傳得三元z3飯名，大宛聞說有仙卿。分泉過屋舂青稻，',41,'御定全唐詩/json/614.json','["傳得三元z3飯名，大宛聞說有仙卿。分泉過屋舂青稻，", "草堂空坐無饑色，時把金津漱一聲。"]'),
('yuding-55','鴛鴦二首','皮日休','唐','御定全唐诗','yuding','','[]','雙絲絹上為新樣，連理枝頭是故園。翠浪萬回同過影，',80,'御定全唐詩/json/614.json','["雙絲絹上為新樣，連理枝頭是故園。翠浪萬回同過影，", "應念孤飛爭別宿，蘆花蕭瑟雨黃昏。", "鈿鎞雕鏤費深功，舞妓衣邊繡莫窮。無日不來湘渚上，", "應笑豪家鸚鵡伴，年年徒被鎖金籠。"]'),
('yuding-0','傷小女','皮日休','唐','御定全唐诗','yuding','','[]','一歲猶未滿，九泉何太深。唯餘卷書草，相對共傷心。',24,'御定全唐詩/json/615.json','["一歲猶未滿，九泉何太深。唯餘卷書草，相對共傷心。"]'),
('yuding-1','秋江曉望','皮日休','唐','御定全唐诗','yuding','','[]','萬頃湖天碧，一星飛鷺白。此時放懷望，不厭為浮客。',24,'御定全唐詩/json/615.json','["萬頃湖天碧，一星飛鷺白。此時放懷望，不厭為浮客。"]'),
('yuding-2','閑夜酒醒','皮日休','唐','御定全唐诗','yuding','','[]','醒來山月高，孤枕群書裏。酒渴漫思茶，山童呼不起。',24,'御定全唐詩/json/615.json','["醒來山月高，孤枕群書裏。酒渴漫思茶，山童呼不起。"]'),
('yuding-3','和魯望風人詩三首','皮日休','唐','御定全唐诗','yuding','','[]','刻石書離恨，因成別後悲。莫言春繭薄，猶有萬重思。',72,'御定全唐詩/json/615.json','["刻石書離恨，因成別後悲。莫言春繭薄，猶有萬重思。", "鏤出容刀飾，親逢巧笑難。日中騷客佩，爭奈即闌幹。", "江上秋聲起，從來浪得名。逆風猶掛席，若不會凡情。"]'),
('yuding-4','古函關','皮日休','唐','御定全唐诗','yuding','','[]','破落古關城，猶能扼帝京。今朝行客過，不待曉雞鳴。',24,'御定全唐詩/json/615.json','["破落古關城，猶能扼帝京。今朝行客過，不待曉雞鳴。"]'),
('yuding-5','聰明泉','皮日休','唐','御定全唐诗','yuding','','[]','一勺如瓊液，將愚擬望賢。欲知心不變，還似飲貪泉。',24,'御定全唐詩/json/615.json','["一勺如瓊液，將愚擬望賢。欲知心不變，還似飲貪泉。"]'),
('yuding-6','史處士','皮日休','唐','御定全唐诗','yuding','','[]','山期須早赴，世累莫遲留。忽遇狂風起，閒心不自由。',24,'御定全唐詩/json/615.json','["山期須早赴，世累莫遲留。忽遇狂風起，閒心不自由。"]'),
('yuding-7','芳草渡','皮日休','唐','御定全唐诗','yuding','','[]','溪南越鄉音，古柳渡江深。日晚無來客，閑船系綠陰。',24,'御定全唐詩/json/615.json','["溪南越鄉音，古柳渡江深。日晚無來客，閑船系綠陰。"]'),
('yuding-8','古宮詞三首','皮日休','唐','御定全唐诗','yuding','','[]','樓殿倚明月，參差如亂峰。宮花半夜發，不待景陽鐘。',72,'御定全唐詩/json/615.json','["樓殿倚明月，參差如亂峰。宮花半夜發，不待景陽鐘。", "閑騎小步馬，獨繞萬年枝。盡日看花足，君王自不知。", "玉枕寐不足，宮花空觸簷。梁間燕不睡，應怪夜明簾。"]'),
('yuding-9','春日陪崔諫議櫻桃園宴','皮日休','唐','御定全唐诗','yuding','','[]','萬樹香飄水麝風，蠟熏花雪盡成紅。',32,'御定全唐詩/json/615.json','["萬樹香飄水麝風，蠟熏花雪盡成紅。", "夜深歡態狀不得，醉客圖開明月中。"]'),
('yuding-10','松江早春','皮日休','唐','御定全唐诗','yuding','','[]','松陵清淨雪消初，見底新安恐未如。',32,'御定全唐詩/json/615.json','["松陵清淨雪消初，見底新安恐未如。", "穩憑船舷無一事，分明數得鱠殘魚。"]'),
('yuding-11','女墳湖','皮日休','唐','御定全唐诗','yuding','','[]','萬貴千奢已寂寥，可憐幽憤為誰嬌。',32,'御定全唐詩/json/615.json','["萬貴千奢已寂寥，可憐幽憤為誰嬌。", "須知韓重相思骨，直在芙蓉向下消。"]'),
('yuding-12','泰伯廟','皮日休','唐','御定全唐诗','yuding','','[]','一廟爭祠兩讓君，幾千年後轉清芬。',32,'御定全唐詩/json/615.json','["一廟爭祠兩讓君，幾千年後轉清芬。", "當時盡解稱高義，誰敢教他莽卓聞。"]'),
('yuding-13','宿木蘭院','皮日休','唐','御定全唐诗','yuding','','[]','木蘭院裏雙棲鶴，長被金鉦聒不眠。',32,'御定全唐詩/json/615.json','["木蘭院裏雙棲鶴，長被金鉦聒不眠。", "今夜宿來還似爾，到明無計夢雲泉。"]'),
('yuding-14','重題薔薇','皮日休','唐','御定全唐诗','yuding','','[]','濃似猩猩初染素，輕如燕燕欲淩空。',32,'御定全唐詩/json/615.json','["濃似猩猩初染素，輕如燕燕欲淩空。", "可憐細麗難勝日，照得深紅作淺紅。"]'),
('yuding-15','春夕酒醒','皮日休','唐','御定全唐诗','yuding','','[]','四弦才罷醉蠻奴，醽醁餘香在翠爐。',32,'御定全唐詩/json/615.json','["四弦才罷醉蠻奴，醽醁餘香在翠爐。", "夜半醒來紅蠟短，一枝寒淚作珊瑚。"]'),
('yuding-16','青門閑泛','皮日休','唐','御定全唐诗','yuding','','[]','青翰虛徐夏思清，愁煙漠漠荇花平。',32,'御定全唐詩/json/615.json','["青翰虛徐夏思清，愁煙漠漠荇花平。", "醉來欲把田田葉，盡裹當時醒酒鯖。"]'),
('yuding-17','木蘭後池三詠：重台蓮花','皮日休','唐','御定全唐诗','yuding','','[]','欹紅婑媠力難任，每葉頭邊半米金。',32,'御定全唐詩/json/615.json','["欹紅婑媠力難任，每葉頭邊半米金。", "可得教他水妃見，兩重元是一重心。"]'),
('yuding-18','木蘭後池三詠：浮萍','皮日休','唐','御定全唐诗','yuding','','[]','嫩似金脂颺似煙，多情渾欲擁紅蓮。',32,'御定全唐詩/json/615.json','["嫩似金脂颺似煙，多情渾欲擁紅蓮。", "明朝擬附南風信，寄與湘妃作翠鈿。"]'),
('yuding-19','木蘭後池三詠：白蓮','皮日休','唐','御定全唐诗','yuding','','[]','但恐醍醐難並潔，只應薝卜可齊香。',32,'御定全唐詩/json/615.json','["但恐醍醐難並潔，只應薝卜可齊香。", "半垂金粉知何似，靜婉臨溪照額黃。"]'),
('yuding-20','重題後池','皮日休','唐','御定全唐诗','yuding','','[]','細雨闌珊眠鷺覺，鈿波悠漾並鴛嬌。',32,'御定全唐詩/json/615.json','["細雨闌珊眠鷺覺，鈿波悠漾並鴛嬌。", "適來會得荊王意，只為蓮莖重細腰。"]'),
('yuding-21','庭中初植松桂，魯望偶題，奉和次韻','皮日休','唐','御定全唐诗','yuding','','[]','毿毿綠發垂輕露，獵獵丹華動細風。',32,'御定全唐詩/json/615.json','["毿毿綠發垂輕露，獵獵丹華動細風。", "恰似青童君欲會，儼然相向立庭中。"]'),
('yuding-22','魯望戲題書印囊奉和次韻','皮日休','唐','御定全唐诗','yuding','','[]','金篆方圓一寸餘，可憐銀艾未思渠。',32,'御定全唐詩/json/615.json','["金篆方圓一寸餘，可憐銀艾未思渠。", "不知夫子將心印，印破人間萬卷書。"]'),
('yuding-23','館娃宮懷古五絕','皮日休','唐','御定全唐诗','yuding','','[]','綺合飄香下太湖，亂兵侵曉上姑蘇。',160,'御定全唐詩/json/615.json','["綺合飄香下太湖，亂兵侵曉上姑蘇。", "越王大有堪羞處，只把西施賺得吳。", "鄭妲無言下玉墀，夜來飛箭滿罘罳。越王定指高臺笑，卻見當時金鏤楣。", "半夜娃宮作戰場，血腥猶雜宴時香。", "西施不及燒殘蠟，猶為君王泣數行。", "素襪雖遮未掩羞，越兵猶怕伍員頭。", "吳王恨魄今如在，只合西施瀨上游。", "響屟廊中金玉步，采蘋山上綺羅身。", "不知水葬今何處，溪月彎彎欲效顰。"]'),
('yuding-24','虎丘寺西小溪閑泛三絕','皮日休','唐','御定全唐诗','yuding','','[]','鼓子花明白石岸，桃枝竹覆翠嵐溪。',96,'御定全唐詩/json/615.json','["鼓子花明白石岸，桃枝竹覆翠嵐溪。", "分明似對天臺洞，應厭頑仙不肯迷。", "絕壑只憐白羽傲，窮溪唯覺錦鱗癡。", "更深尚有通樵處，或是秦人未可知。", "高下不驚紅翡翠，淺深還礙白薔薇。", "船頭系個松根上，欲待逢仙不擬歸。"]'),
('yuding-25','天竺寺八月十五日夜桂子','皮日休','唐','御定全唐诗','yuding','','[]','玉顆珊珊下月輪，殿前拾得露華新。',32,'御定全唐詩/json/615.json','["玉顆珊珊下月輪，殿前拾得露華新。", "至今不會天中事，應是嫦娥擲與人。"]'),
('yuding-26','釣侶二章','皮日休','唐','御定全唐诗','yuding','','[]','趁眠無事避風濤，一鬥霜鱗換濁醪。',64,'御定全唐詩/json/615.json','["趁眠無事避風濤，一鬥霜鱗換濁醪。", "驚怪兒童呼不得，盡沖煙雨漉車螯。", "嚴陵灘勢似雲崩，釣具歸來放石層。", "煙浪濺篷寒不睡，更將枯蚌點漁燈。"]'),
('yuding-27','寄同年韋校書','皮日休','唐','御定全唐诗','yuding','','[]','二年疏放飽江潭，水物山容盡足耽。',32,'御定全唐詩/json/615.json','["二年疏放飽江潭，水物山容盡足耽。", "唯有故人憐未替，欲封幹鱠寄終南。"]'),
('yuding-28','初冬偶作','皮日休','唐','御定全唐诗','yuding','','[]','豹皮茵下百餘錢，劉墮閑沽盡醉眠。',32,'御定全唐詩/json/615.json','["豹皮茵下百餘錢，劉墮閑沽盡醉眠。", "酒病校來無一事，鶴亡松老似經年。"]'),
('yuding-29','醉中寄魯望一壺並一絕','皮日休','唐','御定全唐诗','yuding','','[]','門巷寥寥空紫苔，先生應渴解酲杯。',32,'御定全唐詩/json/615.json','["門巷寥寥空紫苔，先生應渴解酲杯。", "醉中不得親相倚，故遣青州從事來。"]'),
('yuding-30','更次來韻寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','蕭蕭紅葉擲蒼苔，玄晏先生欠一杯。',32,'御定全唐詩/json/615.json','["蕭蕭紅葉擲蒼苔，玄晏先生欠一杯。", "從此問君還酒債，顏延之送幾錢來。"]'),
('yuding-31','重玄寺雙矮檜','皮日休','唐','御定全唐诗','yuding','','[]','撲地枝回是翠鈿，碧絲籠細不成煙。',32,'御定全唐詩/json/615.json','["撲地枝回是翠鈿，碧絲籠細不成煙。", "應如天竺難陀寺，一對狻猊相枕眠。"]'),
('yuding-32','奉酬魯望醉中戲贈','皮日休','唐','御定全唐诗','yuding','','[]','秦吳風俗昔難同，唯有才情事事通。',32,'御定全唐詩/json/615.json','["秦吳風俗昔難同，唯有才情事事通。", "剛戀水雲歸不得，前身應是太湖公。"]'),
('yuding-33','皋橋','皮日休','唐','御定全唐诗','yuding','','[]','皋橋依舊綠楊中，閭裏猶生隱士風。',32,'御定全唐詩/json/615.json','["皋橋依舊綠楊中，閭裏猶生隱士風。", "唯我到來居上館，不知何道勝梁鴻。"]'),
('yuding-34','軍事院霜菊盛開，因書一絕寄上諫議','皮日休','唐','御定全唐诗','yuding','','[]','金華千點曉霜凝，獨對壺觴又不能。',32,'御定全唐詩/json/615.json','["金華千點曉霜凝，獨對壺觴又不能。", "已過重陽三十日，至今猶自待王弘。"]'),
('yuding-35','悼鶴','皮日休','唐','御定全唐诗','yuding','','[]','莫怪朝來淚滿衣，墜毛猶傍水花飛。',32,'御定全唐詩/json/615.json','["莫怪朝來淚滿衣，墜毛猶傍水花飛。", "遼東舊事今千古，卻向人間葬令威。"]'),
('yuding-36','醉中先起李縠戲贈走筆奉酬','皮日休','唐','御定全唐诗','yuding','','[]','麝煙苒苒生銀兔，蠟淚漣漣滴繡閨。',32,'御定全唐詩/json/615.json','["麝煙苒苒生銀兔，蠟淚漣漣滴繡閨。", "舞袖莫欺先醉去，醒來還解驗金泥。"]'),
('yuding-37','奉和魯望招潤卿博士辭以道侶將至之作','皮日休','唐','御定全唐诗','yuding','','[]','癭木樽前地胏圖，為君偏輟俗功夫。',32,'御定全唐詩/json/615.json','["癭木樽前地胏圖，為君偏輟俗功夫。", "靈真散盡光來此，莫戀安妃在後無。"]'),
('yuding-38','奉和再招','皮日休','唐','御定全唐诗','yuding','','[]','飆禦已應歸杳眇，博山猶自對氛氳。',32,'御定全唐詩/json/615.json','["飆禦已應歸杳眇，博山猶自對氛氳。", "不知入夜能來否，紅蠟先教刻五分。"]'),
('yuding-39','酒病偶作','皮日休','唐','御定全唐诗','yuding','','[]','郁林步障晝遮明，一炷濃香養病酲。',32,'御定全唐詩/json/615.json','["郁林步障晝遮明，一炷濃香養病酲。", "何事晚來還欲飲，隔牆聞賣蛤蜊聲。"]'),
('yuding-40','潤卿魯望寒夜見訪，各惜其志，遂成一絕','皮日休','唐','御定全唐诗','yuding','','[]','世外為交不是親，醉吟俱岸白綸巾。',32,'御定全唐詩/json/615.json','["世外為交不是親，醉吟俱岸白綸巾。", "清風月白更三點，未放華陽鶴上人。"]'),
('yuding-41','奉和魯望玩金鸂鶒戲贈','皮日休','唐','御定全唐诗','yuding','','[]','鏤羽雕毛迥出群，溫黁飄出麝臍熏。',32,'御定全唐詩/json/615.json','["鏤羽雕毛迥出群，溫黁飄出麝臍熏。", "夜來曾吐紅茵畔，猶似溪邊睡不聞。"]'),
('yuding-42','友人許惠酒以詩征之','皮日休','唐','御定全唐诗','yuding','','[]','野客蕭然訪我家，霜威白菊兩三花。',32,'御定全唐詩/json/615.json','["野客蕭然訪我家，霜威白菊兩三花。", "子山病起無餘事，只望蒲台酒一車。"]'),
('yuding-43','寒夜文宴潤卿有期不至','皮日休','唐','御定全唐诗','yuding','','[]','草堂虛灑待高真，不意清齋避世塵。',32,'御定全唐詩/json/615.json','["草堂虛灑待高真，不意清齋避世塵。", "料得焚香無別事，存心應降月夫人。"]'),
('yuding-44','汴河懷古二首','皮日休','唐','御定全唐诗','yuding','','[]','萬艘龍舸綠絲間，載到揚州盡不還。',64,'御定全唐詩/json/615.json','["萬艘龍舸綠絲間，載到揚州盡不還。", "應是天教開汴水，一千餘裏地無山。", "盡道隋亡為此河，至今千里賴通波。", "若無水殿龍舟事，共禹論功不較多。"]'),
('yuding-45','寄題天臺國清寺齊梁體','皮日休','唐','御定全唐诗','yuding','','[]','十裏松門國清路，飯猿臺上菩提樹。',32,'御定全唐詩/json/615.json','["十裏松門國清路，飯猿臺上菩提樹。", "怪來煙雨落晴天，元是海風吹瀑布。"]'),
('yuding-46','詠蟹','皮日休','唐','御定全唐诗','yuding','','[]','未游滄海早知名，有骨還從肉上生。',32,'御定全唐詩/json/615.json','["未游滄海早知名，有骨還從肉上生。", "莫道無心畏雷電，海龍王處也橫行。"]'),
('yuding-47','金錢花','皮日休','唐','御定全唐诗','yuding','','[]','陰陽為炭地為爐，鑄出金錢不用模。',32,'御定全唐詩/json/615.json','["陰陽為炭地為爐，鑄出金錢不用模。", "莫向人間逞顏色，不知還解濟貧無。"]'),
('yuding-48','惠山聽松庵','皮日休','唐','御定全唐诗','yuding','','[]','千葉蓮花舊有香，半山金刹照方塘。',32,'御定全唐詩/json/615.json','["千葉蓮花舊有香，半山金刹照方塘。", "殿前日暮高風起，松子聲聲打石床。"]'),
('yuding-0','苦雨雜言寄魯望','皮日休','唐','御定全唐诗','yuding','','[]','吳中十日涔涔雨，歊蒸庳下豪家苦。可憐臨頓陸先生，',113,'御定全唐詩/json/616.json','["吳中十日涔涔雨，歊蒸庳下豪家苦。可憐臨頓陸先生，", "eQ蠃時時上幾案，蛙黽往往跳琴書。桃花米鬥半百錢，", "知君志氣如鐵石，甌冶雖神銷不得。乃知苦雨不復侵，", "府金廩粟虛請來，憶著先生便知愧。愧多饋少真徒然，", "天公箋，方修次，且榜鳴篷來一醉。"]'),
('yuding-1','奉和魯望齊梁怨別次韻','皮日休','唐','御定全唐诗','yuding','','[]','芙蓉泣恨紅鉛落，一朵別時煙似幕。',32,'御定全唐詩/json/616.json','["芙蓉泣恨紅鉛落，一朵別時煙似幕。", "鴛鴦剛解惱離心，夜夜飛來棹邊泊。"]'),
('yuding-2','奉和魯望曉起回文','皮日休','唐','御定全唐诗','yuding','','[]','孤煙曉起初原曲，碎樹微分半浪中。湖後釣筒移夜雨，',40,'御定全唐詩/json/616.json','["孤煙曉起初原曲，碎樹微分半浪中。湖後釣筒移夜雨，", "無事有杯持永日，共君惟好隱牆東。"]'),
('yuding-3','奉酬魯望夏日四聲四首：平聲','皮日休','唐','御定全唐诗','yuding','','[]','塘平芙蓉低，庭閑梧桐高。清煙埋陽烏，藍空含秋毫。',48,'御定全唐詩/json/616.json','["塘平芙蓉低，庭閑梧桐高。清煙埋陽烏，藍空含秋毫。", "冠傾慵移簪，杯幹將餔糟。翛然非隨時，夫君真吾曹。"]'),
('yuding-4','奉酬魯望夏日四聲四首：平上聲','皮日休','唐','御定全唐诗','yuding','','[]','溝渠通疏荷，浦嶼隱淺筱。舟閑攢輕蘋，槳動起靜鳥。',48,'御定全唐詩/json/616.json','["溝渠通疏荷，浦嶼隱淺筱。舟閑攢輕蘋，槳動起靜鳥。", "陰稀餘桑閑，縷盡晚繭小。吾徒當斯時，此道可以了。"]'),
('yuding-5','奉酬魯望夏日四聲四首：平去聲','皮日休','唐','御定全唐诗','yuding','','[]','怡神時高吟，快意乍四顧。村深啼愁鵑，浪霽醒睡鷺。',48,'御定全唐詩/json/616.json','["怡神時高吟，快意乍四顧。村深啼愁鵑，浪霽醒睡鷺。", "書疲行終朝，罩困臥至暮。籲嗟當今交，暫貴便異路。"]'),
('yuding-6','奉酬魯望夏日四聲四首：平入聲','皮日休','唐','御定全唐诗','yuding','','[]','先生何違時，一室習寂曆。松聲將飄堂，嶽色欲壓席。',48,'御定全唐詩/json/616.json','["先生何違時，一室習寂曆。松聲將飄堂，嶽色欲壓席。", "彈琴奔玄雲，劚藥折白石。如教題君詩，若得劄玉冊。"]'),
('yuding-7','苦雨中又作四聲詩寄魯望：平聲','皮日休','唐','御定全唐诗','yuding','','[]','涔涔將經旬，昏昏空迷天。鸕鷀成群嬉，芙蓉相偎眠。',48,'御定全唐詩/json/616.json','["涔涔將經旬，昏昏空迷天。鸕鷀成群嬉，芙蓉相偎眠。", "魚通蓑衣城，帆過菱花田。秋收吾無望，悲之真徒然。"]'),
('yuding-8','苦雨中又作四聲詩寄魯望：平上聲','皮日休','唐','御定全唐诗','yuding','','[]','河平州橋危，壘晚水鳥上。沖崖搜松根，點沼寫芡響。',48,'御定全唐詩/json/616.json','["河平州橋危，壘晚水鳥上。沖崖搜松根，點沼寫芡響。", "舟輕通縈紆，棧墮阻指掌。攜橈將尋君，渚滿坐可往。"]'),
('yuding-9','苦雨中又作四聲詩寄魯望：平去聲','皮日休','唐','御定全唐诗','yuding','','[]','狂霖昏悲吟，瘦桂對病臥。簷虛能彯斜，舍蠹易漏破。',48,'御定全唐詩/json/616.json','["狂霖昏悲吟，瘦桂對病臥。簷虛能彯斜，舍蠹易漏破。", "宵愁將琴攻，晝悶用睡過。堆書仍傾觴，富貴未換個。"]'),
('yuding-10','苦雨中又作四聲詩寄魯望：平入聲','皮日休','唐','御定全唐诗','yuding','','[]','羈棲愁霖中，缺宅屋木惡。荷傾還驚魚，竹滴複觸鶴。',48,'御定全唐詩/json/616.json','["羈棲愁霖中，缺宅屋木惡。荷傾還驚魚，竹滴複觸鶴。", "閑僧千聲琴，宿客一笈藥。悠然思夫君，忽憶蠟屐著。"]'),
('yuding-11','奉和魯望疊韻雙聲二首：疊韻山中吟','皮日休','唐','御定全唐诗','yuding','','[]','穿煙泉潺湲，觸竹犢觳觫。荒篁香牆匡，熟鹿伏屋曲。',24,'御定全唐詩/json/616.json','["穿煙泉潺湲，觸竹犢觳觫。荒篁香牆匡，熟鹿伏屋曲。"]'),
('yuding-12','奉和魯望疊韻雙聲二首：雙聲溪上思','皮日休','唐','御定全唐诗','yuding','','[]','疏杉低通灘，冷鷺立亂浪。草彩欲夷猶，雲容空淡蕩。',24,'御定全唐詩/json/616.json','["疏杉低通灘，冷鷺立亂浪。草彩欲夷猶，雲容空淡蕩。"]'),
('yuding-13','奉和魯望疊韻吳宮詞二首','皮日休','唐','御定全唐诗','yuding','','[]','侵深尋嶔岑，勢厲衛睥睨。荒王將鄉亡，細麗蔽袂逝。',48,'御定全唐詩/json/616.json','["侵深尋嶔岑，勢厲衛睥睨。荒王將鄉亡，細麗蔽袂逝。", "枍栺替制曳，康莊傷荒涼。主虜部伍苦，嬙亡房廊香。"]'),
('yuding-14','奉和魯望閒居雜題五首：晚秋吟','皮日休','唐','御定全唐诗','yuding','','[]','東皋煙雨歸耕日，免去玄冠手刈禾。',32,'御定全唐詩/json/616.json','["東皋煙雨歸耕日，免去玄冠手刈禾。", "火滿酒爐詩在口，今人無計奈儂何。"]'),
('yuding-15','奉和魯望閒居雜題五首：好詩景','皮日休','唐','御定全唐诗','yuding','','[]','青盤香露傾荷女，子墨風流更不言。',32,'御定全唐詩/json/616.json','["青盤香露傾荷女，子墨風流更不言。", "寺寺雲蘿堪度日，京塵到死撲侯門。"]'),
('yuding-16','奉和魯望閒居雜題五首：醒聞檜','皮日休','唐','御定全唐诗','yuding','','[]','解洗餘酲晨半酉，星星仙吹起雲門。',32,'御定全唐詩/json/616.json','["解洗餘酲晨半酉，星星仙吹起雲門。", "耳根無厭聽佳木，會盡山中寂靜源。"]'),
('yuding-17','奉和魯望閒居雜題五首：寺鐘暝','皮日休','唐','御定全唐诗','yuding','','[]','百緣鬥藪無塵土，寸地章煌欲布金。',32,'御定全唐詩/json/616.json','["百緣鬥藪無塵土，寸地章煌欲布金。", "重擊蒲牢唅山日，冥冥煙樹睹棲禽。"]'),
('yuding-18','奉和魯望閒居雜題五首：砌思步','皮日休','唐','御定全唐诗','yuding','','[]','襹襹古薜繃危石，切切陰螿應晚田。',32,'御定全唐詩/json/616.json','["襹襹古薜繃危石，切切陰螿應晚田。", "心事萬端何處止，少夷峰下舊雲泉。"]'),
('yuding-19','奉和魯望藥名離合夏月即事三首','皮日休','唐','御定全唐诗','yuding','','[]','季春人病拋芳杜，仲夏溪波繞壞垣。',96,'御定全唐詩/json/616.json','["季春人病拋芳杜，仲夏溪波繞壞垣。", "衣典濁醪身倚桂，心中無事到雲昏。", "數曲急溪沖細竹，葉舟來往盡能通。", "草香石冷無辭遠，志在天臺一遇中。", "桂葉似茸含露紫，葛花如綬蘸溪黃。", "連雲更入幽深地，骨錄閑攜相獵郎。"]'),
('yuding-20','懷錫山藥名離合二首','皮日休','唐','御定全唐诗','yuding','','[]','暗竇養泉容決決，明園護桂放亭亭。',64,'御定全唐詩/json/616.json','["暗竇養泉容決決，明園護桂放亭亭。", "曆山居處當天半，夏裏松風盡足聽。", "曉景半和山氣白，薇香清淨雜纖雲。", "實頭自是眠平石，腦側空林看虎群。"]'),
('yuding-21','懷鹿門縣名離合二首','皮日休','唐','御定全唐诗','yuding','','[]','山瘦更培秋後桂，溪澄閑數晚來魚。',64,'御定全唐詩/json/616.json','["山瘦更培秋後桂，溪澄閑數晚來魚。", "台前過雁盈千百，泉石無情不寄書。", "十裏松蘿陰亂石，門前幽事雨來新。", "野霜濃處憐殘菊，潭上花開不見人。"]'),
('yuding-22','奉和魯望寒日古人名一絕','皮日休','唐','御定全唐诗','yuding','','[]','北顧歡游悲沈宋，南徐陵寢歎齊梁。',32,'御定全唐詩/json/616.json','["北顧歡游悲沈宋，南徐陵寢歎齊梁。", "水邊韶景無窮柳，寒被江淹一半黃。"]'),
('yuding-23','胥口即事六言二首','皮日休','唐','御定全唐诗','yuding','','[]','波光杳杳不極，霽景澹澹初斜。黑蛺蝶粘蓮蕊，',70,'御定全唐詩/json/616.json','["波光杳杳不極，霽景澹澹初斜。黑蛺蝶粘蓮蕊，", "會把酒船偎荻，共君作個生涯。", "拂釣清風細麗，飄蓑暑雨霏微。湖雲欲散未散，", "斯人到死還樂，誰道剛須用機？"]'),
('yuding-24','夜會問答十','皮日休','唐','御定全唐诗','yuding','','[]','寒夜清，簾外迢迢星斗明。況有蕭閑洞中客，',200,'御定全唐詩/json/616.json','["寒夜清，簾外迢迢星斗明。況有蕭閑洞中客，", "癭木杯，杉贅楠瘤刳得來。莫怪家人畔邊笑，", "落霞琴，寥寥山水揚清音。玉皇仙馭碧雲遠，", "蓮花燭，亭亭嫩蕊生紅玉。不知含淚怨何人，", "金火障，紅獸飛來射羅幌。夜來斜展掩深爐，", "憶山月，前溪後溪清複絕。看看又及桂花時，", "錦鯨薦，碧香紅膩承君宴。幾度閑眠卻覺來，", "懷溪雲，漠漠閑籠鷗鷺群。有時日暮碧將合，", "霜中笛，落梅一曲瑤華滴。不知青女是何人，", "月下橋，風外拂殘衰柳條。倚欄杆處獨自立，"]'),
('yuding-0','讀襄陽耆舊傳，因作詩五百言寄皮襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','漢皋古來雄，山水天下秀。高當軫翼分，化作英髦囿。',576,'御定全唐詩/json/617.json','["漢皋古來雄，山水天下秀。高當軫翼分，化作英髦囿。", "暴秦之前人，灰滅不可究。自從宋生賢，特立冠耆舊。", "離騷既日月，九辯即列宿。卓哉悲秋辭，合在風雅右。", "龐公樂幽隱，辟聘無所就。只愛鹿門泉，泠泠倚岩漱。", "孔明臥龍者，潛伏躬耕耨。忽遭玄德雲，遂起鱗角鬥。", "三胡節皆峻，二習名亦茂。其餘文武家，相望如斥堠。", "緬思齊梁降，寂寞寡清胄。凝融為漪瀾，複結作瑩琇。", "不知粹和氣，有得方大受。將生皮夫子，上帝可其奏。", "並包數公才，用以殿厥後。嘗聞兒童歲，嬉戲陳俎豆。", "積漸開詞源，一派分萬溜。先崇丘旦室，大懼隳結構。", "次補荀孟垣，所貴亡罅漏。仰瞻三皇道，蟣虱在宇宙。", "卻視五霸圖，股掌弄孩幼。或能醢髖髀，或與翼雛鷇。", "或喜掉直舌，或樂斬邪脰。或耨鉏翳薈，或整理錯謬。", "或如百千騎，合遝原野狩。又如曉江平，風死波不皺。", "幽埋力須掘，遺落貲必購。乃于文學中，十倍猗頓富。", "囊乏向咸鎬，馬重遲步驟。專場射策時，縛虎當羿彀。", "歸來把通籍，且作高堂壽。未足逞戈矛，誰雲被文繡。", "從知偶東下，帆影拂吳岫。物象悉摧藏，精靈畏雕鏤。", "伊余抱沈疾，憔悴守圭竇。方推洪範疇，更念大玄首。", "陳詩采風俗，學古窮篆籀。朝朝貰薪米，往往逢責詬。", "既被鄰里輕，亦為妻子陋。持冠適甌越，敢怨不得售。", "窘若曬沙魚，悲如哭霜狖。唯君枉車轍，以逐海上臭。", "披襟兩相對，半夜忽白晝。執熱濯清風，忘憂飲醇酎。", "驅為文翰侶，駑皂參驥廄。有時諧宮商，自喜真邂逅。"]'),
('yuding-1','襲美先輩以龜蒙所獻五百言，既蒙見和復示榮唱至於千字，提獎之重，蔑有稱實，再抒鄙懷用伸酬謝','陸龜蒙','唐','御定全唐诗','yuding','','[]','洪範分九疇，轉成天下規。河圖孕八卦，煥作玄中奇。',577,'御定全唐詩/json/617.json','["洪範分九疇，轉成天下規。河圖孕八卦，煥作玄中奇。", "先開否臧源，次築經緯基。粵若魯聖出，正當周德衰。", "越疆必載質，曆國將扶危。諸侯恣崛強，王室方陵遲。", "歌鳳時不偶，獲麟心益悲。始嗟吾道窮，竟使空言垂。", "首贊五十易，又刪三百詩。遂令篇籍光，可並日月姿。", "向非筆削功，未必無瑕疵。迨至夫子沒，微言散如枝。", "所宗既不同，所得亦異宜。名法在深刻，虛玄至希夷。", "自從戰伐來，一派縱橫馳。寒穀生豔木，沸潭結流澌。", "驚奔失壯士，好惡隨纖兒。嬴氏並六合，勢尊丞相斯。", "加於挾書律，盡取坑焚之。南勒會稽頌，北恢胡亥阺。", "猶懷遍巡狩，不暇親維持。及漢文景後，鴻生方dr摫。", "簸揚堯舜風，反作三代吹。飄颻四百載，左右為藩籬。", "鄴下曹父子，獵賢甚熊羆。發論若霞駁，裁詩如錦摛。", "徐王應劉輩，頭角咸相衰。或有妙絕賞，或為獨步推。", "或許潤色美，或嫌詆訶癡。倏以中利病，且非混醇醨。", "雅當乎魏文，麗矣哉陳思。不肯少選妄，恐貽後世嗤。", "吾祖仗才力，革車蒙虎皮。手持一白旄，直向文場麾。", "輕若脫鉗釱，豁如抽扊扅。精鋼不足利，騕褭何勞追。", "大可罩山嶽，微堪析毫釐。十體免負贅，百家咸起痿。", "爭入鬼神奧，不容天地私。一篇邁華藻，萬古無孑遺。", "刻鵠尚未已，雕龍奮而為。劉生吐英辯，上下窮高卑。", "下臻宋與齊，上指軒從羲。豈但標八索，殆將包兩儀。", "人謠洞野老，騷怨明湘累。立本以致詰，驅宏來抵隵。", "清如朔雪嚴，緩若春煙羸。或欲開戶牖，或將飾纓緌。"]'),
('yuding-2','奉酬襲美先輩吳中苦雨一百韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','微生參最靈，天與意緒拙。人皆機巧求，百徑無一達。',576,'御定全唐詩/json/617.json','["微生參最靈，天與意緒拙。人皆機巧求，百徑無一達。", "家為唐臣來，奕世唯稷卨。只垂青白風，凜凜自貽厥。", "猶殘賜書在，編簡苦斷絕。其間忠孝字，萬古光不滅。", "孱孫誠瞢昧，有志常搰搰。敢雲嗣良弓，但欲終守節。", "喧嘩不入耳，讒佞不掛舌。仰詠堯舜言，俯遵周孔轍。", "所貪既仁義，豈暇理生活。縱有舊田園，拋來亦蕪沒。", "因之成否塞，十載真契闊。凍骭一襜褕，饑腸少糠籺。", "甘心付天壤，委分任回斡。笠澤臥孤雲，桐江釣明月。", "盈筐盛芡芰，滿釜煮鱸鱖。酒幟風外俯，茶槍露中擷。", "歌謠非大雅，捃摭為小說。上可補熏莖，傍堪跐芽蘖。", "方當賣罾罩，盡以易紙劄。蹤跡尚吳門，夢魂先魏闕。", "尋聞天子詔，赫怒誅叛卒。宵旰憫烝黎，謨明問征伐。", "王師雖繼下，賊壘未即拔。此時淮海波，半是生人血。", "霜戈驅少壯，敗屋棄羸耋。踐蹋比塵埃，焚燒同稿秸。", "吾皇自神聖，執事皆間傑。射策亦何為，春卿遂聊輟。", "伊余將貢技，未有恥可刷。卻問漁樵津，重耕煙雨墢。", "諸侯急兵食，冗剩方翦截。不可抱詞章，巡門事幹謁。", "歸來闔蓬楗，壁立空豎褐。暖手抱孤煙，披書向殘雪。", "幽憂和憤懣，忽愁自驚蹶。文兮乏寸毫，武也無尺鐵。", "平生所韜蓄，到死不開豁。念此令人悲，翕然生內熱。", "加之被皸瘃，況複久藜糲。既為霜露侵，一臥增百疾。", "筋骸將束縛，腠理如棰撻。初謂抵狂貙，又如當毒蠍。", "江南多事鬼，巫覡連甌粵。可口是妖訛，恣情專賞罰。", "良醫只備位，藥肆或虛設。而我正萎痿，安能致訶咄。"]'),
('yuding-3','奉酬襲美先輩初夏見寄次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','積雨晦皋圃，門前煙水準。蘋蘅增遙吹，枕席分餘清。',277,'御定全唐詩/json/617.json','["積雨晦皋圃，門前煙水準。蘋蘅增遙吹，枕席分餘清。", "村旆詫酒美，賒來滿鋞程。未必減宣子，何羨謝公榮。", "借宅去人遠，敗牆連古城。愁鴟占枯枿，野鼠趨前楹。", "昨日雲破損，晚林先覺晴。幽篁倚微照，碧粉含疏莖。", "蠹簡有遺字，gs琴無泛聲。蠶寒繭尚薄，燕喜雛新成。", "覽物正搖思，得君初夏行。誠明複散誕，化匠安能爭。", "海浪刷三島，天風吹六英。洪崖領玉節，坐使虛音生。", "吾祖傲洛客，因言幾為傖。末裔實漁者，敢懷幹墨卿。", "唯思釣璜老，遂得持竿情。何須乞鵝炙，豈在斟羊羹。", "畦蔬與甕醁，便可相攜迎。蟠木幾甚曲，筍皮冠且輕。", "閒心放羈靮，醉腳從欹傾。一徑有餘遠，一窗有餘明。", "秦皇苦不達，天下何足並。"]'),
('yuding-4','奉和襲美二遊詩：徐詩','陸龜蒙','唐','御定全唐诗','yuding','','[]','嘗聞四書曰，經史子集焉。苟非天祿中，此事無由全。',493,'御定全唐詩/json/617.json','["嘗聞四書曰，經史子集焉。苟非天祿中，此事無由全。", "自從秦火來，歷代逢迍邅。漢祖入關日，蕭何為政年。", "盡力取圖籍，遂持天下權。中興熹平時，教化還相宣。", "立石刻五經，置於太學前。賊卓亂王室，君臣如轉圜。", "洛陽且煨燼，載籍宜為煙。逮晉武革命，生民才息肩。", "惠懷亟寡昧，戎羯俄腥膻。已覺天地閉，競為東南遷。", "日既不暇給，墳索何由專。爾後國脆弱，人多尚虛玄。", "任學者得謗，清言者為賢。直至沈範輩，始家藏簡編。", "禦府有不足，仍令就之傳。梁元渚宮日，盡取如蚳蝝。", "兵威忽破碎，焚爇無遺篇。近者隋後主，搜羅勢駢闐。", "寶函映玉軸，彩翠明霞鮮。伊唐受命初，載史聲連延。", "砥柱不我助，驚波湧淪漣。遂令因去書，半在餘浮泉。", "貞觀購亡逸，蓬瀛漸周旋。炅然東壁光，與月爭流天。", "偉矣開元中，王道真平平。八萬五千卷，一一皆塗鉛。", "人間盛傳寫，海內奔窮研。目雲西齋書，有過東皋田。", "吾聞徐氏子，奕世皆才賢。因知遺孫謀，不在黃金錢。", "插架幾萬軸，森森若戈鋋。風吹簽牌聲，滿室鏗鏘然。", "佳哉鹿門子，好問如除t9。倏來參卿處，遂得參卿憐。", "開懷展櫥簏，唯在性所便。素業已千仞，今為峻雲巔。", "雄才舊百派，相近浮日川。君抱王佐圖，縱步淩陶甄。", "他時若報德，誰在參卿先。"]'),
('yuding-5','奉和襲美二遊詩：任詩','陸龜蒙','唐','御定全唐诗','yuding','','[]','吳之辟疆園，在昔勝概敵。前聞富修竹，後說紛怪石。',288,'御定全唐詩/json/617.json','["吳之辟疆園，在昔勝概敵。前聞富修竹，後說紛怪石。", "風煙慘無主，載祀將六百。草色與行人，誰能問遺跡。", "不知清景在，盡付任君宅。卻是五湖光，偷來傍簷隙。", "出門向城路，車馬聲躪躒。入門望亭隈，水木氣岑寂。", "犨牆繞曲岸，勢似行無極。十步一危梁，乍疑當絕壁。", "池容澹而古，樹意蒼然僻。魚驚尾半紅，鳥下衣全碧。", "斜來島嶼隱，恍若瀟湘隔。雨靜持殘絲，煙消有餘脈。", "朅來任公子，擺落名利役。雖將祿代耕，頗愛巾隨策。", "秋籠支遁鶴，夜榻戴顒客。說史足為師，譚禪差作伯。", "君多鹿門思，到此情便適。偶蔭桂堪帷，縱吟苔可席。", "顧余真任誕，雅遂中心獲。但知醉還醒，豈知玄尚白。", "甘閑在雞口，不貴封龍額。即此自怡神，何勞謝公屐。"]'),
('yuding-6','次追和清遠道士詩韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','一代先後賢，聲容劇河漢。況茲邁古士，複曆蒼崖竄。',144,'御定全唐詩/json/617.json','["一代先後賢，聲容劇河漢。況茲邁古士，複曆蒼崖竄。", "辰經幾十萬，邈與靈壽玩。海岳尚推移，都鄙固蕪漫。", "羸僧下高閣，獨鳥沒遠岸。嘯初風雨來，吟餘鐘唄亂。", "如何煉精魄，萬祀忽欲半。寧為斷臂憂，肯作秋柏散。", "吾聞酆宮內，日月自昏旦。左右修文郎，縱橫灑篇翰。", "斯人久冥漠，得不垂慨歎。庶或有神交，相從重興贊。"]'),
('yuding-7','補沈恭子詩','陸龜蒙','唐','御定全唐诗','yuding','','[]','靈質貫軒昊，遐年越商周。自然失遠裔，安得怨寡儔。',144,'御定全唐詩/json/617.json','["靈質貫軒昊，遐年越商周。自然失遠裔，安得怨寡儔。", "我亦小國胤，易名慚見優。雖非放曠懷，雅奉逍遙遊。", "攜手桂枝下，屬詞山之幽。風雨一以過，林麓颯然秋。", "落日倚石壁，天寒登古丘。荒泉已無夕，敗葉翳不流。", "亂翠缺月隱，衰紅清露愁。覽物性未逸，反為情所囚。", "異才偶絕境，佳藻窮冥搜。虛傾寂寞音，敢作雜佩酬。"]'),
('yuding-0','《讀陰符經》寄鹿門子','陸龜蒙','唐','御定全唐诗','yuding','','[]','清晨整冠坐，朗詠三百言。備識天地意，獻詞犯乾坤。',276,'御定全唐詩/json/618.json','["清晨整冠坐，朗詠三百言。備識天地意，獻詞犯乾坤。", "何事不隱德，降靈生軒轅。口銜造化斧，鑿破機關門。", "五賊忽迸逸，萬物爭崩奔。虛施神仙要，莫救華池源。", "但學戰勝術，相高甲兵屯。龍蛇競起陸，鬥血浮中原。", "成湯與周武，反復更為尊。下及秦漢得，黷弄兵亦煩。", "奸強自林據，仁弱無枝蹲。狂喉恣吞噬，逆翼爭飛翻。", "家家伺天發，不肯匡淫昏。生民墜塗炭，比屋為冤魂。", "只為讀此書，大樸難久存。微臣與軒轅，亦是萬世孫。", "未能窮意義，豈敢求瑕痕。曾亦愛兩句，可與賢達論。", "生者死之根，死者生之根。方寸了十字，萬化皆胚腪。", "身外更何事，眼前徒自喧。黃河但東注，不見歸昆侖。", "晝短苦夜永，勸君傾一尊。"]'),
('yuding-1','奉和襲美初夏遊楞伽精舍次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','吳都涵汀洲，碧液浸郡郭。微雨蕩春醉，上下一清廓。',445,'御定全唐詩/json/618.json','["吳都涵汀洲，碧液浸郡郭。微雨蕩春醉，上下一清廓。", "奇蹤欲探討，靈物先瘵瘼。飄然蘭葉舟，旋倚煙霞泊。", "吟譚亂篙艫，夢寐雜巘崿。纖情不可逃，洪筆難暫閣。", "豈知楞伽會，乃在山水箔。金仙著書日，世界名極樂。", "薝卜冠諸香，琉璃代華堊。禽言經不輟，象口川寧涸。", "萬善峻為城，巉巉扞群惡。清晨欲登造，安得無自愕。", "險穴駭坤牢，高蘿掛天笮。池容淡相向，蛟怪如可摸。", "苔蔽石髓根，蒲差水心鍔。嵐侵答摩髻，日照狻猊絡。", "仰首乍眩施，回眸更輝z8。簷端凝飛羽，磴外浮碧落。", "到回解風襟，臨幽濯雲屩。塵機性非便，靜境心所著。", "自取海鷗知，何煩屍祝酢。峰圍震澤岸，翠浪舞綃幕。", "瀲灩豈堯遭，嶘嵃非禹鑿。潛聽鐘梵處，別有松桂壑。", "靄重燈不光，泉寒網猶薄。僮能躡孤刹，鳥慣親摐鐸。", "服道身可遺，乞閒心已諾。人間亦何事，萬態相毒蠚。", "戰壘競高深，儒衣謾褒博。宣尼名位達，未必春秋作。", "管氏包霸圖，須人解其縛。伊餘采樵者，蓬藋方索寞。", "近得風雅情，聊將聖賢度。多君富遒采，識度兩清恪。", "詎寵生滅詞，肯教夷夏錯。未為堯舜用，且向煙霞托。", "我亦擺塵埃，他年附鴻鶴。"]'),
('yuding-2','奉和襲美公齋四詠次韻：小松','陸龜蒙','唐','御定全唐诗','yuding','','[]','擢秀逋客岩，遺根飛鳥徑。因求飾清閟，遂得辭危夐。',108,'御定全唐詩/json/618.json','["擢秀逋客岩，遺根飛鳥徑。因求飾清閟，遂得辭危夐。", "貞同柏有心，立若珠無脛。枝形短未怪，鬣數差難定。", "況密三天風，方遵四時柄。那興培塿歎，免答鄰里病。", "微霜靜可分，片月疏堪映。奇當虎頭筆，韻葉通明性。", "會拂陽烏胸，掄才膺帝命。"]'),
('yuding-3','奉和襲美公齋四詠次韻：小桂','陸龜蒙','唐','御定全唐诗','yuding','','[]','諷賦輕八植，擅名方一枝。才高不滿意，更自寒山移。',97,'御定全唐詩/json/618.json','["諷賦輕八植，擅名方一枝。才高不滿意，更自寒山移。", "宛宛別雲態，蒼蒼出塵姿。煙歸助華杪，雪點迎芳蕤。", "青條坐可結，白日如奔螭。諒無pk翦憂，即是蕭森時。", "洛浦雖有蔭，騷人聊自怡。終為濟川楫，豈在論高卑。"]'),
('yuding-4','奉和襲美公齋四詠次韻：新竹','陸龜蒙','唐','御定全唐诗','yuding','','[]','別塢破苔蘚，嚴城樹軒楹。恭聞稟璿璣，化質離青冥。',108,'御定全唐詩/json/618.json','["別塢破苔蘚，嚴城樹軒楹。恭聞稟璿璣，化質離青冥。", "色可定雞頸，實堪招鳳翎。立窺五嶺秀，坐對三都屏。", "晴月窈窕入，曙煙霏微生。昔者尚借宅，況來處賓庭。", "金罍縱傾倒，碧露還鮮醒。若非抱苦節，何以偶惟馨。", "徐觀稚龍出，更賦錦苞零。"]'),
('yuding-5','奉和襲美公齋四詠次韻：鶴屏','陸龜蒙','唐','御定全唐诗','yuding','','[]','時人重花屏，獨即胎化狀。叢毛練分彩，疏節筇相望。',96,'御定全唐詩/json/618.json','["時人重花屏，獨即胎化狀。叢毛練分彩，疏節筇相望。", "曾無氃氋態，頗得連軒樣。勢擬搶高尋，身猶在函丈。", "如憂雞鶩鬥，似憶煙霞向。塵世任縱橫，霜襟自閑放。", "空資明遠思，不待浮丘相。何由振玉衣，一舉棲瀛閬。"]'),
('yuding-6','奉和襲美酬前進士崔潞盛制見寄因贈至一百四十言','陸龜蒙','唐','御定全唐诗','yuding','','[]','孔聖鑄顏事，垂之千載餘。其間王道乖，化作荊榛墟。',168,'御定全唐詩/json/618.json','["孔聖鑄顏事，垂之千載餘。其間王道乖，化作荊榛墟。", "天必授賢哲，為時攻翦除。軻雄骨已朽，百代徒趑趄。", "近者韓文公，首為閑辟鋤。夫子又繼起，陰霾終廓如。", "搜得萬古遺，裁成十編書。南山盛雲雨，東序堆瓊琚。", "偶此真籍客，悠揚兩情攄。清詞忽窈窕，雅韻何虛徐。", "唱既野芳坼，酬還天籟疏。輕波掠翡翠，曉露披芙渠。", "儷曲信寡和，末流難嗣初。空持一竿餌，有意漁鯨魚。"]'),
('yuding-7','奉和襲美太湖詩二十首：初入太湖','陸龜蒙','唐','御定全唐诗','yuding','','[]','東南具區雄，天水合為一。高帆大弓滿，羿射爭箭疾。',240,'御定全唐詩/json/618.json','["東南具區雄，天水合為一。高帆大弓滿，羿射爭箭疾。", "時當暑雨後，氣象仍鬱密。乍如開雕笯，聳翅忽飛出。", "行將十洲近，坐覺八極溢。耳目駭鴻蒙，精神寒佶栗。", "坑來鬥呀豁，湧處驚嵯崒。嶮異拔龍湫，喧如破蛟室。", "斯須風妥帖，若受命平秩。微茫誠端倪，遠嶠疑格筆。", "巉巉見銅闕，左右皆輔弼。盤空儼相趨，去勢猶橫逸。", "嘗聞咸池氣，下注作清質。至今涵赤霄，尚且浴白日。", "又雲構浮玉，宛與昆閬匹。肅為靈官家，此事難致詰。", "才迎沙嶼好，指顧俄已失。山川互蔽虧，魚鳥空聱耴。", "何當授真檢，得召天吳術。一一問朝宗，方應可譚悉。"]'),
('yuding-8','奉和襲美太湖詩二十首：曉次神景宮','陸龜蒙','唐','御定全唐诗','yuding','','[]','曉帆逗碕岸，高步入神景。灑灑襟袖清，如臨蕊珠屏。',168,'御定全唐詩/json/618.json','["曉帆逗碕岸，高步入神景。灑灑襟袖清，如臨蕊珠屏。", "雖然群動息，此地常寂靜。翠鑷有寒鏘，碧花無定影。", "憑軒羽人傲，夾戶天獸猛。稽首朝元君，褰衣就虛省。", "呀空雪牙利，嗽水石齒冷。香母未垂嬰，芝田不論頃。", "遙通河漢口，近撫松桂頂。飯薦七白蔬，杯釃九光杏。", "人間附塵躅，固陋真鉗頸。肯信抃鼇傾，猶疑夏蟲永。", "玄津蕩瓊壟，紫汞啼金鼎。盡出冰霜書，期君一披省。"]'),
('yuding-9','奉和襲美太湖詩二十首：入林屋洞','陸龜蒙','唐','御定全唐诗','yuding','','[]','知名十小天，林屋當第九。題之為左神，理之以天后。',192,'御定全唐詩/json/618.json','["知名十小天，林屋當第九。題之為左神，理之以天后。", "魁堆辟邪輩，左右專備守。自非方瞳人，不敢窺洞口。", "唯君好奇士，複嘯忘情友。致傘在風林，低冠入雲竇。", "中深劇苔井，傍坎才藥臼。石角忽支頤，藤根時束肘。", "初為大幽怖，漸見微明誘。屹若造靈封，森如達仙藪。", "嘗聞白芝秀，狀與琅花偶。又坐紫泉光，甘如酌天酒。", "何人能挹嚼，餌以代漿糗。卻笑探五符，徒勞步雙鬥。", "真君不可見，焚盥空遲久。眷戀玉碣文，行行但回首。"]'),
('yuding-10','奉和襲美太湖詩二十首：雨中游包山精舍','陸龜蒙','唐','御定全唐诗','yuding','','[]','包山信神仙，主者上真職。及棲鐘梵侶，又是清涼域。',144,'御定全唐詩/json/618.json','["包山信神仙，主者上真職。及棲鐘梵侶，又是清涼域。", "乃知煙霞地，絕俗無不得。岩開一徑分，柏擁深殿黑。", "僧閑若圖畫，像古非雕刻。海客施明珠，湘蕤料淨食。", "有魚皆玉尾，有烏盡金臆。手攜鞞鐸佉，若在中印國。", "千峰殘雨過，萬籟清且極。此時空寂心，可以遺智識。", "知君戰未勝，尚倚功名力。卻下聽經徒，孤帆有行色。"]'),
('yuding-11','奉和襲美太湖詩二十首：毛公壇','陸龜蒙','唐','御定全唐诗','yuding','','[]','古有韓終道，授之劉先生。身如碧鳳凰，羽翼披輕輕。',204,'御定全唐詩/json/618.json','["古有韓終道，授之劉先生。身如碧鳳凰，羽翼披輕輕。", "先生盛驅役，臣伏甲與丁。勢可倒五嶽，不唯鞭群靈。", "飄颻駕翔螭，白日朝太清。空遺古壇在，稠疊煙蘿屏。", "遠懷步罡夕，列宿森然明。四角鎮露獸，三層差羽嬰。", "回眸盼七炁，運足馳疏星。象外真既感，區中道俄成。", "邇來向千祀，雲嶠空崢嶸。石上橘花落，石根瑤草青。", "時時白鹿下，此外無人行。我訪岑寂境，自言齋戒精。", "如今君安死，魂魄猶膻腥。有笈皆綠字，有芝皆紫莖。", "相將望瀛島，浩蕩淩滄溟。"]'),
('yuding-12','奉和襲美太湖詩二十首：三宿神景宮','陸龜蒙','唐','御定全唐诗','yuding','','[]','靈蹤未遍尋，不覺溪色暝。回頭問棲所，稍下杉蘿徑。',168,'御定全唐詩/json/618.json','["靈蹤未遍尋，不覺溪色暝。回頭問棲所，稍下杉蘿徑。", "岩居更幽絕，澗戶相隱映。過此即神宮，虛堂愜雲性。", "四軒盡疏達，一榻何清零。仿佛聞玉笙，鼓鏗動涼磬。", "風凝古松粒，露壓修荷柄。萬籟既無聲，澄明但心聽。", "希微辨真語，若授虛皇命。尺宅按來平，華池漱餘淨。", "頻窺宿羽麗，三吸晨霞盛。豈獨冷衣襟，便堪遺造請。", "徒深物外趣，未脫塵中病。舉首謝靈峰，徜徉事歸榜。"]'),
('yuding-13','奉和襲美太湖詩二十首：以毛公泉獻大諫清河公','陸龜蒙','唐','御定全唐诗','yuding','','[]','先生煉飛精，羽化成翩翻。荒壇與古甃，隱軫清泠存。',144,'御定全唐詩/json/618.json','["先生煉飛精，羽化成翩翻。荒壇與古甃，隱軫清泠存。", "四面蹙山骨，中心含月魂。除非紫水脈，即是金沙源。", "香實灑桂蕊，甘惟漬雲根。向來探幽人，酌罷祛蒙昏。", "況公珪璋質，近處諫諍垣。又聞虛靜姿，早掛冰雪痕。", "君對瑤華味，重獻蘭熏言。當應滌煩暑，朗詠翬飛軒。", "我願得一掬，攀天叫重閽。霏霏散為雨，用以移焦原。"]'),
('yuding-14','奉和襲美太湖詩二十首：縹緲峰','陸龜蒙','唐','御定全唐诗','yuding','','[]','左右皆跳岑，孤峰挺然起。因思縹緲稱，乃在虛無裏。',216,'御定全唐詩/json/618.json','["左右皆跳岑，孤峰挺然起。因思縹緲稱，乃在虛無裏。", "清晨躋磴道，便是孱顏始。據石即更歌，遇泉還徙倚。", "花奇忽如薦，樹曲渾成幾。樂靜煙靄知，忘機猿狖喜。", "頻攀峻過鬥，末造平如砥。舉首閡青冥，回眸聊下視。", "高帆大於鳥，廣墠才類蟻。就此微茫中，爭先未嘗已。", "葛洪話剛氣，去地四千里。苟能乘之遊，止若道路耳。", "吾將自峰頂，便可朝帝扆。盡欲活群生，不唯私一己。", "超騎明月蜍，複弄華星蕊。卻下蓬萊巔，重窺清淺水。", "身為大塊客，自號天隨子。他日向華陽，敲雲問名氏。"]'),
('yuding-15','奉和襲美太湖詩二十首：桃花塢','陸龜蒙','唐','御定全唐诗','yuding','','[]','行行問絕境，貴與名相親。空經桃花塢，不見秦時人。',108,'御定全唐詩/json/618.json','["行行問絕境，貴與名相親。空經桃花塢，不見秦時人。", "願此為東風，吹起枝上春。願此作流水，潛浮蕊中塵。", "願此為好鳥，得棲花際鄰。願此作幽蝶，得隨花下賓。", "朝為照花日，暮作涵花津。試為探花士，作此偷桃臣。", "桃源不我棄，庶可全天真。"]'),
('yuding-16','奉和襲美太湖詩二十首：明月灣','陸龜蒙','唐','御定全唐诗','yuding','','[]','昔聞明月觀，只傷荒野基。今逢明月灣，不值三五時。',180,'御定全唐詩/json/618.json','["昔聞明月觀，只傷荒野基。今逢明月灣，不值三五時。", "擇此二明月，洞庭看最奇。連山忽中斷，遠樹分毫釐。", "周回二十裏，一片澄風漪。見說秋半夜，淨無雲物欺。", "兼之星斗藏，獨有神仙期。初聞鏘鐐跳，積漸調參差。", "空中卓羽衛，波上停龍螭。蹤舞玉煙節，高歌碧霜詞。", "清光悄不動，萬象寒咿咿。此會非俗致，無由得旁窺。", "但當乘扁舟，酒翁仍相隨。或徹三弄笛，或成數聯詩。", "自然瑩心骨，何用神仙為。"]'),
('yuding-17','奉和襲美太湖詩二十首：練瀆','陸龜蒙','唐','御定全唐诗','yuding','','[]','越恃君子眾，大將壓全吳。吳將派天澤，以練舟師徒。',168,'御定全唐詩/json/618.json','["越恃君子眾，大將壓全吳。吳將派天澤，以練舟師徒。", "一鏡止千里，支流忽然迂。蒼奩朿洪波，坐似馮夷軀。", "戰艦百萬輩，浮宮三十餘。平川盛丁寧，絕島分儲胥。", "鳳押半鶴膝，錦杠雜肥胡。香煙與殺氣，浩浩隨風驅。", "彈射盡高鳥，杯觥醉潛魚。山靈恐見鞭，水府愁為墟。", "兵利德日削，反為讎國屠。至今鉤鏃殘，尚與泥沙俱。", "照此月倍苦，來茲煙亦孤。丁魂尚有淚，合灑青楓枯。"]'),
('yuding-18','奉和襲美太湖詩二十首：投龍潭','陸龜蒙','唐','御定全唐诗','yuding','','[]','名山潭洞中，自古多秘邃。君將接神物，聊用申祀事。',144,'御定全唐詩/json/618.json','["名山潭洞中，自古多秘邃。君將接神物，聊用申祀事。", "熔金象牙角，尺木無不備。亦既奉真官，因之徇前志。", "持來展明誥，敬以投嘉瑞。鱗光煥水容，目色燒山翠。", "吾皇病秦漢，豈獨探幽異。所貴風雨時，民皆受其賜。", "良田為巨浸，汙澤成赤地。掌職一不行，精靈又何寄。", "唯貪血食飽，但據驪珠睡。何必費黃金，年年授星使。"]'),
('yuding-19','奉和襲美太湖詩二十首：孤園寺','陸龜蒙','唐','御定全唐诗','yuding','','[]','浮屠從西來，事者極梁武。岩幽與水曲，結構無遺土。',144,'御定全唐詩/json/618.json','["浮屠從西來，事者極梁武。岩幽與水曲，結構無遺土。", "窮山林幹盡，竭海珠璣聚。況即侍從臣，敢愛煙波塢。", "幡條玉龍扣，殿角金虯舞。釋子厭樓臺，生人露風雨。", "今來四百載，像設藏雲浦。輕鴿亂馴鷗，鳴鐘和朝櫓。", "庭蕉裂旗旆，野蔓差纓組。石上解空人，窗前聽經虎。", "林虛葉如織，水淨沙堪數。遍問得中天，歸修釋迦譜。"]'),
('yuding-20','奉和襲美太湖詩二十首：上真觀','陸龜蒙','唐','御定全唐诗','yuding','','[]','嘗聞升三清，真有上中下。官居乘佩服，一一自相亞。',192,'御定全唐詩/json/618.json','["嘗聞升三清，真有上中下。官居乘佩服，一一自相亞。", "霄裙或霞粲，侍女忽玉姹。坐進金碧腴，去馳飆欻駕。", "今來上真觀，恍若心靈訝。只恐暫神遊，又疑新羽化。", "風餘撼朱草，雲破生瑤榭。望極覺波平，行虛信煙藉。", "閑開飛龜帙，靜倚宿鳳架。俗狀既能遺，塵冠聊以卸。", "人間方大火，此境無朱夏。松蓋蔭日車，泉紳垂天罅。", "窮幽不知倦，複息芝園舍。鏘佩引涼姿，焚香禮遙夜。", "無情走聲利，有志依閒暇。何處好迎僧，希將石樓借。"]'),
('yuding-21','奉和襲美太湖詩二十首：銷夏灣','陸龜蒙','唐','御定全唐诗','yuding','','[]','霞島焰難泊，雲峰奇未收。蕭條千里灣，獨自清如秋。',144,'御定全唐詩/json/618.json','["霞島焰難泊，雲峰奇未收。蕭條千里灣，獨自清如秋。", "古岸過新雨，高蘿蔭橫流。遙風吹蒹葭，折處鳴颼颼。", "昔予守圭竇，過於回祿囚。日為籧筁徒，分作祗裯讎。", "願狎寒水怪，不封朱轂侯。豈知煙浪涯，坐可思重裘。", "健若數尺鯉，泛然雙白鷗。不識號火井，孰問名焦丘。", "我真魚鳥家，盡室營扁舟。遺名複避世，消夏還消憂。"]'),
('yuding-22','奉和襲美太湖詩二十首：包山祠','陸龜蒙','唐','御定全唐诗','yuding','','[]','靜境林麓好，古祠煙靄濃。自非通靈才，敢陟群仙峰。',96,'御定全唐詩/json/618.json','["靜境林麓好，古祠煙靄濃。自非通靈才，敢陟群仙峰。", "百里波浪遝，中坐簫鼓重。真君具瓊輿，仿佛來相從。", "清露濯巢鳥，陰雲生晝龍。風飄橘柚香，日動幡蓋容。", "將命禮且潔，所祈年不凶。終當以疏聞，特用諸侯封。"]'),
('yuding-23','奉和襲美太湖詩二十首：聖姑廟','陸龜蒙','唐','御定全唐诗','yuding','','[]','渺渺洞庭水，盈盈芳嶼神。因知古佳麗，不獨湘夫人。',120,'御定全唐詩/json/618.json','["渺渺洞庭水，盈盈芳嶼神。因知古佳麗，不獨湘夫人。", "流蘇蕩遙吹，斜領生輕塵。蜀彩駁霞碎，吳綃盤霧勻。", "可憐飛燕姿，合是乘鸞賓。坐想煙雨夕，兼知花草春。", "空登油壁車，窈窕誰相親。好贈玉條脫，堪攜紫綸巾。", "殷勤撥香池，重薦汀洲蘋。明朝動蘭楫，不翅星河津。"]'),
('yuding-24','奉和襲美太湖詩二十首：太湖石','陸龜蒙','唐','御定全唐诗','yuding','','[]','他山豈無石，厥狀皆可薦。端然遇良工，坐使天質變。',156,'御定全唐詩/json/618.json','["他山豈無石，厥狀皆可薦。端然遇良工，坐使天質變。", "或裁基棟宇，礧砢成廣殿。或剖出溫瑜，精光具華瑱。", "或將破仇敵，百炮資苦戰。或用鏡功名，萬古如會面。", "今之洞庭者，一以非此選。槎牙真不才，反作天下彥。", "所奇者嵌崆，所尚者蔥蒨。旁穿參洞穴，內竅均環釧。", "刻削九琳窗，玲瓏五明扇。新雕碧霞段，旋破秋天片。", "無力置池塘，臨風只流眄。"]'),
('yuding-25','奉和襲美太湖詩二十首：崦裏','陸龜蒙','唐','御定全唐诗','yuding','','[]','山橫路若絕，轉楫逢平川。川中水木幽，高下兼良田。',145,'御定全唐詩/json/618.json','["山橫路若絕，轉楫逢平川。川中水木幽，高下兼良田。", "溝塍墮微溜，桑柘含疏煙。處處倚蠶箔，家家下魚筌。", "騃犢臥新fO，野禽爭折蓮。試招搔首翁，共語殘陽邊。", "今來九州內，未得皆恬然。賊陣始吉語，狂波又凶年。", "吾翁欲何道，守此常安眠。笑我掉頭去，蘆中聞刺船。", "餘知隱地術，可以齊真仙。終當從之遊，庶複全於天。"]'),
('yuding-26','奉和襲美太湖詩二十首：石板','陸龜蒙','唐','御定全唐诗','yuding','','[]','一片倒山屏，何時隳洞門。屹然空闊中，萬古波濤痕。',144,'御定全唐詩/json/618.json','["一片倒山屏，何時隳洞門。屹然空闊中，萬古波濤痕。", "我意上帝命，持來壓泉源。恐為庚辰官，囚怪力所掀。", "又疑廣袤次，零落潛驚奔。不然遭霹靂，強半沈無垠。", "如何造化首，便截秋雲根。往事不足問，奇蹤安可論。", "吾今病煩暑，據簟常昏昏。欲從石公乞，瑩理平如璊。", "前後植桂檜，東西置琴尊。盡攜天壤徒，浩唱羲皇言。"]'),
('yuding-0','雜諷九首','陸龜蒙','唐','御定全唐诗','yuding','','[]','紅蠶緣枯桑，青繭大如甕。人爭捩其臂，羿矢亦不中。',564,'御定全唐詩/json/619.json','["紅蠶緣枯桑，青繭大如甕。人爭捩其臂，羿矢亦不中。", "微微待賢祿，一一希入夢。縱操上古言，口噤難即貢。", "蛟龍在怒水，拔取牙角弄。丹穴如可遊，家家畜孤鳳。", "凶門尚兒戲，戰血波澒溶。社鬼苟有靈，誰能遏秋慟。", "童麋來觸犀，德力不相及。伊無愜心事，只有碎首泣。", "況將鵬虱校，數又百與十。攻如餓鴟叫，勢若脫兔急。", "斯為朽關鍵，怒犖抉以入。年來橫干戈，未見拔城邑。", "得非佐饔者，齒齒待啜汁。羈維豪傑輩，四駭方少縶。", "此皆乘時利，縱舍在呼吸。吾欲斧其吭，無雷動幽蟄。", "鴚鵝慘于冰，陸立懷所適。斯人道仍閟，不得不嗚呃。", "當時布衣士，亦作天子客。至今東方生，滿口自誇白。", "終為萬乘交，談笑無所隔。致君非有書，乃是堯舜畫。", "只今侯門峻，日掃貧賤跡。朝趨九韶音，暮列五鼎食。", "如聞恭儉語，謇謇事夕惕。可拍伊牧肩，功名被金石。", "赤舌可燒城，讒邪易為伍。詩人疾之甚，取俾投豺虎。", "長風吹窾木，始有音韻吐。無木亦無風，笙簧由喜怒。", "女媧煉五石，天缺猶可補。當其利口銜，罅漏不複數。", "元精遺萬類，雙目如牖戶。非是既相參，重瞳亦為瞽。", "東南有狂兕，獵者西北矢。利塵白冥冥，獨此清夜止。", "無人語其事，偶坐窺天紀。安得東壁明，洪洪用墳史。", "搜揚好古士，一以罄雲水。流堪灑菁英，風足去稗秕。", "如能出奇計，坐可平賊壘。徐陳羲皇道，高駕太平軌。", "攫疏成特雄，濯垢為具美。貢賢當上賞，景福視所履。", "永播南熏音，垂之萬年耳。"]'),
('yuding-1','美人','陸龜蒙','唐','御定全唐诗','yuding','','[]','美人抱瑤瑟，哀怨彈別鶴。雌雄南北飛，一旦異棲托。',72,'御定全唐詩/json/619.json','["美人抱瑤瑟，哀怨彈別鶴。雌雄南北飛，一旦異棲托。", "諒非金石性，安得宛如昨。生為並蒂花，亦有先後落。", "秋林對斜日，光景自相薄。猶欲悟君心，朝朝佩蘭若。"]'),
('yuding-2','感事','陸龜蒙','唐','御定全唐诗','yuding','','[]','將軍被鮫函，只畏金石鏃。豈知讒箭利，一中成赤族。',72,'御定全唐詩/json/619.json','["將軍被鮫函，只畏金石鏃。豈知讒箭利，一中成赤族。", "古來信簧舌，巧韻淒鏘曲。君聞悅耳音，盡日聽不足。", "初因起毫髮，漸可離骨肉。所以賢達心，求人須任目。"]'),
('yuding-3','素絲','陸龜蒙','唐','御定全唐诗','yuding','','[]','園客麗獨繭，詩人吟五緵。如何墨子淚，反以悲途窮。',72,'御定全唐詩/json/619.json','["園客麗獨繭，詩人吟五緵。如何墨子淚，反以悲途窮。", "我意豈如是，願參天地功。為線補君袞，為弦系君桐。", "左右修闕職，宮商還古風。端然潔白心，可與神明通。"]'),
('yuding-4','次幽獨君韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','靈氣獨不死，尚能成綺文。如何孤窆裏，猶自讀三墳。',96,'御定全唐詩/json/619.json','["靈氣獨不死，尚能成綺文。如何孤窆裏，猶自讀三墳。", "落日送萬古，秋聲含七哀。枯株不蕭瑟，枝幹虛崔嵬。", "伊昔臨大道，歌鐘醉高臺。台今已平地，只有春風回。", "明月白草死，積陰荒隴摧。聖賢亦如此，慟絕真悠哉。"]'),
('yuding-5','贈遠','陸龜蒙','唐','御定全唐诗','yuding','','[]','芙蓉匣中鏡，欲照心還懶。本是細腰人，別來羅帶緩。',72,'御定全唐詩/json/619.json','["芙蓉匣中鏡，欲照心還懶。本是細腰人，別來羅帶緩。", "從君出門後，不奏雲和管。妾思冷如簧，時時望君暖。", "心期夢中見，路永魂夢短。怨坐泣西風，秋窗月華滿。"]'),
('yuding-6','村夜二篇','陸龜蒙','唐','御定全唐诗','yuding','','[]','江上冬日短，裴回草堂暝。鴻當絕塞來，客向孤村病。',528,'御定全唐詩/json/619.json','["江上冬日短，裴回草堂暝。鴻當絕塞來，客向孤村病。", "綿綿起歸念，咽咽興微詠。菊徑月方高，橘齋霜已並。", "盤餐蔬粟粗，史籍簽牌盛。目冷松桂寒，耳喧兒女競。", "開瓶浮蟻綠，試筆秋毫勁。晝戶亦重關，寒屏遞相映。", "詩從騷雅得，字向鉛槧正。遇敵舞蛇矛，逢談捉犀柄。", "無名升甲乙，有志扶荀孟。守道希昔賢，為文通古聖。", "幽憂廢長劍，憔悴慚清鏡。只會魚鳥情，詎知時俗性。", "浮虛多徇勢，老懶圖曆聘。既不務人知，空餘樂天命。", "吾家在田野，家事苦遼夐。耕稼一以微，囷倉自然罄。", "愁襟風葉亂，獨坐燈花迸。明發成浩歌，誰能少傾聽。", "世既賤文章，歸來事耕稼。伊人著農道，我亦賦田舍。", "所悲勞者苦，敢用詞為詫。只效芻牧言，誰防輕薄罵。", "嘻今居寵祿，各自矜雄霸。堂上考華鐘，門前佇高駕。", "纖洪動絲竹，水陸供鱠炙。小雨靜樓臺，微風動蘭麝。", "吹噓川可倒，眄睞花爭姹。萬戶膏血窮，一筵歌舞價。", "安知勤播植，卒歲無閒暇。種以春鳸初，獲從秋隼下。", "專專望穜稑，搰搰條桑柘。日晏腹未充，霜繁體猶裸。", "平生守仁義，所疾唯狙詐。上誦周孔書，沈溟至酣藉。", "豈無致君術，堯舜不上下。豈無活國方，頗牧齊教化。", "蛟龍任幹死，雲雨終不借。羿臂束如囚，徒勞誇善射。", "才能誚箕斗，辯可移嵩華。若與甿輩量，饑寒殆相亞。", "長吟倚清瑟，孤憤生遙夜。自古有遺賢，吾容偏稱謝。"]'),
('yuding-7','記事','陸龜蒙','唐','御定全唐诗','yuding','','[]','本作漁釣徒，心將遂疏放。苦為饑寒累，未得恣閑暢。',432,'御定全唐詩/json/619.json','["本作漁釣徒，心將遂疏放。苦為饑寒累，未得恣閑暢。", "去年十二月，身住霅溪上。病裏賀豐登，雞豚聊饋餉。", "巍峨卞山雪，凝冽不可向。瘦骨倍加寒，徒為厚繒纊。", "晴來露青靄，千仞缺尋丈。臥恐玉華銷，時時推枕望。", "雖然營衛困，亦覺精神王。把筆強題詩，粗言瑰怪狀。", "吳興鄭太守，文律頗清壯。鳳尾與鯨牙，紛披落雜唱。", "緘書寄城內，搪突無以況。料峭採蓮船，縱橫簸天浪。", "方傾謝公酒，忽值莊生喪。默默阻音徽，臨風但惆悵。", "春歸迨秋末，固自嬰微恙。歲晏弗躬親，何由免欺誑。", "今來觀刈獲，乃在松江並。門外兩潮過，波瀾光蕩漾。", "都緣新蔔築，是事皆草創。爾後如有年，還應愜微尚。", "天高氣味爽，野迥襟懷曠。感物動牢愁，憤時頻骯髒。", "平生樂篇翰，至老安敢忘。駿骨正牽鹽，玄文終覆醬。", "嗟今多赤舌，見善惟蔽謗。忖度大為防，涵容寬作量。", "圖書筐簏外，關眼皆剩長。餓隸亦勝無，薄田家所仰。", "稍離饑寒患，學古真可強。聖道庶經營，世途多踉蹌。", "近聞天子詔，複許私醞釀。促使舂酒材，呼兒具盆盎。", "宵長擁吟褐，日晏開書幌。我醉卿可還，陶然似元亮。"]'),
('yuding-8','孤雁','陸龜蒙','唐','御定全唐诗','yuding','','[]','我生天地間，獨作南賓雁。哀鳴慕前侶，不免飲啄晏。',216,'御定全唐詩/json/619.json','["我生天地間，獨作南賓雁。哀鳴慕前侶，不免飲啄晏。", "雖蒙小雅詠，未脫魚網患。況是婚禮須，憂為弋者篡。", "晴鳶爭上下，意氣苦淩慢。吾常嚇鴛雛，爾輩安足訕。", "回頭語晴鳶，汝食腐鼠慣。無異駑駘群，戀短豆皂棧。", "豈知瀟湘岸，葭菼蘋萍間。有石形狀奇，寒流古來灣。", "閑看麋鹿志，了不憂芻豢。世所重巾冠，何妨野夫丱。", "騷人誇蕙芷，易象取陸莧。漆園逍遙篇，中亦載斥鷃。", "汝惟材性下，嗜好不可諫。身雖慕高翔，糞壤是盻盼。", "或聞通鬼魅，怪祟立可辯。硩蔟書尚存，甯容恣妖幻。"]'),
('yuding-9','南涇漁父','陸龜蒙','唐','御定全唐诗','yuding','','[]','予方任疏慵，地僻即所好。江流背村落，偶往心已嫪。',240,'御定全唐詩/json/619.json','["予方任疏慵，地僻即所好。江流背村落，偶往心已嫪。", "田家相去遠，岑寂且縱傲。出戶手先筇，見人頭未帽。", "南涇有漁父，往往攜稚造。問其所以漁，對我真蹈道。", "我初簎魚鱉，童丱至於耄。窟穴與生成，自然通壼奧。", "孜孜戒吾屬，天物不可暴。大小參去留，候其孳養報。", "終朝獲魚利，魚亦未常耗。同覆天地中，違仁辜覆燾。", "餘觀為政者，此意諒難到。民皆死搜求，莫肯興湣悼。", "今年川澤旱，前歲山源潦。牒訴已盈庭，聞之類禽噪。", "譬如死雞鶩，豈不容乳抱。孟子譏宋人，非其揠苗躁。", "吾嘉漁父旨，雅葉賢哲操。倘遇采詩官，斯文誠敢告。"]'),
('yuding-10','引泉詩','陸龜蒙','唐','御定全唐诗','yuding','','[]','上嗣位六載，吾宗刺桐川。餘來拜旌戟，詔下之明年。',360,'御定全唐詩/json/619.json','["上嗣位六載，吾宗刺桐川。餘來拜旌戟，詔下之明年。", "是時春三月，繞郭花蟬聯。嵐盤百萬髻，上插黃金鈿。", "授以道士館，置榻於東偏。滿院聲碧樹，空堂形老仙。", "本性樂凝淡，及來更虛玄。焚香禮真像，盥手披靈編。", "新定山角角，烏龍獨巉然。除非淨晴日，不見蒼崖巔。", "上有拏雲峰，下有噴壑泉。泉分數十汊，落處皆崢潺。", "寒聲入爛醉，聒破西窗眠。支筇起獨尋，只在牆東邊。", "呼童具畚鍤，立鑿莓苔穿。灇淙一派墮，練帶橫斜牽。", "亂石拋落落，寒流響濺濺。狂奴七裏瀨，縮到疏楹前。", "跳花潑半散，湧沫飛旋圓。勢束三峽掛，瀉危孤磴懸。", "曾聞瑤池溜，亦灌朱草田。鳧伯弄翠蕊，鸞雛舞丹煙。", "淩風捩桂柁，隔霧馳犀船。況當玄元家，嘗著道德篇。", "上善可比水，斯文參五千。精靈若在此，肯惡微波傳。", "不擬爭滴瀝，還應會淪漣。出門複飛箭，合勢浮青天。", "必有學真子，鹿冠秋鶴顏。如能輔餘志，日使疏其源。"]'),
('yuding-11','紀夢游甘露寺','陸龜蒙','唐','御定全唐诗','yuding','','[]','昔臥嵩高雲，雲窗正寒夕。披裘忽生夢，似到空王宅。',384,'御定全唐詩/json/619.json','["昔臥嵩高雲，雲窗正寒夕。披裘忽生夢，似到空王宅。", "峨天一峰立，欄楯橫半壁。級倚綠巔差，關臨赤霄辟。", "捫虛陟孤峭，不翅千餘尺。疊掌望罘罳，分明袒肩釋。", "淩香稽首罷，嘹嘵□□□。高戶乘北風，聲號大波白。", "光中目難送，定驗方可覿。樹細鴻蒙煙，島疏零落碧。", "須臾群籟入，空水相噴激。積浪亞寒堆，呀如鬥危石。", "跳音簇鞞鼓，濺沫交矛戟。鳥疾帆亦奔，紛紛助勁敵。", "思非水靈怒，即是饑龍擘。怯懾不敢前，荷襟汗沾霢。", "回經定僧處，泉木光相射。岩磴雲族棲，柖柯露華適。", "逍遙得真趨，邐迤尋常跡。山腹貯孤亭，嵐根四垂帟。", "誰題雪月句，乃是曹劉格。閬闕一枝瓊，邊樓數聲笛。", "吟高矍然起，若自蒼旻擲。短燭墮餘花，圓蟾掛斜魄。", "自從神錫境，無處不登陟。忽上南徐山，心期豁而獲。", "豈伊煩惱骨，合到清涼域。暗得蝴蝶身，幽期盡相識。", "奈何有名氏，未列金閨籍。翻慚丱頂童，得奉真如策。", "雲濤觸風望，毫管和煙搦。聊記夢中游，留之問禪客。"]'),
('yuding-12','惜花','陸龜蒙','唐','御定全唐诗','yuding','','[]','人壽期滿百，花開唯一春。其間風雨至，旦夕旋為塵。',36,'御定全唐詩/json/619.json','["人壽期滿百，花開唯一春。其間風雨至，旦夕旋為塵。", "若使花解愁，愁於看花人。"]'),
('yuding-13','別離','陸龜蒙','唐','御定全唐诗','yuding','','[]','丈夫非無淚，不灑離別間。杖劍對尊酒，恥為遊子顏。',48,'御定全唐詩/json/619.json','["丈夫非無淚，不灑離別間。杖劍對尊酒，恥為遊子顏。", "蝮蛇一螫手，壯士即解腕。所志在功名，離別何足歎。"]'),
('yuding-14','鳴雁行','陸龜蒙','唐','御定全唐诗','yuding','','[]','朔風動地來，吹起沙上聲。閨中有邊思，玉箸此時橫。',36,'御定全唐詩/json/619.json','["朔風動地來，吹起沙上聲。閨中有邊思，玉箸此時橫。", "莫怕兒女恨，主人烹不鳴。"]'),
('yuding-15','短歌行','陸龜蒙','唐','御定全唐诗','yuding','','[]','爪牙在身上，陷阱猶可制。爪牙在胸中，劍戟無所畏。',48,'御定全唐詩/json/619.json','["爪牙在身上，陷阱猶可制。爪牙在胸中，劍戟無所畏。", "人言畏猛虎，誰是撩頭弊。只見古來心，奸雄暗相噬。"]'),
('yuding-16','挾瑟歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','挾瑟為君撫，君嫌聲太古。寥寥倚浪系，eP々沈湘語。',37,'御定全唐詩/json/619.json','["挾瑟為君撫，君嫌聲太古。寥寥倚浪系，eP々沈湘語。", "賴有秋風知，清泠吹玉柱。"]'),
('yuding-17','婕妤怨','陸龜蒙','唐','御定全唐诗','yuding','','[]','妾貌非傾國，君王忽然寵。南山掌上來，下敵新恩重。',48,'御定全唐詩/json/619.json','["妾貌非傾國，君王忽然寵。南山掌上來，下敵新恩重。", "後宮多窈窕，日日學新聲。一落君王耳，南山又須輕。"]'),
('yuding-18','江南曲','陸龜蒙','唐','御定全唐诗','yuding','','[]','為愛江南春，涉江聊采蘋。水深煙浩浩，空對雙車輪。',72,'御定全唐詩/json/619.json','["為愛江南春，涉江聊采蘋。水深煙浩浩，空對雙車輪。", "車輪明月團，車蓋浮雲盤。雲月徒自好，水中行路難。", "遙遙洛陽道，夾道生春草。寄語棹船郎，莫誇風浪好。"]'),
('yuding-0','漁具詩：網','陸龜蒙','唐','御定全唐诗','yuding','','[]','大罟綱目繁，空江波浪黑。沉沉到波底，恰共波同色。',48,'御定全唐詩/json/620.json','["大罟綱目繁，空江波浪黑。沉沉到波底，恰共波同色。", "牽時萬鬐入，已有千鈞力。尚悔不橫流，恐他人更得。"]'),
('yuding-1','漁具詩：罩','陸龜蒙','唐','御定全唐诗','yuding','','[]','左手揭圓罛，輕橈弄舟子。不知潛鱗處，但去籠煙水。',48,'御定全唐詩/json/620.json','["左手揭圓罛，輕橈弄舟子。不知潛鱗處，但去籠煙水。", "時穿紫屏破，忽值朱衣起。貴得不貴名，敢論魴與鯉。"]'),
('yuding-2','漁具詩：罱','陸龜蒙','唐','御定全唐诗','yuding','','[]','有意烹小鮮，乘流駐孤棹。雖然煩取捨，未肯求津要。',48,'御定全唐詩/json/620.json','["有意烹小鮮，乘流駐孤棹。雖然煩取捨，未肯求津要。", "多為蝦蜆誤，已分鵁鶄笑。寄語龍伯人，荒唐不同調。"]'),
('yuding-3','漁具詩：釣筒','陸龜蒙','唐','御定全唐诗','yuding','','[]','短短截筠光，悠悠臥江色。蓬差櫓相應，雨慢煙交織。',48,'御定全唐詩/json/620.json','["短短截筠光，悠悠臥江色。蓬差櫓相應，雨慢煙交織。", "須臾中芳餌，迅疾如飛翼。彼竭我還浮，君看不爭得。"]'),
('yuding-4','漁具詩：釣車','陸龜蒙','唐','御定全唐诗','yuding','','[]','溪上持只輪，溪邊指茅屋。閑乘風水便，敢議朱丹轂。',48,'御定全唐詩/json/620.json','["溪上持只輪，溪邊指茅屋。閑乘風水便，敢議朱丹轂。", "高多倚衡懼，下有折軸速。曷若載逍遙，歸來臥雲族。"]'),
('yuding-5','漁具詩：魚梁','陸龜蒙','唐','御定全唐诗','yuding','','[]','能編似雲薄，橫絕清川口。缺處欲隨波，波中先置笱。',48,'御定全唐詩/json/620.json','["能編似雲薄，橫絕清川口。缺處欲隨波，波中先置笱。", "投身入籠檻，自古難飛走。盡日水濱吟，殷勤謝漁叟。"]'),
('yuding-6','漁具詩：叉魚','陸龜蒙','唐','御定全唐诗','yuding','','[]','春溪正含綠，良夜才參半。持矛若羽輕，列燭如星爛。',48,'御定全唐詩/json/620.json','["春溪正含綠，良夜才參半。持矛若羽輕，列燭如星爛。", "傷鱗跳密藻，碎首沈遙岸。盡族染東流，傍人作佳玩。"]'),
('yuding-7','漁具詩：射魚','陸龜蒙','唐','御定全唐诗','yuding','','[]','彎弓注碧潯，掉尾行涼沚。青楓下晚照，正在澄明裏。',48,'御定全唐詩/json/620.json','["彎弓注碧潯，掉尾行涼沚。青楓下晚照，正在澄明裏。", "抨弦斷荷扇，濺血殷菱蕊。若使禽荒聞，移之暴煙水。"]'),
('yuding-8','漁具詩：鳴桹','陸龜蒙','唐','御定全唐诗','yuding','','[]','水淺藻荇澀，釣罩無所及。鏗如木鐸音，勢若金鉦急。',48,'御定全唐詩/json/620.json','["水淺藻荇澀，釣罩無所及。鏗如木鐸音，勢若金鉦急。", "驅之就深處，用以資俯拾。搜羅爾甚微，遁去將何入。"]'),
('yuding-9','漁具詩：滬','陸龜蒙','唐','御定全唐诗','yuding','','[]','萬植禦洪波，森然倒林薄。千顱咽雲上，過半隨潮落。',48,'御定全唐詩/json/620.json','["萬植禦洪波，森然倒林薄。千顱咽雲上，過半隨潮落。", "其間風信背，更值雷聲惡。天道亦裒多，吾將移海若。"]'),
('yuding-10','漁具詩：qF','陸龜蒙','唐','御定全唐诗','yuding','','[]','斬木置水中，枝條互相蔽。寒魚遂家此，自以為生計。',48,'御定全唐詩/json/620.json','["斬木置水中，枝條互相蔽。寒魚遂家此，自以為生計。", "春冰忽融冶，盡取無遺裔。所托成禍機，臨川一凝睇。"]'),
('yuding-11','漁具詩：種魚','陸龜蒙','唐','御定全唐诗','yuding','','[]','鑿池收赬鱗，疏疏置雲嶼。還同汗漫遊，遂以江湖處。',48,'御定全唐詩/json/620.json','["鑿池收赬鱗，疏疏置雲嶼。還同汗漫遊，遂以江湖處。", "如非一神守，潛被蛟龍主。蛟龍若無道，跛鱉亦可禦。"]'),
('yuding-12','漁具詩：藥魚','陸龜蒙','唐','御定全唐诗','yuding','','[]','香餌綴金鉤，日中懸者幾。盈川是毒流，細大同時死。',48,'御定全唐詩/json/620.json','["香餌綴金鉤，日中懸者幾。盈川是毒流，細大同時死。", "不唯空飼犬，便可將貽蟻。苟負竭澤心，其他盡如此。"]'),
('yuding-13','漁具詩：舴艋','陸龜蒙','唐','御定全唐诗','yuding','','[]','篷棹兩三事，天然相與閑。朝隨稚子去，暮唱菱歌還。',48,'御定全唐詩/json/620.json','["篷棹兩三事，天然相與閑。朝隨稚子去，暮唱菱歌還。", "倚石遲後侶，徐橈供遠山。君看萬斛載，沈溺須臾間。"]'),
('yuding-14','漁具詩：笭箵','陸龜蒙','唐','御定全唐诗','yuding','','[]','誰謂笭箵小，我謂笭箵大。盛魚自足餐，寘璧能為害。',48,'御定全唐詩/json/620.json','["誰謂笭箵小，我謂笭箵大。盛魚自足餐，寘璧能為害。", "時將刷蘋浪，又取懸藤帶。不及腰上金，何勞問蓍蔡。"]'),
('yuding-15','奉和襲美添漁具五篇：漁庵','陸龜蒙','唐','御定全唐诗','yuding','','[]','結茅次煙水，用以資嘯傲。豈謂釣家流，忽同禪室號。',48,'御定全唐詩/json/620.json','["結茅次煙水，用以資嘯傲。豈謂釣家流，忽同禪室號。", "閑憑山叟占，晚有溪禽嫪。華屋莫相非，各隨吾所好。"]'),
('yuding-16','奉和襲美添漁具五篇：釣磯','陸龜蒙','唐','御定全唐诗','yuding','','[]','揀得白雲根，秋潮未曾沒。坡阤坐鼇背，散漫垂龍發。',48,'御定全唐詩/json/620.json','["揀得白雲根，秋潮未曾沒。坡阤坐鼇背，散漫垂龍發。", "持竿從掩霧，置酒複待月。即此放神情，何勞適吳越。"]'),
('yuding-17','奉和襲美添漁具五篇：蓑衣','陸龜蒙','唐','御定全唐诗','yuding','','[]','山前度微雨，不廢小澗漁。上有青襏襫，下有新腒疏。',48,'御定全唐詩/json/620.json','["山前度微雨，不廢小澗漁。上有青襏襫，下有新腒疏。", "滴瀝珠影泫，離披嵐彩虛。君看荷制者，不得安吾廬。"]'),
('yuding-18','奉和襲美添漁具五篇：箬笠','陸龜蒙','唐','御定全唐诗','yuding','','[]','朝攜下楓浦，晚戴出煙艇。冒雪或平簷，聽泉時仄頂。',48,'御定全唐詩/json/620.json','["朝攜下楓浦，晚戴出煙艇。冒雪或平簷，聽泉時仄頂。", "飆移靄然色，波亂危如影。不識九衢塵，終年居下泂。"]'),
('yuding-19','奉和襲美添漁具五篇：背蓬','陸龜蒙','唐','御定全唐诗','yuding','','[]','敏手劈江筠，隨身織煙殼。沙禽固不知，釣伴猶初覺。',48,'御定全唐詩/json/620.json','["敏手劈江筠，隨身織煙殼。沙禽固不知，釣伴猶初覺。", "閑從翠微拂，靜唱滄浪濯。見說萬山潭，漁童盡能學。"]'),
('yuding-20','樵人十詠：樵溪','陸龜蒙','唐','御定全唐诗','yuding','','[]','山高溪且深，蒼蒼但群木。抽條欲千尺，眾亦疑樸樕。',48,'御定全唐詩/json/620.json','["山高溪且深，蒼蒼但群木。抽條欲千尺，眾亦疑樸樕。", "一朝蒙翦伐，萬古辭林麓。若遇燎玄穹，微煙出雲族。"]'),
('yuding-21','樵人十詠：樵家','陸龜蒙','唐','御定全唐诗','yuding','','[]','草木黃落時，比鄰見相喜。門當清澗盡，屋在寒雲裏。',48,'御定全唐詩/json/620.json','["草木黃落時，比鄰見相喜。門當清澗盡，屋在寒雲裏。", "山棚日才下，野灶煙初起。所謂順天民，唐堯亦如此。"]'),
('yuding-22','樵人十詠：樵叟','陸龜蒙','唐','御定全唐诗','yuding','','[]','自小即胼胝，至今凋鬢髮。所圖山褐厚，所愛山爐熱。',48,'御定全唐詩/json/620.json','["自小即胼胝，至今凋鬢髮。所圖山褐厚，所愛山爐熱。", "不知冠蓋好，但信煙霞活。富貴如疾顛，吾從老岩穴。"]'),
('yuding-23','樵人十詠：樵子','陸龜蒙','唐','御定全唐诗','yuding','','[]','生自蒼崖邊，能諳白雲養。才穿遠林去，已在孤峰上。',48,'御定全唐詩/json/620.json','["生自蒼崖邊，能諳白雲養。才穿遠林去，已在孤峰上。", "薪和野花束，步帶山詞唱。日暮不歸來，柴扉有人望。"]'),
('yuding-24','樵人十詠：樵徑','陸龜蒙','唐','御定全唐诗','yuding','','[]','石脈青靄間，行行自幽絕。方愁山繚繞，更值雲遮截。',48,'御定全唐詩/json/620.json','["石脈青靄間，行行自幽絕。方愁山繚繞，更值雲遮截。", "爭推好林浪，共約歸時節。不似名利途，相期覆車轍。"]'),
('yuding-25','樵人十詠：樵斧','陸龜蒙','唐','御定全唐诗','yuding','','[]','淬礪秋水清，攜持遠山曙。丁丁在前澗，杳杳無尋處。',48,'御定全唐詩/json/620.json','["淬礪秋水清，攜持遠山曙。丁丁在前澗，杳杳無尋處。", "巢傾鳥猶在，樹盡猿方去。授鉞者何人，吾今易其慮。"]'),
('yuding-26','樵人十詠：樵擔','陸龜蒙','唐','御定全唐诗','yuding','','[]','輕無鬥儲價，重則筋力絕。欲下半岩時，憂襟兩如結。',48,'御定全唐詩/json/620.json','["輕無鬥儲價，重則筋力絕。欲下半岩時，憂襟兩如結。", "風高勢還卻，雪厚疑中折。負荷誠獨難，移之贈來哲。"]'),
('yuding-27','樵人十詠：樵風','陸龜蒙','唐','御定全唐诗','yuding','','[]','朝隨早潮去，暮帶殘陽返。向背得清飆，相追無近遠。',48,'御定全唐詩/json/620.json','["朝隨早潮去，暮帶殘陽返。向背得清飆，相追無近遠。", "采山一何遲，服道常苦蹇。仙術信能為，年華未將晚。"]'),
('yuding-28','樵人十詠：樵火','陸龜蒙','唐','御定全唐诗','yuding','','[]','積雪抱松塢，蠹根然草堂。深爐與遠燒，此夜仍交光。',48,'御定全唐詩/json/620.json','["積雪抱松塢，蠹根然草堂。深爐與遠燒，此夜仍交光。", "或似坐奇獸，或如焚異香。堪嗟宦遊子，凍死道路傍。"]'),
('yuding-29','樵人十詠：樵歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','縱調為野吟，徐徐下雲磴。因知負樵樂，不減援琴興。',48,'御定全唐詩/json/620.json','["縱調為野吟，徐徐下雲磴。因知負樵樂，不減援琴興。", "出林方自轉，隔水猶相應。但取天壤情，何求郢人稱。"]'),
('yuding-30','奉和襲美酒中十詠：酒星','陸龜蒙','唐','御定全唐诗','yuding','','[]','萬古醇酎氣，結而成晶熒。降為嵇阮徒，動與尊罍並。',48,'御定全唐詩/json/620.json','["萬古醇酎氣，結而成晶熒。降為嵇阮徒，動與尊罍並。", "不獨祭天廟，亦應邀客星。何當八月槎，載我遊青冥。"]'),
('yuding-31','奉和襲美酒中十詠：酒泉','陸龜蒙','唐','御定全唐诗','yuding','','[]','初懸碧崖口，漸注青溪腹。味既敵中山，飲寧拘一斛。',48,'御定全唐詩/json/620.json','["初懸碧崖口，漸注青溪腹。味既敵中山，飲寧拘一斛。", "春疑浸花骨，暮若酣雲族。此地得封侯，終身持美祿。"]'),
('yuding-32','奉和襲美酒中十詠：酒篘','陸龜蒙','唐','御定全唐诗','yuding','','[]','山齋醞方熟，野童編近成。持來歡伯內，坐使賢人清。',48,'御定全唐詩/json/620.json','["山齋醞方熟，野童編近成。持來歡伯內，坐使賢人清。", "不待盎中滿，旋供花下傾。汪汪日可挹，未羨黃金籝。"]'),
('yuding-33','奉和襲美酒中十詠：酒床','陸龜蒙','唐','御定全唐诗','yuding','','[]','六尺樣何奇，溪邊濯來潔。糟深貯方半，石重流還咽。',48,'御定全唐詩/json/620.json','["六尺樣何奇，溪邊濯來潔。糟深貯方半，石重流還咽。", "閑移秋病可，偶聽寒夢缺。往往枕眠時，自疑陶靖節。"]'),
('yuding-34','奉和襲美酒中十詠：酒壚','陸龜蒙','唐','御定全唐诗','yuding','','[]','錦裏多佳人，當壚自沽酒。高低過反坫，大小隨圓瓿。',48,'御定全唐詩/json/620.json','["錦裏多佳人，當壚自沽酒。高低過反坫，大小隨圓瓿。", "數錢紅燭下，滌器春江口。若得奉君歡，十千求一鬥。"]'),
('yuding-35','奉和襲美酒中十詠：酒樓','陸龜蒙','唐','御定全唐诗','yuding','','[]','百尺江上起，東風吹酒香。行人落帆上，遠樹涵殘陽。',48,'御定全唐詩/json/620.json','["百尺江上起，東風吹酒香。行人落帆上，遠樹涵殘陽。", "凝睇複凝睇，一觴還一觴。須知憑欄客，不醉難為腸。"]'),
('yuding-36','奉和襲美酒中十詠：酒旗','陸龜蒙','唐','御定全唐诗','yuding','','[]','搖搖倚青岸，遠蕩遊人思。風欹翠竹杠，雨澹香醪字。',48,'御定全唐詩/json/620.json','["搖搖倚青岸，遠蕩遊人思。風欹翠竹杠，雨澹香醪字。", "才來隔煙見，已覺臨江遲。大旆非不榮，其如有王事。"]'),
('yuding-37','奉和襲美酒中十詠：酒尊','陸龜蒙','唐','御定全唐诗','yuding','','[]','黃金即為侈，白石又太拙。斫得奇樹根，中如老蛟穴。',48,'御定全唐詩/json/620.json','["黃金即為侈，白石又太拙。斫得奇樹根，中如老蛟穴。", "時招山下叟，共酌林間月。盡醉兩忘言，誰能作天舌。"]'),
('yuding-38','奉和襲美酒中十詠：酒城','陸龜蒙','唐','御定全唐诗','yuding','','[]','何代驅生靈，築之為釀地。殊無甲兵守，但有糟漿氣。',48,'御定全唐詩/json/620.json','["何代驅生靈，築之為釀地。殊無甲兵守，但有糟漿氣。", "雉堞屹如狂，女牆低似醉。必若據而爭，先登儀狄氏。"]'),
('yuding-39','奉和襲美酒中十詠：酒鄉','陸龜蒙','唐','御定全唐诗','yuding','','[]','誰知此中路，暗出虛無際。廣莫是鄰封，華胥為附麗。',48,'御定全唐詩/json/620.json','["誰知此中路，暗出虛無際。廣莫是鄰封，華胥為附麗。", "三杯聞古樂，伯雅逢遺裔。自爾等榮枯，何勞問玄弟。"]'),
('yuding-40','添酒中六詠：酒池','陸龜蒙','唐','御定全唐诗','yuding','','[]','萬斛輸曲沼，千鐘未為多。殘霞入醍齊，遠岸澄白酂。',48,'御定全唐詩/json/620.json','["萬斛輸曲沼，千鐘未為多。殘霞入醍齊，遠岸澄白酂。", "後土亦沈醉，奸臣空浩歌。邇來荒淫君，尚得乘餘波。"]'),
('yuding-41','添酒中六詠：酒龍','陸龜蒙','唐','御定全唐诗','yuding','','[]','銅雀羽儀麗，金龍光彩奇。潛傾鄴宮酒，忽作商庭漦。',48,'御定全唐詩/json/620.json','["銅雀羽儀麗，金龍光彩奇。潛傾鄴宮酒，忽作商庭漦。", "若怒鱗甲赤，如酣頭角垂。君臣坐相滅，安用驕奢為。"]'),
('yuding-42','添酒中六詠：酒甕','陸龜蒙','唐','御定全唐诗','yuding','','[]','候暖麹糵調，覆深苫蓋淨。溢處每淋漓，沉來還濎瀅。',48,'御定全唐詩/json/620.json','["候暖麹糵調，覆深苫蓋淨。溢處每淋漓，沉來還濎瀅。", "常聞清涼酎，可養希夷性。盜飲以為名，得非君子病。"]'),
('yuding-43','添酒中六詠：酒船','陸龜蒙','唐','御定全唐诗','yuding','','[]','昔人性何誕，欲載無窮酒。波上任浮身，風來即開口。',48,'御定全唐詩/json/620.json','["昔人性何誕，欲載無窮酒。波上任浮身，風來即開口。", "荒唐意難遂，沉湎名不朽。千古如比肩，問君能繼不。"]'),
('yuding-44','添酒中六詠：酒槍','陸龜蒙','唐','御定全唐诗','yuding','','[]','景山實名士，所玩垂清塵。嘗作酒家語，自言中聖人。',48,'御定全唐詩/json/620.json','["景山實名士，所玩垂清塵。嘗作酒家語，自言中聖人。", "奇器質含古，挫糟未應醇。唯懷魏公子，即此飛觴頻。"]'),
('yuding-45','添酒中六詠：酒杯','陸龜蒙','唐','御定全唐诗','yuding','','[]','叔夜傲天壤，不將琴酒疏。制為酒中物，恐是琴之餘。',48,'御定全唐詩/json/620.json','["叔夜傲天壤，不將琴酒疏。制為酒中物，恐是琴之餘。", "一弄廣陵散，又裁絕交書。頹然擲林下，身世俱何如。"]'),
('yuding-46','奉和襲美茶具十詠：茶塢','陸龜蒙','唐','御定全唐诗','yuding','','[]','茗地曲隈回，野行多繚繞。向陽就中密，背澗差還少。',48,'御定全唐詩/json/620.json','["茗地曲隈回，野行多繚繞。向陽就中密，背澗差還少。", "遙盤雲髻慢，亂簇香篝小。何處好幽期，滿岩春露曉。"]'),
('yuding-47','奉和襲美茶具十詠：茶人','陸龜蒙','唐','御定全唐诗','yuding','','[]','天賦識靈草，自然鐘野姿。閑來北山下，似與東風期。',48,'御定全唐詩/json/620.json','["天賦識靈草，自然鐘野姿。閑來北山下，似與東風期。", "雨後探芳去，雲間幽路危。唯應報春鳥，得共斯人知。"]'),
('yuding-48','奉和襲美茶具十詠：茶筍','陸龜蒙','唐','御定全唐诗','yuding','','[]','所孕和氣深，時抽玉苕短。輕煙漸結華，嫩蕊初成管。',48,'御定全唐詩/json/620.json','["所孕和氣深，時抽玉苕短。輕煙漸結華，嫩蕊初成管。", "尋來青靄曙，欲去紅雲暖。秀色自難逢，傾筐不曾滿。"]'),
('yuding-49','奉和襲美茶具十詠：茶籝','陸龜蒙','唐','御定全唐诗','yuding','','[]','金刀劈翠筠，織似波文斜。製作自野老，攜持伴山娃。',48,'御定全唐詩/json/620.json','["金刀劈翠筠，織似波文斜。製作自野老，攜持伴山娃。", "昨日鬥煙粒，今朝貯綠華。爭歌調笑曲，日暮方還家。"]'),
('yuding-50','奉和襲美茶具十詠：茶舍','陸龜蒙','唐','御定全唐诗','yuding','','[]','旋取山上材，駕為山下屋。門因水勢斜，壁任岩隈曲。',48,'御定全唐詩/json/620.json','["旋取山上材，駕為山下屋。門因水勢斜，壁任岩隈曲。", "朝隨鳥俱散，暮與雲同宿。不憚采掇勞，只憂官未足。"]'),
('yuding-51','《奉和襲美茶具十詠：茶灶','陸龜蒙','唐','御定全唐诗','yuding','','[]','無突抱輕嵐，有煙映初旭。盈鍋玉泉沸，滿甑雲芽熟。',48,'御定全唐詩/json/620.json','["無突抱輕嵐，有煙映初旭。盈鍋玉泉沸，滿甑雲芽熟。", "奇香襲春桂，嫩色淩秋菊。煬者若吾徒，年年看不足。"]'),
('yuding-52','奉和襲美茶具十詠：茶焙','陸龜蒙','唐','御定全唐诗','yuding','','[]','左右搗凝膏，朝昏布煙縷。方圓隨樣拍，次第依層取。',48,'御定全唐詩/json/620.json','["左右搗凝膏，朝昏布煙縷。方圓隨樣拍，次第依層取。", "山謠縱高下，火候還文武。見說焙前人，時時炙花脯。"]'),
('yuding-53','奉和襲美茶具十詠：茶鼎','陸龜蒙','唐','御定全唐诗','yuding','','[]','新泉氣味良，古鐵形狀醜。那堪風雪夜，更值煙霞友。',48,'御定全唐詩/json/620.json','["新泉氣味良，古鐵形狀醜。那堪風雪夜，更值煙霞友。", "曾過赬石下，又住清溪口。且共薦皋盧，何勞傾鬥酒。"]'),
('yuding-54','奉和襲美茶具十詠：茶甌','陸龜蒙','唐','御定全唐诗','yuding','','[]','昔人謝塸埞，徒為妍詞飾。豈如珪璧姿，又有煙嵐色。',48,'御定全唐詩/json/620.json','["昔人謝塸埞，徒為妍詞飾。豈如珪璧姿，又有煙嵐色。", "光參筠席上，韻雅金罍側。直使于闐君，從來未嘗識。"]'),
('yuding-55','奉和襲美茶具十詠：煮茶','陸龜蒙','唐','御定全唐诗','yuding','','[]','閑來松間坐，看煮松上雪。時於浪花裏，並下藍英末。',48,'御定全唐詩/json/620.json','["閑來松間坐，看煮松上雪。時於浪花裏，並下藍英末。", "傾餘精爽健，忽似氛埃滅。不合別觀書，但宜窺玉劄。"]'),
('yuding-0','置酒行','陸龜蒙','唐','御定全唐诗','yuding','','[]','落塵花片排香痕，闌珊醉露棲愁魂。洞庭波色惜不得，',41,'御定全唐詩/json/621.json','["落塵花片排香痕，闌珊醉露棲愁魂。洞庭波色惜不得，", "安知寂寞西海頭，青pF未垂孤鳳餓。"]'),
('yuding-1','江湖散人歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','江湖散人天骨奇，短髮搔來蓬半垂。手提孤篁曳寒繭，',274,'御定全唐詩/json/621.json','["江湖散人天骨奇，短髮搔來蓬半垂。手提孤篁曳寒繭，", "夜棲止與禽獸雜，獨自構架縱橫枝。因而稱曰有巢氏，", "無端後聖穿鑿破，一派前導千流隨。多方惱亂元氣死，", "風波不獨困一士，凡百器具皆能施。罛疏滬腐鱸鱖脫，", "奴顏婢膝真乞丐，反以正直為狂癡。所以頭欲散，", "靜則守桑柘，亂則逃妻兒。金鑣貝帶未嘗識，", "大君年小丞相少，當軸自請都旌旗。神鋒悉出羽林仗，", "禁軍近自肅宗置，抑遏輔國爭雄雌。必然大段剪凶逆，", "歸來輒擬荷鋤笠，詬吏已責租錢遲。興師十萬一日費，", "均荒補敗豈無術，布在方冊撐頹隵。冰霜襦袴易反掌。", "白麵諸郎殊不知。江湖散人悲古道，悠悠幸寄羲皇傲。", "官家未議活蒼生，拜賜江湖散人號。"]'),
('yuding-2','五歌：放牛','陸龜蒙','唐','御定全唐诗','yuding','','[]','江草秋窮似秋半，十角吳牛放江岸。鄰肩抵尾乍依隈，',40,'御定全唐詩/json/621.json','["江草秋窮似秋半，十角吳牛放江岸。鄰肩抵尾乍依隈，", "日暮相將帶雨歸，田家煙火微茫濕。"]'),
('yuding-3','五歌：水鳥','陸龜蒙','唐','御定全唐诗','yuding','','[]','水鳥山禽雖異名，天工各與雙翅翎。雛巢吞啄即一例，',112,'御定全唐詩/json/621.json','["水鳥山禽雖異名，天工各與雙翅翎。雛巢吞啄即一例，", "為人羅絆取材力，韋鞲彩綬懸金鈴。三驅不以鳥捕鳥，", "鷗閑鶴散兩自遂，意思不受人丁寧。今朝棹倚寒江汀，", "婦女衣襟便佞舌，始得金籠日提挈。精神卓犖背人飛，", "殷勤謝汝莫相猜，歸來長短同群活。"]'),
('yuding-4','五歌：刈獲','陸龜蒙','唐','御定全唐诗','yuding','','[]','自春徂秋天弗雨，廉廉早稻才遮畝。芒粒稀疏熟更輕，',96,'御定全唐詩/json/621.json','["自春徂秋天弗雨，廉廉早稻才遮畝。芒粒稀疏熟更輕，", "凶年是物即為災，百陣野鳧千穴鼠。平明抱杖入田中，", "天職誰司下民籍，苟有區區宜析析。本作耕耘意若何，", "今之為政異當時，一任流離恣征索。平生幸遇華陽客，"]'),
('yuding-5','五歌：雨夜','陸龜蒙','唐','御定全唐诗','yuding','','[]','屋小茅幹雨聲大，自疑身著蓑衣臥。兼似孤舟小泊時，',40,'御定全唐詩/json/621.json','["屋小茅幹雨聲大，自疑身著蓑衣臥。兼似孤舟小泊時，", "背壁殘燈不及螢，重挑卻向燈前坐。"]'),
('yuding-6','五歌：食魚','陸龜蒙','唐','御定全唐诗','yuding','','[]','江南春旱魚無澤，歲晏未曾腥鼎鬲。今朝有客賣鱸魴，',48,'御定全唐詩/json/621.json','["江南春旱魚無澤，歲晏未曾腥鼎鬲。今朝有客賣鱸魴，", "且作吳羹助早餐，飽臥晴簷曝寒背。橫戈負羽正紛紛，"]'),
('yuding-7','丁隱君歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','華陽道士南游歸，手中半卷青蘿衣。自言逋客持贈我，',96,'御定全唐詩/json/621.json','["華陽道士南游歸，手中半卷青蘿衣。自言逋客持贈我，", "盤燒天竺春筍肥，琴倚洞庭秋石瘦。草堂暗引龍泓溜，", "去歲倡狂有黃寇，官軍解散無人鬥。滿城奔迸翰之閑，", "今來利作采樵客，可以拋身麋鹿群。丁隱君，丁隱君，"]'),
('yuding-8','紫溪翁歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','一丘之木，其棲深也屋，吾容不辱；一溪之石，',21,'御定全唐詩/json/621.json','["一丘之木，其棲深也屋，吾容不辱；一溪之石，"]'),
('yuding-9','賡歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','采江之魚兮，朝船有鱸。采江之蔬兮，暮筐有蒲。',42,'御定全唐詩/json/621.json','["采江之魚兮，朝船有鱸。采江之蔬兮，暮筐有蒲。", "左圖且書，右琴與壺。壽歟夭歟，貴歟賤歟。"]'),
('yuding-10','鶴媒歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','偶系漁舟汀樹枝，因看射鳥令人悲。盤空野鶴忽然下，',91,'御定全唐詩/json/621.json','["偶系漁舟汀樹枝，因看射鳥令人悲。盤空野鶴忽然下，", "裴回未忍過南塘，且應同聲就同類。梳翎宛若相逢喜，", "媒歡舞躍勢離披，似諂功能邀弩兒。雲飛水宿各自物，", "君不見荒陂野鶴陷良媒，同類同聲真可畏。"]'),
('yuding-11','慶封宅古井行','陸龜蒙','唐','御定全唐诗','yuding','','[]','古甓團團蘚花碧，鼎渫寒泉深百尺。江南戴白盡能言，',88,'御定全唐詩/json/621.json','["古甓團團蘚花碧，鼎渫寒泉深百尺。江南戴白盡能言，", "雖過魯國羞魯儒，欲弄吳民竊吳柄。吳分岩邑號朱方，", "一朝雲夢圍兵至，胸陷鋒鋩腦塗地。因知富德不富財，", "今歌此井示吳人，斷綆沉瓶自茲始。"]'),
('yuding-12','小雞山樵人歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','長其船兮利其斧，輸予薪兮勿予侮。田予登兮榖予庾，',24,'御定全唐詩/json/621.json','["長其船兮利其斧，輸予薪兮勿予侮。田予登兮榖予庾，"]'),
('yuding-13','吳俞兒舞歌：劍俞','陸龜蒙','唐','御定全唐诗','yuding','','[]','枝月喉，棹霜脊，北斗離離在寒碧。龍魂清，虎尾白，',60,'御定全唐詩/json/621.json','["枝月喉，棹霜脊，北斗離離在寒碧。龍魂清，虎尾白，", "四睨之人股佶栗，欲定不定定不得。舂牘殘，兒且止。", "狄胡有膽大如山，怖亦死。"]'),
('yuding-14','吳俞兒舞歌：矛俞','陸龜蒙','唐','御定全唐诗','yuding','','[]','手盤風，頭背分，電光戰扇，欲刺敲心留半線。',62,'御定全唐詩/json/621.json','["手盤風，頭背分，電光戰扇，欲刺敲心留半線。", "纏肩繞脰，dl合眩旋，卓植赴列，奪避中節。", "前沖函禮穴，上指孛彗滅，與君一用來有截。"]'),
('yuding-15','弩俞','陸龜蒙','唐','御定全唐诗','yuding','','[]','牛來開弦，人為置鏃。捩機關，迸山谷，鹿駭澀，隼擊遲。',69,'御定全唐詩/json/621.json','["牛來開弦，人為置鏃。捩機關，迸山谷，鹿駭澀，隼擊遲。", "析毫中睫，洞腋分龜。達堅壘，殘雄師，可以冠猛樂壯曲。", "抑揚蹈厲，有裂犀兕之氣者，非公與？"]'),
('yuding-16','句曲山朝真詞二首：迎真','陸龜蒙','唐','御定全唐诗','yuding','','[]','九華磬答寒泉急，十絕幡搖翠微濕。司命旍旌未下來，',40,'御定全唐詩/json/621.json','["九華磬答寒泉急，十絕幡搖翠微濕。司命旍旌未下來，", "空洞靈章發一聲，春來萬壑煙花醒。"]'),
('yuding-17','句曲山朝真詞二首：送真','陸龜蒙','唐','御定全唐诗','yuding','','[]','縈雲鳳髻飄然解，玉鉞玄幹儼先邁。朝真弟子悄無言，',40,'御定全唐詩/json/621.json','["縈雲鳳髻飄然解，玉鉞玄幹儼先邁。朝真弟子悄無言，", "萬象銷沉一瞬間，空餘月外聞殘佩。"]'),
('yuding-18','戰秋辭','陸龜蒙','唐','御定全唐诗','yuding','','[]','八月空堂，前臨隙荒。抽關散扇，晨烏未光。左右物態，',260,'御定全唐詩/json/621.json','["八月空堂，前臨隙荒。抽關散扇，晨烏未光。左右物態，", "槁艾矢束，矯蔓弦張。蛙合助吹，鳥分啟行。", "若革進而金止，固違陰而就陽。無何，雲顏師，風旨伯。", "蒼茫慘澹，隳危摵劃。煙蒙上焚，雨陣下棘。如濠者注，", "如矢者僕，如弦者磔；如吹者喑，如行者惕。", "石有發兮盡累，木有耳兮咸馘。雲風雨煙，乘勝之勢驕；", "杉篁蕉蔓，敗北之氣摵。天隨子曰：籲，秋無神則已，", "昨宇今燼，朝人暮屍。萬犢一啖，千倉一炊。擾踐邊朔，", "凶渠歌笑，裂地無疑。天有四序，秋為司刑。少昊負扆，", "可塹溺顛陷，可夭劄迷冥。曾忘鏖剪，自意澄寧。", "苟蠟禮之雲責，觸天怒而誰丁，奈何欺荒庭？淩壞砌，"]'),
('yuding-19','祝牛宮辭','陸龜蒙','唐','御定全唐诗','yuding','','[]','四牸三牯，中一去乳。天霜降寒，納此室處。',110,'御定全唐詩/json/621.json','["四牸三牯，中一去乳。天霜降寒，納此室處。", "老農拘拘，度地不畝。東西幾何，七舉其武。", "南北幾何，丈二加五。偶楹當閑，載尺入土。", "太歲在亥，餘不足數。上締蓬茅，下遠官府。", "耕耨以時，飲食得所。或寢或臥，免風免雨。", "宜爾子孫，實我倉庾。"]'),
('yuding-20','迎潮送潮辭：迎潮','陸龜蒙','唐','御定全唐诗','yuding','','[]','江霜嚴兮楓葉丹，潮聲高兮墟落寒。鷗巢卑兮漁箔短，',61,'御定全唐詩/json/621.json','["江霜嚴兮楓葉丹，潮聲高兮墟落寒。鷗巢卑兮漁箔短，", "密幽人兮款柴門，寂寞流連兮依稀舊痕。", "濡腴澤槁兮潮之恩，不屍其功兮歸於混元。"]'),
('yuding-21','迎潮送潮辭：送潮','陸龜蒙','唐','御定全唐诗','yuding','','[]','潮西來兮又東下，日染中流兮紅灑灑。汀葭蒼兮嶼蓼枯，',49,'御定全唐詩/json/621.json','["潮西來兮又東下，日染中流兮紅灑灑。汀葭蒼兮嶼蓼枯，", "愛長波兮數數，一幅巾兮無纓可濯。帆生塵兮楫有衣，"]'),
('yuding-22','問吳宮辭','陸龜蒙','唐','御定全唐诗','yuding','','[]','彼吳之宮兮江之那涯，複道盤兮當高且斜。',43,'御定全唐詩/json/621.json','["彼吳之宮兮江之那涯，複道盤兮當高且斜。", "波搖疏兮霧蒙箔，菡萏國兮鴛鴦家。鸞之簫兮蛟之瑟，"]'),
('yuding-0','螢詩','陸龜蒙','唐','御定全唐诗','yuding','','[]','肖翹雖振羽，戚促盡疑冰。風助流還急，煙遮點漸凝。',48,'御定全唐詩/json/622.json','["肖翹雖振羽，戚促盡疑冰。風助流還急，煙遮點漸凝。", "不須輕列宿，才可擬孤燈。莫倚隋家事，曾煩下詔征。"]'),
('yuding-1','蟬','陸龜蒙','唐','御定全唐诗','yuding','','[]','只憑風作使，全仰柳為都。一腹清何甚，雙翎薄更無。',48,'御定全唐詩/json/622.json','["只憑風作使，全仰柳為都。一腹清何甚，雙翎薄更無。", "伴貂金換酒，並雀畫成圖。恐是千年恨，偏令落日呼。"]'),
('yuding-2','秋熱','陸龜蒙','唐','御定全唐诗','yuding','','[]','自惜秋捐扇，今來意未衰。殷勤付柔握，淅瀝待清吹。',48,'御定全唐詩/json/622.json','["自惜秋捐扇，今來意未衰。殷勤付柔握，淅瀝待清吹。", "午氣朱崖近，宵聲白羽隨。總如南國候，無複婕妤悲。"]'),
('yuding-3','村中晚望','陸龜蒙','唐','御定全唐诗','yuding','','[]','抱杖柴門立，江村日易斜。雁寒猶憶侶，人病更離家。',48,'御定全唐詩/json/622.json','["抱杖柴門立，江村日易斜。雁寒猶憶侶，人病更離家。", "短鬢看成雪，雙眸舊有花。何須萬里外，即此是天涯。"]'),
('yuding-4','四明山詩：石窗','陸龜蒙','唐','御定全唐诗','yuding','','[]','石窗何處見，萬仞倚晴虛。積靄迷青瑣，殘霞動綺疏。',48,'御定全唐詩/json/622.json','["石窗何處見，萬仞倚晴虛。積靄迷青瑣，殘霞動綺疏。", "山應列圓嶠，宮便接方諸。只有三奔客，時來教隱書。"]'),
('yuding-5','四明山詩：過雲','陸龜蒙','唐','御定全唐诗','yuding','','[]','相訪一程雲，雲深路僅分。嘯台隨日辨，樵斧帶風聞。',48,'御定全唐詩/json/622.json','["相訪一程雲，雲深路僅分。嘯台隨日辨，樵斧帶風聞。", "曉著衣全濕，寒沖酒不醺。幾回歸思靜，仿佛見蘇君。"]'),
('yuding-6','四明山詩：雲南','陸龜蒙','唐','御定全唐诗','yuding','','[]','雲南更有溪，丹礫盡無泥。藥有巴賨賣，枝多越鳥啼。',49,'御定全唐詩/json/622.json','["雲南更有溪，丹礫盡無泥。藥有巴賨賣，枝多越鳥啼。", "夜清先月午，秋近少嵐迷。若得山顏住，芝zC手自攜。"]'),
('yuding-7','四明山詩：雲北','陸龜蒙','唐','御定全唐诗','yuding','','[]','雲北是陽川，人家洞壑連。壇當星斗下，樓拶翠微邊。',48,'御定全唐詩/json/622.json','["雲北是陽川，人家洞壑連。壇當星斗下，樓拶翠微邊。", "一半遙峰雨，三條古井煙。金庭如有路，應到左神天。"]'),
('yuding-8','四明山詩：鹿亭','陸龜蒙','唐','御定全唐诗','yuding','','[]','鹿亭岩下置，時領白麛過。草細眠應久，泉香飲自多。',48,'御定全唐詩/json/622.json','["鹿亭岩下置，時領白麛過。草細眠應久，泉香飲自多。", "認聲來月塢，尋跡到煙蘿。早晚吞金液，騎將上絳河。"]'),
('yuding-9','四明山詩：樊榭','陸龜蒙','唐','御定全唐诗','yuding','','[]','樊榭何年築，人應白日飛。至今山客說，時駕玉麟歸。',48,'御定全唐詩/json/622.json','["樊榭何年築，人應白日飛。至今山客說，時駕玉麟歸。", "乳蒂緣松嫩，芝台出石微。憑欄虛目斷，不見羽華衣。"]'),
('yuding-10','四明山詩：潺湲洞','陸龜蒙','唐','御定全唐诗','yuding','','[]','石淺洞門深，潺潺萬古音。似吹雙羽管，如奏落霞琴。',48,'御定全唐詩/json/622.json','["石淺洞門深，潺潺萬古音。似吹雙羽管，如奏落霞琴。", "倒穴漂龍沫，穿松濺鶴襟。何人乘月弄，應作上清吟。"]'),
('yuding-11','四明山詩：青欞子','陸龜蒙','唐','御定全唐诗','yuding','','[]','山實號青欞，環岡次第生。外形堅綠殼，中味敵璚英。',48,'御定全唐詩/json/622.json','["山實號青欞，環岡次第生。外形堅綠殼，中味敵璚英。", "墮石樵兒拾，敲林宿鳥驚。亦應仙吏守，時取薦層城。"]'),
('yuding-12','四明山詩：鞠侯','陸龜蒙','唐','御定全唐诗','yuding','','[]','何事鞠侯名，先封在四明。但為連臂飲，不作斷腸聲。',48,'御定全唐詩/json/622.json','["何事鞠侯名，先封在四明。但為連臂飲，不作斷腸聲。", "野蔓垂纓細，寒泉佩玉清。滿林遊宦子，誰為作君卿。"]'),
('yuding-13','奉和襲美贈魏處士五貺詩：五瀉舟','陸龜蒙','唐','御定全唐诗','yuding','','[]','樣自桐川得，詞因隱地成。好漁翁亦喜，新白鳥還驚。',48,'御定全唐詩/json/622.json','["樣自桐川得，詞因隱地成。好漁翁亦喜，新白鳥還驚。", "沙際擁江沫，渡頭橫雨聲。尚應嫌越相，遺禍不遺名。"]'),
('yuding-14','奉和襲美贈魏處士五貺詩：華頂杖','陸龜蒙','唐','御定全唐诗','yuding','','[]','萬古陰崖雪，靈根不為枯。瘦於霜鶴脛，奇似黑龍須。',48,'御定全唐詩/json/622.json','["萬古陰崖雪，靈根不為枯。瘦於霜鶴脛，奇似黑龍須。", "拄訪譚玄客，持看潑墨圖。湖雲如有路，兼可到仙都。"]'),
('yuding-15','奉和襲美贈魏處士五貺詩：太湖硯','陸龜蒙','唐','御定全唐诗','yuding','','[]','誰截小秋灘，閑窺四緒寬。繞為千嶂遠，深置一潭寒。',48,'御定全唐詩/json/622.json','["誰截小秋灘，閑窺四緒寬。繞為千嶂遠，深置一潭寒。", "坐久雲應出，詩成墨未幹。不知新博物，何處擬重刊。"]'),
('yuding-16','奉和襲美贈魏處士五貺詩：烏龍養和','陸龜蒙','唐','御定全唐诗','yuding','','[]','養和名字好，偏寄道情深。所以親逋客，兼能助五禽。',48,'御定全唐詩/json/622.json','["養和名字好，偏寄道情深。所以親逋客，兼能助五禽。", "倚肩滄海望，鉤膝白雲吟。不是逍遙侶，誰知世外心。"]'),
('yuding-17','奉和襲美贈魏處士五貺詩：訶陵尊','陸龜蒙','唐','御定全唐诗','yuding','','[]','魚骼匠成尊，猶殘海浪痕。外堪欺玳瑁，中可酌昆侖。',48,'御定全唐詩/json/622.json','["魚骼匠成尊，猶殘海浪痕。外堪欺玳瑁，中可酌昆侖。", "水繞苔磯曲，山當草閣門。此中醒複醉，何必問乾坤。"]'),
('yuding-18','奉酬襲美早春病中書事','陸龜蒙','唐','御定全唐诗','yuding','','[]','只貪詩調苦，不計病容生。我亦休文瘦，君能叔寶清。',48,'御定全唐詩/json/622.json','["只貪詩調苦，不計病容生。我亦休文瘦，君能叔寶清。", "藥須勤一服，春莫累多情。欲入毗耶問，無人敵淨名。"]'),
('yuding-19','又酬次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','從來多遠思，尤向靜中生。所以令心苦，還應是骨清。',48,'御定全唐詩/json/622.json','["從來多遠思，尤向靜中生。所以令心苦，還應是骨清。", "酒香偏入夢，花落又關情。積此風流事，爭無後世名。"]'),
('yuding-20','奉酬襲美秋晚見題二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','為愛晚窗明，門前亦懶行。圖書看得熟，鄰里見還生。',96,'御定全唐詩/json/622.json','["為愛晚窗明，門前亦懶行。圖書看得熟，鄰里見還生。", "鳥啄琴材響，僧傳藥味精。緣君多古思，攜手上空城。", "何事樂漁樵，巾車或倚橈。和詩盈古篋，賒酒半寒瓢。", "失雨園蔬赤，無風蚛葉凋。清言一相遺，吾道未全消。"]'),
('yuding-21','奉和襲美初冬章上人院','陸龜蒙','唐','御定全唐诗','yuding','','[]','每伴來方丈，還如到四禪。菊承荒砌露，茶待遠山泉。',48,'御定全唐詩/json/622.json','["每伴來方丈，還如到四禪。菊承荒砌露，茶待遠山泉。", "畫古全無跡，林寒卻有煙。相看吟未竟，金磬已泠然。"]'),
('yuding-22','襲美見題郊居十首，因次韻酬之以伸榮謝','陸龜蒙','唐','御定全唐诗','yuding','','[]','近來唯樂靜，移傍故城居。閑打修琴料，時封謝藥書。',480,'御定全唐詩/json/622.json','["近來唯樂靜，移傍故城居。閑打修琴料，時封謝藥書。", "夜停江上鳥，晴曬篋中魚。出亦圖何事，無勞置棧車。", "倩人醫病樹，看僕補衡茅。散發還同阮，無心敢慕巢。", "簡便書露竹，尊待破霜匏。日好林間坐，煙蘿近欲交。", "倭僧留海紙，山匠制雲床。懶外應無敵，貧中直是王。", "池平鷗思喜，花盡蝶情忙。欲問新秋計，菱絲一畝強。", "故山空自擲，當路竟誰知。只有經時策，全無養拙資。", "病深憐灸客，炊晚信樵兒。謾欲陳風俗，周官未采詩。", "福地能容塹，玄關詎有扉。靜思瓊版字，閑洗鐵筇衣。", "鳥破涼煙下，人沖暮雨歸。故園秋草夢，猶記綠微微。", "水影沉魚器，鄰聲動緯車。燕輕捎墜葉，蜂懶臥燋花。", "說史評諸例，論兵到百家。明時如不用，歸去種桑麻。", "禹穴奇編缺，雷平異境殘。靜吟封籙檢，歸興削帆竿。", "白石堪為飯，青蘿好作冠。幾時當斗柄，同上步罡壇。", "強起披衣坐，徐行處暑天。上階來鬥雀，移樹去驚蟬。", "莫問鹽車駿，誰看醬瓿玄。黃金如可化，相近買雲泉。", "野入青蕪巷，陂侵白竹門。風高開栗刺，沙淺露芹根。", "迸鼠緣藤桁，饑烏立石盆。東吳雖不改，誰是武王孫。", "疏慵真有素，時勢盡無能。風月雖為敵，林泉幸未憎。", "酒材經夏闕，詩債待秋徴。只有君同癖，閑來對曲肱。"]'),
('yuding-23','和張廣文賁旅泊吳門次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','高秋能叩觸，天籟忽成文。苦調雖潛倚，靈音自絕群。',48,'御定全唐詩/json/622.json','["高秋能叩觸，天籟忽成文。苦調雖潛倚，靈音自絕群。", "茅峰曾醮鬥，笠澤久眠雲。許伴山中躅，三年任一醺。"]'),
('yuding-24','又次前韻酬廣文','陸龜蒙','唐','御定全唐诗','yuding','','[]','獨倚秋光岸，風漪學簟文。玄堪教鳳集，書好換鵝群。',48,'御定全唐詩/json/622.json','["獨倚秋光岸，風漪學簟文。玄堪教鳳集，書好換鵝群。", "葉墮平臺月，香消古徑雲。強歌非白紵，聊以送餘醺。"]'),
('yuding-25','送延陵張宰','陸龜蒙','唐','御定全唐诗','yuding','','[]','春盡未離關，之官亦似閑。不嫌請薄俸，為喜帶名山。',48,'御定全唐詩/json/622.json','["春盡未離關，之官亦似閑。不嫌請薄俸，為喜帶名山。", "默禱三真後，高吟十字還。只應江上鳥，時下訟庭間。"]'),
('yuding-26','送人罷官歸茅山','陸龜蒙','唐','御定全唐诗','yuding','','[]','呼僮曉拂鞍，歸上大茅端。薄俸雖休入，明霞自足餐。',48,'御定全唐詩/json/622.json','["呼僮曉拂鞍，歸上大茅端。薄俸雖休入，明霞自足餐。", "暗霜松粒赤，疏雨草堂寒。又鑿中峰石，重修醮月壇。"]'),
('yuding-27','立春日','陸龜蒙','唐','御定全唐诗','yuding','','[]','去年花落時，題作送春詩。自為重相見，應無今日悲。',48,'御定全唐詩/json/622.json','["去年花落時，題作送春詩。自為重相見，應無今日悲。", "道孤逢識寡，身病買名遲。一夜東風起，開簾不敢窺。"]'),
('yuding-28','中秋夜寄友生','陸龜蒙','唐','御定全唐诗','yuding','','[]','秋來一度滿，重見色難齊。獨坐猶過午，同吟不到西。',48,'御定全唐詩/json/622.json','["秋來一度滿，重見色難齊。獨坐猶過午，同吟不到西。", "疏芒唯鬥在，殘白合河迷。更憶前年望，孤舟泊大溪。"]'),
('yuding-0','奉和襲美古杉三十韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','眾木盡相遺，孤芳獨任奇。鍤天形硉兀，當殿勢俯危。',362,'御定全唐詩/json/623.json','["眾木盡相遺，孤芳獨任奇。鍤天形硉兀，當殿勢俯危。", "恐是誇娥怒，教臨嶻嶭衰。節穿開耳目，根癭坐熊羆。", "世只論榮落，人誰問等衰。有巔從日上，無葉與秋欺。", "虎搏應難動，雕蹲不敢遲。戰鋒新缺齾，燒岸黑bO黧。", "鬥死龍骸雜，爭奔鹿角差。肢銷洪水腦，棱聳梵天眉。", "磔索珊瑚湧，森嚴獬豸窺。向空分犖指，衝浪出鯨鬐。", "楊僕船橦在，蚩尤陣纛隳。下連金粟固，高用鐵菱披。", "挺若苻堅棰，浮于祖納椎。崢嶸驚露鶴，bp趚閡雲螭。", "傍宇將支壓，撐霄欲抵隵。背交蟲臂挶，相向鶻拳追。", "格筆差猶立，階幹卓未麾。鬼神應暗畫，風雨恐潛移。", "已覺寒松伏，偏宜後土疲。好邀清嘯傲，堪映古茅茨。", "材大應容蠍，年深必孕夔。後雕依佛氏，初植必僧彌。", "擁腫煩莊辯，槎牙費庾詞。詠多靈府困，搜苦化權卑。", "類既區中寡，朋當物外推。蟠桃標日域，珠草侍仙墀。", "真宰誠求夢，春工幸可醫。若能噓嶰竹，猶足動華滋。"]'),
('yuding-1','奉和襲美新秋言懷三十韻次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','身閑唯愛靜，籬外是荒郊。地僻憐同巷，庭喧厭累巢。',362,'御定全唐詩/json/623.json','["身閑唯愛靜，籬外是荒郊。地僻憐同巷，庭喧厭累巢。", "岸聲搖舴艋，窗影辨蠨蛸。徑只溪禽下，關唯野客敲。", "竹岡從古凸，池緣本來bn。早藕擎霜節，涼花束紫梢。", "漁情隨錘網，獵興起鳴髇。好夢經年說，名方著處抄。", "才疏惟自補，技癢欲誰抓。窗靜常懸dO，鞭閑不正鞘。", "山衣輕斧藻，天籟逸弦匏。蕙轉風前帶，桃烘雨後膠。", "蘚幹黏晚砌，煙濕動晨庖。沉約便圖籍，揚雄重酒肴。", "目曾窺絕洞，耳不犯征鐃。曆外窮飛朔，蓍中記伏爻。", "石林空寂曆，雲肆肯嘵譊。松桂何妨蠹，龜龍亦任嘲。", "未能丹作髓，誰相紫為胞。莫把榮枯異，但和大小包。", "由弓猿不捷，梁圈虎忘虓。舊友懷三益，關山阻二崤。", "道隨書簏古，時共釣輪拋。好作忘機士，須為莫逆交。", "看君馳諫草，憐我臥衡茅。出處雖冥默，熏蕕肯溷殽。", "岸沙從鶴印，崖蜜勸人摷。白菌盈枯枿，黃精滿綠筲。", "仙因隱居信，禪是淨名教。勿謂江湖永，終浮一大瓟。"]'),
('yuding-2','和襲美江南書情二十韻寄祕閣韋校書貽之商洛宋先輩垂文二同年次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','我志如魚樂，君詞稱鳳銜。暫來從露冕，何事買雲岩。',240,'御定全唐詩/json/623.json','["我志如魚樂，君詞稱鳳銜。暫來從露冕，何事買雲岩。", "水石應容病，松篁未聽讒。罐香松蠹膩，山信藥苗緘。", "愛鷺欹危立，思猿矍鑠獑。謝才偏許脁，阮放最憐咸。", "大樂寧忘缶，奇工肯顧瑊。客愁迷舊隱，鷹健想秋毚。", "硯缺猶慵琢，文繁卻要芟。雨餘幽沼淨，霞散遠峰巉。", "洗筆煙成段，培花土作杴。訪僧還覓伴，醫鶴自須監。", "荒廟猶懷季，清灘幾夢嚴。背風開蠹簡，衝浪試新帆。", "悶憶年支酒，閑裁古樣衫。釣家隨野舫，仙蘊逐雕函。", "度歲賒羸馬，先春買小螊。共疏泉入竹，同坐月過杉。", "染翰窮高致，懷賢發至諴。不堪潘子鬢，愁促易髟髟。"]'),
('yuding-3','憶襲美洞庭觀步奉和次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','聞君遊靜境，雅具更摐摐。竹傘遮雲徑，藤鞋踏蘚矼。',120,'御定全唐詩/json/623.json','["聞君遊靜境，雅具更摐摐。竹傘遮雲徑，藤鞋踏蘚矼。", "杖斑花不一，尊大癭成雙。水鳥行沙嶼，山僧禮石幢。", "已甘三秀味，誰念百牢腔。遠棹投何處，殘陽到幾窗。", "仙謠珠樹曲，村餉白醅缸。地裏方吳會，人風似冉厖。", "探幽非遁世，尋勝肯迷邦。為讀江南傳，何賢過二龐。"]'),
('yuding-4','江墅言懷','陸龜蒙','唐','御定全唐诗','yuding','','[]','病身兼稚子，田舍劣相容。跡共公卿絕，貧須稼穡供。',120,'御定全唐詩/json/623.json','["病身兼稚子，田舍劣相容。跡共公卿絕，貧須稼穡供。", "月方行到閏，霜始近言濃。樹少棲禽雜，村孤守犬重。", "汀洲藏晚弋，籬落露寒舂。野弁欹還整，家書拆又封。", "杉篁宜夕照，窗戶倚疏鐘。南北唯聞戰，縱橫未勝農。", "大春雖苦學，叔夜本多慵。直使貂裘弊，猶堪過一冬。"]'),
('yuding-5','自和次前韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','命既時相背，才非世所容。著書糧易絕，多病藥難供。',120,'御定全唐詩/json/623.json','["命既時相背，才非世所容。著書糧易絕，多病藥難供。", "夢為懷山數，愁因戒酒濃。鳥媒呈不一，魚寨下仍重。", "晚桁蓑兼褐，晴簷織帶舂。著簽分水味，標石認田封。", "此地家三戶，何人祿萬鐘。草堂聊當貴，金穴任輕農。", "把釣竿初冷，題詩筆未慵。莫憂寒事晚，江上少嚴冬。"]'),
('yuding-6','秋日遣懷十六韻寄道侶','陸龜蒙','唐','御定全唐诗','yuding','','[]','盡日臨風坐，雄詞妙略兼。共知時世薄，甯恨歲華淹。',192,'御定全唐詩/json/623.json','["盡日臨風坐，雄詞妙略兼。共知時世薄，甯恨歲華淹。", "且把靈方試，休憑吉夢占。夜然燒汞火，朝煉洗金鹽。", "有路求真隱，無媒舉孝廉。自然成嘯傲，不是學沉潛。", "水恨同心隔，霜愁兩鬢沾。鶴屏憐掩扇，烏帽愛垂簷。", "雅調宜觀樂，清才稱典簽。冠俯玄發少，書健紫毫尖。", "故疾因秋召，塵容畏日黔。壯圖須行行，儒服謾襜襜。", "片石聊當枕，橫煙欲代簾。蠹根延穴蟻，疏葉漏庭蟾。", "藥鼎高低鑄，雲庵早晚苫。胡麻如重寄，從誚我無厭。"]'),
('yuding-7','京口與友生話別','陸龜蒙','唐','御定全唐诗','yuding','','[]','共是悲秋客，相逢恨不堪。雁頻辭薊北，人尚在江南。',361,'御定全唐詩/json/623.json','["共是悲秋客，相逢恨不堪。雁頻辭薊北，人尚在江南。", "名利機初發，樵漁事先諳。松門穿戴寺，荷徑繞秦潭。", "繩檢真難束，疏慵卻易耽。枕當高樹穩，茶試遠泉甘。", "架上經唯一，尊前雅只三。風雲勞夢想，天地人醺酣。", "曆自堯階數，書因禹穴探。禦龍雖世祿，下馬亦清譚。", "國計徒盈策，家儲不滿甔。斷簾從燕出，俯弁請人簪。", "木墜涼來葉，山橫霽後嵐。竹窗深窈窕，苔洞綠龕弇。", "積行依顏子，和光則老聃。杖誠為虎節，披信作鮫函。", "養鷺看窺沼，尋僧助結庵。功名思馬援，歌唱咽羊曇。", "乞食羞孤鳳，無衣羨八蠶。系帆留宿客，吟句任羸驂。", "寵鶴空無衛，占烏未見gm。香還須是桂，青會出於藍。", "蜀酒時傾瓿，吳蝦遍發坩。玉封千挺藕，霜閉一筒柑。", "惜佩終邀禍，辭環好激貪。宗溟雖畎澮，成廈必楩楠。", "碧玉雕琴薦，黃金飾劍鐔。煙緣莎砌引，水為藥畦擔。", "博物君能繼，多才我尚慚。別離猶得在，秋鬢未鬖鬖。"]'),
('yuding-8','丹陽道中寄友生','陸龜蒙','唐','御定全唐诗','yuding','','[]','煙樹綠微微，春流浸竹扉。短蓑攜稚去，孤艇載魚歸。',96,'御定全唐詩/json/623.json','["煙樹綠微微，春流浸竹扉。短蓑攜稚去，孤艇載魚歸。", "海俗蘆編室，村娃練束衣。舊栽奴橘老，新刈女桑肥。", "錦鯉沖風擲，絲禽掠浪飛。短亭幽徑入，陳廟數峰圍。", "地廢金牛暗，陵荒石獸稀。思君同一望，帆上怨餘暉。"]'),
('yuding-9','寄茅山何道士','陸龜蒙','唐','御定全唐诗','yuding','','[]','終身持玉舄，丹訣未應傳。況是曾同宿，相違便來年。',120,'御定全唐詩/json/623.json','["終身持玉舄，丹訣未應傳。況是曾同宿，相違便來年。", "問顏知更少，聽話想逾玄。古籙文垂露，新金汞絕煙。", "蜂供和餌蜜，人寄買溪錢。紫燕長巢硐，青龜忽上蓮。", "篋藏征隱詔，囊佩攝生篇。圃暖芝台秀，岩春乳管圓。", "池棲子孫鶴，堂宿弟兄仙。幸閱靈書次，心期賜一編。"]'),
('yuding-10','江南秋懷寄華陽山人','陸龜蒙','唐','御定全唐诗','yuding','','[]','櫛發涼天曙，含毫故國情。歸心一夜極，病體九秋輕。',577,'御定全唐詩/json/623.json','["櫛發涼天曙，含毫故國情。歸心一夜極，病體九秋輕。", "忽起襜褕詠，因悲絡緯鳴。逢山即堪隱，何路可圖榮。", "揲策空占命，持竿不釣名。忘憂如有待，縱懶似無營。", "小徑才分草，斜扉劣辨荊。冷荷承露菂，疏菊臥煙莖。", "譜為聽琴閱，圖緣看海幀。鷺毛浮島白，魚尾撇波赬。", "庭橘低攀嗅，園葵旋折烹。餓烏窺食案，鬥鼠落書棚。", "種豆悲楊惲，投瓜憶衛旍。東林誰處士，南郭自先生。", "分野星多蹇，連山卦少亨。衣裾徒博大，文籍漫縱橫。", "蘭葉騷人佩，蓴絲內史羹。鶡冠難適越，羊酪未饒傖。", "倚嘯微抽恨，論玄好析酲。棲遲勞鼓篋，豪俠愛金籝。", "煉藥傳丹鼎，嘗茶試石bP。沼連枯葦暗，窗對脫梧明。", "未達譏張翰，非才嫉禰衡。遠懷魂易黯，幽憤骨堪驚。", "礪缺知矛利，磨瑕見璧瑛。道源疏滴瀝，儒肆售精誠。", "敢歎良時擲，猶勝亂世攖。相秦猶幾死，王漢尚當黥。", "飲啄期應定，窮通勢莫爭。髡鉗為皂隸，譚笑得公卿。", "浴日安知量，追風不計程。塵埃張耳分，肝膽季心傾。", "諭蜀專操檄，通甌獨請纓。匹夫能曲踴，萬騎可橫行。", "許國輕妻子，防邊重戰耕。俄分上尊酒，驟厭五侯鯖。", "靜默供三語，從容等一枰。弘深司馬法，雄傑貳師兵。", "朔雪埋烽燧，寒笳裂旆旌。乘時收句注，即日掃欃槍。", "武昔威殊俗，文今被八弦。琮璜陳始畢，韶夏教初成。", "芽孽群妖滅，松筠百度貞。郎官青瑣拜，使者繡衣迎。", "帝道將雲辟，澆波漸砥平。學徒羞說霸，佳士恥為跉。", "負杖歌棲畝，操觚賦北征。才當曹鬥怯，書比惠車盈。"]'),
('yuding-11','送宣武從事越中按獄','陸龜蒙','唐','御定全唐诗','yuding','','[]','曉看呈使範，知欲敕星軺。水國難驅傳，山城便倚橈。',96,'御定全唐詩/json/623.json','["曉看呈使範，知欲敕星軺。水國難驅傳，山城便倚橈。", "秉籌先獨立，持法稱高標。旌旆臨危堞，金絲發麗譙。", "別愁當翠巘，冤望隔風潮。木落孤帆迥，江寒疊鼓飄。", "客鴻吳島盡，殘雪剡汀消。坐想休秦獄，春應到柳條。"]'),
('yuding-12','江南冬至和人懷洛下','陸龜蒙','唐','御定全唐诗','yuding','','[]','昔居清洛涯，長恨苦寒遲。自作江南客，稀遲下雪時。',72,'御定全唐詩/json/623.json','["昔居清洛涯，長恨苦寒遲。自作江南客，稀遲下雪時。", "有煙棲菊梗，無凍落杉枝。背日能尋徑，臨風尚覆棋。", "鳥聲渾欲轉，草邑固應知。與看平湖上，東流或片澌。"]'),
('yuding-13','謹和諫議罷郡敘懷六韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','已報東吳政，初捐左契歸。天應酬苦節，人不犯寒威。',72,'御定全唐詩/json/623.json','["已報東吳政，初捐左契歸。天應酬苦節，人不犯寒威。", "江上思重借，朝端望載饑。紫泥封夜詔，金殿賜春衣。", "對酒情何遠，裁詩思極微。待升熔造日，江海問漁扉。"]'),
('yuding-0','二遺詩','陸龜蒙','唐','御定全唐诗','yuding','','[]','誰從毫末見參天，又到蒼蒼化石年。萬古清風吹作籟，',40,'御定全唐詩/json/624.json','["誰從毫末見參天，又到蒼蒼化石年。萬古清風吹作籟，", "幸與野人俱散誕，不煩良匠更雕鐫。"]'),
('yuding-1','鵁鶄','陸龜蒙','唐','御定全唐诗','yuding','','[]','詞賦曾誇鸀鳿流，果為名誤別滄洲。雖蒙靜置疏籠晚，',40,'御定全唐詩/json/624.json','["詞賦曾誇鸀鳿流，果為名誤別滄洲。雖蒙靜置疏籠晚，", "防徽避繳無窮事，好與裁書謝白鷗。"]'),
('yuding-2','新秋月夕，客有自遠相尋者，作吳體二首以贈','陸龜蒙','唐','御定全唐诗','yuding','','[]','風初寥寥月乍滿，杉篁左右供餘清。因君一話故山事，',80,'御定全唐詩/json/624.json','["風初寥寥月乍滿，杉篁左右供餘清。因君一話故山事，", "日聞羽檄日夜急，掉臂欲歸岩下行。", "驚聞遠客訪良夜，扶病起坐綸巾欹。清談白紵思悄悄，", "林端片月落未落，強慰別情言後期。"]'),
('yuding-3','閒書','陸龜蒙','唐','御定全唐诗','yuding','','[]','病學高僧置一床，披衣才暇即焚香。閑階雨過苔花潤，',40,'御定全唐詩/json/624.json','["病學高僧置一床，披衣才暇即焚香。閑階雨過苔花潤，", "升平聞道無時節，試問中林亦不妨。"]'),
('yuding-4','獨夜','陸龜蒙','唐','御定全唐诗','yuding','','[]','新秋霽夜有清境，窮襜病客無佳期。生公把經向石說，',40,'御定全唐詩/json/624.json','["新秋霽夜有清境，窮襜病客無佳期。生公把經向石說，", "古稱獨坐與獨立，若比群居終校奇。"]'),
('yuding-5','寄吳融','陸龜蒙','唐','御定全唐诗','yuding','','[]','一夜秋聲入井桐，數枝危綠怕西風。霏霏晚砌煙華上，',40,'御定全唐詩/json/624.json','["一夜秋聲入井桐，數枝危綠怕西風。霏霏晚砌煙華上，", "到頭江畔從漁事，織作中流萬尺篊。"]'),
('yuding-6','中秋待月','陸龜蒙','唐','御定全唐诗','yuding','','[]','轉缺霜輪上轉遲，好風偏似送佳期。簾斜樹隔情無限，',40,'御定全唐詩/json/624.json','["轉缺霜輪上轉遲，好風偏似送佳期。簾斜樹隔情無限，", "何人為校清涼力，未似初圓欲午時。"]'),
('yuding-7','重憶白菊','陸龜蒙','唐','御定全唐诗','yuding','','[]','我憐貞白重寒芳，前後叢生夾小堂。月朵暮開無絕豔，',40,'御定全唐詩/json/624.json','["我憐貞白重寒芳，前後叢生夾小堂。月朵暮開無絕豔，", "更憶幽窗凝一夢，夜來村落有微霜。"]'),
('yuding-8','別墅懷歸','陸龜蒙','唐','御定全唐诗','yuding','','[]','水國初冬和暖天，南榮方好背陽眠。題詩朝憶複暮憶，',40,'御定全唐詩/json/624.json','["水國初冬和暖天，南榮方好背陽眠。題詩朝憶複暮憶，", "何人授我黃金百，買取蘇君負郭田。"]'),
('yuding-9','寄淮南鄭寶書記','陸龜蒙','唐','御定全唐诗','yuding','','[]','記室千年翰墨孤，唯君才學似應徐。五丁驅得神功盡，',40,'御定全唐詩/json/624.json','["記室千年翰墨孤，唯君才學似應徐。五丁驅得神功盡，", "清詞醉草無因見，但釣寒江半尺鱸。"]'),
('yuding-10','小雪後書事','陸龜蒙','唐','御定全唐诗','yuding','','[]','時候頻過小雪天，江南寒色未曾偏。楓汀尚憶逢人別，',40,'御定全唐詩/json/624.json','["時候頻過小雪天，江南寒色未曾偏。楓汀尚憶逢人別，", "鄰翁意緒相安慰，多說明年是稔年。"]'),
('yuding-11','寒夜同襲美訪北禪院寂上人','陸龜蒙','唐','御定全唐诗','yuding','','[]','月樓風殿靜沉沉，披拂霜華訪道林。鳥在寒枝棲影動，',40,'御定全唐詩/json/624.json','["月樓風殿靜沉沉，披拂霜華訪道林。鳥在寒枝棲影動，", "自是海邊鷗伴侶，不勞金偈更降心。"]'),
('yuding-12','和襲美江南道中懷茅山廣文南陽博士三首次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','一片輕帆背夕陽，望三峰拜七真堂。天寒夜漱雲牙淨，',120,'御定全唐詩/json/624.json','["一片輕帆背夕陽，望三峰拜七真堂。天寒夜漱雲牙淨，", "莫言洞府能招隱，會輾飆輪見玉皇。", "壺中行坐可攜天，何況林間息萬緣。組綬任垂三品石，", "想得雷平春色動，五芝煙甲又芊眠。", "良常應不動移文，金醴從酸亦自醺。桂父舊歌飛絳雪，", "珍重雙雙玉條脫，盡憑三島寄羊君。"]'),
('yuding-13','早春雪中作吳體寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','迎春避臘不肯下，欺花凍草還飄然。光填馬窟蓋塞外，',40,'御定全唐詩/json/624.json','["迎春避臘不肯下，欺花凍草還飄然。光填馬窟蓋塞外，", "君披鶴氅獨自立，何人解道真神仙。"]'),
('yuding-14','奉和襲美吳中言情見寄次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','菰煙蘆雪是儂鄉，釣線隨身好坐忘。徒愛右軍遺點畫，',40,'御定全唐詩/json/624.json','["菰煙蘆雪是儂鄉，釣線隨身好坐忘。徒愛右軍遺點畫，", "莫問江邊漁艇子，玉皇看賜羽衣裳。"]'),
('yuding-15','和襲美揚州看辛夷花次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','柳疏梅墮少春叢，天遣花神別致功。高處朵稀難避日，',40,'御定全唐詩/json/624.json','["柳疏梅墮少春叢，天遣花神別致功。高處朵稀難避日，", "不待群芳應有意，等閒桃杏即爭紅。"]'),
('yuding-16','奉和襲美行次野梅次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','飛棹參差拂早梅，強欺寒色尚低徊。風憐薄媚留香與，',40,'御定全唐詩/json/624.json','["飛棹參差拂早梅，強欺寒色尚低徊。風憐薄媚留香與，", "不知謝客離腸醒，臨水應添萬恨來。"]'),
('yuding-17','奉和襲美暇日獨處見寄','陸龜蒙','唐','御定全唐诗','yuding','','[]','謝府殷樓少暇時，又拋清宴入書帷。三千餘歲上下古，',40,'御定全唐詩/json/624.json','["謝府殷樓少暇時，又拋清宴入書帷。三千餘歲上下古，", "知君滿篋前朝事，鳳諾龍奴借與窺。"]'),
('yuding-18','奉和襲美見訪不遇','陸龜蒙','唐','御定全唐诗','yuding','','[]','為愁煙岸老塵囂，扶病呼兒劚翠苕。只道府中持簡牘，',40,'御定全唐詩/json/624.json','["為愁煙岸老塵囂，扶病呼兒劚翠苕。只道府中持簡牘，", "倚仗遍吟春照午，一池冰段幾多消。"]'),
('yuding-19','酬襲美見寄海蟹','陸龜蒙','唐','御定全唐诗','yuding','','[]','藥杯應阻蟹螯香，卻乞江邊採捕郎。自是揚雄知郭索，',40,'御定全唐詩/json/624.json','["藥杯應阻蟹螯香，卻乞江邊採捕郎。自是揚雄知郭索，", "強作南朝風雅客，夜來偷醉早梅傍。"]'),
('yuding-20','奉和襲美開元寺客省早景即事次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','日上罘罳疊影紅，一聲清梵萬緣空。褵褷滿地貝多雪，',40,'御定全唐詩/json/624.json','["日上罘罳疊影紅，一聲清梵萬緣空。褵褷滿地貝多雪，", "靈香散盡禪家接，誰共殷源小品同。"]'),
('yuding-21','獨夜有懷因作吳體寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','人吟側景抱凍竹，鶴夢缺月沈枯梧。清澗無波鹿無魄，',40,'御定全唐詩/json/624.json','["人吟側景抱凍竹，鶴夢缺月沈枯梧。清澗無波鹿無魄，", "不然快作燕市飲，笑撫肉枅眠酒壚。"]'),
('yuding-22','闔閭城北有賣花翁，討春之士往往造焉，因招襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','故城邊有賣花翁，水曲舟輕去盡通。十畝芳菲為舊業，',40,'御定全唐詩/json/624.json','["故城邊有賣花翁，水曲舟輕去盡通。十畝芳菲為舊業，", "若要見春歸處所，不過攜手問東風。"]'),
('yuding-23','奉和襲美病中庭際海石榴花盛發見寄次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','紫府真人餉露囊，猗蘭燈燭未熒煌。丹華乞曙先侵日，',40,'御定全唐詩/json/624.json','["紫府真人餉露囊，猗蘭燈燭未熒煌。丹華乞曙先侵日，", "那堪謝氏庭前見，一段清香染郤郎。"]'),
('yuding-24','襲美以春橘見惠兼之雅篇，因次韻酬謝','陸龜蒙','唐','御定全唐诗','yuding','','[]','到春猶作九秋鮮，應是親封白帝煙。良玉有漿須讓味，',40,'御定全唐詩/json/624.json','["到春猶作九秋鮮，應是親封白帝煙。良玉有漿須讓味，", "珍重更過三十子，不堪分付野人邊。"]'),
('yuding-25','奉和襲美病中書情寄上崔諫議次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','或偃虛齋或在公，藹然林下昔賢風。庭前有蝶爭煙蕊，',40,'御定全唐詩/json/624.json','["或偃虛齋或在公，藹然林下昔賢風。庭前有蝶爭煙蕊，", "西園夜燭偏堪憶，曾為題詩刻半紅。"]'),
('yuding-26','奉酬襲美病中見寄','陸龜蒙','唐','御定全唐诗','yuding','','[]','逢花逢月便相招，忽臥雲航隔野橋。春恨與誰同酩酊，',40,'御定全唐詩/json/624.json','["逢花逢月便相招，忽臥雲航隔野橋。春恨與誰同酩酊，", "早晚卻還岩下電，共尋芳徑結煙條。"]'),
('yuding-27','奉和襲美病孔雀','陸龜蒙','唐','御定全唐诗','yuding','','[]','懶移金翠傍簷楹，斜倚芳叢舊態生。唯奈瘴煙籠飲啄，',40,'御定全唐詩/json/624.json','["懶移金翠傍簷楹，斜倚芳叢舊態生。唯奈瘴煙籠飲啄，", "爭得鷓鴣來伴著，不妨還校有心情。"]'),
('yuding-28','上元日道室焚修寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','三清今日聚靈官，玉刺齊抽謁廣寒。執蓋冒花香寂曆，',40,'御定全唐詩/json/624.json','["三清今日聚靈官，玉刺齊抽謁廣寒。執蓋冒花香寂曆，", "唯有世塵中小兆，夜來心拜七星壇。"]'),
('yuding-29','正月十五惜春寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','六分春色一分休，滿眼東波儘是愁。花匠凝寒應束手，',40,'御定全唐詩/json/624.json','["六分春色一分休，滿眼東波儘是愁。花匠凝寒應束手，", "見織短篷裁小楫，拏煙閑弄個漁舟。"]'),
('yuding-30','襲美病中聞余游顏家園見寄，次韻酬之','陸龜蒙','唐','御定全唐诗','yuding','','[]','日華風蕙正交光，羯末相攜藉草塘。佳酒旋傾醽醁嫩，',40,'御定全唐詩/json/624.json','["日華風蕙正交光，羯末相攜藉草塘。佳酒旋傾醽醁嫩，", "今日好為聯句會，不成剛為欠檀郎。"]'),
('yuding-31','春雨即事寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','小謝輕埃日日飛，城邊江上阻春暉。雖愁野岸花房凍，',40,'御定全唐詩/json/624.json','["小謝輕埃日日飛，城邊江上阻春暉。雖愁野岸花房凍，", "比鄰釣叟無塵事，灑笠鳴蓑夜半歸。"]'),
('yuding-32','奉和襲美抱疾杜門見寄次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','雖失春城醉上期，下帷裁遍未裁詩。因吟郢岸百畝蕙，',40,'御定全唐詩/json/624.json','["雖失春城醉上期，下帷裁遍未裁詩。因吟郢岸百畝蕙，", "但醫沈約重瞳健，不怕江花不滿枝。"]'),
('yuding-33','偶掇野蔬寄襲美有作','陸龜蒙','唐','御定全唐诗','yuding','','[]','野園煙裏自幽尋，嫩甲香蕤引漸深。行歇每依鴉舅影，',40,'御定全唐詩/json/624.json','["野園煙裏自幽尋，嫩甲香蕤引漸深。行歇每依鴉舅影，", "欲助春盤還愛否，不妨蕭灑似家林。"]'),
('yuding-34','奉和襲美臥疾感春見寄次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','共尋花思極飛騰，疾帶春寒去未能。煙徑水涯多好鳥，',40,'御定全唐詩/json/624.json','["共尋花思極飛騰，疾帶春寒去未能。煙徑水涯多好鳥，", "除卻數函圖籍外，更將何事結良朋。"]'),
('yuding-35','徐方平後聞赦因寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','新春旒扆禦翬軒，海內初傳渙汗恩。秦獄已收為厲氣，',40,'御定全唐詩/json/624.json','["新春旒扆禦翬軒，海內初傳渙汗恩。秦獄已收為厲氣，", "除卻數般傷痛外，不知何事及王孫。"]'),
('yuding-36','襲美以魚箋見寄，因謝成篇','陸龜蒙','唐','御定全唐诗','yuding','','[]','搗成霜粒細鱗鱗，知作愁吟喜見分。向日乍驚新繭色，',40,'御定全唐詩/json/624.json','["搗成霜粒細鱗鱗，知作愁吟喜見分。向日乍驚新繭色，", "見倚小窗親襞染，盡圖春色寄夫君。"]'),
('yuding-37','次和襲美病後春思','陸龜蒙','唐','御定全唐诗','yuding','','[]','氣和靈府漸氤氳，酒有賢人藥有君。七字篇章看月得，',40,'御定全唐詩/json/624.json','["氣和靈府漸氤氳，酒有賢人藥有君。七字篇章看月得，", "早晚共搖孤艇去，紫屏風外碧波文。"]'),
('yuding-38','襲美以公齋小宴見招，因代書寄之','陸龜蒙','唐','御定全唐诗','yuding','','[]','早雲才破漏春陽，野客晨興喜又忙。自與酌量煎藥水，',40,'御定全唐詩/json/624.json','["早雲才破漏春陽，野客晨興喜又忙。自與酌量煎藥水，", "唯待數般幽事了，不妨還入少年場。"]'),
('yuding-39','京口','陸龜蒙','唐','御定全唐诗','yuding','','[]','江幹古渡傷離情，斷山零落春潮平。東風料峭客帆遠，',40,'御定全唐詩/json/624.json','["江幹古渡傷離情，斷山零落春潮平。東風料峭客帆遠，", "可憐宋帝籌帷處，蒼翠無煙草自生。"]'),
('yuding-40','潤州送人往長洲','陸龜蒙','唐','御定全唐诗','yuding','','[]','秋來頻上向吳亭，每上思歸意剩生。廢苑池台煙裏色，',40,'御定全唐詩/json/624.json','["秋來頻上向吳亭，每上思歸意剩生。廢苑池台煙裏色，", "君住松江多少日，為嘗鱸鱠與蓴羹。"]'),
('yuding-41','潤州江口送人謁池陽衛郎中','陸龜蒙','唐','御定全唐诗','yuding','','[]','山翁曾約舊交歡，須拂侯門側注冠。月在石頭搖戍角，',40,'御定全唐詩/json/624.json','["山翁曾約舊交歡，須拂侯門側注冠。月在石頭搖戍角，", "待取新秋歸更好，九華蒼翠入樓寒。"]'),
('yuding-0','襲美以紗巾見惠繼以雅音，因次韻酬謝','陸龜蒙','唐','御定全唐诗','yuding','','[]','薄如蟬翅背斜陽，不稱春前贈罱郎。初覺頂寒生遠吹，',40,'御定全唐詩/json/625.json','["薄如蟬翅背斜陽，不稱春前贈罱郎。初覺頂寒生遠吹，", "知有芙蓉留自戴，欲峨煙霧訪黃房。"]'),
('yuding-1','聞襲美有親迎之期因以寄賀','陸龜蒙','唐','御定全唐诗','yuding','','[]','梁鴻夫婦欲雙飛，細雨輕寒拂雉衣。初下雪窗因眷戀，',40,'御定全唐詩/json/625.json','["梁鴻夫婦欲雙飛，細雨輕寒拂雉衣。初下雪窗因眷戀，", "見說春風偏有賀，露花千朵照庭闈。"]'),
('yuding-2','襲美以巨魚之半見分因以酬謝','陸龜蒙','唐','御定全唐诗','yuding','','[]','誰與春江上信魚，可憐霜刃截來初。鱗隳似撤騷人屋，',40,'御定全唐詩/json/625.json','["誰與春江上信魚，可憐霜刃截來初。鱗隳似撤騷人屋，", "今朝最是家童喜，免泥荒畦掇野蔬。"]'),
('yuding-3','奉和襲美館娃宮懷古次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','鏤楣消落濯春雨，蒼翠無言空斷崖。草碧未能忘帝女，',40,'御定全唐詩/json/625.json','["鏤楣消落濯春雨，蒼翠無言空斷崖。草碧未能忘帝女，", "賴在伍員騷思少，吳王才免似荊懷。"]'),
('yuding-4','同襲美遊北禪院','陸龜蒙','唐','御定全唐诗','yuding','','[]','連延花蔓映風廊，岸幘披襟到竹房。居士只今開梵處，',40,'御定全唐詩/json/625.json','["連延花蔓映風廊，岸幘披襟到竹房。居士只今開梵處，", "今日有情消未得，欲將名理問思光。"]'),
('yuding-5','襲美以紫石硯見贈以詩迎之','陸龜蒙','唐','御定全唐诗','yuding','','[]','霞骨堅來玉自愁，琢成飛燕古釵頭。澄沙脆弱聞應伏，',40,'御定全唐詩/json/625.json','["霞骨堅來玉自愁，琢成飛燕古釵頭。澄沙脆弱聞應伏，", "君能把贈閑吟客，遍寫江南物象酬。"]'),
('yuding-6','和襲美送孫發百篇游天臺','陸龜蒙','唐','御定全唐诗','yuding','','[]','直應天授與詩情，百詠唯消一日成。去把彩毫揮下國，',40,'御定全唐詩/json/625.json','["直應天授與詩情，百詠唯消一日成。去把彩毫揮下國，", "珍重興公徒有賦，石樑深處是君行。"]'),
('yuding-7','奉和襲美聞開元寺開筍園寄章上人','陸龜蒙','唐','御定全唐诗','yuding','','[]','春龍爭地養檀欒，況是雙林雨後看。迸出似毫當垤eJ，',41,'御定全唐詩/json/625.json','["春龍爭地養檀欒，況是雙林雨後看。迸出似毫當垤eJ，", "更得錦苞零落後，粉環高下挶煙寒。"]'),
('yuding-8','薔薇','陸龜蒙','唐','御定全唐诗','yuding','','[]','倚牆當戶自橫陳，致得貧家似不貧。外布芳菲雖笑日，',40,'御定全唐詩/json/625.json','["倚牆當戶自橫陳，致得貧家似不貧。外布芳菲雖笑日，", "遇有客來堪玩處，一端晴綺照煙新。"]'),
('yuding-9','奉和襲美開元寺佛缽詩','陸龜蒙','唐','御定全唐诗','yuding','','[]','空王初受逞神功，四缽須臾現一重。持次想添香積飯，',40,'御定全唐詩/json/625.json','["空王初受逞神功，四缽須臾現一重。持次想添香積飯，", "從此寶函香裏見，不須西去詣靈峰。"]'),
('yuding-10','酬襲美夏首病癒見招次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','雨多青合是垣衣，一幅蠻箋夜款扉。蕙帶又聞寬沈約，',40,'御定全唐詩/json/625.json','["雨多青合是垣衣，一幅蠻箋夜款扉。蕙帶又聞寬沈約，", "除卻伴談秋水外，野鷗何處更忘機。"]'),
('yuding-11','新夏東郊閑泛有懷襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','遲於春日好於秋，野客相攜上釣舟。經略彴時冠暫亞，',40,'御定全唐詩/json/625.json','["遲於春日好於秋，野客相攜上釣舟。經略彴時冠暫亞，", "料得祇君能愛此，不爭煙水似封侯。"]'),
('yuding-12','四月十五日道室書事寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','烏飯新炊芼臛香，道家齋日以為常。月苗杯舉存三洞，',40,'御定全唐詩/json/625.json','["烏飯新炊芼臛香，道家齋日以為常。月苗杯舉存三洞，", "可中值著雷平信，為覓閑眠苦竹床。"]'),
('yuding-13','看壓新醅寄懷襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','曉壓糟床漸有聲，旋如荒澗野泉清。身前古態熏應出，',40,'御定全唐詩/json/625.json','["曉壓糟床漸有聲，旋如荒澗野泉清。身前古態熏應出，", "尊中若使常能淥，兩綬通侯總強名。"]'),
('yuding-14','奉和襲美登初陽樓寄懷北平郎中','陸龜蒙','唐','御定全唐诗','yuding','','[]','遠窗浮檻亦成年，幾伴楊公白晝筵。日暖煙花曾撲地，',40,'御定全唐詩/json/625.json','["遠窗浮檻亦成年，幾伴楊公白晝筵。日暖煙花曾撲地，", "無限恩波猶在目，東風吹起細漪漣。"]'),
('yuding-15','奉和夏初襲美見訪題小齋次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','四鄰多是老農家，百樹雞桑半頃麻。盡趁晴明修網架，',40,'御定全唐詩/json/625.json','["四鄰多是老農家，百樹雞桑半頃麻。盡趁晴明修網架，", "不是對君吟複醉，更將何事送年華。"]'),
('yuding-16','奉和襲美所居首夏水木尤清，適然有作次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','柿陰成列藥花空，卻憶桐江下釣筒。亦以魚蝦供熟鷺，',40,'御定全唐詩/json/625.json','["柿陰成列藥花空，卻憶桐江下釣筒。亦以魚蝦供熟鷺，", "更愛夜來風月好，轉思玄度對支公。"]'),
('yuding-17','奉和襲美題達上人藥圃二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','藥味多從遠客齎，旋添花圃旋成畦。三椏舊種根應異，',80,'御定全唐詩/json/625.json','["藥味多從遠客齎，旋添花圃旋成畦。三椏舊種根應異，", "從今直到清秋日，又有香苗幾番齊。", "淨名無語示清羸，藥草搜來喻更微。一雨一風皆遂性，", "莫怪獨親幽圃坐，病容銷盡欲依歸。"]'),
('yuding-18','奉和襲美懷華陽潤卿博士三首','陸龜蒙','唐','御定全唐诗','yuding','','[]','幾降真官授隱書，洛公曾到夢中無。眉間入靜三辰影，',120,'御定全唐詩/json/625.json','["幾降真官授隱書，洛公曾到夢中無。眉間入靜三辰影，", "金墟福地能容否，願作岡前蔣負芻。", "火景應難到洞宮，蕭閑堂冷任天風。談玄麈尾拋雲底，", "奇編早晚教傳授，免以神仙問葛洪。", "終日焚香禮洞雲，更思琪樹轉勞神。曾尋下泊常經月，", "清齋若見茅司命，乞取朱兒十二斤。"]'),
('yuding-19','以竹夾膝寄贈襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','截得筼簹冷似龍，翠光橫在暑天中。堪臨薤簟閑憑月，',40,'御定全唐詩/json/625.json','["截得筼簹冷似龍，翠光橫在暑天中。堪臨薤簟閑憑月，", "添君雅具教多著，為著西齋譜一通。"]'),
('yuding-20','奉和襲美夏景無事因懷章來二上人次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','簷外青陽有二梅，折來堪下凍醪杯。高杉自欲生龍腦，',80,'御定全唐詩/json/625.json','["簷外青陽有二梅，折來堪下凍醪杯。高杉自欲生龍腦，", "還聞擬結東林社，爭奈淵明醉不來。", "忽憶高僧坐夏堂，厭泉聲鬧笑雲忙。山重海澹懷中印，", "何時更問逍遙義，五粒松陰半石床。"]'),
('yuding-21','頃自桐江得一釣車以襲美樂煙波之思因出以為玩俄辱三篇復抒酬答','陸龜蒙','唐','御定全唐诗','yuding','','[]','旋屈金鉤劈翠筠，手中盤作釣魚輪。忘情不效孤醒客，',120,'御定全唐詩/json/625.json','["旋屈金鉤劈翠筠，手中盤作釣魚輪。忘情不效孤醒客，", "任他華轂低頭笑，此地終無覆敗人。", "曾招漁侶下清潯，獨繭初隨一錘深。細輾煙華無轍跡，", "得失任渠但取樂，不曾生個是非心。", "病來懸著脆緡絲，獨喜高情為我持。數幅尚凝煙雨態，", "第一莫教諳此境，倚天功業待君為。"]'),
('yuding-22','奉和襲美吳中書事寄漢南裴尚書','陸龜蒙','唐','御定全唐诗','yuding','','[]','風清地古帶前朝，遺事紛紛未寂寥。三泖涼波魚蕝動，',40,'御定全唐詩/json/625.json','["風清地古帶前朝，遺事紛紛未寂寥。三泖涼波魚蕝動，", "不用懷歸忘此景，吳王看即奉弓招。"]'),
('yuding-23','奉和襲美夏景沖澹偶作次韻二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','蟬雀參差在扇紗，竹襟輕利籜冠斜。壚中有酒文園會，',80,'御定全唐詩/json/625.json','["蟬雀參差在扇紗，竹襟輕利籜冠斜。壚中有酒文園會，", "閑思兩地忘名者，不信人間發解華。", "只于池曲象山幽，便是瀟湘浸石樓。斜拂芡盤輕鶩下，", "莫道仙家無好爵，方諸還拜碧琳侯。"]'),
('yuding-24','奉和襲美送李明府之任南海','陸龜蒙','唐','御定全唐诗','yuding','','[]','春盡之官直到秋，嶺雲深處憑瀧樓。居人愛近沈珠浦，',40,'御定全唐詩/json/625.json','["春盡之官直到秋，嶺雲深處憑瀧樓。居人愛近沈珠浦，", "之君不戀南枝久，拋卻經冬白罽裘。"]'),
('yuding-25','奉和襲美寄題羅浮軒轅先生所居','陸龜蒙','唐','御定全唐诗','yuding','','[]','鼎成仙馭入崆峒，百世猶傳至道風。暫應青詞為穴鳳，',40,'御定全唐詩/json/625.json','["鼎成仙馭入崆峒，百世猶傳至道風。暫應青詞為穴鳳，", "預恐浮山歸有日，載將雲室十洲東。"]'),
('yuding-26','奉和襲美寄瓊州楊舍人','陸龜蒙','唐','御定全唐诗','yuding','','[]','明時非罪謫何偏，鵩鳥巢南更數千。酒滿椰杯消毒霧，',40,'御定全唐詩/json/625.json','["明時非罪謫何偏，鵩鳥巢南更數千。酒滿椰杯消毒霧，", "只以直誠天自信，不勞詩句詠貪泉。"]'),
('yuding-27','奉和襲美宿報恩寺水閣','陸龜蒙','唐','御定全唐诗','yuding','','[]','峰抱池光曲岸平，月臨虛檻夜何清。僧穿小檜才分影，',40,'御定全唐詩/json/625.json','["峰抱池光曲岸平，月臨虛檻夜何清。僧穿小檜才分影，", "周顒不用裁書勸，自得涼天證道情。"]'),
('yuding-28','奉和襲美醉中偶作見寄次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','海鶴飄飄韻莫儕，在公猶與俗情乖。初呈酒務求專判，',40,'御定全唐詩/json/625.json','["海鶴飄飄韻莫儕，在公猶與俗情乖。初呈酒務求專判，", "憐君醉墨風流甚，幾度題詩小謝齋。"]'),
('yuding-29','奉和襲美寄滑州李副使員外','陸龜蒙','唐','御定全唐诗','yuding','','[]','洛生閑詠正抽毫，忽傍旌旗著戰袍。檄下連營皆破膽，',40,'御定全唐詩/json/625.json','["洛生閑詠正抽毫，忽傍旌旗著戰袍。檄下連營皆破膽，", "除卻征南為上將，平徐功業更誰高。"]'),
('yuding-30','奉和襲美吳中言懷寄南海二同年','陸龜蒙','唐','御定全唐诗','yuding','','[]','曾見淩風上赤霄，盡將華藻赴嘉招。城連虎踞山圖麗，',40,'御定全唐詩/json/625.json','["曾見淩風上赤霄，盡將華藻赴嘉招。城連虎踞山圖麗，", "庭中必有君遷樹，莫向空台望漢朝。"]'),
('yuding-31','奉和襲美傷史拱山人','陸龜蒙','唐','御定全唐诗','yuding','','[]','曾說山棲欲去尋，豈知霜骨葬寒林。常依淨住師冥目，',40,'御定全唐詩/json/625.json','["曾說山棲欲去尋，豈知霜骨葬寒林。常依淨住師冥目，", "唯君獨在江雲外，誰誄孤貞置峴岑。"]'),
('yuding-32','白鷗詩','陸龜蒙','唐','御定全唐诗','yuding','','[]','慣向溪頭漾淺沙，薄煙微雨是生涯。時時失伴沈山影，',40,'御定全唐詩/json/625.json','["慣向溪頭漾淺沙，薄煙微雨是生涯。時時失伴沈山影，", "池塘信美應難戀，針在魚唇劍在蝦。"]'),
('yuding-33','懷楊台文楊鼎文二秀才','陸龜蒙','唐','御定全唐诗','yuding','','[]','秋早相逢待得春，崇蘭清露小山雲。寒花獨自愁中見，',40,'御定全唐詩/json/625.json','["秋早相逢待得春，崇蘭清露小山雲。寒花獨自愁中見，", "重思醉墨縱橫甚，書破羊欣白練裙。"]'),
('yuding-34','奉和襲美謝友人惠人參','陸龜蒙','唐','御定全唐诗','yuding','','[]','五葉初成椵樹陰，紫團峰外即雞林。名參鬼蓋須難見，',40,'御定全唐詩/json/625.json','["五葉初成椵樹陰，紫團峰外即雞林。名參鬼蓋須難見，", "殷勤潤取相如肺，封禪書成動帝心。"]'),
('yuding-35','嚴子重以詩遊於名勝間，舊矣。余晚於江南相遇，甚樂。不幸且沒襲美，作詩序而弔之其名，真不朽矣，又何戚其死哉？余因息悲而為之和','陸龜蒙','唐','御定全唐诗','yuding','','[]','每值江南日落春，十年詩酒愛逢君。芙蓉湖上吟船倚，',40,'御定全唐詩/json/625.json','["每值江南日落春，十年詩酒愛逢君。芙蓉湖上吟船倚，", "猶憐未蔔佳城處，更劚要離塚畔雲。"]'),
('yuding-36','算山','陸龜蒙','唐','御定全唐诗','yuding','','[]','水繞蒼山固護來，當時盤踞實雄才。周郎計策清宵定，',40,'御定全唐詩/json/625.json','["水繞蒼山固護來，當時盤踞實雄才。周郎計策清宵定，", "何如今日家天下，閶闔門臨萬國開。"]'),
('yuding-37','寄茅山何威儀二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','大小三峰次九華，靈蹤今盡屬何家。漢時仙上雲巔鶴，',80,'御定全唐詩/json/625.json','["大小三峰次九華，靈蹤今盡屬何家。漢時仙上雲巔鶴，", "年來已奉黃庭教，夕煉腥魂曉吸霞。", "曾向人間拜節旄，乍疑因夢到仙曹。身輕曳羽霞襟狹，", "從聞此日搜奇話，轉覺魂飛夜夜勞。"]'),
('yuding-0','早秋吳體寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','荒庭古村只獨倚，敗蟬殘蛩苦相仍。雖然詩膽大如鬥，',40,'御定全唐詩/json/626.json','["荒庭古村只獨倚，敗蟬殘蛩苦相仍。雖然詩膽大如鬥，", "安得彎弓似明月，快箭拂下西飛鵬。"]'),
('yuding-1','病中秋懷寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','病容愁思苦相兼，清鏡無形未我嫌。貪廣異蔬行徑窄。',64,'御定全唐詩/json/626.json','["病容愁思苦相兼，清鏡無形未我嫌。貪廣異蔬行徑窄。", "故求偏藥出錢添。同人散後休賒酒，雙燕辭來始下簾。", "更有是非齊未得，重憑詹尹拂龜占。"]'),
('yuding-2','秋賦有期因寄襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','雲似無心水似閑，忽思名在貢書間。煙霞鹿弁聊懸著，',40,'御定全唐詩/json/626.json','["雲似無心水似閑，忽思名在貢書間。煙霞鹿弁聊懸著，", "廣寒宮樹枝多少，風送高低便可攀。"]'),
('yuding-3','和襲美新秋即事次韻三首','陸龜蒙','唐','御定全唐诗','yuding','','[]','心似孤雲任所之，世塵中更有誰知。愁尋冷落驚雙鬢，',120,'御定全唐詩/json/626.json','["心似孤雲任所之，世塵中更有誰知。愁尋冷落驚雙鬢，", "兼須為月求高處，即是霜輪殺滿時。", "帆楫衣裳盡釣徒，往來蹤跡遍三吳。閑中展卷興亡小，", "還須待致升平了，即往扁舟放五湖。", "聲利從來解破除，秋灘唯憶下桐廬。鸕鷀陣合殘陽少，", "當時任使真堪笑，波上三年學炙魚。"]'),
('yuding-4','和襲美贈南陽潤卿將歸雷平','陸龜蒙','唐','御定全唐诗','yuding','','[]','朝市山林隱一般，卻歸那減臥雲歡。墮階紅葉誰收得，',40,'御定全唐詩/json/626.json','["朝市山林隱一般，卻歸那減臥雲歡。墮階紅葉誰收得，", "真仙若降如相問，曾步星罡繞醮壇。"]'),
('yuding-5','顧道士亡，弟子奉束帛乞銘於襲美，因賦戲贈','陸龜蒙','唐','御定全唐诗','yuding','','[]','童初真府召為郎，君與抽毫刻便房。亦謂神仙同許郭，',40,'御定全唐詩/json/626.json','["童初真府召為郎，君與抽毫刻便房。亦謂神仙同許郭，", "唯我有文無賣處，筆鋒銷盡墨池荒。"]'),
('yuding-6','和訪寂上人不遇','陸龜蒙','唐','御定全唐诗','yuding','','[]','芭蕉霜後石欄荒，林下無人閉竹房。經抄未成拋素幾，',40,'御定全唐詩/json/626.json','["芭蕉霜後石欄荒，林下無人閉竹房。經抄未成拋素幾，", "早晚卻還宗炳社，夜深風雪對禪床。"]'),
('yuding-7','秋夕文宴','陸龜蒙','唐','御定全唐诗','yuding','','[]','筆陣初臨夜正清，擊銅遙認小金鉦。飛觥壯若游燕市，',40,'御定全唐詩/json/626.json','["筆陣初臨夜正清，擊銅遙認小金鉦。飛觥壯若游燕市，", "梁王座上多詞客，五韻甘心第七成。"]'),
('yuding-8','南陽廣文欲于荊襄卜居，襲美有贈，代酬次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','不知天隱在何鄉，且欲煙霞跡暫雙。鶴廟未能齊月馭，',40,'御定全唐詩/json/626.json','["不知天隱在何鄉，且欲煙霞跡暫雙。鶴廟未能齊月馭，", "莫惜查頭容釣伴，也應東印有餘江。"]'),
('yuding-9','和襲美寄毗陵魏處士朴','陸龜蒙','唐','御定全唐诗','yuding','','[]','經苑初成墨沼開，何人林下肯尋來。若非宗測圖山后，',40,'御定全唐詩/json/626.json','["經苑初成墨沼開，何人林下肯尋來。若非宗測圖山后，", "唯應地主公田熟，時送君家麹糵材。"]'),
('yuding-10','和襲美初冬偶作寄南陽潤卿次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','逐日生涯敢計冬，可嗟寒事落然空。窗憐返照緣書小，',40,'御定全唐詩/json/626.json','["逐日生涯敢計冬，可嗟寒事落然空。窗憐返照緣書小，", "不知海上今清淺，試與飛書問洛公。"]'),
('yuding-11','和襲美冬曉章上人院','陸龜蒙','唐','御定全唐诗','yuding','','[]','山寒偏是曉來多，況值禪窗雪氣和。病客功夫經未演，',40,'御定全唐詩/json/626.json','["山寒偏是曉來多，況值禪窗雪氣和。病客功夫經未演，", "從此逍遙知有地，更乘清月伴君過。"]'),
('yuding-12','和襲美寄題鏡岩周尊師所居','陸龜蒙','唐','御定全唐诗','yuding','','[]','見說身輕鶴不如，石房無侶共雲居。清晨自削靈香柹，',40,'御定全唐詩/json/626.json','["見說身輕鶴不如，石房無侶共雲居。清晨自削靈香柹，", "知君便入懸珠會，早晚東騎白鯉魚。"]'),
('yuding-13','寒夜文宴得驚字','陸龜蒙','唐','御定全唐诗','yuding','','[]','各將寒調觸詩情，旋見微澌入硯生。霜月滿庭人暫起，',40,'御定全唐詩/json/626.json','["各將寒調觸詩情，旋見微澌入硯生。霜月滿庭人暫起，", "千里建康衰草外，含毫誰是憶昭明。"]'),
('yuding-14','送潤卿還華陽','陸龜蒙','唐','御定全唐诗','yuding','','[]','何事輕舟近臘回，茅家兄弟欲歸來。封題玉洞虛無奏，',40,'御定全唐詩/json/626.json','["何事輕舟近臘回，茅家兄弟欲歸來。封題玉洞虛無奏，", "殷勤為向東鄉薦，灑掃含真雪後臺。"]'),
('yuding-15','和襲美為新羅弘惠上人撰靈鷲山周禪師碑送歸詩','陸龜蒙','唐','御定全唐诗','yuding','','[]','一函迢遞過東瀛，只為先生處乞銘。已得雄詞封靜檢，',40,'御定全唐詩/json/626.json','["一函迢遞過東瀛，只為先生處乞銘。已得雄詞封靜檢，", "遙想勒成新塔下，盡望空碧禮文星。"]'),
('yuding-16','和襲美寒日書齋即事三首，每篇各用一韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','不必探幽上鬱岡，公齋吟嘯亦何妨。唯求薏苡供僧食，',120,'御定全唐詩/json/626.json','["不必探幽上鬱岡，公齋吟嘯亦何妨。唯求薏苡供僧食，", "餘杭山酒猶封在，遙囑高人未肯嘗。", "已上星津八月槎，文通猶自學丹砂。仙經寫得空三洞，", "方諸更是憐才子，錫賚於君合有差。", "名價皆酬百萬餘，尚憐方丈講玄虛。西都賓問曾成賦，", "清朝還要廷臣在，兩地甯容便結廬。"]'),
('yuding-17','和襲美臘後送內大德從勖游天臺','陸龜蒙','唐','御定全唐诗','yuding','','[]','應緣南國盡南宗，欲訪靈溪路暗通。歸思不離雙闕下，',40,'御定全唐詩/json/626.json','["應緣南國盡南宗，欲訪靈溪路暗通。歸思不離雙闕下，", "若戀吾君先拜疏，為論台岳未封公。"]'),
('yuding-18','和襲美寄題玉霄峰葉涵象尊師所居','陸龜蒙','唐','御定全唐诗','yuding','','[]','天臺一萬八千丈，師在浮雲端掩扉。永夜只知星斗大，',40,'御定全唐詩/json/626.json','["天臺一萬八千丈，師在浮雲端掩扉。永夜只知星斗大，", "南望煙霞空再拜，欲將飛魄問靈威。"]'),
('yuding-19','南陽廣文博士還雷平後寄','陸龜蒙','唐','御定全唐诗','yuding','','[]','微微春色染林塘，親撥煙霞坐澗房。陰洞雪膠知未入，',40,'御定全唐詩/json/626.json','["微微春色染林塘，親撥煙霞坐澗房。陰洞雪膠知未入，", "幾遍侍晨官欲降，曙壇先起獨焚香。"]'),
('yuding-20','和襲美題支山南峰僧次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','眉毫霜細欲垂肩，自說初棲海嶽年。萬壑煙霞秋後到，',40,'御定全唐詩/json/626.json','["眉毫霜細欲垂肩，自說初棲海嶽年。萬壑煙霞秋後到，", "好是清冬無外事，匡林齋罷向陽眠。"]'),
('yuding-21','送董少卿游茅山','陸龜蒙','唐','御定全唐诗','yuding','','[]','威輦高懸度世名，至今仙裔作公卿。將隨羽節朝珠闕，',40,'御定全唐詩/json/626.json','["威輦高懸度世名，至今仙裔作公卿。將隨羽節朝珠闕，", "應知四扇靈方在，待取歸時綠發生。"]'),
('yuding-22','和襲美寄懷南陽潤卿','陸龜蒙','唐','御定全唐诗','yuding','','[]','高抱相逢各絕塵，水經山疏不離身。才情未擬湯從事，',40,'御定全唐詩/json/626.json','["高抱相逢各絕塵，水經山疏不離身。才情未擬湯從事，", "誰憐故國無生計，唯種南塘二畝芹。"]'),
('yuding-23','襲美將以綠罽為贈因成四韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','三徑風霜利若刀，襜褕吹斷罥蓬蒿。病中只自悲龍具，',40,'御定全唐詩/json/626.json','["三徑風霜利若刀，襜褕吹斷罥蓬蒿。病中只自悲龍具，", "陳王輕暖如相遺，免致衰荷效廣騷。"]'),
('yuding-24','和過張祜處士丹陽故居','陸龜蒙','唐','御定全唐诗','yuding','','[]','勝華通子共悲辛，荒徑今為舊宅鄰。一代交遊非不貴，',40,'御定全唐詩/json/626.json','["勝華通子共悲辛，荒徑今為舊宅鄰。一代交遊非不貴，", "聞道平生多愛石，至今猶泣洞庭人。"]'),
('yuding-25','和襲美寄廣文先生','陸龜蒙','唐','御定全唐诗','yuding','','[]','忽辭明主事真君，直取姜巴路入雲。龍篆拜時輕誥命，',40,'御定全唐詩/json/626.json','["忽辭明主事真君，直取姜巴路入雲。龍篆拜時輕誥命，", "應笑世間名利火，等閒靈府剩先焚。"]'),
('yuding-26','和襲美先輩悼鶴','陸龜蒙','唐','御定全唐诗','yuding','','[]','一夜圓吭絕不鳴，八公虛道得千齡。方添上客雲眠思，',40,'御定全唐詩/json/626.json','["一夜圓吭絕不鳴，八公虛道得千齡。方添上客雲眠思，", "君才幸自清如水，更向芝田為刻銘。"]'),
('yuding-27','幽居有白菊一叢因而成詠呈知己','陸龜蒙','唐','御定全唐诗','yuding','','[]','還是延年一種材，即將瑤朵冒霜開。不如紅豔臨歌扇，',40,'御定全唐詩/json/626.json','["還是延年一種材，即將瑤朵冒霜開。不如紅豔臨歌扇，", "月中若有閒田地，為勸嫦娥作意裁。"]'),
('yuding-28','和襲美傷開元觀顧道士','陸龜蒙','唐','御定全唐诗','yuding','','[]','何事神超入杳冥，不騎孤鶴上三清。多應白簡迎將去，',40,'御定全唐詩/json/626.json','["何事神超入杳冥，不騎孤鶴上三清。多應白簡迎將去，", "武皇徒有飄飄思，誰問山中宰相名。"]'),
('yuding-29','和襲美醉中即席贈潤卿博士次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','共是虛皇簡上仙，清詞如羽欲飄然。登山凡著幾緉屐，',40,'御定全唐詩/json/626.json','["共是虛皇簡上仙，清詞如羽欲飄然。登山凡著幾緉屐，", "誰知海上無名者，只記漁歌不記年。"]'),
('yuding-30','送浙東德師侍禦罷府西歸','陸龜蒙','唐','御定全唐诗','yuding','','[]','王謝遺蹤玉籍仙，三年閑上鄂君船。詩懷白閣僧吟苦，',40,'御定全唐詩/json/626.json','["王謝遺蹤玉籍仙，三年閑上鄂君船。詩懷白閣僧吟苦，", "芙蓉散盡西歸去，唯有山陰九萬箋。"]'),
('yuding-31','送羊振文先輩往桂陽歸覲','陸龜蒙','唐','御定全唐诗','yuding','','[]','風雅先生去一麾，過庭才子趣歸期。讓王門外開帆葉，',40,'御定全唐詩/json/626.json','["風雅先生去一麾，過庭才子趣歸期。讓王門外開帆葉，", "靈均精魄如能問，又得千年賈傅詞。"]'),
('yuding-32','襲美留振文宴龜蒙抱病不赴猥示倡和因次韻酬謝','陸龜蒙','唐','御定全唐诗','yuding','','[]','綺席風開照露晴，只將茶荈代雲觥。繁弦似玉紛紛碎，',24,'御定全唐詩/json/626.json','["綺席風開照露晴，只將茶荈代雲觥。繁弦似玉紛紛碎，"]'),
('yuding-33','和襲美重送圓載上人歸日本國','陸龜蒙','唐','御定全唐诗','yuding','','[]','老思東極舊岩扉，卻待秋風泛舶歸。曉梵陽烏當石磬，',40,'御定全唐詩/json/626.json','["老思東極舊岩扉，卻待秋風泛舶歸。曉梵陽烏當石磬，", "遙想到時思魏闕，只應遙拜望斜暉。"]'),
('yuding-34','和襲美褚家林亭','陸龜蒙','唐','御定全唐诗','yuding','','[]','一陣西風起浪花，繞欄杆下散瑤華。高窗曲檻仙侯府，',40,'御定全唐詩/json/626.json','["一陣西風起浪花，繞欄杆下散瑤華。高窗曲檻仙侯府，", "若知方外還如此，不要秋乘上海槎。"]'),
('yuding-35','歸雁','陸龜蒙','唐','御定全唐诗','yuding','','[]','北走南徵象我曹，天涯迢遞翼應勞。似悲邊雪音猶苦，',40,'御定全唐詩/json/626.json','["北走南徵象我曹，天涯迢遞翼應勞。似悲邊雪音猶苦，", "時人不問隨陽意，空拾欄邊翡翠毛。"]'),
('yuding-36','王先輩草堂','陸龜蒙','唐','御定全唐诗','yuding','','[]','松徑隈雲到靜堂，杏花臨澗水流香。身從亂後全家隱，',40,'御定全唐詩/json/626.json','["松徑隈雲到靜堂，杏花臨澗水流香。身從亂後全家隱，", "何如聖代彈冠出，方朔曾為漢侍郎。"]'),
('yuding-37','傷越','陸龜蒙','唐','御定全唐诗','yuding','','[]','越溪自古好風煙，盜束兵纏已半年。訪戴客愁隨水遠，',40,'御定全唐詩/json/626.json','["越溪自古好風煙，盜束兵纏已半年。訪戴客愁隨水遠，", "早晚山川盡如故，清吟閑上鄂君船。"]'),
('yuding-38','新定陪太守一百五夜南館玩月','陸龜蒙','唐','御定全唐诗','yuding','','[]','風雨教春處處傷，一宵雲盡見滄浪。全無片燭侵光彩，',40,'御定全唐詩/json/626.json','["風雨教春處處傷，一宵雲盡見滄浪。全無片燭侵光彩，", "卻嫌殷浩南樓夕，一帶秋聲入恨長。"]'),
('yuding-39','中元夜寄道侶二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','學餌霜茸骨未輕，每逢真夕夢還清。丁甯獨受金妃約，',80,'御定全唐詩/json/626.json','["學餌霜茸骨未輕，每逢真夕夢還清。丁甯獨受金妃約，", "須臾枕上桐窗曉，露壓千枝滴滴聲。", "橘齋風露已清餘，東郭先生病未除。孤枕易為蛩破夢，", "唯羨羽人襟似水，平持旄節步空虛。"]'),
('yuding-40','寄懷華陽道士','陸龜蒙','唐','御定全唐诗','yuding','','[]','華陽門外五芝生，餐罷愁君入杳冥。遙夜獨棲還有夢，',240,'御定全唐詩/json/626.json','["華陽門外五芝生，餐罷愁君入杳冥。遙夜獨棲還有夢，", "醮後幾時歸紫閣，別來終日誦黃庭。閑教辨藥僮名甲，", "深沈穀響含疏磬，片段嵐光落畫屏。休采古書探禹穴，", "架上黑椽長褐穩，案頭丹篆小符靈。霓軒入洞齊初月，", "凝神密室多生白，敘事聯編盡殺青。匝地山川皆暗寫，", "翠壁上吟朝複暮，暖雲邊臥醉還醒。倚身長短裁筇杖，", "常思近圃看栽杏，擬借鄰峰伴采苓。掩樹半扉晴靄靄，", "蟾魄幾應臨蕙帳，漁竿猶尚枕楓汀。銜煙細草無端綠，", "初征漢棧宜飛檄，待破燕山好勒銘。六轡未收千里馬，", "合在深崖齊散術，自求滄海點流萍。頻拋俗物心還爽，"]'),
('yuding-0','人日代客子','陸龜蒙','唐','御定全唐诗','yuding','','[]','人日兼春日，長懷複短懷。遙知雙彩勝，並在一金釵。',24,'御定全唐詩/json/627.json','["人日兼春日，長懷複短懷。遙知雙彩勝，並在一金釵。"]'),
('yuding-1','築城詞二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','城上一培土，手中千萬杵。築城畏不堅，堅城在何處。',48,'御定全唐詩/json/627.json','["城上一培土，手中千萬杵。築城畏不堅，堅城在何處。", "莫歎將軍逼，將軍要卻敵。城高功亦高，爾命何勞惜。"]'),
('yuding-2','古意','陸龜蒙','唐','御定全唐诗','yuding','','[]','君心莫淡薄，妾意正棲托。願得雙車輪，一夜生四角。',24,'御定全唐詩/json/627.json','["君心莫淡薄，妾意正棲托。願得雙車輪，一夜生四角。"]'),
('yuding-3','春曉','陸龜蒙','唐','御定全唐诗','yuding','','[]','春庭曉景別，清露花邐迤。黃蜂一過慵，夜夜棲香蕊。',24,'御定全唐詩/json/627.json','["春庭曉景別，清露花邐迤。黃蜂一過慵，夜夜棲香蕊。"]'),
('yuding-4','雜興','陸龜蒙','唐','御定全唐诗','yuding','','[]','桃李傍簷楹，無人賞春華。時情重不見，卻憶菖蒲花。',24,'御定全唐詩/json/627.json','["桃李傍簷楹，無人賞春華。時情重不見，卻憶菖蒲花。"]'),
('yuding-5','雁','陸龜蒙','唐','御定全唐诗','yuding','','[]','南北路何長，中間萬弋張。不知煙霧裏，幾隻到衡陽。',24,'御定全唐詩/json/627.json','["南北路何長，中間萬弋張。不知煙霧裏，幾隻到衡陽。"]'),
('yuding-6','寄遠','陸龜蒙','唐','御定全唐诗','yuding','','[]','鬢亂羞雲卷，眉空羨月生。中原猶將將，何日重卿卿。',24,'御定全唐詩/json/627.json','["鬢亂羞雲卷，眉空羨月生。中原猶將將，何日重卿卿。"]'),
('yuding-7','庭前','陸龜蒙','唐','御定全唐诗','yuding','','[]','合歡能解恚，萱草信忘憂。盡向庭前種，萋萋特地愁。',24,'御定全唐詩/json/627.json','["合歡能解恚，萱草信忘憂。盡向庭前種，萋萋特地愁。"]'),
('yuding-8','洞房怨','陸龜蒙','唐','御定全唐诗','yuding','','[]','玉鍤朝扶鬢，金梯晚下臺。春衫將別淚，一夜兩難裁。',24,'御定全唐詩/json/627.json','["玉鍤朝扶鬢，金梯晚下臺。春衫將別淚，一夜兩難裁。"]'),
('yuding-9','江行','陸龜蒙','唐','御定全唐诗','yuding','','[]','酒旗菰葉外，樓影浪花中。醉帆張數幅，唯待鯉魚風。',24,'御定全唐詩/json/627.json','["酒旗菰葉外，樓影浪花中。醉帆張數幅，唯待鯉魚風。"]'),
('yuding-10','巫峽','陸龜蒙','唐','御定全唐诗','yuding','','[]','巫峽七百里，巫山十二重。年年自雲雨，環佩竟誰逢。',24,'御定全唐詩/json/627.json','["巫峽七百里，巫山十二重。年年自雲雨，環佩竟誰逢。"]'),
('yuding-11','歸路','陸龜蒙','唐','御定全唐诗','yuding','','[]','漸入新豐路，衰紅映小橋。渾如七年病，初得一丸銷。',24,'御定全唐詩/json/627.json','["漸入新豐路，衰紅映小橋。渾如七年病，初得一丸銷。"]'),
('yuding-12','南塘曲','陸龜蒙','唐','御定全唐诗','yuding','','[]','妾住東湖下，郎居南浦邊。閑臨煙水望，認得采菱船。',24,'御定全唐詩/json/627.json','["妾住東湖下，郎居南浦邊。閑臨煙水望，認得采菱船。"]'),
('yuding-13','黃金二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','自古黃金貴，猶沽駿與才。近來簪珥重，無可上高臺。',48,'御定全唐詩/json/627.json','["自古黃金貴，猶沽駿與才。近來簪珥重，無可上高臺。", "平分從滿篋，醉擲任成堆。恰莫持千萬，明明買禍胎。"]'),
('yuding-14','夕陽','陸龜蒙','唐','御定全唐诗','yuding','','[]','渡口和帆落，城邊帶角收。如何茂陵客，江上倚危樓。',24,'御定全唐詩/json/627.json','["渡口和帆落，城邊帶角收。如何茂陵客，江上倚危樓。"]'),
('yuding-15','殘雪','陸龜蒙','唐','御定全唐诗','yuding','','[]','桂冷微停素，峰幹不遍嵐。何溪背林處，猶覆定僧庵。',24,'御定全唐詩/json/627.json','["桂冷微停素，峰幹不遍嵐。何溪背林處，猶覆定僧庵。"]'),
('yuding-16','古態','陸龜蒙','唐','御定全唐诗','yuding','','[]','古態日漸薄，新妝心更勞。城中皆一尺，非妾髻鬟高。',24,'御定全唐詩/json/627.json','["古態日漸薄，新妝心更勞。城中皆一尺，非妾髻鬟高。"]'),
('yuding-17','大堤','陸龜蒙','唐','御定全唐诗','yuding','','[]','大堤春日暮，驄馬解鏤衢。請君留上客，容妾薦雕胡。',24,'御定全唐詩/json/627.json','["大堤春日暮，驄馬解鏤衢。請君留上客，容妾薦雕胡。"]'),
('yuding-18','金陵道','陸龜蒙','唐','御定全唐诗','yuding','','[]','北雁行行直，東流澹澹春。當時六朝客，還道帝鄉人。',24,'御定全唐詩/json/627.json','["北雁行行直，東流澹澹春。當時六朝客，還道帝鄉人。"]'),
('yuding-19','離騷','陸龜蒙','唐','御定全唐诗','yuding','','[]','天問複招魂，無因徹帝閽。豈知千麗句，不敵一讒言。',24,'御定全唐詩/json/627.json','["天問複招魂，無因徹帝閽。豈知千麗句，不敵一讒言。"]'),
('yuding-20','對酒','陸龜蒙','唐','御定全唐诗','yuding','','[]','後代稱歡伯，前賢號聖人。且須謀日富，不要道家貧。',24,'御定全唐詩/json/627.json','["後代稱歡伯，前賢號聖人。且須謀日富，不要道家貧。"]'),
('yuding-21','寄南嶽客乞靈蕪香','陸龜蒙','唐','御定全唐诗','yuding','','[]','聞說融峰下，靈香似反魂。春來正堪采，試為劚雲根。',24,'御定全唐詩/json/627.json','["聞說融峰下，靈香似反魂。春來正堪采，試為劚雲根。"]'),
('yuding-22','山陽燕中郊樂錄','陸龜蒙','唐','御定全唐诗','yuding','','[]','淮上能無雨，回頭總是情。蒲帆渾未織，爭得一歡成。',24,'御定全唐詩/json/627.json','["淮上能無雨，回頭總是情。蒲帆渾未織，爭得一歡成。"]'),
('yuding-23','偶作','陸龜蒙','唐','御定全唐诗','yuding','','[]','雙眉初出繭，兩鬢正藏鴉。自有王昌在，何勞近宋家。',24,'御定全唐詩/json/627.json','["雙眉初出繭，兩鬢正藏鴉。自有王昌在，何勞近宋家。"]'),
('yuding-24','有示','陸龜蒙','唐','御定全唐诗','yuding','','[]','相對莫辭貧，蓬蒿任塞門。無情是金玉，不報主人恩。',24,'御定全唐詩/json/627.json','["相對莫辭貧，蓬蒿任塞門。無情是金玉，不報主人恩。"]'),
('yuding-25','秋思三首','陸龜蒙','唐','御定全唐诗','yuding','','[]','桐露珪初落，蘭風佩欲衰。不知能賦客，何似枉刀兒。',72,'御定全唐詩/json/627.json','["桐露珪初落，蘭風佩欲衰。不知能賦客，何似枉刀兒。", "誰在嫖姚幕，能教霹靂車。至今思禿尾，無以代寒菹。", "未得同齏杵，何時減藥囊。莫言天帝醉，秦暴不靈長。"]'),
('yuding-26','早春','陸龜蒙','唐','御定全唐诗','yuding','','[]','雨冷唯添暑，煙初不著春。數枝花纇小，愁殺扈芳人。',24,'御定全唐詩/json/627.json','["雨冷唯添暑，煙初不著春。數枝花纇小，愁殺扈芳人。"]'),
('yuding-27','懷仙三首','陸龜蒙','唐','御定全唐诗','yuding','','[]','聞道陽都女，連娟耳細長。自非黃犢客，不得到雲房。',72,'御定全唐詩/json/627.json','["聞道陽都女，連娟耳細長。自非黃犢客，不得到雲房。", "但服鐶剛子，兼吟曲素詞。須知臣漢客，還見布龍兒。", "神燭光華麗，靈祛羽翼生。已傳餐玉粒，猶自買雲英。"]'),
('yuding-28','芙蓉','陸龜蒙','唐','御定全唐诗','yuding','','[]','閑吟鮑照賦，更起屈平愁。莫引西風動，紅衣不耐秋。',24,'御定全唐詩/json/627.json','["閑吟鮑照賦，更起屈平愁。莫引西風動，紅衣不耐秋。"]'),
('yuding-29','春思','陸龜蒙','唐','御定全唐诗','yuding','','[]','怨鶯新語澀，雙蝶鬥飛高。作個名春恨，浮生百倍勞。',24,'御定全唐詩/json/627.json','["怨鶯新語澀，雙蝶鬥飛高。作個名春恨，浮生百倍勞。"]'),
('yuding-30','風人詩四首','陸龜蒙','唐','御定全唐诗','yuding','','[]','十萬全師出，遙知正憶君。一心如瑞麥，長作兩岐分。',96,'御定全唐詩/json/627.json','["十萬全師出，遙知正憶君。一心如瑞麥，長作兩岐分。", "破檗供朝爨，須憐是苦辛。曉天窺落宿，誰識獨醒人。", "旦日思雙屨，明時願早諧。丹青傳四瀆，難寫是秋懷。", "聞道更新幟，多應發舊旗。征衣無伴搗，獨處自然悲。"]'),
('yuding-31','樂府雜詠六首：雙吹管','陸龜蒙','唐','御定全唐诗','yuding','','[]','長短裁浮筠，參差作飛鳳。高樓微月夜，吹出江南弄。',24,'御定全唐詩/json/627.json','["長短裁浮筠，參差作飛鳳。高樓微月夜，吹出江南弄。"]'),
('yuding-32','樂府雜詠六首：東飛鳧','陸龜蒙','唐','御定全唐诗','yuding','','[]','裁得尺錦書，欲寄東飛鳧。脛短翅亦短，雌雄戀菰蒲。',24,'御定全唐詩/json/627.json','["裁得尺錦書，欲寄東飛鳧。脛短翅亦短，雌雄戀菰蒲。"]'),
('yuding-33','樂府雜詠六首：花成子','陸龜蒙','唐','御定全唐诗','yuding','','[]','春風等君意，亦解欺桃李。寫得去時真，歸來不相似。',24,'御定全唐詩/json/627.json','["春風等君意，亦解欺桃李。寫得去時真，歸來不相似。"]'),
('yuding-34','樂府雜詠六首：月成弦','陸龜蒙','唐','御定全唐诗','yuding','','[]','孤光照還沒，轉益傷離別。妾若是嫦娥，長圓不教缺。',24,'御定全唐詩/json/627.json','["孤光照還沒，轉益傷離別。妾若是嫦娥，長圓不教缺。"]'),
('yuding-35','樂府雜詠六首：孤燭怨','陸龜蒙','唐','御定全唐诗','yuding','','[]','前回邊使至，聞道交河戰。坐想鼓鞞聲，寸心攢百箭。',24,'御定全唐詩/json/627.json','["前回邊使至，聞道交河戰。坐想鼓鞞聲，寸心攢百箭。"]'),
('yuding-36','樂府雜詠六首：金吾子','陸龜蒙','唐','御定全唐诗','yuding','','[]','嫁得金吾子，常聞輕薄名。君心如不重，妾腰徒自輕。',24,'御定全唐詩/json/627.json','["嫁得金吾子，常聞輕薄名。君心如不重，妾腰徒自輕。"]'),
('yuding-37','子夜四時歌：春','陸龜蒙','唐','御定全唐诗','yuding','','[]','山連翠羽屏，草接煙華席。望盡南飛燕，佳人斷消息。',24,'御定全唐詩/json/627.json','["山連翠羽屏，草接煙華席。望盡南飛燕，佳人斷消息。"]'),
('yuding-38','子夜四時歌：夏','陸龜蒙','唐','御定全唐诗','yuding','','[]','蘭眼抬路斜，鶯唇映花老。金龍傾漏盡，玉井敲冰早。',24,'御定全唐詩/json/627.json','["蘭眼抬路斜，鶯唇映花老。金龍傾漏盡，玉井敲冰早。"]'),
('yuding-39','子夜四時歌：秋','陸龜蒙','唐','御定全唐诗','yuding','','[]','涼漢清泬寥，衰林怨風雨。愁聽絡緯唱，似與羈魂語。',24,'御定全唐詩/json/627.json','["涼漢清泬寥，衰林怨風雨。愁聽絡緯唱，似與羈魂語。"]'),
('yuding-40','子夜四時歌：冬','陸龜蒙','唐','御定全唐诗','yuding','','[]','南雲走冷圭，北籟號空木。年年任霜霰，不減筼簹綠。',24,'御定全唐詩/json/627.json','["南雲走冷圭，北籟號空木。年年任霜霰，不減筼簹綠。"]'),
('yuding-41','大子夜歌二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','歌謠數百種，子夜最可憐。慷慨吐清音，明轉出天然。',48,'御定全唐詩/json/627.json','["歌謠數百種，子夜最可憐。慷慨吐清音，明轉出天然。", "絲竹發歌響，假器揚清音。不知歌謠妙，聲勢出口心。"]'),
('yuding-42','子夜警歌二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','鏤碗傳綠酒，雕爐熏紫煙。誰知苦寒調，共作白雪弦。',48,'御定全唐詩/json/627.json','["鏤碗傳綠酒，雕爐熏紫煙。誰知苦寒調，共作白雪弦。", "恃愛如欲進，含羞出不前。朱口發豔歌，玉指弄嬌弦。"]'),
('yuding-43','子夜變歌三首','陸龜蒙','唐','御定全唐诗','yuding','','[]','人傳歡負情，我自未嘗見。三更開門去，始知子夜變。',72,'御定全唐詩/json/627.json','["人傳歡負情，我自未嘗見。三更開門去，始知子夜變。", "歲月如流邁，春盡秋已至。熒熒條上花，零落何乃駛。", "歲月如流邁，行已及素秋。蟋蟀吟堂前，惆悵使儂愁。"]'),
('yuding-44','江南曲五首','陸龜蒙','唐','御定全唐诗','yuding','','[]','魚戲蓮葉間，參差隱葉扇。鵁鶄鸀鳿窺，瀲灩無因見。',120,'御定全唐詩/json/627.json','["魚戲蓮葉間，參差隱葉扇。鵁鶄鸀鳿窺，瀲灩無因見。", "魚戲蓮葉東，初霞射紅尾。旁臨謝山側，恰值清風起。", "魚戲蓮葉西，盤盤舞波急。潛依曲岸涼，正直斜光入。", "魚戲蓮葉南，欹危舞煙疊。光搖越鳥巢，影亂吳娃楫。", "魚戲蓮葉北，澄陽動微漣。回看帝子渚，稍背鄂君船。"]'),
('yuding-0','陌上桑','陸龜蒙','唐','御定全唐诗','yuding','','[]','皓齒還如貝色含，長眉亦似煙華貼。',32,'御定全唐詩/json/628.json','["皓齒還如貝色含，長眉亦似煙華貼。", "鄰娃盡著繡襠襦，獨自提筐采蠶葉。"]'),
('yuding-1','自遣詩三十首','陸龜蒙','唐','御定全唐诗','yuding','','[]','五年重別舊山村，樹有交柯犢有孫。',384,'御定全唐詩/json/628.json','["五年重別舊山村，樹有交柯犢有孫。", "更感卞峰顏色好，曉雲才散便當門。", "雪下孤村淅淅鳴，病魂無睡灑來清。", "心搖只待東窗曉，長愧寒雞第一聲。", "多情多感自難忘，只有風流共古長。", "座上不遺金帶枕，陳王詞賦為誰傷。", "甫裏先生未白頭，酒旗猶可戰高樓。", "長鯨好鱠無因得，乞取艅艎作釣舟。", "花瀨濛濛紫氣昏，水邊山曲更深村。", "終須揀取幽棲處，老檜成雙便作門。", "陰洞曾為采藥行，冷雲凝絕燭微明。", "玉芝敲折琤然墮，合有真人上姓名。", "長歎人間發易華，暗將心事許煙霞。", "病來前約分明在，藥鼎書囊便是家。", "醞得秋泉似玉容，比於雲液更應濃。", "思量北海徐劉輩，枉向人間號酒龍。", "羊侃多應自古豪，解盤金槊置纖腰。", "縱然此事教雙得，不博溪田二頃苗。", "偶然攜稚看微波，臨水春寒一倍多。", "便使筆精如逸少，懶能書字換群鵝。", "昔聞莊叟迢迢夢，又道韓生苒苒飛。", "知有姓名聊寄問，更無言語抱斜暉。", "雪侵春事太無端，舞急微還近臘寒。", "應是也疑真宰怪，休時猶未遍林巒。"]'),
('yuding-2','別墅懷歸','陸龜蒙','唐','御定全唐诗','yuding','','[]','東去滄溟百里餘，沿江潮信到吾廬。',32,'御定全唐詩/json/628.json','["東去滄溟百里餘，沿江潮信到吾廬。", "就中家在蓬山下，一日堪憑兩寄書。"]'),
('yuding-3','野井','陸龜蒙','唐','御定全唐诗','yuding','','[]','朱閣前頭露井多，碧梧桐下美人過。',32,'御定全唐詩/json/628.json','["朱閣前頭露井多，碧梧桐下美人過。", "寒泉未必能如此，奈有銀瓶素綆何。"]'),
('yuding-4','南征','陸龜蒙','唐','御定全唐诗','yuding','','[]','丞相南征定有無，幕中誰是騁良圖。',32,'御定全唐詩/json/628.json','["丞相南征定有無，幕中誰是騁良圖。", "遙知賊膽縱橫破，繞帳生犀一萬株。"]'),
('yuding-5','北渡','陸龜蒙','唐','御定全唐诗','yuding','','[]','江客柴門枕浪花，鳴機寒櫓任嘔啞。',32,'御定全唐詩/json/628.json','["江客柴門枕浪花，鳴機寒櫓任嘔啞。", "輕舟過去真堪畫，驚起鸕鷀一陣斜。"]'),
('yuding-6','夜泊詠棲鴻','陸龜蒙','唐','御定全唐诗','yuding','','[]','可憐霜月暫相依，莫向衡陽趁逐飛。',32,'御定全唐詩/json/628.json','["可憐霜月暫相依，莫向衡陽趁逐飛。", "同是江南寒夜客，羽毛單薄稻粱微。"]'),
('yuding-7','早行','陸龜蒙','唐','御定全唐诗','yuding','','[]','水寒孤棹觸天文，直似乘槎去問津。',32,'御定全唐詩/json/628.json','["水寒孤棹觸天文，直似乘槎去問津。", "縱使碧虛無限好，客星名字也愁人。"]'),
('yuding-8','木蘭堂','陸龜蒙','唐','御定全唐诗','yuding','','[]','洞庭波浪渺無津，日日征帆送遠人。',32,'御定全唐詩/json/628.json','["洞庭波浪渺無津，日日征帆送遠人。", "幾度木蘭舟上望，不知元是此花身。"]'),
('yuding-9','和襲美春夕陪崔諫議櫻桃園宴','陸龜蒙','唐','御定全唐诗','yuding','','[]','佳人芳樹雜春蹊，花外煙蒙月漸低。',32,'御定全唐詩/json/628.json','["佳人芳樹雜春蹊，花外煙蒙月漸低。", "幾度豔歌清欲轉，流鶯驚起不成棲。"]'),
('yuding-10','和襲美松江早春','陸龜蒙','唐','御定全唐诗','yuding','','[]','柳下江餐待好風，暫時還得狎漁翁。',32,'御定全唐詩/json/628.json','["柳下江餐待好風，暫時還得狎漁翁。", "一生無事煙波足，唯有沙邊水勃公。"]'),
('yuding-11','和襲美女墳湖','陸龜蒙','唐','御定全唐诗','yuding','','[]','水準波淡繞回塘，鶴殉人沉萬古傷。',32,'御定全唐詩/json/628.json','["水準波淡繞回塘，鶴殉人沉萬古傷。", "應是離魂雙不得，至今沙上少鴛鴦。"]'),
('yuding-12','和襲美泰伯廟','陸龜蒙','唐','御定全唐诗','yuding','','[]','故國城荒德未荒，年年椒奠濕中堂。',32,'御定全唐詩/json/628.json','["故國城荒德未荒，年年椒奠濕中堂。", "邇來父子爭天下，不信人間有讓王。"]'),
('yuding-13','和襲美木蘭院次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','苦吟清漏迢迢極，月過花西尚未眠。',32,'御定全唐詩/json/628.json','["苦吟清漏迢迢極，月過花西尚未眠。", "猶憶故山欹警枕，夜來嗚咽似流泉。"]'),
('yuding-14','和襲美重題薔薇','陸龜蒙','唐','御定全唐诗','yuding','','[]','穠華自古不得久，況是倚春春已空。',32,'御定全唐詩/json/628.json','["穠華自古不得久，況是倚春春已空。", "更被夜來風雨惡，滿階狼藉沒多紅。"]'),
('yuding-15','和襲美春夕酒醒','陸龜蒙','唐','御定全唐诗','yuding','','[]','幾年無事傍江湖，醉倒黃公舊酒壚。',32,'御定全唐詩/json/628.json','["幾年無事傍江湖，醉倒黃公舊酒壚。", "覺後不知明月上，滿身花影倩人扶。"]'),
('yuding-16','和襲美木蘭後池三詠：重台蓮花','陸龜蒙','唐','御定全唐诗','yuding','','[]','水國煙鄉足芰荷，就中芳瑞此難過。',32,'御定全唐詩/json/628.json','["水國煙鄉足芰荷，就中芳瑞此難過。", "風情為與吳王近，紅萼常教一倍多。"]'),
('yuding-17','和襲美木蘭後池三詠：浮萍','陸龜蒙','唐','御定全唐诗','yuding','','[]','晚來風約半池明，重疊侵沙綠罽成。',32,'御定全唐詩/json/628.json','["晚來風約半池明，重疊侵沙綠罽成。", "不用臨池更相笑，最無根蒂是浮名。"]'),
('yuding-18','和襲美木蘭後池三詠：白蓮','陸龜蒙','唐','御定全唐诗','yuding','','[]','素花多蒙別豔欺，此花真合在瑤池。',32,'御定全唐詩/json/628.json','["素花多蒙別豔欺，此花真合在瑤池。", "還應有恨無人覺，月曉風清欲墮時。"]'),
('yuding-19','和襲美重題後池','陸龜蒙','唐','御定全唐诗','yuding','','[]','曉煙清露暗相和，浴雁浮鷗意緒多。',32,'御定全唐詩/json/628.json','["曉煙清露暗相和，浴雁浮鷗意緒多。", "卻是陳王詞賦錯，枉將心事托微波。"]'),
('yuding-20','和胥門閑泛','陸龜蒙','唐','御定全唐诗','yuding','','[]','細槳輕撶下白蘋，故城花謝綠陰新。',32,'御定全唐詩/json/628.json','["細槳輕撶下白蘋，故城花謝綠陰新。", "豈無今日逃名士，試問南塘著屟人。"]'),
('yuding-21','襲美初植松桂偶題','陸龜蒙','唐','御定全唐诗','yuding','','[]','軒陰冉冉移斜日，寒韻泠泠入晚風。',32,'御定全唐詩/json/628.json','["軒陰冉冉移斜日，寒韻泠泠入晚風。", "煙格月姿曾不改，至今猶似在山中。"]'),
('yuding-22','和襲美館娃宮懷古五絕','陸龜蒙','唐','御定全唐诗','yuding','','[]','三千雖衣水犀珠，半夜夫差國暗屠。',160,'御定全唐詩/json/628.json','["三千雖衣水犀珠，半夜夫差國暗屠。", "猶有八人皆二八，獨教西子占亡吳。", "一宮花渚漾漣漪，俀墮鴉鬟出繭眉。", "可料座中歌舞袖，便將殘節拂降旗。", "幾多雲榭倚青冥，越焰燒來一片平。", "此地最應沾恨血，至今春草不勻生。", "江色分明練繞台，戰帆遙隔綺疏開。", "波神自厭荒淫主，勾踐樓船穩帖來。", "寶襪香綦碎曉塵，亂兵誰惜似花人。", "伯勞應是精靈使，猶向殘陽泣暮春。"]'),
('yuding-23','和襲美虎丘寺西小溪閑泛三絕','陸龜蒙','唐','御定全唐诗','yuding','','[]','樹號相思枝拂地，鳥語提壺聲滿溪。',96,'御定全唐詩/json/628.json','["樹號相思枝拂地，鳥語提壺聲滿溪。", "雲涯一裏千萬曲，直是漁翁行也迷。", "荒柳臥波渾似困，宿雲遮塢未全癡。", "雲情柳意蕭蕭會，若問諸餘總不知。", "每逢孤嶼一倚楫，便欲狂歌同采薇。", "任是煙蘿中待月，不妨欹枕扣舷歸。"]'),
('yuding-24','和襲美天竺寺八月十五夜桂子','陸龜蒙','唐','御定全唐诗','yuding','','[]','霜實常聞秋半夜，天臺天竺墮雲岑。',32,'御定全唐詩/json/628.json','["霜實常聞秋半夜，天臺天竺墮雲岑。", "如何兩地無人種，卻是湘漓是桂林。"]'),
('yuding-25','戲題襲美書印囊','陸龜蒙','唐','御定全唐诗','yuding','','[]','鵲銜龜顧妙無餘，不愛封侯愛石渠。',32,'御定全唐詩/json/628.json','["鵲銜龜顧妙無餘，不愛封侯愛石渠。", "應笑休文過萬卷，至今誰道沈家書。"]'),
('yuding-26','和襲美釣侶二章','陸龜蒙','唐','御定全唐诗','yuding','','[]','一艇輕撶看曉濤，接z5拋下漉春醪。',65,'御定全唐詩/json/628.json','["一艇輕撶看曉濤，接z5拋下漉春醪。", "相逢便倚蒹葭泊，更唱菱歌擘蟹螯。", "雨後沙虛古岸崩，魚梁移入亂雲層。", "歸時月墮汀洲暗，認得妻兒結網燈。"]'),
('yuding-27','和襲美寄同年韋校書','陸龜蒙','唐','御定全唐诗','yuding','','[]','萬古風煙滿故都，清才搜括妙無餘。',32,'御定全唐詩/json/628.json','["萬古風煙滿故都，清才搜括妙無餘。", "可中寄與芸香客，便是江南地裏書。"]'),
('yuding-28','和襲美初冬偶作','陸龜蒙','唐','御定全唐诗','yuding','','[]','桐下空階疊綠錢，貂裘初綻擁高眠。',32,'御定全唐詩/json/628.json','["桐下空階疊綠錢，貂裘初綻擁高眠。", "小爐低幌還遮掩，酒滴灰香似去年。"]'),
('yuding-29','襲美醉中寄一壺並一絕，走筆次韻奉酬','陸龜蒙','唐','御定全唐诗','yuding','','[]','酒痕衣上雜莓苔，猶憶紅螺一兩杯。',32,'御定全唐詩/json/628.json','["酒痕衣上雜莓苔，猶憶紅螺一兩杯。", "正被繞籬荒菊笑，日斜還有白衣來。"]'),
('yuding-30','再和次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','階下饑禽啄嫩苔，野人方倒病中杯。',32,'御定全唐詩/json/628.json','["階下饑禽啄嫩苔，野人方倒病中杯。", "寒蔬賣卻還沽吃，可有金貂換得來。"]'),
('yuding-31','和襲美重玄寺雙矮檜','陸龜蒙','唐','御定全唐诗','yuding','','[]','可憐煙刺是青螺，如到雙林誤禮多。',32,'御定全唐詩/json/628.json','["可憐煙刺是青螺，如到雙林誤禮多。", "更憶早秋登北固，海門蒼翠出晴波。"]'),
('yuding-32','醉中戲贈襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','南北風流舊不同，傖吳今日若相通。',32,'御定全唐詩/json/628.json','["南北風流舊不同，傖吳今日若相通。", "病來猶伴金杯滿，欲得人呼小褚公。"]'),
('yuding-33','潤卿遺青z3飯兼之一絕，聊用答謝','陸龜蒙','唐','御定全唐诗','yuding','','[]','舊聞香積金仙食，今見青精玉斧餐。',32,'御定全唐詩/json/628.json','["舊聞香積金仙食，今見青精玉斧餐。", "自笑鏡中無骨錄，可能飛上紫雪端。"]'),
('yuding-34','文宴招潤卿博士辭以道侶將至一絕寄之','陸龜蒙','唐','御定全唐诗','yuding','','[]','仙客何時下鶴翎，方瞳如水腦華清。',32,'御定全唐詩/json/628.json','["仙客何時下鶴翎，方瞳如水腦華清。", "不過傳達楊君夢，從許人間小兆聽。"]'),
('yuding-35','再招','陸龜蒙','唐','御定全唐诗','yuding','','[]','遙知道侶談玄次，又是文交麗事時。',32,'御定全唐詩/json/628.json','["遙知道侶談玄次，又是文交麗事時。", "雖是寒輕雲重日，也留花簟待徐摛。"]'),
('yuding-36','玩金鸂鶒戲贈襲美','陸龜蒙','唐','御定全唐诗','yuding','','[]','曾向溪邊泊暮雲，至今猶憶浪花群。',32,'御定全唐詩/json/628.json','["曾向溪邊泊暮雲，至今猶憶浪花群。", "不知鏤羽凝香霧，堪與鴛鴦覺後聞。"]'),
('yuding-37','子規一首','陸龜蒙','唐','御定全唐诗','yuding','','[]','碧竿微露月玲瓏，謝豹傷心獨叫風。',32,'御定全唐詩/json/628.json','["碧竿微露月玲瓏，謝豹傷心獨叫風。", "高處已應聞滴血，山榴一夜幾枝紅。"]'),
('yuding-38','寄題天臺國清寺齊梁體','陸龜蒙','唐','御定全唐诗','yuding','','[]','峰帶樓臺天外立，明河色近罘罳濕。',32,'御定全唐詩/json/628.json','["峰帶樓臺天外立，明河色近罘罳濕。", "松間石上定僧寒，半夜楢溪水聲急。"]'),
('yuding-39','奉和諫議酬先輩霜菊','陸龜蒙','唐','御定全唐诗','yuding','','[]','紫莖芳豔照西風，只怕霜華掠斷叢。',32,'御定全唐詩/json/628.json','["紫莖芳豔照西風，只怕霜華掠斷叢。", "爭奈病夫難強飲，應須速自召車公。"]'),
('yuding-40','和襲美詠皋橋','陸龜蒙','唐','御定全唐诗','yuding','','[]','橫截春流架斷虹，憑欄猶思五噫風。',32,'御定全唐詩/json/628.json','["橫截春流架斷虹，憑欄猶思五噫風。", "今來未必非梁孟，卻是無人斷伯通。"]'),
('yuding-41','和襲美悼鶴','陸龜蒙','唐','御定全唐诗','yuding','','[]','酆都香稻字重思，遙想飛魂去未饑。',32,'御定全唐詩/json/628.json','["酆都香稻字重思，遙想飛魂去未饑。", "爭奈野鴉無數健，黃昏來占舊棲枝。"]'),
('yuding-42','和醉中襲美先起次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','莫唱豔歌凝翠黛，已通仙籍在金閨。',32,'御定全唐詩/json/628.json','["莫唱豔歌凝翠黛，已通仙籍在金閨。", "他時若寄相思淚，紅粉痕應伴紫泥。"]'),
('yuding-43','和襲美酒病偶作次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','柳疏桐下晚窗明，只有微風為折酲。',32,'御定全唐詩/json/628.json','["柳疏桐下晚窗明，只有微風為折酲。", "唯欠白綃籠解散，洛生閑詠兩三聲。"]'),
('yuding-44','憶白菊','陸龜蒙','唐','御定全唐诗','yuding','','[]','稚子書傳白菊開，西成相滯未容回。',32,'御定全唐詩/json/628.json','["稚子書傳白菊開，西成相滯未容回。", "月明階下窗紗薄，多少清香透入來。"]'),
('yuding-45','和同潤卿寒夜訪襲美各惜其志次韻','陸龜蒙','唐','御定全唐诗','yuding','','[]','醉韻飄飄不可親，掉頭吟側華陽巾。',32,'御定全唐詩/json/628.json','["醉韻飄飄不可親，掉頭吟側華陽巾。", "如能跂腳南窗下，便是羲皇世上人。"]'),
('yuding-46','和襲美寒夜文宴潤卿有期不至','陸龜蒙','唐','御定全唐诗','yuding','','[]','細雨輕觴玉漏終，上清詞句落吟中。',32,'御定全唐詩/json/628.json','["細雨輕觴玉漏終，上清詞句落吟中。", "松齋一夜懷貞白，霜外空聞五粒風。"]'),
('yuding-47','移石盆','陸龜蒙','唐','御定全唐诗','yuding','','[]','移得龍泓瀲灩寒，月輪初下白雲端。',32,'御定全唐詩/json/628.json','["移得龍泓瀲灩寒，月輪初下白雲端。", "無人盡日澄心坐，倒影新篁一兩竿。"]'),
('yuding-48','石竹花詠','陸龜蒙','唐','御定全唐诗','yuding','','[]','曾看南朝畫國娃，古蘿衣上碎明霞。',32,'御定全唐詩/json/628.json','["曾看南朝畫國娃，古蘿衣上碎明霞。", "而今莫共金錢鬥，買卻春風是此花。"]'),
('yuding-0','和襲美友人許惠酒以詩征之','陸龜蒙','唐','御定全唐诗','yuding','','[]','凍醪初漉嫩如春，輕蟻漂漂雜蕊塵。',32,'御定全唐詩/json/629.json','["凍醪初漉嫩如春，輕蟻漂漂雜蕊塵。", "得伴方平同一醉，明朝應作蔡經身。"]'),
('yuding-1','聞圓載上人挾儒書洎釋典歸日本國，更作一絕以送','陸龜蒙','唐','御定全唐诗','yuding','','[]','九流三藏一時傾，萬軸光淩渤澥聲。',32,'御定全唐詩/json/629.json','["九流三藏一時傾，萬軸光淩渤澥聲。", "從此遺編東去後，卻應荒外有諸生。"]'),
('yuding-2','閑吟','陸龜蒙','唐','御定全唐诗','yuding','','[]','閑吟料得三更盡，始把孤燈背竹窗。',32,'御定全唐詩/json/629.json','["閑吟料得三更盡，始把孤燈背竹窗。", "一夜西風高浪起，不教歸夢過寒江。"]'),
('yuding-3','秘色越器','陸龜蒙','唐','御定全唐诗','yuding','','[]','九秋風露越窯開，奪得千峰翠色來。',32,'御定全唐詩/json/629.json','["九秋風露越窯開，奪得千峰翠色來。", "好向中宵盛沆瀣，共嵇中散鬥遺杯。"]'),
('yuding-4','景陽宮井','陸龜蒙','唐','御定全唐诗','yuding','','[]','古堞煙埋宮井樹，陳主吳姬墮泉處。',32,'御定全唐詩/json/629.json','["古堞煙埋宮井樹，陳主吳姬墮泉處。", "舜沒蒼梧萬里雲，卻不聞將二妃去。"]'),
('yuding-5','江南二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','便風船尾香粳熟，細雨層頭赤鯉跳。',64,'御定全唐詩/json/629.json','["便風船尾香粳熟，細雨層頭赤鯉跳。", "待得江餐閑望足，日斜方動木蘭橈。", "村邊紫豆花垂次，岸上紅梨葉戰初。", "莫怪煙中重回首，酒家青紵一行書。"]'),
('yuding-6','溪思雨中','陸龜蒙','唐','御定全唐诗','yuding','','[]','雨映前山萬絇絲，櫓聲衝破似鳴機。',32,'御定全唐詩/json/629.json','["雨映前山萬絇絲，櫓聲衝破似鳴機。", "無端織得愁成段，堪作騷人酒病衣。"]'),
('yuding-7','江城夜泊','陸龜蒙','唐','御定全唐诗','yuding','','[]','漏移寒箭丁丁急，月掛虛弓靄靄明。',32,'御定全唐詩/json/629.json','["漏移寒箭丁丁急，月掛虛弓靄靄明。", "此夜離魂堪射斷，更須江笛兩三聲。"]'),
('yuding-8','宮人斜','陸龜蒙','唐','御定全唐诗','yuding','','[]','草著愁煙似不春，晚鶯哀怨問行人。',32,'御定全唐詩/json/629.json','["草著愁煙似不春，晚鶯哀怨問行人。", "須知一種埋香骨，猶勝昭君作虜塵。"]'),
('yuding-9','送棋客','陸龜蒙','唐','御定全唐诗','yuding','','[]','滿目山川似勢棋，況當秋雁正斜飛。',32,'御定全唐詩/json/629.json','["滿目山川似勢棋，況當秋雁正斜飛。", "金門若召羊玄保，賭取江東太守歸。"]'),
('yuding-10','漢宮詞','陸龜蒙','唐','御定全唐诗','yuding','','[]','招靈閣上霓旌絕，柏梁台中珠翠稠。',32,'御定全唐詩/json/629.json','["招靈閣上霓旌絕，柏梁台中珠翠稠。", "一身三十六宮夜，露滴玉盤青桂秋。"]'),
('yuding-11','上清','陸龜蒙','唐','御定全唐诗','yuding','','[]','玉林風露寂寥清，仙妃對月閑吹笙。',32,'御定全唐詩/json/629.json','["玉林風露寂寥清，仙妃對月閑吹笙。", "新篁冷澀曲未盡，細拂雲枝棲鳳驚。"]'),
('yuding-12','秋荷','陸龜蒙','唐','御定全唐诗','yuding','','[]','蒲茸承露有佳色，茭葉束煙如效顰。',32,'御定全唐詩/json/629.json','["蒲茸承露有佳色，茭葉束煙如效顰。", "盈盈一水不得渡，冷翠遺香愁向人。"]'),
('yuding-13','有別二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','且將絲wf系蘭舟，醉下煙汀減去愁。',65,'御定全唐詩/json/629.json','["且將絲wf系蘭舟，醉下煙汀減去愁。", "江上有樓君莫上，落花隨浪正東流。", "池上已看鶯舌默，雲間應即雁翰開。", "唯愁別後當風立，萬樹將秋入恨來。"]'),
('yuding-14','病中曉思','陸龜蒙','唐','御定全唐诗','yuding','','[]','月墮霜西竹井寒，轆轤絲凍下瓶難。',32,'御定全唐詩/json/629.json','["月墮霜西竹井寒，轆轤絲凍下瓶難。", "幽人病久渾成渴，愁見龍書一鼎幹。"]'),
('yuding-15','送友人之湖上','陸龜蒙','唐','御定全唐诗','yuding','','[]','故人溪上有漁舟，竿倚風蘋夜不收。',32,'御定全唐詩/json/629.json','["故人溪上有漁舟，竿倚風蘋夜不收。", "欲寄一函聊問訊，洪喬寧作置書郵。"]'),
('yuding-16','寒日逢僧','陸龜蒙','唐','御定全唐诗','yuding','','[]','瘦脛高褰梵屟輕，野塘風勁錫環鳴。',32,'御定全唐詩/json/629.json','["瘦脛高褰梵屟輕，野塘風勁錫環鳴。", "如何不向深山裏，坐擁閑雲過一生。"]'),
('yuding-17','冬柳','陸龜蒙','唐','御定全唐诗','yuding','','[]','柳汀斜對野人窗，零落衰條傍曉江。',32,'御定全唐詩/json/629.json','["柳汀斜對野人窗，零落衰條傍曉江。", "正是霜風飄斷處，寒鷗驚起一雙雙。"]'),
('yuding-18','寄友人','陸龜蒙','唐','御定全唐诗','yuding','','[]','敬亭寒夜溪聲裏，同聽先生講太玄。',32,'御定全唐詩/json/629.json','["敬亭寒夜溪聲裏，同聽先生講太玄。", "上得雲梯不回首，釣竿猶在五湖邊。"]'),
('yuding-19','島樹','陸龜蒙','唐','御定全唐诗','yuding','','[]','波濤漱苦盤根淺，風雨飄多著葉遲。',32,'御定全唐詩/json/629.json','["波濤漱苦盤根淺，風雨飄多著葉遲。", "迥出孤煙殘照裏，鷺鶿相對立高枝。"]'),
('yuding-20','頭陀僧','陸龜蒙','唐','御定全唐诗','yuding','','[]','萬峰圍繞一峰深，向此長修苦行心。',32,'御定全唐詩/json/629.json','["萬峰圍繞一峰深，向此長修苦行心。", "自掃雪中歸鹿跡，天明恐被獵人尋。"]'),
('yuding-21','晚渡','陸龜蒙','唐','御定全唐诗','yuding','','[]','半波風雨半波晴，漁曲飄秋野調清。',32,'御定全唐詩/json/629.json','["半波風雨半波晴，漁曲飄秋野調清。", "各樣蓮船逗村去，笠簷蓑袂有殘聲。"]'),
('yuding-22','贈老僧二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','枯貌自同霜裏木，餘生唯指佛前燈。',64,'御定全唐詩/json/629.json','["枯貌自同霜裏木，餘生唯指佛前燈。", "少時寫得坐禪影，今見問人何處僧。", "自有家山供衲線，不離溪曲取庵茅。", "舊曾聞說林中鳥，定後長來頂上巢。"]'),
('yuding-23','憶山泉','陸龜蒙','唐','御定全唐诗','yuding','','[]','一夜寒聲來夢裏，平明著屐到聲邊。',32,'御定全唐詩/json/629.json','["一夜寒聲來夢裏，平明著屐到聲邊。", "心期盛夏同過此，脫卻荷衣石上眠。"]'),
('yuding-24','白芙蓉','陸龜蒙','唐','御定全唐诗','yuding','','[]','澹然相對卻成勞，月染風裁個個高。',32,'御定全唐詩/json/629.json','["澹然相對卻成勞，月染風裁個個高。", "似說玉皇親謫墮，至今猶著水霜袍。"]'),
('yuding-25','嚴光釣台','陸龜蒙','唐','御定全唐诗','yuding','','[]','片帆竿外揖清風，石立雲孤萬古中。',32,'御定全唐詩/json/629.json','["片帆竿外揖清風，石立雲孤萬古中。", "不是狂奴為故態，仲華爭得黑頭公。"]'),
('yuding-26','讀陳拾遺集','陸龜蒙','唐','御定全唐诗','yuding','','[]','蓬顆何時與恨平，蜀江衣帶蜀山輕。',32,'御定全唐詩/json/629.json','["蓬顆何時與恨平，蜀江衣帶蜀山輕。", "尋聞騎士梟黃祖，自是無人祭禰衡。"]'),
('yuding-27','吳宮懷古','陸龜蒙','唐','御定全唐诗','yuding','','[]','香徑長洲盡棘叢，奢雲豔雨只悲風。',32,'御定全唐詩/json/629.json','["香徑長洲盡棘叢，奢雲豔雨只悲風。", "吳王事事須亡國，未必西施勝六宮。"]'),
('yuding-28','送琴客之建康','陸龜蒙','唐','御定全唐诗','yuding','','[]','蕙風杉露共泠泠，三峽寒泉漱玉清。',32,'御定全唐詩/json/629.json','["蕙風杉露共泠泠，三峽寒泉漱玉清。", "君到南朝訪遺事，柳家雙鎖舊知名。"]'),
('yuding-29','閨怨','陸龜蒙','唐','御定全唐诗','yuding','','[]','白袷行人又遠遊，日斜空上映花樓。',32,'御定全唐詩/json/629.json','["白袷行人又遠遊，日斜空上映花樓。", "愁絲墮絮相逢著，絆惹春風卒未休。"]'),
('yuding-30','丁香','陸龜蒙','唐','御定全唐诗','yuding','','[]','江上悠悠人不問，十年雲外醉中身。',32,'御定全唐詩/json/629.json','["江上悠悠人不問，十年雲外醉中身。", "殷勤解卻丁香結，縱放繁枝散誕春。"]'),
('yuding-31','種蒲','陸龜蒙','唐','御定全唐诗','yuding','','[]','杜若溪邊手自移，旋抽煙劍碧參差。',32,'御定全唐詩/json/629.json','["杜若溪邊手自移，旋抽煙劍碧參差。", "何時織得孤帆去，懸向秋風訪所思。"]'),
('yuding-32','范蠡','陸龜蒙','唐','御定全唐诗','yuding','','[]','平吳專越禍胎深，豈是功成有去心。',32,'御定全唐詩/json/629.json','["平吳專越禍胎深，豈是功成有去心。", "勾踐不知嫌鳥喙，歸來猶自鑄良金。"]'),
('yuding-33','山僧二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','山蘚幾重生草履，澗泉長自滿銅瓶。',64,'御定全唐詩/json/629.json','["山蘚幾重生草履，澗泉長自滿銅瓶。", "時將如意敲眠虎，遣向林間坐聽經。", "一夏不離蒼島上，秋來頻話石城南。", "思歸瀑布聲前坐，卻把松枝拂舊庵。"]'),
('yuding-34','上雲樂','陸龜蒙','唐','御定全唐诗','yuding','','[]','青絲作筰桂為船，白兔搗藥蝦蟆丸。',32,'御定全唐詩/json/629.json','["青絲作筰桂為船，白兔搗藥蝦蟆丸。", "便浮天漢泊星渚，回首笑君承露盤。"]'),
('yuding-35','新秋雜題六首：眠','陸龜蒙','唐','御定全唐诗','yuding','','[]','一簟臨窗薤葉秋，小簾風蕩半離鉤。',32,'御定全唐詩/json/629.json','["一簟臨窗薤葉秋，小簾風蕩半離鉤。", "魂清雨急夢難到，身在五湖波上頭。"]'),
('yuding-36','新秋雜題六首：行','陸龜蒙','唐','御定全唐诗','yuding','','[]','尋人直到月塢北，覓鶴便過雲峰西。',32,'御定全唐詩/json/629.json','["尋人直到月塢北，覓鶴便過雲峰西。", "只今猶有疏野調，但繞莓苔風雨畦。"]'),
('yuding-37','新秋雜題六首：倚','陸龜蒙','唐','御定全唐诗','yuding','','[]','橘下凝情香染巾，竹邊留思露搖身。',32,'御定全唐詩/json/629.json','["橘下凝情香染巾，竹邊留思露搖身。", "背煙垂首盡日立，憶得山中無事人。"]'),
('yuding-38','新秋雜題六首：吟','陸龜蒙','唐','御定全唐诗','yuding','','[]','憶山搖膝石上晚，懷古掉頭溪畔涼。',32,'御定全唐詩/json/629.json','["憶山搖膝石上晚，懷古掉頭溪畔涼。", "有時得句一聲發，驚起鷺鶿和夕陽。"]'),
('yuding-39','新秋雜題六首：食','陸龜蒙','唐','御定全唐诗','yuding','','[]','日午空齋帶睡痕，水蔬山藥薦盤飧。',32,'御定全唐詩/json/629.json','["日午空齋帶睡痕，水蔬山藥薦盤飧。", "林烏信我無機事，長到而今下石盆。"]'),
('yuding-40','新秋雜題六首：坐','陸龜蒙','唐','御定全唐诗','yuding','','[]','偶避蟬聲來隙地，忽隨鴻影入遼天。',32,'御定全唐詩/json/629.json','["偶避蟬聲來隙地，忽隨鴻影入遼天。", "閑僧不會寂寥意，道學西方人坐禪。"]'),
('yuding-41','新沙','陸龜蒙','唐','御定全唐诗','yuding','','[]','渤澥聲中漲小堤，官家知後海鷗知。',32,'御定全唐詩/json/629.json','["渤澥聲中漲小堤，官家知後海鷗知。", "蓬萊有路教人到，應亦年年稅紫芝。"]'),
('yuding-42','鄴宮詞二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','魏武平生不好香，楓膠蕙炷潔宮房。',64,'御定全唐詩/json/629.json','["魏武平生不好香，楓膠蕙炷潔宮房。", "可知遺令非前事，卻有餘熏在繡囊。", "花飛蝶駭不愁人，水殿雲廊別置春。", "曉日靚妝千騎女，白櫻桃下紫綸巾。"]');
